INSERT INTO ecommerce_offline.ecom_product (product_id, title, brand, category, sub_category, category_path, base_price, price_min, price_max, stock_total, image_path, raw_json, source_file)
VALUES
    ('p_beauty_001', '雅诗兰黛特润修护肌活精华露淡纹紧致保湿夜间修护抗初老精华30ml', '雅诗兰黛', '美妆护肤', '精华', '美妆护肤/精华', 720.0, 720.0, 1260.0, 300, '1_美妆护肤/images/p_beauty_001_live.jpg', '{"product_id":"p_beauty_001","title":"雅诗兰黛特润修护肌活精华露淡纹紧致保湿夜间修护抗初老精华30ml","brand":"雅诗兰黛","category":"美妆护肤","sub_category":"精华","base_price":720.0,"image_path":"1_美妆护肤/images/p_beauty_001_live.jpg","skus":[{"sku_id":"s_p_beauty_001_1","properties":{"容量":"30ml 经典装"},"price":720.0},{"sku_id":"s_p_beauty_001_2","properties":{"容量":"50ml 加大装"},"price":980.0},{"sku_id":"s_p_beauty_001_3","properties":{"容量":"75ml 家用装"},"price":1260.0}],"rag_knowledge":{"marketing_description":"雅诗兰黛特润修护肌活精华露（小棕瓶）是品牌经典抗初老单品，主打夜间肌底修护。核心成分含高浓度二裂酵母发酵产物溶胞物，能深入修护日间紫外线、污染造成的损伤，促进肌肤代谢；搭配透明质酸锁水保湿，猴面包树籽提取物淡纹紧致。适合25+有干纹细纹、熬夜后暗沉的抗初老人群，夜间护肤时使用效果更佳。建议每晚洁面爽肤后，取3-4滴掌心温热，轻按面部至吸收，后续搭配面霜锁养。注意开封后6个月内用完，敏感肌先做耳后测试，避免不适。","official_faq":[{"question":"这款精华的核心成分二裂酵母发酵产物溶胞物有什么作用？","answer":"二裂酵母发酵产物溶胞物是这款精华的核心修护成分，它能模拟皮肤微生态，帮助修护日间紫外线、污染等外界刺激造成的肌底损伤，促进肌肤新陈代谢，增强皮肤屏障功能。同时，它还能协同其他保湿和抗初老成分，提升肌肤对营养的吸收效率，长期使用可改善皮肤稳定性、细腻度，减少干纹细纹的产生。"},{"question":"不同规格的小棕瓶怎么选？30ml、50ml、75ml各适合什么情况？","answer":"不同规格的选择可根据使用需求和频率：30ml经典装适合初次尝试或短期出差携带，小巧便携；50ml加大装性价比更高，单毫升价格比30ml更划算，适合日常长期使用的用户；75ml家用装容量大更实惠，适合对产品效果认可的老用户囤货，或家庭多人共用，能满足较长时间的使用需求。"},{"question":"这款精华适合敏感肌吗？使用前需要注意什么？","answer":"这款精华大部分肤质适用，但敏感肌需谨慎。因含活性修护成分，建议敏感肌使用前取少量精华涂抹于耳后或手臂内侧，观察24小时无红肿、刺痛等不适再使用。此外，开封后建议6个月内用完，避免成分失活影响效果；存放时需远离阳光直射和高温环境，保持成分活性。"}],"user_reviews":[{"nickname":"李小米","rating":1,"content":"用了两次就脸颊泛红刺痛，我是敏感肌平时用其他精华都没事，这款成分可能太刺激了。虽然包装是正品，但真的不适合敏感肌，早知道先做测试，现在只能闲置，浪费720块，太心疼了。"},{"nickname":"王梓涵","rating":2,"content":"用了快一个月，保湿还行，但淡纹紧致完全没效果。我26岁有轻微干纹，每晚都用，干纹还是在，720块30ml性价比太低，不会再回购了。"},{"nickname":"张雅静","rating":5,"content":"熬夜党救星！每晚3滴吸收超快不黏腻，第二天皮肤不暗沉。半个月后眼角干纹淡了，皮肤也紧致些，已经回购50ml加大装，太爱这款精华了！"},{"nickname":"刘梦琪","rating":2,"content":"包装设计有问题，瓶口总残留精华，倒的时候会滴外面浪费。用了三周除了保湿没别的效果，抗初老根本没感觉，价格还贵，有点失望。"},{"nickname":"陈宇飞","rating":1,"content":"混油皮用了反而更干，还冒闭口。想抗初老结果皮肤状态更差，这款可能不适合混油皮，后悔买了，以后不会再试雅诗兰黛小棕瓶了。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_001.json'),
    ('p_beauty_002', '兰蔻小黑瓶全新精华肌底液修护维稳细腻毛孔提亮肤色30ml', '兰蔻', '美妆护肤', '精华', '美妆护肤/精华', 760.0, 760.0, 1480.0, 300, '1_美妆护肤/images/p_beauty_002_live.jpg', '{"product_id":"p_beauty_002","title":"兰蔻小黑瓶全新精华肌底液修护维稳细腻毛孔提亮肤色30ml","brand":"兰蔻","category":"美妆护肤","sub_category":"精华","base_price":760.0,"image_path":"1_美妆护肤/images/p_beauty_002_live.jpg","skus":[{"sku_id":"s_p_beauty_002_1","properties":{"容量":"30ml 标准装"},"price":760.0},{"sku_id":"s_p_beauty_002_2","properties":{"容量":"50ml 加大装"},"price":1080.0},{"sku_id":"s_p_beauty_002_3","properties":{"容量":"75ml 家庭装"},"price":1480.0}],"rag_knowledge":{"marketing_description":"兰蔻小黑瓶精华肌底液是品牌经典明星产品，核心成分含98%高纯度二裂酵母发酵产物溶胞物，搭配益生元复合物，能深入肌底修护受损屏障，强韧肌肤抵御力。适合25+初抗老、皮肤不稳定（换季敏感/熬夜暗沉）、毛孔粗大的人群。日常护肤可作为第一步使用，早晚洁面后取3-4滴，轻轻按摩至吸收，后续叠加其他精华或面霜效果更佳。熬夜后用它急救，能快速缓解肌肤疲劳感；换季时用可稳定肌肤状态。注意事项：开封后建议6个月内用完，敏感肌使用前先在耳后做局部测试，避免不适。不同规格中，50ml和75ml性价比更高，适合长期使用的用户。","official_faq":[{"question":"兰蔻小黑瓶精华和其他精华的使用顺序应该怎么安排？","answer":"兰蔻小黑瓶属于肌底液，作用是打开肌肤吸收通道，所以应在洁面爽肤后、其他功效型精华前使用。比如你有抗老精华或美白精华，先涂小黑瓶，按摩吸收后再涂后续精华，这样能让后续产品更好地渗透。如果只使用小黑瓶，可直接后续涂面霜。注意不要和含酸类的产品同时使用过于频繁，以免刺激肌肤，建议间隔使用或咨询专业人士。"},{"question":"敏感肌可以使用兰蔻小黑瓶吗？需要注意哪些事项？","answer":"兰蔻小黑瓶含益生元复合物，能调节肌肤微生态，大部分敏感肌是可以使用的，但个体差异存在。敏感肌使用前务必先在耳后或手臂内侧做局部测试，观察24小时无红肿刺痛再上脸。使用时建议从少量开始（2-3滴），逐步建立耐受。如果使用过程中出现不适，应立即停止并清洗，严重时咨询皮肤科医生。另外，敏感肌在换季或肌肤状态不稳定时，可减少使用频率，每周2-3次即可。"},{"question":"兰蔻小黑瓶的不同规格（30ml/50ml/75ml）怎么选择？哪个性价比更高？","answer":"30ml适合初次尝试的用户，方便体验效果，但单价相对较高；50ml是性价比之选，单价约21.6元/ml，比30ml的25.3元/ml更划算，适合长期使用的用户；75ml家庭装单价约19.7元/ml，是最划算的，适合家庭多人使用或囤货。如果是第一次用，建议先买30ml试试；如果已经确认适合自己，优先选50ml或75ml，能节省不少成本。另外，注意开封后的保质期，75ml需要在6个月内用完，避免产品变质影响效果。"}],"user_reviews":[{"nickname":"小桃子","rating":5,"content":"用了快一个月啦！之前换季皮肤总是泛红敏感，现在稳定多了！早上起来脸摸起来滑滑的，毛孔真的细腻了不少，尤其是T区的粗毛孔，现在看起来干净很多。熬夜后用第二天也不会暗沉，肤色提亮效果很明显，吸收超快，不会黏腻。已经回购50ml的了，性价比比30ml高～"},{"nickname":"李木子","rating":1,"content":"太失望了！用了一次就满脸泛红刺痛，还长了小疹子。之前看评价说敏感肌能用，结果我这个混干敏感肌完全不耐受。找客服反馈，说让我先做测试，但我明明用在耳后测试过没事，上脸就不行。可能是里面的某些成分不适合我，再也不敢用了，浪费钱！"},{"nickname":"张一一","rating":1,"content":"用了一个月，完全没看到任何效果！毛孔还是那么大，肤色也没提亮，维稳更是谈不上，该敏感还是敏感。价格这么贵，结果一点用都没有，感觉智商税了。还不如我之前用的平价精华，以后再也不买兰蔻小黑瓶了。"},{"nickname":"王萌萌","rating":3,"content":"用了两周，效果比较平淡。没有特别惊艳的感觉，毛孔稍微有点改善，但不明显。提亮肤色的话，可能要长期用？吸收还可以，不黏腻，但价格确实有点贵，30ml很快就用完了，感觉性价比一般。给3分吧，不算差但也没达到预期。"},{"nickname":"陈西西","rating":3,"content":"维稳效果还行，换季的时候用没有过敏，但提亮和细腻毛孔的效果真的很弱。用了快一个月，皮肤状态没太大变化。而且瓶子设计有点问题，按压头有时候会漏，浪费了不少。整体感觉中规中矩，没有宣传的那么好。"},{"nickname":"赵小星","rating":3,"content":"吸收挺快的，不油腻，但效果真的一般般。毛孔没怎么变细，肤色也没提亮多少。可能是我肤质的问题？混油皮用着感觉还行，但性价比不高，760块30ml有点贵。如果效果再好点还能接受，现在只能给3分了。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_002.json'),
    ('p_beauty_003', 'SK-II护肤精华露神仙水晶透保湿调理角质收缩毛孔230ml', 'SK-II', '美妆护肤', '化妆水', '美妆护肤/化妆水', 1690.0, 620.0, 1690.0, 300, '1_美妆护肤/images/p_beauty_003_live.jpg', '{"product_id":"p_beauty_003","title":"SK-II护肤精华露神仙水晶透保湿调理角质收缩毛孔230ml","brand":"SK-II","category":"美妆护肤","sub_category":"化妆水","base_price":1690.0,"image_path":"1_美妆护肤/images/p_beauty_003_live.jpg","skus":[{"sku_id":"s_p_beauty_003_1","properties":{"容量":"160ml 标准装"},"price":1240.0},{"sku_id":"s_p_beauty_003_2","properties":{"容量":"230ml 经典大容量"},"price":1690.0},{"sku_id":"s_p_beauty_003_3","properties":{"容量":"75ml 旅行装"},"price":620.0}],"rag_knowledge":{"marketing_description":"SK-II神仙水（护肤精华露）核心成分是90%以上的PITERA™酵母发酵滤液，这是SK-II独家灵魂成分，含氨基酸、矿物质、有机酸等多种活性物质。适合25+有初老迹象、毛孔粗大、角质粗糙或肤色暗沉的人群。日常护肤可作为洁面后第一步，用化妆棉擦拭全脸，或熬夜、约会前湿敷5-10分钟急救。它能温和调理角质，促进肌肤代谢，收缩毛孔，让皮肤水晶透亮、保湿不油腻。使用建议：洁面后取适量倒在化妆棉上轻擦或轻拍吸收；敏感肌首次需耳后测试建立耐受；开封后6个月内用完，避光保存。","official_faq":[{"question":"神仙水中的PITERA™成分具体对肌肤有哪些作用？","answer":"PITERA™是SK-II通过特殊酵母发酵得到的滤液，含与肌肤天然保湿因子结构相似的氨基酸、矿物质、有机酸等成分。它能调节水油平衡，温和软化老废角质，促进新陈代谢，让粗糙角质层变细腻；增强肌肤屏障，改善毛孔粗大，长期使用使肌肤透亮弹润，是实现“水晶透”效果的核心原因。"},{"question":"230ml经典大容量装相比其他规格有什么优势？","answer":"230ml大容量装优势在于性价比和便利性。单价每毫升更低，适合长期使用者节省成本；不用频繁补货，减少重复购买麻烦；适合家庭或个人长期使用，不用担心短期过期，是追求性价比和长期使用的理想选择。"},{"question":"敏感肌可以使用神仙水吗？需要注意什么？","answer":"敏感肌可尝试但需谨慎。PITERA™有调理角质作用，初期可能轻微刺痛泛红，属正常适应现象。首次用取少量耳后或手臂测试，24小时无不适再少量用；初期每周2-3次，逐渐增加频率建立耐受；若持续红肿刺痛，立即停用并咨询专业人士。"},{"question":"神仙水应在护肤步骤哪个环节使用？正确方法是什么？","answer":"神仙水应在洁面后第一步使用，替代爽肤水。正确方法：一是取3-4滴倒化妆棉上轻擦全脸，重点T区和毛孔粗大处去角质；二是浸湿化妆棉敷T区、额头等5-10分钟急救，快速改善暗沉粗糙。使用后搭配精华乳液锁水。"},{"question":"开封后神仙水保质期多久？如何正确保存？","answer":"开封后建议6个月内用完，因PITERA™活性成分易受空气、光线、温度影响流失。保存需避免阳光直射和高温，放阴凉干燥处；每次用后拧紧瓶盖防空气进入；不放在浴室潮湿环境，以免滋生细菌。超6个月未用完不建议继续使用。"}],"user_reviews":[{"nickname":"林小夏","rating":2,"content":"用了一周神仙水，每次擦完脸颊都有点刺痛，开始以为是皮肤干，后来还冒了几颗闭口痘，毛孔也没收缩迹象。我的敏感肌真的不适合这款，虽然大家都说好，但对我太刺激，只能闲置，心疼钱。"},{"nickname":"张默默","rating":3,"content":"买的230ml大容量，用了半个月，保湿还行皮肤不干，但收缩毛孔效果不明显，T区毛孔还是大。价格这么贵，性价比一般，效果再明显点就好了，暂时不回购。"},{"nickname":"李思思","rating":2,"content":"旅行装75ml，用了几次皮肤反而更干，发酵酸味有点重闻着不习惯。本想试试效果，结果干皮用着不适合，保湿不够还紧绷，以后不会再买了。"},{"nickname":"王佳琪","rating":5,"content":"用了三个月神仙水太惊喜！每天化妆棉擦，角质明显细腻，T区毛孔小很多，皮肤透亮，同事问我换了护肤品。230ml耐用性价比高，会一直回购！"},{"nickname":"赵晓雨","rating":5,"content":"熬夜后湿敷十分钟，皮肤立刻不暗沉，透亮有光泽。坚持一个月闭口几乎消了，毛孔细腻，皮肤状态稳定。不愧是神仙水，贵但效果值得，下次囤230ml。"},{"nickname":"陈雨桐","rating":4,"content":"整体效果不错，保湿透亮，皮肤摸起来光滑。但收缩毛孔没宣传明显，T区还是粗。价格有点贵，有更多优惠就好了，长期用有点压力。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_003.json'),
    ('p_beauty_004', '资生堂新红妍肌活精华露红腰子修护维稳强韧肌底精华50ml', '资生堂', '美妆护肤', '精华', '美妆护肤/精华', 590.0, 590.0, 1040.0, 300, '1_美妆护肤/images/p_beauty_004_live.jpg', '{"product_id":"p_beauty_004","title":"资生堂新红妍肌活精华露红腰子修护维稳强韧肌底精华50ml","brand":"资生堂","category":"美妆护肤","sub_category":"精华","base_price":590.0,"image_path":"1_美妆护肤/images/p_beauty_004_live.jpg","skus":[{"sku_id":"s_p_beauty_004_1","properties":{"容量":"30ml 经典装"},"price":590.0},{"sku_id":"s_p_beauty_004_2","properties":{"容量":"50ml 加大装"},"price":860.0},{"sku_id":"s_p_beauty_004_3","properties":{"容量":"75ml 家用装"},"price":1040.0}],"rag_knowledge":{"marketing_description":"资生堂新红妍肌活精华露（红腰子）是品牌明星修护精华，核心含ULTIMUNE肌活复合物，能激活肌肤自身防御机制，强韧肌底。添加保加利亚玫瑰水与透明质酸，兼顾舒缓与保湿。适合换季敏感、熬夜后肌肤暗沉不稳定、或长期受外界刺激的人群。日常护肤时，洁面爽肤后取2-3泵，轻柔按摩全脸至吸收，早晚均可使用。换季或肌肤状态差时可增加用量。注意：敏感肌首次使用建议先在耳后做局部测试，开封后6个月内用完，避免成分失效影响效果。","official_faq":[{"question":"红腰子精华中的ULTIMUNE肌活复合物具体有什么作用？","answer":"ULTIMUNE复合物是资生堂专研成分，通过激活朗格汉斯细胞活性，增强肌肤自身的防御能力，帮助抵御外界污染、紫外线等刺激。同时能促进肌底胶原生成，改善肌肤粗糙、泛红等问题，让肌肤更稳定强韧。长期使用可减少敏感反复，维持肌肤健康状态。"},{"question":"敏感肌可以使用红腰子精华吗？需要注意哪些事项？","answer":"红腰子精华主打修护维稳，大部分敏感肌可使用。但敏感肌个体差异大，首次使用建议先在耳后或手臂内侧做局部测试，观察24小时无不适再全脸使用。若肌肤处于急性敏感期（如红肿、刺痛），建议先缓解症状再使用。使用时避免与刺激性强的产品（如高浓度酸类）叠加，以免加重肌肤负担。"},{"question":"红腰子精华不同规格的开封后建议使用期限是多久？","answer":"30ml经典装建议开封后3个月内用完，50ml加大装建议4个月内，75ml家用装建议6个月内。因为精华含活性成分，开封后易受空气、温度影响氧化失效，所以尽量在建议期限内用完，以保证效果。存放时需避免阳光直射，放在阴凉干燥处。"},{"question":"红腰子精华在护肤步骤中应如何使用？与其他产品搭配会冲突吗？","answer":"红腰子精华属于肌底精华，应在洁面、爽肤水后，其他功能性精华（如美白、抗老）前使用。取2-3泵均匀涂抹全脸，轻轻按摩至吸收。它与大多数护肤品兼容性好，但若搭配酸类或高浓度活性产品，建议间隔使用（如早上用红腰子，晚上用酸类），避免肌肤过度刺激。"}],"user_reviews":[{"nickname":"林小夏","rating":2,"content":"买的50ml加大装，想着性价比高些。结果用了三天脸上就起了小红疹，还有点痒，赶紧停了。客服说敏感肌能用，但我可能是对里面某个成分不耐受？而且质地对混油皮来说有点黏，夏天用着闷，吸收也慢。花了860块结果用不了，太失望了，只能给2星。"},{"nickname":"张梦溪","rating":5,"content":"红腰子真的是我的维稳救星！已经用了两瓶75ml的了。我是干敏皮，换季的时候脸容易泛红脱皮，用这个之后明显稳定多了。质地是清爽的蛋清状，拍几下就吸收了，用完脸软软的，第二天起来皮肤状态超棒。熬夜后用它，暗沉也改善不少，强烈推荐给敏感肌姐妹！"},{"nickname":"李浩然","rating":3,"content":"30ml经典装用了快一个月，感觉效果一般般。维稳是有点用，但没宣传的那么神。质地还行，吸收也快，但对干皮来说冬天用不够滋润，得再叠加个保湿精华。价格590块30ml，性价比感觉不高。整体就是中规中矩，给3星吧。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_004.json'),
    ('p_beauty_005', '科颜氏新集焕白均衡亮肤淡斑精华液提亮肤色淡化斑点精华30ml', '科颜氏', '美妆护肤', '精华', '美妆护肤/精华', 520.0, 520.0, 780.0, 200, '1_美妆护肤/images/p_beauty_005_live.jpg', '{"product_id":"p_beauty_005","title":"科颜氏新集焕白均衡亮肤淡斑精华液提亮肤色淡化斑点精华30ml","brand":"科颜氏","category":"美妆护肤","sub_category":"精华","base_price":520.0,"image_path":"1_美妆护肤/images/p_beauty_005_live.jpg","skus":[{"sku_id":"s_p_beauty_005_1","properties":{"容量":"30ml 标准装"},"price":520.0},{"sku_id":"s_p_beauty_005_2","properties":{"容量":"50ml 加大装"},"price":780.0}],"rag_knowledge":{"marketing_description":"科颜氏新集焕白均衡亮肤淡斑精华液，核心卖点在于温和淡斑与均匀提亮肤色，专为有日晒斑、熬夜暗沉、痘印色素沉淀问题的人群设计。其含有的维生素C衍生物（乙基维生素C）能有效抑制黑色素生成，玻色因成分则帮助修护肌肤屏障，同时添加透明质酸保湿因子，让精华在淡斑的同时保持肌肤水润。质地清爽不黏腻，适合早晚护肤使用，尤其适合长期面对电脑、日晒较多或作息不规律的人群。使用建议：取3-4滴于掌心，轻轻拍打至全脸吸收，后续搭配乳液或面霜锁住养分；白天使用时务必配合足量防晒，避免紫外线加重色素沉淀。注意事项：敏感肌首次使用前需在耳后做皮肤测试，若出现红肿刺痛请立即停用。","official_faq":[{"question":"这款淡斑精华适合哪些肤质？敏感肌可以用吗？","answer":"这款精华适合中性、混合性、干性及油性肤质，质地清爽易吸收，不会给肌肤造成负担。对于敏感肌，产品中采用的是温和的维生素C衍生物（乙基维生素C）和玻色因成分，刺激性较低，但仍建议敏感肌人群在使用前先取少量精华涂抹于耳后或手臂内侧，观察24小时无红肿、瘙痒等不适反应后再正常使用，确保肌肤适应。"},{"question":"使用这款精华多久能看到淡斑效果？","answer":"淡斑效果因人而异，通常情况下，坚持使用4-8周可看到明显改善。因为黑色素的代谢周期约为28天，所以需要持续使用才能让成分充分发挥作用。建议每天早晚坚持使用，并配合防晒措施，这样能更快看到斑点淡化、肤色均匀的效果。如果使用3个月后仍无明显变化，可咨询专业护肤顾问调整使用方法。"},{"question":"白天使用这款精华需要注意什么？","answer":"白天使用时，最重要的是配合足量防晒产品。因为精华中的维生素C成分具有一定的光敏性（虽然乙基维生素C相对稳定），若不做好防晒，紫外线会加速黑色素生成，反而影响淡斑效果。建议在精华吸收后，涂抹SPF30+以上的防晒霜，并根据日晒情况及时补涂，确保肌肤免受紫外线伤害。"},{"question":"30ml和50ml规格除了容量还有其他区别吗？","answer":"30ml和50ml规格的精华在成分、质地和功效上完全一致，仅容量不同。50ml加大装的单价更划算，适合长期使用的用户；30ml标准装则适合初次尝试的用户，或者旅行携带更方便。两种规格的包装设计相同，均采用滴管式取用，方便控制用量，保持产品卫生。"},{"question":"这款精华可以和其他精华叠加使用吗？比如抗老精华？","answer":"可以叠加使用，但建议遵循“先薄后厚、先水后油”的原则。若要叠加抗老精华（如含视黄醇的产品），建议先使用这款淡斑精华（质地较轻薄），待其完全吸收后再涂抹抗老精华。需要注意的是，若叠加多种功效型产品，需观察肌肤是否出现不适，避免过度营养导致肌肤负担。敏感肌叠加时更需谨慎，建议逐步添加。"},{"question":"这款精华的质地如何？是否会搓泥？","answer":"这款精华质地是透明的蛋清状，非常清爽，流动性强，涂抹后快速吸收，不会留下黏腻感。一般情况下，正确使用不会搓泥，但需注意后续护肤品的搭配：避免与含有高分子聚合物的产品（如某些凝胶状面霜）同时使用，且涂抹时手法要轻柔，不要来回揉搓。若出现搓泥，可减少精华用量或调整后续产品顺序。"}],"user_reviews":[{"nickname":"小敏","rating":3,"content":"用了快一个月，感觉肤色稍微亮了一点，但颧骨上的晒斑几乎没变化。质地倒是挺清爽的，吸收也快，就是价格有点贵，520块30ml，感觉性价比一般。再用一段时间看看吧，如果还是没效果可能不会回购了。"},{"nickname":"阿雅","rating":5,"content":"太惊喜了！用了两个月，脸上的痘印和小斑点真的淡了很多，肤色也均匀了不少。质地很清爽，夏天用也不油腻，吸收超快，早上用搭配防晒也没搓泥。已经回购50ml的加大装了，性价比更高，会一直用下去！"},{"nickname":"大张","rating":1,"content":"完全不适合我！用了三天，脸上就起了好多小红疹，还特别痒，应该是过敏了。我是混油皮，之前用其他科颜氏产品都没事，这次不知道怎么回事。联系客服退货了，建议敏感肌一定要先做测试再买，别像我一样踩雷。"},{"nickname":"玲玲","rating":3,"content":"用了三个星期，斑点没怎么变淡，肤色倒是提亮了一丢丢。质地是不错，不黏腻，但淡斑效果比预期的差。可能我的斑点比较顽固？或者需要更长时间？暂时没看到明显的淡斑效果，有点失望，再用段时间看看吧。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_005.json'),
    ('p_beauty_006', '巴黎欧莱雅新多重防护隔离露水感轻薄高倍防晒修护提亮30ml', '巴黎欧莱雅', '美妆护肤', '防晒', '美妆护肤/防晒', 170.0, 170.0, 190.0, 200, '1_美妆护肤/images/p_beauty_006_live.jpg', '{"product_id":"p_beauty_006","title":"巴黎欧莱雅新多重防护隔离露水感轻薄高倍防晒修护提亮30ml","brand":"巴黎欧莱雅","category":"美妆护肤","sub_category":"防晒","base_price":170.0,"image_path":"1_美妆护肤/images/p_beauty_006_live.jpg","skus":[{"sku_id":"s_p_beauty_006_1","properties":{"规格":"30ml 水感轻肌款"},"price":170.0},{"sku_id":"s_p_beauty_006_2","properties":{"规格":"40ml 清爽型"},"price":190.0}],"rag_knowledge":{"marketing_description":"巴黎欧莱雅新多重防护隔离露，主打水感轻薄质地，上脸瞬间推开成膜，无厚重黏腻感。采用欧莱雅专利麦色滤科技，实现SPF50+ PA++++高倍广谱防晒，有效阻隔UVA/UVB，添加玻尿酸与维生素E，防晒同时修护肌肤屏障，自然提亮肤色，让后续妆容更服帖。适合油皮、混油皮及追求清爽肤感人群，日常通勤、上学、逛街或短途户外游玩适用。使用建议：出门前15分钟取一枚硬币大小，面部颈部均匀拍打吸收，后续可叠加粉底或散粉。注意事项：敏感肌先做耳后测试，长时间户外每2-3小时补涂，避免接触眼睛破损肌肤。","official_faq":[{"question":"这款隔离露的防晒指数是多少？适合户外长时间使用吗？","answer":"这款隔离露防晒指数为SPF50+ PA++++，属高倍广谱防晒，能抵御98%以上UVB（晒伤）和UVA（晒黑老化）。日常通勤或1-2小时短户外足够，但长时间阳光下（如海边爬山）需每2-3小时补涂。其防水防汗性能一般，遇大量出汗或水需及时补涂，以维持防晒效果。"},{"question":"水感轻肌款（30ml）和清爽型（40ml）有什么区别？怎么选？","answer":"两款核心防晒成分一致，差异在质地和容量。30ml水感轻肌款更水润，带轻微提亮，适合自然妆感、日常通勤；40ml清爽型更清爽，控油稍好，适合油皮或夏季高温。30ml便携补涂，40ml长期使用。油皮夏天选清爽型，干皮或追求提亮选水感轻肌款。"},{"question":"涂完这款隔离露还需要再涂粉底吗？会不会搓泥？","answer":"隔离露带自然提亮，肤色均匀且爱裸妆可直接用；需遮瑕可叠加粉底。搓泥多与后续产品质地相关，建议隔离完全成膜（1-2分钟）再涂后续，选同品牌或质地相近产品，避免含硅过多粉底，以防成分反应搓泥。"},{"question":"敏感肌可以用这款隔离露吗？有没有酒精成分？","answer":"这款隔离露不含酒精、香精和parabens防腐剂，相对温和。但敏感肌肤质差异大，初次使用需耳后或手臂内侧做24小时测试，无红肿瘙痒再用。含维生素E可修护屏障，对敏感肌友好，但仍需谨慎测试，不适立即停用清洗。"},{"question":"这款隔离露的提亮效果自然吗？会不会假白？","answer":"提亮效果自然，属伪素颜级，无明显假白。采用与肤色相近的自然白色号，上脸均匀肤色、遮盖轻微暗沉，肌肤更透亮。肤色较深可能提亮不明显，肤色较白则更有光泽。一般不会假白，可根据自身肤色选择。"},{"question":"开封后多久需要用完？保存有什么注意事项？","answer":"开封后建议6个月内用完，防晒活性成分随时间失效影响效果。保存需避免阳光直射和高温，放阴凉干燥处（如梳妆台抽屉），勿放浴室潮湿处，防细菌滋生或成分变质。每次用后拧紧瓶盖，防止空气氧化成分。"}],"user_reviews":[{"nickname":"小敏","rating":2,"content":"这款隔离露用两次就过敏了，脸颊发红还痒。之前用其他欧莱雅产品没事，这次不知道为啥。质地轻薄，但涂完半小时就不舒服，赶紧洗掉。虽不含酒精，但某些成分可能不适合我敏感肌，建议敏感肌先测试再买，别像我踩雷。"},{"nickname":"阿哲","rating":4,"content":"整体还行，防晒效果不错，上次公园玩一下午没晒黑。但T区两小时后出油，混油皮夏天控油稍弱。提亮自然不用涂粉底，这点方便。若控油再好点就完美，给四星。"},{"nickname":"丽丽","rating":3,"content":"用一周发现搓泥严重！先涂爽肤水再隔离再粉底，脸上一块一块的。单独用隔离也搓泥，不知道是不是手法问题？质地水润但搓泥影响体验，给三星，希望改进配方。"},{"nickname":"小雅","rating":5,"content":"太喜欢这款隔离！质地像水一样，推开瞬间成膜，不油腻夏天也舒服。提亮自然，肤色均匀透亮，同事问我皮肤是不是变好。防晒指数够，海边玩一天没晒黑晒伤。30ml便携补涂方便，已回购第二次！"},{"nickname":"明明","rating":3,"content":"提亮效果一般，我肤色偏黄涂完没变化还是暗沉。价格贵30ml170元性价比不高。涂完有点干，干皮冬天需先涂很多保湿霜。没想象中好，给三星。"},{"nickname":"琪琪","rating":5,"content":"这款隔离真绝了！轻薄像没涂，上脸清爽不闷痘。油皮夏天用没问题，T区也不太油。防晒效果好，每天上班涂下班皮肤好好。提亮自然不用粉底省时间，40ml清爽型容量大能用很久，性价比不错，推荐油皮朋友！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_006.json'),
    ('p_beauty_007', '薇诺娜舒敏保湿特护霜敏感肌修护屏障舒缓干痒保湿面霜50g', '薇诺娜', '美妆护肤', '面霜', '美妆护肤/面霜', 268.0, 89.0, 268.0, 200, '1_美妆护肤/images/p_beauty_007_live.jpg', '{"product_id":"p_beauty_007","title":"薇诺娜舒敏保湿特护霜敏感肌修护屏障舒缓干痒保湿面霜50g","brand":"薇诺娜","category":"美妆护肤","sub_category":"面霜","base_price":268.0,"image_path":"1_美妆护肤/images/p_beauty_007_live.jpg","skus":[{"sku_id":"s_p_beauty_007_1","properties":{"规格":"15g 体验装"},"price":89.0},{"sku_id":"s_p_beauty_007_2","properties":{"规格":"50g 标准装"},"price":268.0}],"rag_knowledge":{"marketing_description":"薇诺娜舒敏保湿特护霜专为敏感肌打造，核心成分含马齿苋提取物（快速舒缓泛红干痒）、青刺果油（补充皮肤脂质修护屏障）及透明质酸（深层锁水保湿）。适合屏障受损、换季泛红、干痒脱皮的敏感肌人群，日常可作基础保湿面霜，换季或医美后可厚敷急救。使用时取黄豆大小均匀涂抹面部，轻按至吸收；急救时厚敷15-20分钟后擦去剩余。注意：开封后6个月内用完，敏感肌首次用前需耳后测试，避免与刺激性产品叠加。","official_faq":[{"question":"这款特护霜能改善哪些敏感肌常见问题？","answer":"它主要针对敏感肌的屏障受损、换季泛红、干痒脱皮、紧绷等问题。马齿苋提取物可舒缓炎症，缓解泛红干痒；青刺果油补充脂质强化屏障；透明质酸锁水解决干燥。日常用维持稳定，换季或医美后用加速修护，减少敏感反应，适合长期敏感或突发敏感人群。"},{"question":"15g体验装和50g标准装成分效果有区别吗？","answer":"两者成分完全一致，效果无差异。15g适合首次尝试用户测试肤质，50g适合长期使用性价比更高。无论规格，核心成分比例相同，都能达到舒缓修护效果。建议敏感肌先试15g，确认无不适再买50g。"},{"question":"可以厚敷当急救面膜用吗？","answer":"可以。皮肤严重泛红干痒或脱皮时，取2-3倍用量厚敷15-20分钟后擦去多余膏体，无需清洗。厚敷让成分充分渗透，快速舒缓炎症，补充水分脂质缓解紧急敏感。但不建议每天厚敷，日常以薄涂为主。"},{"question":"用后会有黏腻感吗？","answer":"不会。质地是清爽乳霜状，易推开吸收快，吸收后呈哑光或半哑光状态，无黏腻感或油膜感。混油敏感肌夏天用也不闷痘油腻，轻薄配方兼顾保湿修护与使用感，适合各季节敏感肌。"},{"question":"医美后多久可以使用？","answer":"医美项目（如光子嫩肤、果酸焕肤）后24-48小时，红肿消退即可用。成分温和无刺激，能修护受损屏障，缓解干燥泛红。使用前局部测试，确认无不适再全脸薄涂，避免过度摩擦皮肤。"}],"user_reviews":[{"nickname":"林小果","rating":1,"content":"买了15g体验装，结果用一次就过敏了。我是干敏肌，本想修护屏障，用后脸颊更红更痒还起疹子。客服让停用，但价格不便宜却过敏，真的很失望，敏感肌试新护肤品要谨慎。"},{"nickname":"张敏敏","rating":5,"content":"敏感肌多年换季必泛红干痒，这款特护霜救了我！用一周泛红减轻干痒缓解，质地清爽吸收快不黏腻，晚上厚敷第二天皮肤水嫩。50g虽贵但效果好，已回购第二次，会一直用。"},{"nickname":"李萌萌","rating":5,"content":"医美后医生推荐，用后无刺激感。光子嫩肤后皮肤敏感干红，用它舒缓效果立竿见影，保湿够。先试15g体验装不错，现在买了50g，推荐给医美后的姐妹，很安心。"},{"nickname":"王静静","rating":2,"content":"混油敏感肌夏天用有点厚重，涂完T区出油更多，吸收慢需久按摩。舒缓效果还行但夏天闷，性价比一般，冬天可能好点，但不会再回购了。"},{"nickname":"刘娅娅","rating":5,"content":"干敏肌救星！冬天皮肤脱皮，用很多面霜没用，这款三天就好，皮肤柔软细腻。成分温和无香精酒精，已回购第三次，家里常备，强烈推荐干敏肌姐妹！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_007.json'),
    ('p_beauty_008', '玉兰油新生塑颜金纯面霜紧致提拉淡纹保湿抗初老大红瓶50g', '玉兰油', '美妆护肤', '面霜', '美妆护肤/面霜', 239.0, 89.0, 259.0, 300, '1_美妆护肤/images/p_beauty_008_live.jpg', '{"product_id":"p_beauty_008","title":"玉兰油新生塑颜金纯面霜紧致提拉淡纹保湿抗初老大红瓶50g","brand":"玉兰油","category":"美妆护肤","sub_category":"面霜","base_price":239.0,"image_path":"1_美妆护肤/images/p_beauty_008_live.jpg","skus":[{"sku_id":"s_p_beauty_008_1","properties":{"规格":"50g 日霜"},"price":239.0},{"sku_id":"s_p_beauty_008_2","properties":{"规格":"50g 滋润型"},"price":259.0},{"sku_id":"s_p_beauty_008_3","properties":{"规格":"14g 随身装"},"price":89.0}],"rag_knowledge":{"marketing_description":"玉兰油新生塑颜金纯面霜（大红瓶）是针对25+初老肌肤设计的抗衰利器，核心成分含高浓度烟酰胺与五胜肽（Pal-KTTKS），烟酰胺助力提亮肤色、促进胶原蛋白生成，五胜肽精准淡退动态纹与静态纹，搭配透明质酸深层锁水，实现紧致提拉、淡纹保湿三重功效。SKU分三种：50g日霜质地轻盈，适合日常通勤或春夏使用；50g滋润型添加额外保湿因子，适合秋冬或干皮；14g随身装方便出差旅行补涂。使用时取黄豆大小均匀涂于面部颈部，配合向上提拉按摩更易吸收。敏感肌建议先做耳后测试，开封后6个月内用完，避免阳光直射。","official_faq":[{"question":"大红瓶日霜和滋润型有哪些具体区别？","answer":"两者核心成分一致，但质地与适用场景不同。日霜质地轻薄水润，吸收快不闷痘，适合春夏季节或混合/油皮日常使用，价格239元；滋润型质地更醇厚，添加额外锁水成分，保湿力更强，适合秋冬季节或干皮使用，价格259元。建议根据季节和肤质选择，干皮秋冬选滋润型，油皮或春夏选日霜。"},{"question":"14g随身装和50g正装的成分是否相同？","answer":"成分完全相同，只是容量差异。14g随身装专为外出设计，方便携带补涂，适合短途出差、旅行或试用；50g正装性价比更高，适合长期使用。两者都含烟酰胺、五胜肽等核心抗衰成分，效果一致，可根据需求选择。"},{"question":"敏感肌能用大红瓶吗？","answer":"大红瓶含烟酰胺，敏感肌需谨慎。建议先取少量在耳后或手臂内侧测试，观察24小时无红肿、瘙痒等不适再使用。若耐受，可从每周2-3次开始，逐渐增加频率；若出现不适，立即停用并清洗。搭配温和洁面和爽肤水，减少皮肤刺激。"},{"question":"大红瓶对法令纹有淡化效果吗？","answer":"有一定效果。五胜肽能刺激胶原蛋白和弹力纤维合成，长期坚持使用（通常28天以上），可看到法令纹变浅、皮肤紧致度提升。建议涂抹时针对法令纹区域做向上提拉按摩，每次3-5分钟，增强吸收和效果。"},{"question":"大红瓶需要搭配其他抗衰产品吗？","answer":"可根据需求搭配。若追求更强抗衰效果，可搭配同系列新生塑颜精华；若皮肤偏干，可加用保湿精华。但基础护肤（水+精华+面霜）已足够，避免叠加过多产品导致皮肤负担。注意选择成分兼容的产品，避免冲突。"},{"question":"大红瓶开封后保质期多久？","answer":"开封后建议6个月内用完。因为核心成分如五胜肽、烟酰胺易氧化失效，长时间存放会降低效果。存放时需密封，避免阳光直射和高温环境，最好放在阴凉干燥处，每次使用后及时盖紧瓶盖。"}],"user_reviews":[{"nickname":"林小夏","rating":5,"content":"用了一个月大红瓶日霜，效果真的惊喜！之前熬夜后的暗沉感消失了，皮肤变得透亮，法令纹也淡了一些，早上起来脸不油不干，很舒服。质地轻薄好吸收，夏天用完全不闷痘，搭配按摩手法，脸感觉紧致了不少。已经推荐给闺蜜，会回购正装！"},{"nickname":"张萌萌","rating":3,"content":"买的滋润型，结果用了一周开始闷痘，可能是太厚重了。我是混油肌，秋冬用也觉得有点油腻，虽然保湿确实不错，早上起来脸很润，但闷痘这点让我很困扰。可能更适合干皮吧，我还是换日霜试试，希望不会再长痘。"},{"nickname":"李思思","rating":3,"content":"随身装价格有点坑，89块14g，算下来比50g的贵好多。用了一周感觉没什么明显效果，可能需要更长时间？但性价比真的不高，早知道直接买正装了。而且小瓶子的盖子有点松，担心会漏，这点设计不太好。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_008.json'),
    ('p_beauty_009', '珀莱雅弹润透亮青春精华液双抗精华提亮肤色淡纹保湿精华50ml', '珀莱雅', '美妆护肤', '精华', '美妆护肤/精华', 280.0, 210.0, 280.0, 200, '1_美妆护肤/images/p_beauty_009_live.jpg', '{"product_id":"p_beauty_009","title":"珀莱雅弹润透亮青春精华液双抗精华提亮肤色淡纹保湿精华50ml","brand":"珀莱雅","category":"美妆护肤","sub_category":"精华","base_price":280.0,"image_path":"1_美妆护肤/images/p_beauty_009_live.jpg","skus":[{"sku_id":"s_p_beauty_009_1","properties":{"容量":"30ml 标准装"},"price":210.0},{"sku_id":"s_p_beauty_009_2","properties":{"容量":"50ml 双抗精华2.0"},"price":280.0}],"rag_knowledge":{"marketing_description":"珀莱雅双抗精华2.0（50ml）主打抗氧抗糖双效修护，核心成分含高浓度麦角硫因+虾青素，协同清除自由基、抑制糖化反应，改善暗沉蜡黄与初老细纹。适合25+有初老迹象、熬夜后肤色暗沉或长期面对电子屏的人群。日常护肤可早晚使用，熬夜后可厚涂急救。使用时取3-4滴于掌心，轻揉乳化后按压上脸，搭配珀莱雅红宝石精华可强化抗老效果。注意事项：敏感肌需先在耳后做皮肤测试，开封后建议6个月内用完，避免阳光直射存放。","official_faq":[{"question":"珀莱雅双抗精华2.0相比1.0有哪些升级？","answer":"2.0版本在成分上升级了麦角硫因浓度，新增胶原促生成分，抗氧抗糖效果更持久；质地更清爽易吸收，减少黏腻感；包装采用真空按压泵，更卫生防氧化。适合追求更强修护力且喜欢清爽质地的用户，敏感肌也能更安心使用（仍需测试）。"},{"question":"敏感肌可以使用双抗精华2.0吗？","answer":"双抗精华2.0配方相对温和，但含活性成分，敏感肌需谨慎。建议先取少量在耳后或手腕内侧做24小时皮肤测试，无红肿、瘙痒等不适再使用。使用时可减少用量（2-3滴），搭配舒缓型爽肤水，避免与高浓度酸类产品同时使用，若出现不适立即停用并咨询皮肤科医生。"},{"question":"双抗精华2.0适合和哪些护肤品搭配？","answer":"日常可搭配温和洁面+保湿爽肤水+双抗精华+乳液/面霜；抗老需求可叠加珀莱雅红宝石精华（早双抗晚红宝石）；美白需求可搭配烟酰胺类产品（需间隔使用）。注意避免与高浓度维C、酸类产品同时使用，以免刺激皮肤。夏季可搭配清爽型乳液，冬季搭配滋润面霜增强保湿。"}],"user_reviews":[{"nickname":"林小夏","rating":2,"content":"用了一周左右，额头和下巴长了好几个闭口，不知道是不是成分不耐受。质地是清爽的，但上脸后有点轻微刺痛感，可能我是敏感肌？之前用1.0没这种情况，2.0反而更刺激？暂时停了，等闭口消了再试试，希望不是产品问题。"},{"nickname":"张沐沐","rating":5,"content":"太爱这款了！熬夜党福音！连续用了半个月，早上起来脸不再蜡黄，肤色明显提亮，连眼角的干纹都淡了一些。质地清爽不黏腻，吸收很快，后续上妆也不卡粉。50ml的量很足，性价比高，会回购！"},{"nickname":"李思思","rating":1,"content":"收到货时包装漏了一半，精华都流出来了，联系客服半天没回复。用了一次就过敏，脸上发红发痒，赶紧洗掉了。再也不会买了，太失望了！"},{"nickname":"王晴晴","rating":4,"content":"整体还不错，吸收挺快的，用了两周肤色有一点点提亮，但效果不是特别明显。香味有点浓，我不太喜欢，要是能淡一点就好了。保湿效果一般，夏天用刚好，冬天可能需要叠加面霜。"},{"nickname":"赵晓雨","rating":4,"content":"质地清爽，夏天用很舒服，不会闷痘。但抗糖效果感觉不明显，可能需要长期用？另外，按压泵有时候会按多，浪费了一些。总体还行，性价比中等。"},{"nickname":"陈萌萌","rating":4,"content":"温和不刺激，敏感肌用了没过敏。但提亮效果比较慢，用了一个月才看到一点点变化。价格有点小贵，要是有活动会再考虑回购。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_009.json'),
    ('p_beauty_010', '安热沙金灿倍护防晒乳高倍防水防汗清爽户外面部身体防晒60ml', '安热沙', '美妆护肤', '防晒', '美妆护肤/防晒', 298.0, 118.0, 298.0, 200, '1_美妆护肤/images/p_beauty_010_live.jpg', '{"product_id":"p_beauty_010","title":"安热沙金灿倍护防晒乳高倍防水防汗清爽户外面部身体防晒60ml","brand":"安热沙","category":"美妆护肤","sub_category":"防晒","base_price":298.0,"image_path":"1_美妆护肤/images/p_beauty_010_live.jpg","skus":[{"sku_id":"s_p_beauty_010_1","properties":{"规格":"60ml 经典金瓶"},"price":298.0},{"sku_id":"s_p_beauty_010_2","properties":{"规格":"20ml 便携装"},"price":118.0}],"rag_knowledge":{"marketing_description":"安热沙金灿倍护防晒乳（经典金瓶）是户外防晒的明星产品，核心采用品牌特有的Aqua Booster EX遇水增强技术，遇汗遇水后防晒膜更紧密，SPF50+ PA++++的高倍防护能有效阻隔UVA/UVB，避免晒伤晒黑。适合户外爱好者、通勤族及易出汗人群，无论是爬山、海滩度假还是日常上班都适用。质地清爽不油腻，涂抹后快速成膜，无明显泛白感。成分中添加保湿因子，兼顾防晒与肌肤保湿。使用建议：出门前15-20分钟均匀涂抹于面部及身体暴露部位，面部用量约一元硬币大小；防水配方需用卸妆产品清洁，敏感肌建议先在耳后做皮肤测试，避免入眼，存放于阴凉干燥处。","official_faq":[{"question":"这款防晒乳的防水防汗效果能维持多久？适合游泳时使用吗？","answer":"这款防晒乳采用安热沙专利的Aqua Booster EX技术，防水防汗持续时间可达80分钟，符合国际防水标准（ISO 18841）。游泳或长时间户外活动时，若持续浸泡水中或大量出汗，建议每2小时补涂一次，以确保防护效果。日常通勤出汗较少的情况下，可维持4-6小时无需补涂。"},{"question":"经典金瓶60ml和20ml便携装在成分和防晒效果上有区别吗？","answer":"两者成分与防晒效果完全一致，均为SPF50+ PA++++，采用相同的遇水增强技术。区别仅在于容量：60ml适合家庭或长期使用，性价比更高；20ml便携装体积小巧，方便随身携带补涂，适合出差、旅行或日常放在包里使用。"},{"question":"这款防晒乳适合敏感肌使用吗？需要做皮肤测试吗？","answer":"虽然产品质地温和，但部分敏感肌人群可能对其中的某些成分（如酒精）敏感。建议敏感肌用户在使用前，先取少量产品涂抹于耳后或手臂内侧，观察24小时无红肿、刺痛等不适反应后再使用。若使用过程中出现不适，应立即停止使用并清洗干净。"},{"question":"涂抹这款防晒乳后需要卸妆吗？用普通洁面产品可以清洁干净吗？","answer":"由于这款防晒乳具有防水防汗配方，普通洁面产品可能无法彻底清洁。建议使用卸妆产品（如卸妆油、卸妆乳）进行清洁，之后再用洁面产品清洗一次，确保残留的防晒成分被完全去除，避免堵塞毛孔引发肌肤问题。"},{"question":"这款防晒乳的清爽度如何？会不会有油腻感或泛白现象？","answer":"产品质地为清爽乳液状，涂抹后快速成膜，不会有明显油腻感。大部分用户反馈无泛白现象，但少数肤色较深的用户可能会感觉轻微提亮，不过很快会与肤色融合。建议涂抹时均匀推开，避免局部用量过多导致泛白。"},{"question":"户外活动时，多久需要补涂一次这款防晒乳？","answer":"户外活动时，若处于阳光强烈的环境（如海滩、高原），建议每2小时补涂一次；若大量出汗或游泳后，应立即补涂。补涂前需用纸巾轻轻吸干皮肤表面的汗水或水分，再均匀涂抹防晒乳，确保防护效果持续。"}],"user_reviews":[{"nickname":"小太阳","rating":5,"content":"上周和朋友去爬泰山，全程暴晒6小时，就靠这款安热沙金瓶防晒！早上涂了一次，中途补涂了一次，下来后皮肤一点没晒伤，连晒黑都不明显！防水防汗真的牛，爬山出了好多汗，防晒膜也没掉，涂在脸上清爽不闷痘，也没有泛白，太适合户外了！以后户外防晒就锁定它了，性价比也不错！"},{"nickname":"夏小沫","rating":4,"content":"买的20ml便携装，平时放包里补涂很方便。日常通勤用着还行，防晒效果不错，下午下班脸也没晒红。不过刚涂上去的时候有点点泛白，要等个三五分钟才自然，而且便携装单价确实比大瓶贵不少，要是能多搞点活动就好了。整体还是满意的，毕竟方便携带。"},{"nickname":"林小夕","rating":2,"content":"本来很期待这款防晒，结果用了两次就过敏了！涂在脸上有点刺刺的，过了半天脸颊就泛红起小疹子，赶紧洗掉了。我是混干敏感肌，可能这款里的酒精成分不适合我吧。而且涂完感觉有点闷，T区出油更厉害了，还长了两颗闭口。以后不会再买了，敏感肌慎入！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_010.json'),
    ('p_beauty_011', '珊珂洗颜专科绵润泡沫洁面乳细腻丰富泡沫温和清洁洁面120g', '珊珂', '美妆护肤', '洁面', '美妆护肤/洁面', 52.0, 52.0, 69.0, 200, '1_美妆护肤/images/p_beauty_011_live.jpg', '{"product_id":"p_beauty_011","title":"珊珂洗颜专科绵润泡沫洁面乳细腻丰富泡沫温和清洁洁面120g","brand":"珊珂","category":"美妆护肤","sub_category":"洁面","base_price":52.0,"image_path":"1_美妆护肤/images/p_beauty_011_live.jpg","skus":[{"sku_id":"s_p_beauty_011_1","properties":{"规格":"120g 标准装"},"price":52.0},{"sku_id":"s_p_beauty_011_2","properties":{"规格":"150ml 起泡泵装"},"price":69.0}],"rag_knowledge":{"marketing_description":"珊珂洗颜专科绵润泡沫洁面乳主打绵密细腻的泡沫清洁体验，核心添加蚕丝蛋白精华与双重透明质酸，既能深入毛孔带走油脂污垢，又能在清洁后留下水润保护膜。适合中性、混合性皮肤日常使用，无论是晨间唤醒肌肤还是晚间卸除淡妆后的二次清洁都很合适。标准装需搭配起泡网搓出丰富泡沫，泵装则直接按压即可获得绵密泡泡，使用更便捷。注意事项：敏感肌首次使用建议先在耳后做皮肤测试，避免入眼，若不慎入眼请立即用清水冲洗；干性皮肤使用后建议及时涂抹保湿产品。","official_faq":[{"question":"这款洁面乳的泡沫为什么能做到如此绵密细腻？","answer":"珊珂洗颜专科洁面乳特别添加了蚕丝蛋白精华和高效起泡成分，配合独特的配方工艺，使得洁面膏在与水接触后能快速形成密集且富有弹性的泡沫。这些泡沫不仅能扩大清洁面积，还能深入毛孔吸附油脂和污垢，同时减少对皮肤表面的摩擦，让清洁过程更温和。使用起泡网时，泡沫会更加丰盈，触感如同云朵般柔软，提升清洁的舒适感。"},{"question":"120g标准装和150ml起泡泵装的主要区别是什么？","answer":"两者的核心成分和清洁效果一致，但使用方式和容量不同。120g标准装为膏状质地，需要取适量（约1cm长）配合起泡网揉搓出泡沫，适合喜欢手动起泡的用户；150ml起泡泵装则是按压式设计，直接按压2-3次就能得到绵密泡沫，使用更省时省力，尤其适合赶时间的早晨。价格上，泵装因便利性和容量稍大，价格略高（69元），标准装52元更经济实惠。"},{"question":"敏感肌可以使用这款洁面乳吗？","answer":"这款洁面乳主打温和清洁，但含有一定的清洁成分（如表面活性剂），敏感肌使用前建议先在耳后或手臂内侧进行皮肤测试，观察24小时无红肿、瘙痒等不适再使用。若测试后无异常，使用时需注意避免过度揉搓，清洁时间控制在30秒左右，冲洗干净后及时涂抹保湿产品，减少皮肤刺激。如果本身是极易敏感的肌肤，建议选择专门针对敏感肌的洁面产品。"},{"question":"这款洁面乳能去除日常淡妆吗？","answer":"对于日常的淡妆（如隔离霜、轻薄粉底、腮红等），这款洁面乳的清洁力基本可以满足，绵密的泡沫能有效吸附并带走彩妆残留。但如果是浓妆（如防水眼线、持久口红、厚重粉底），建议先使用卸妆产品（卸妆油/乳）进行卸妆，再用这款洁面乳进行二次清洁，这样能更彻底地清除残留，避免毛孔堵塞。"},{"question":"使用这款洁面乳后皮肤会紧绷吗？","answer":"大部分用户反馈使用后不会紧绷，因为配方中添加了双重透明质酸，能在清洁过程中保留皮肤表面的水分，形成一层水润保护膜。但干性皮肤或在干燥季节使用时，可能会感觉轻微紧绷，建议后续及时涂抹保湿水和乳液。中性、混合性皮肤使用后通常能保持清爽水润的状态，不会有紧绷感。"},{"question":"如何正确使用这款洁面乳达到最佳效果？","answer":"标准装：取约1cm长的洁面膏，放在起泡网中央，加少量温水揉搓30秒左右，直到形成丰盈绵密的泡沫，然后将泡沫均匀涂抹在湿润的脸上，轻轻按摩T区等油脂较多的部位，避免用力揉搓，最后用清水彻底冲洗干净。泵装：先将脸部湿润，按压泵头2-3次取泡沫，直接涂抹在脸上按摩，后续步骤同上。建议每天使用1-2次，避免过度清洁。"}],"user_reviews":[{"nickname":"小草莓","rating":5,"content":"这款洁面乳真的太好用了！我是混合性皮肤，早上用它洗脸，泡沫超级绵密，像棉花糖一样，洗得很干净但完全不紧绷。标准装搭配起泡网，每次只要一点点就能搓出很多泡沫，性价比很高。已经回购第三次了，推荐给身边的朋友，她们也都说不错。洗完脸后皮肤感觉很清爽，后续上护肤品吸收也快，真的爱了！"},{"nickname":"林小夏","rating":2,"content":"买的是150ml的起泡泵装，本来以为会很方便，结果按压出来的泡沫一点都不绵密，像水一样稀，洗的时候感觉清洁力不够，而且洗完脸后皮肤特别干，紧绷得难受。我是干性皮肤，可能这款不适合我？还是说泵装的质量有问题？总之挺失望的，不会再回购了。"},{"nickname":"阿凯","rating":3,"content":"标准装用了一段时间，泡沫确实很多，清洁力也还行，夏天用感觉挺清爽的。但是冬天用的话，洗完脸后会有点紧绷，尤其是脸颊部位。而且感觉对我这种油性皮肤来说，清洁力又不够强，T区还是有点油。整体来说一般般，给个3分吧，希望能改进一下保湿和清洁力的平衡。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_011.json'),
    ('p_beauty_012', '理肤泉特安舒缓修复霜滋润型敏感肌保湿修护屏障面霜40ml', '理肤泉', '美妆护肤', '面霜', '美妆护肤/面霜', 260.0, 260.0, 260.0, 200, '1_美妆护肤/images/p_beauty_012_live.jpg', '{"product_id":"p_beauty_012","title":"理肤泉特安舒缓修复霜滋润型敏感肌保湿修护屏障面霜40ml","brand":"理肤泉","category":"美妆护肤","sub_category":"面霜","base_price":260.0,"image_path":"1_美妆护肤/images/p_beauty_012_live.jpg","skus":[{"sku_id":"s_p_beauty_012_1","properties":{"规格":"40ml 滋润型"},"price":260.0},{"sku_id":"s_p_beauty_012_2","properties":{"规格":"40ml 清爽型"},"price":260.0}],"rag_knowledge":{"marketing_description":"理肤泉特安舒缓修复霜滋润型是专为干性敏感肌打造的屏障修复神器，核心卖点在于温和修复受损屏障、长效保湿舒缓泛红。含高浓度理肤泉温泉水，富含硒、锌等矿物质，能快速舒缓肌肤刺激与泛红；添加神经酰胺3和4，精准补充皮肤屏障缺失的脂质，增强锁水能力；乳木果油与甘油协同作用，深层滋润干燥肌肤，缓解脱皮紧绷。适用人群为干性敏感肌、屏障受损肌肤，尤其适合换季泛红、空调房干燥、医美术后修复场景。使用建议：早晚洁面后取黄豆大小，轻柔按摩至吸收，避免拉扯；泛红严重时可厚敷10分钟作急救。注意事项：开封后6个月内用完，若出现刺痛红肿立即停用，存放于阴凉干燥处，避免阳光直射。","official_faq":[{"question":"滋润型和清爽型有什么区别？分别适合什么肤质？","answer":"滋润型与清爽型核心修复成分一致，但保湿油脂含量不同。滋润型添加更多乳木果油和甘油，质地绵密丰厚，锁水能力更强，适合干性敏感肌或秋冬季节使用，能应对干燥脱皮；清爽型质地更轻薄，含轻质油脂，吸收更快，适合中性/混合敏感肌或夏季使用，避免闷痘。两者均无香料、酒精、防腐剂，敏感肌可根据肤质和季节选择。"},{"question":"这款修复霜的核心成分有哪些？对敏感肌有什么帮助？","answer":"核心成分包括5%理肤泉温泉水，富含矿物质，舒缓抗炎，减轻泛红刺痛；神经酰胺3和4，补充皮肤屏障脂质，增强皮肤抵御力；乳木果油与甘油，深层滋润干燥肌肤；此外无香料、酒精、parabens等刺激性成分。这些成分协同作用，既能修复受损屏障，又能减少外界刺激，让敏感肌维持稳定状态，适合日常保湿与急救修复。"},{"question":"敏感肌在哪些场景下使用这款面霜效果最好？","answer":"敏感肌在以下场景使用效果显著：换季时（春秋）皮肤易泛红脱皮，用它稳定肌肤；空调房长期待着皮肤干燥紧绷，用它长效保湿；医美术后（如光子嫩肤）屏障脆弱，用它加速修复；晒后皮肤发红发烫，厚敷10分钟缓解不适；日常干性敏感肌作为基础保湿霜，维持屏障健康。这些场景下使用能充分发挥其修复与舒缓作用。"},{"question":"使用这款面霜需要注意什么？可以和其他护肤品叠加吗？","answer":"使用前需做耳后测试，确认无过敏反应；开封后6个月内用完，避免成分失效；存放于阴凉干燥处，远离阳光。可与其他护肤品叠加，建议先用水、精华，再涂面霜，但避免与高浓度酸类（如水杨酸、果酸）同时使用，以免加重刺激。若皮肤处于急性过敏期（严重泛红瘙痒），建议暂停使用并咨询医生。"}],"user_reviews":[{"nickname":"林小夏","rating":1,"content":"本来以为是敏感肌救星，结果用了三天脸更红了，还有刺痛感。我是干性敏感肌，之前用别的修复霜都没事，这款滋润型质地太厚重，吸收慢，第二天T区还泛油光。260元40ml性价比不高，修复效果没看到反而加重敏感，太失望了，以后不会回购。"},{"nickname":"张萌萌","rating":5,"content":"干敏皮福音！换季脸泛红脱皮，用这款滋润型三天就稳定了。质地绵密舒服，吸收后皮肤软软的，不油不紧绷。晚上厚敷一层，第二天脸水润润的，泛红减轻很多。成分安全无香味，敏感肌放心用，已经回购第二次了，强烈推荐给干敏皮姐妹！"},{"nickname":"李大明","rating":1,"content":"滋润型太油了，混合敏感肌夏天用完全不行，涂上去像糊了层油，闷得难受还长闭口。用了一周脸颊泛红没改善，260块钱白花了，只能闲置。建议混合肌夏天慎买滋润型，选清爽型可能更好。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_012.json'),
    ('p_beauty_013', '方里柔焦蜜粉饼控油定妆细腻粉质隐匿毛孔提亮肤色粉饼7g', '方里', '美妆护肤', '蜜粉', '美妆护肤/蜜粉', 99.0, 99.0, 139.0, 200, '1_美妆护肤/images/p_beauty_013_live.jpg', '{"product_id":"p_beauty_013","title":"方里柔焦蜜粉饼控油定妆细腻粉质隐匿毛孔提亮肤色粉饼7g","brand":"方里","category":"美妆护肤","sub_category":"蜜粉","base_price":99.0,"image_path":"1_美妆护肤/images/p_beauty_013_live.jpg","skus":[{"sku_id":"s_p_beauty_013_1","properties":{"产品规格":"7g 清透色"},"price":99.0},{"sku_id":"s_p_beauty_013_2","properties":{"产品规格":"12g 清透色补充装"},"price":139.0}],"rag_knowledge":{"marketing_description":"方里这款柔焦蜜粉饼简直是油皮混油皮的福音！7g的小巧体积揣在包里便携性拉满，细腻如烟的粉质上脸瞬间柔焦，毛孔被隐形得干干净净，还能自然提亮肤色，拒绝假白感。核心卖点是控油定妆+隐匿毛孔+提亮，适合油皮、混油皮日常通勤、夏季长时间带妆或容易出油的场景。使用时建议取粉后先在盖子上蹭掉余粉，轻拍上脸（T区重点按压）；干皮姐妹需做好保湿打底避免卡粉。补充装12g不含外壳，性价比更高，适合回购用户替换，环保又省钱。","official_faq":[{"question":"7g装和12g补充装的区别是什么？","answer":"7g装是带外壳和粉扑的完整包装，方便随身携带；12g补充装不含外壳与粉扑，需搭配原有外壳使用，单克价格更实惠。两者粉质、色号（清透色）及控油柔焦效果一致，补充装适合已有外壳的用户回购，容量更大性价比更高。"},{"question":"清透色会假白吗？适合哪些肤色？","answer":"清透色是自然提亮款，上脸无假白感，能均匀肤色让皮肤通透。适合大多数肤色：黄一白、黄二白、自然肤色均能驾驭，深肤色用它定妆也不会违和，反而让妆容更干净持久，不会显得突兀。"},{"question":"控油效果能维持多久？","answer":"控油效果因肤质和环境而异：油皮夏季通勤可维持4-6小时不泛油；混油皮T区能维持3-5小时。高温或出汗多的环境建议随身携带补妆，其细腻粉质补妆时不会卡粉结块，能保持妆容完整。"},{"question":"干皮能用吗？需注意什么？","answer":"干皮可用但需做好保湿打底：先涂保湿乳液/面霜确保皮肤水润，取粉勿过多，轻拍上脸避免干燥部位反复涂抹，减少卡粉。特别干燥的皮肤可只在T区等出油部位使用，既定妆又不加重干燥感。"}],"user_reviews":[{"nickname":"小敏","rating":2,"content":"干皮表示卡粉严重！明明做好保湿了，眼下和法令纹还是卡出小细纹，下午更明显。控油效果也一般，混干T区下午就出油，粉扑还硬，上脸不舒服。可能这款更适合油皮，干皮慎入。"},{"nickname":"阿杰","rating":2,"content":"外壳塑料感重，粉质细腻但提亮效果几乎无，黄二白用着和没涂一样。定妆3小时不到T区就油，补充装没外壳还要单独买，麻烦。追求明显提亮和持久控油的别买。"},{"nickname":"莉莉","rating":2,"content":"用一次就过敏起小红疹，成分可能不适合我。粉扑质量差，两次就掉毛沾脸。找客服反应说我皮肤问题，没解决办法，以后不会再买方里蜜粉了。"},{"nickname":"小美","rating":3,"content":"粉质细腻毛孔隐形效果不错，不厚重。但控油一般，油皮中午就得补妆。清透色自然不假白，可惜粉扑小用着不方便。99元不算贵但性价比一般，勉强中评。"},{"nickname":"小雅","rating":5,"content":"油皮夏天福音！早上定妆到下午6点T区仅微油，粉质细腻像磨皮，毛孔全隐形。清透色自然提亮不假白，7g便携补妆方便，粉扑柔软舒服。已回购补充装，太爱了！"},{"nickname":"小宇","rating":5,"content":"混油皮表示完美！控油效果好到下午不脱妆，粉质细腻不卡粉，毛孔隐形超棒。清透色适合黄二白，自然提亮。12g补充装划算，换芯环保。强烈推荐油皮混油皮姐妹！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_013.json'),
    ('p_beauty_014', '花西子空气蜜粉轻盈定妆控油提亮肤色细腻粉质散粉8.5g', '花西子', '美妆护肤', '蜜粉', '美妆护肤/蜜粉', 169.0, 169.0, 169.0, 200, '1_美妆护肤/images/p_beauty_014_live.jpg', '{"product_id":"p_beauty_014","title":"花西子空气蜜粉轻盈定妆控油提亮肤色细腻粉质散粉8.5g","brand":"花西子","category":"美妆护肤","sub_category":"蜜粉","base_price":169.0,"image_path":"1_美妆护肤/images/p_beauty_014_live.jpg","skus":[{"sku_id":"s_p_beauty_014_1","properties":{"规格":"8.5g 经典空气蜜粉"},"price":169.0},{"sku_id":"s_p_beauty_014_2","properties":{"规格":"8.5g 控油款"},"price":169.0}],"rag_knowledge":{"marketing_description":"花西子空气蜜粉（8.5g）以“空气感定妆”为核心，打造清透持久的妆效。经典款与控油款双选择，满足不同肤质需求。核心卖点在于超细蚕丝粉体，上脸零厚重感，同时添加珍珠粉提亮肤色，自然不假白。适用人群包括混油、油皮日常通勤，干皮夏季或T区局部使用；使用场景覆盖上班、约会、旅行等长时间带妆场合。成分上，天然温和配方，无酒精无刺激，敏感肌可先做耳后测试。使用建议：粉扑轻蘸后抖去余粉，按压式上妆，T区重点加强；注意事项：存放干燥处，开封后12个月内用完，避免粉末入眼。","official_faq":[{"question":"如何用这款蜜粉打造持久不脱妆效果？","answer":"先确保底妆完全干透，取粉扑蘸粉后在盒盖轻压去余粉，以按压手法从中央向外推开，重点按压T区、鼻翼等易出油部位。易脱妆区域可采用“三明治定妆法”：底妆后轻拍一层蜜粉，喷定妆喷雾待干，再薄涂一层蜜粉。补妆时先用吸油纸吸油，再补涂蜜粉，避免厚重感，这样能有效延长持妆时间。"}],"user_reviews":[{"nickname":"小敏","rating":2,"content":"买的控油款，本以为适合油皮，结果下午3点T区就出油脱妆，比之前用的散粉差远了。粉质没宣传的细腻，上脸偶尔有小颗粒卡粉，尤其是鼻翼两侧，妆面粗糙。包装好看但实用性一般，不会回购。"},{"nickname":"阿雅","rating":5,"content":"经典款太好用了！粉质超级细腻，上脸像空气一样无厚重感，提亮自然不假白。混油皮早上8点上妆，下午6点只有T区轻微出油，妆面完整。粉扑柔软取粉均匀，每次用都舒服，已回购第二次。"},{"nickname":"莉莉","rating":5,"content":"控油款适合大油皮！夏天出门最怕脱妆，这款早上涂完到晚上9点回家，妆面还是哑光，只有一点油光，补一次就够。粉质细腻不卡粉，提亮自然不灰，包装小巧补妆方便，推荐油皮姐妹。"},{"nickname":"小宇","rating":2,"content":"经典款用两次就过敏，脸上起小红疹，不知道是不是成分问题。定妆效果一般，中午就浮粉，额头斑驳。虽然粉质细腻，但不适合我肤质，只能闲置，敏感肌谨慎购买。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_014.json'),
    ('p_beauty_015', '完美日记仿生膜精华唇釉丝绒哑光滋润显色持妆唇部彩妆3g', '完美日记', '美妆护肤', '唇釉', '美妆护肤/唇釉', 120.0, 120.0, 129.0, 200, '1_美妆护肤/images/p_beauty_015_live.jpg', '{"product_id":"p_beauty_015","title":"完美日记仿生膜精华唇釉丝绒哑光滋润显色持妆唇部彩妆3g","brand":"完美日记","category":"美妆护肤","sub_category":"唇釉","base_price":120.0,"image_path":"1_美妆护肤/images/p_beauty_015_live.jpg","skus":[{"sku_id":"s_p_beauty_015_1","properties":{"色号规格":"3g 经典色号"},"price":120.0},{"sku_id":"s_p_beauty_015_2","properties":{"色号规格":"3g 限定色号"},"price":129.0}],"rag_knowledge":{"marketing_description":"完美日记这款仿生膜精华唇釉，3g小巧便携，核心采用仿生膜技术，能模拟唇部天然脂质结构形成透气保护膜，锁住水分同时呈现高级丝绒哑光质感。不同于普通哑光唇釉的拔干问题，它添加透明质酸与植物精华，上唇滋润不紧绷，显色饱满均匀，持妆长达6小时不易掉色沾杯。适合日常通勤的上班族、爱美的学生党，或是需要持久妆容的约会、聚会场景。使用建议：清洁唇部后，干燥季节可薄涂润唇膏打底再涂抹；注意开封后6个月内用完，避免阳光直射，若出现过敏请立即停用。","official_faq":[{"question":"这款唇釉的仿生膜技术具体有什么作用？","answer":"仿生膜技术是核心亮点，它模拟唇部天然脂质结构，上唇后快速形成轻薄透气的保护膜。这层膜能锁住唇部水分，减少干燥起皮；增强唇釉附着力，让显色更持久且不易沾杯掉色；同时透气性能避免唇部闷感，即使长时间戴口罩也不易蹭掉，保持妆容完整性，兼顾美观与舒适。"},{"question":"经典色号和限定色号除了价格差异，还有什么区别？","answer":"除价格外，两者区别在色号设计与配方细节：限定色号多为季节/联名专属，颜色更具潮流感（如秋冬暖调焦糖、节日亮泽红），部分添加珠光或特殊质感成分提升层次；经典色号是长期在售的百搭款，适合日常使用，配方更侧重基础滋润与持妆。限定款因独特性与配方调整，价格略高9元。"},{"question":"哑光质地会不会拔干？需要提前打底吗？","answer":"这款哑光唇釉添加透明质酸与植物保湿成分，拔干情况优于普通哑光款。是否打底看唇部状态：干燥唇建议薄涂润唇膏等待1-2分钟吸收后再涂，减少干燥感；唇部状态好可直接涂。干燥季节或空调房，建议随身携带润唇膏补涂边缘，保持舒适，避免长时间干燥导致起皮。"}],"user_reviews":[{"nickname":"小草莓","rating":5,"content":"经典色#101奶茶调太适合上班了！上唇丝绒哑光但一点不拔干，之前用别家哑光唇釉半天就起皮，这款一整天唇部都润润的。持妆超久，中午吃了饭几乎没掉，补涂一下就好。3g小管子放包里很方便，已经回购第二次，推荐给闺蜜们都爱上了！"},{"nickname":"莉莉安","rating":5,"content":"限定色#007红棕色绝了！显白到发光，黄皮完全hold住。仿生膜技术真牛，戴口罩一上午都没蹭掉多少，之前的唇釉早花了。涂起来顺滑，一层就饱和，滋润度冬天也够。虽然比经典款贵9元，但颜色独特又好用，下次还蹲限定！"},{"nickname":"阿月","rating":2,"content":"买的经典#003豆沙色和图片差太多，实物偏紫调显老。持妆没说的久，下午喝几杯水就掉大半，得频繁补涂。我唇部偏干，没打底涂完下午就拔干起皮，保湿成分好像没起作用。颜色踩雷又不持久，不会再回购了。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_015.json'),
    ('p_beauty_016', 'AHC塑颜修护全脸眼霜紧致淡纹保湿提亮多效眼周护理30ml', 'AHC', '美妆护肤', '眼霜', '美妆护肤/眼霜', 139.0, 139.0, 159.0, 200, '1_美妆护肤/images/p_beauty_016_live.jpg', '{"product_id":"p_beauty_016","title":"AHC塑颜修护全脸眼霜紧致淡纹保湿提亮多效眼周护理30ml","brand":"AHC","category":"美妆护肤","sub_category":"眼霜","base_price":139.0,"image_path":"1_美妆护肤/images/p_beauty_016_live.jpg","skus":[{"sku_id":"s_p_beauty_016_1","properties":{"规格":"30ml 第七代全脸眼霜"},"price":139.0},{"sku_id":"s_p_beauty_016_2","properties":{"规格":"30ml 升级版"},"price":159.0}],"rag_knowledge":{"marketing_description":"AHC塑颜修护全脸眼霜是一款针对眼周及全脸初老问题的多效护理产品，30ml大容量满足日常需求。核心卖点在于全脸可用，不仅能改善眼周干燥、细纹、暗沉，还可用于法令纹、抬头纹等部位，实现一站式修护。成分上添加高浓度玻尿酸深层锁水，视黄醇衍生物温和淡纹，烟酰胺提亮肤色，质地轻盈易吸收。适用人群为25+有初老迹象、眼周干燥或有细纹暗沉的人群。使用场景：早晚洁面后，取黄豆大小点涂眼周及需要护理区域，轻轻打圈按摩至吸收。注意事项：敏感肌建议先耳后测试，避免入眼，开封后6个月内用完，存放于阴凉干燥处。","official_faq":[{"question":"AHC第七代全脸眼霜和升级版有什么区别？","answer":"第七代和升级版的核心成分一致，但升级版在有效成分浓度上有所提升，比如视黄醇衍生物含量增加15%，同时添加了新的积雪草提取物增强修护力，淡纹和保湿效果更显著。升级版的质地更清爽，吸收更快，适合夏季或油性肌肤使用。价格上升级版贵20元，是因为成分升级和工艺优化，追求更好效果的用户可选择升级版。"},{"question":"这款眼霜真的可以全脸使用吗？","answer":"是的，这款眼霜配方温和，不含酒精、香精等刺激性成分，除眼周外，法令纹、抬头纹、颈纹等易产生细纹的部位都可使用。它的多效配方能同时满足不同区域的修护需求，相当于一瓶多用，性价比很高。使用时注意避开眼内，其他部位按正常护肤步骤涂抹即可，不会对皮肤造成负担。"},{"question":"敏感肌能用这款眼霜吗？","answer":"大部分敏感肌可以使用，但由于含有视黄醇衍生物，少数敏感肌可能会出现轻微刺激。建议敏感肌用户先在耳后或手臂内侧做局部测试，无不适再使用。使用时从少量开始，逐步建立耐受，避免频繁使用。若出现红肿、瘙痒等过敏反应，应立即停用并咨询皮肤科医生。"}],"user_reviews":[{"nickname":"小敏","rating":4,"content":"用了快半个月，保湿效果还可以，眼周不再干干的，但淡纹效果暂时没看出来。质地有点厚重，夏天用感觉有点闷，不过吸收后还好。整体来说中规中矩，没有特别惊喜，但也不算差，给个4分吧。"},{"nickname":"阿雅","rating":5,"content":"真的太惊喜了！用了一个月，眼周的干纹明显淡了，尤其是笑起来的细纹几乎看不见。保湿也超持久，早上起来眼周还是润润的。全脸用在法令纹处，感觉也紧致了一点。价格也实惠，30ml能用很久，会无限回购的，必须给5分！"},{"nickname":"阿明","rating":3,"content":"用了一周，没感觉到任何效果，保湿一般，下午眼周就开始干了。而且味道有点怪怪的，不是很喜欢。139元的价格也不算便宜，感觉性价比不高，有点失望，给3分。"},{"nickname":"丽丽","rating":1,"content":"太糟糕了！用了两次就过敏了，眼周红肿发痒，赶紧停用了。联系客服，只说让我自己承担运费退货，态度也不好。再也不会买AHC的产品了，强烈不推荐，给1分！"},{"nickname":"小宇","rating":3,"content":"质地太稠了，每次都要按摩很久才吸收，而且用了一个月，淡纹效果几乎没有。包装也很普通，没有想象中高大上。整体感觉一般，没有达到预期，给3分。"},{"nickname":"琪琪","rating":3,"content":"用了三周，提亮效果不明显，眼周还是暗沉。保湿还可以，但也没特别突出。价格比其他眼霜贵一点，但效果跟不上，有点不值，给3分。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_016.json'),
    ('p_beauty_017', '芳珂纳米温和净化卸妆油深层清洁毛孔无添加卸妆液120ml', '芳珂', '美妆护肤', '卸妆', '美妆护肤/卸妆', 178.0, 178.0, 198.0, 200, '1_美妆护肤/images/p_beauty_017_live.jpg', '{"product_id":"p_beauty_017","title":"芳珂纳米温和净化卸妆油深层清洁毛孔无添加卸妆液120ml","brand":"芳珂","category":"美妆护肤","sub_category":"卸妆","base_price":178.0,"image_path":"1_美妆护肤/images/p_beauty_017_live.jpg","skus":[{"sku_id":"s_p_beauty_017_1","properties":{"规格":"120ml 经典蓝瓶"},"price":178.0},{"sku_id":"s_p_beauty_017_2","properties":{"规格":"120ml 限量设计款"},"price":198.0}],"rag_knowledge":{"marketing_description":"芳珂纳米温和净化卸妆油是敏感肌友好型卸妆产品，核心卖点在于纳米级卸妆分子与无添加配方——纳米分子能深入毛孔包裹彩妆及污垢，无香料、酒精、防腐剂等刺激成分，通过敏感肌测试。适用人群涵盖敏感肌、混合肌及追求温和清洁的人群，日常淡妆、浓妆（含防水彩妆）均适用。使用场景包括每日晚间卸妆、出差便携（120ml容量适中）。使用建议：干手干脸取2-3泵，按摩1-2分钟（眼唇重点按摩），加少量水乳化至白色乳液状，温水冲洗；注意事项：开封后60天内用完（无防腐剂易变质），皮肤有伤口或过敏期暂停使用，存放于阴凉干燥处。","official_faq":[{"question":"这款卸妆油真的适合敏感肌吗？有没有添加香料酒精？","answer":"是的，芳珂这款卸妆油主打无添加配方，不含香料、酒精、防腐剂、矿物油等刺激性成分，通过了敏感肌测试。纳米级的卸妆分子能温和包裹彩妆和污垢，不会拉扯皮肤，敏感肌可以放心使用，但如果是极敏感肌，建议先在耳后做皮肤测试。"},{"question":"它能卸除防水类彩妆吗？比如防水睫毛膏和眼线？","answer":"可以的。这款卸妆油的纳米分子能深入毛孔和睫毛根部，溶解防水彩妆的油脂成分。使用时建议针对眼唇部位多按摩几秒，让卸妆油充分接触彩妆，然后加水乳化，就能轻松卸除，不会残留。亲测防水睫毛膏也能卸干净，不用额外用眼唇卸妆液。"},{"question":"开封后保质期是多久？为什么？","answer":"开封后建议60天内用完。因为这款卸妆油采用无防腐剂配方，为了保证产品的新鲜度和安全性，避免细菌滋生，所以开封后的使用周期较短。建议每次使用后拧紧瓶盖，放在阴凉干燥处保存，不要阳光直射。"},{"question":"乳化速度快吗？会不会有残留感？","answer":"乳化速度很快，遇水后几秒就能变成白色乳液状。只要充分乳化并用清水冲洗干净，就不会有残留感。使用时注意加少量水，轻轻按摩让乳化完全，然后用温水冲洗，之后皮肤会感觉清爽不紧绷，不会像有些卸妆油那样油腻腻的。"},{"question":"经典蓝瓶和限量设计款有什么区别？成分一样吗？","answer":"成分是完全一样的，都是纳米温和净化卸妆油。区别主要在于包装设计，限量款的瓶身会有特殊的图案或颜色，更具收藏价值。价格上限量款比经典款贵20元，所以如果追求性价比选经典蓝瓶，如果喜欢独特包装可以选限量款。"},{"question":"使用后需要再用洁面产品吗？","answer":"建议使用。虽然这款卸妆油乳化彻底后残留少，但为了确保皮肤完全清洁，尤其是油性肌肤或化浓妆的情况下，后续使用温和的洁面产品能进一步清洁毛孔，避免油脂和污垢堆积。干性或敏感肌如果觉得皮肤不油腻，也可以根据自身情况选择是否用洁面。"}],"user_reviews":[{"nickname":"林小夏","rating":3,"content":"买的经典蓝瓶，卸妆效果还可以，防水睫毛膏能卸，但乳化后冲洗总感觉有点膜感，不像宣传的那么清爽。而且开封后60天用完压力有点大，我平时淡妆，120ml感觉用不完就要过期了，这点不太友好。还有价格有点小贵，性价比一般吧。"},{"nickname":"张萌萌","rating":5,"content":"敏感肌福音！之前用别的卸妆油会泛红，这款完全不会。纳米技术真的很温和，卸完脸不紧绷，防水眼线也能轻松卸掉。乳化速度超快，冲洗后一点残留都没有。已经回购第三次了，经典蓝瓶性价比高，推荐给所有敏感肌姐妹！"},{"nickname":"李大力","rating":1,"content":"太失望了！买的限量款，价格贵就算了，用了两次居然长闭口！我是混合肌，之前用别的卸妆油都没事，这款说是无添加但还是刺激到我了。而且瓶身设计有问题，按压泵头不好用，每次按出来的量要么太多要么太少，体验感极差，不会再买了。"},{"nickname":"王甜甜","rating":5,"content":"无限回购的卸妆油！纳米分子真的能深入毛孔，每次卸完都感觉毛孔很干净，不会堵塞。无添加配方很安心，孕期也能用。乳化快，冲洗后皮肤滑滑的，不油腻。限量款的包装超好看，摆化妆台上心情都变好，虽然贵一点但值得！"},{"nickname":"赵小宇","rating":3,"content":"卸妆效果还行，但有个问题：开封后必须60天用完，我出差多，有时候一个月都用不了几次，结果还没用到一半就过期了，太浪费了。而且价格178元120ml，对比其他品牌同容量的卸妆油，性价比不算高。如果能延长开封保质期就好了。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_017.json'),
    ('p_beauty_018', 'The Ordinary烟酰胺10%锌1%精华液平衡油脂淡化毛孔提亮肤色30ml', 'The Ordinary', '美妆护肤', '精华', '美妆护肤/精华', 59.0, 59.0, 98.0, 200, '1_美妆护肤/images/p_beauty_018_live.jpg', '{"product_id":"p_beauty_018","title":"The Ordinary烟酰胺10%锌1%精华液平衡油脂淡化毛孔提亮肤色30ml","brand":"The Ordinary","category":"美妆护肤","sub_category":"精华","base_price":59.0,"image_path":"1_美妆护肤/images/p_beauty_018_live.jpg","skus":[{"sku_id":"s_p_beauty_018_1","properties":{"容量":"30ml 标准装"},"price":59.0},{"sku_id":"s_p_beauty_018_2","properties":{"容量":"60ml 大容量装"},"price":98.0}],"rag_knowledge":{"marketing_description":"The Ordinary这款烟酰胺10%锌1%精华液是油痘肌和暗沉肌的高性价比选择。核心成分10%烟酰胺能调节皮脂分泌、淡化毛孔并提亮肤色，1%锌则辅助控油舒缓。适合油性/混合性皮肤、有毛孔粗大或肤色不均问题的人群。日常护肤时，洁面爽肤后取2-3滴涂抹全脸（避开眼周），初期建议隔天使用建立耐受，后续可增至每日。注意：敏感肌需先耳后测试，避免与高浓度酸类（如水杨酸）同时使用，使用期间做好防晒。","official_faq":[{"question":"10%烟酰胺浓度会刺激皮肤吗？","answer":"10%属于较高浓度烟酰胺，初次使用可能有轻微刺痛或泛红。建议先在耳后/手臂内侧测试，无不适再用。初期每周2-3次，每次2-3滴，待皮肤适应后逐渐增加频率。若持续不适，暂停使用或咨询医生。敏感肌需谨慎，可先选低浓度产品。"},{"question":"这款精华适合什么肤质？","answer":"成分功效完全相同，仅容量和价格不同。30ml单价约1.97元/ml，60ml约1.63元/ml，大容量更划算。初次尝试选30ml，长期使用选60ml更经济。"}],"user_reviews":[{"nickname":"小敏","rating":2,"content":"用两次就泛红刺痛，混干皮hold不住10%浓度。之前用5%烟酰胺没事，这个太刺激了。涂完脸紧绷，还起了小疹子，敏感肌慎入！"},{"nickname":"阿强","rating":3,"content":"控油效果一般，早上涂下午T区还是油。毛孔没见小，质地略黏吸收慢。用了一个月没明显变化，性价比普通。"},{"nickname":"小美","rating":5,"content":"油痘肌救星！半个月T区出油减少，毛孔细腻了，肤色提亮。清爽不黏，吸收快。30ml能用俩月，价格超实惠，会回购60ml！"},{"nickname":"丽丽","rating":3,"content":"效果不明显，三周肤色没变化。涂多了搓泥，和后续乳液不兼容。用量得控制，不然容易卡粉，整体一般。"},{"nickname":"大兵","rating":5,"content":"男生油皮福音！控油超棒，早上涂到晚上不油，毛孔变小。价格便宜，60ml能用很久，推荐给油皮朋友！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_018.json'),
    ('p_beauty_019', '兰蔻清滢柔肤水大粉水保湿舒缓干性肌肤柔润爽肤水400ml', '兰蔻', '美妆护肤', '化妆水', '美妆护肤/化妆水', 582.0, 360.0, 582.0, 200, '1_美妆护肤/images/p_beauty_019_live.jpg', '{"product_id":"p_beauty_019","title":"兰蔻清滢柔肤水大粉水保湿舒缓干性肌肤柔润爽肤水400ml","brand":"兰蔻","category":"美妆护肤","sub_category":"化妆水","base_price":582.0,"image_path":"1_美妆护肤/images/p_beauty_019_live.jpg","skus":[{"sku_id":"s_p_beauty_019_1","properties":{"容量":"400ml 清滢柔肤水"},"price":582.0},{"sku_id":"s_p_beauty_019_2","properties":{"容量":"200ml 旅行装"},"price":360.0}],"rag_knowledge":{"marketing_description":"兰蔻清滢柔肤水（大粉水）是干性肌肤的秋冬保湿救星！核心卖点在于它浓稠如精华液的质地，却能快速渗透不粘腻，蕴含玫瑰精华与玻尿酸成分，深层舒缓干燥肌肤，补充流失水分。适用人群精准锁定干性、偏干及换季敏感干皮，日常护肤第一步用它，早晚轻拍或用化妆棉擦拭都可，妆前打底还能让底妆更服帖。400ml大容量适合居家长期使用，200ml旅行装则方便出差携带。注意事项：敏感肌首次使用建议先在耳后做局部测试，避免直接接触眼周，开封后6个月内用完效果最佳。","official_faq":[{"question":"兰蔻大粉水适合敏感干皮吗？成分里有没有舒缓成分？","answer":"兰蔻大粉水主要针对干性肌肤设计，成分中添加了玫瑰精华和玻尿酸，玫瑰精华能舒缓肌肤不适感，玻尿酸则强效锁水。不过敏感肌肤质特殊，建议首次使用前先取少量在耳后或手腕内侧做24小时皮肤测试，确认无红肿、刺痛等过敏反应后再正常使用。如果测试过程中出现不适，应立即停止使用并咨询皮肤科医生。"},{"question":"大粉水的质地和普通爽肤水有什么不同？吸收速度快吗？","answer":"大粉水的质地比普通爽肤水更浓稠，接近精华液的质感，但触肤后能迅速被肌肤吸收，不会留下粘腻感。普通爽肤水多为清爽型，主要作用是二次清洁，而大粉水兼具清洁、保湿和舒缓三重功效，更适合干性肌肤补充水分。使用时轻拍至吸收，能让肌肤立刻感受到水润柔软，后续搭配乳液或面霜锁水效果更好。"},{"question":"400ml和200ml旅行装的成分是否一致？哪种更划算？","answer":"两种规格的成分完全一致，只是容量不同。400ml大容量适合日常居家使用，按每天早晚各一次计算，一瓶大概能使用3-4个月，单价更实惠；200ml旅行装则方便出差、旅游携带，避免大瓶液体过安检的麻烦。如果是长期使用，建议选择400ml更划算；如果经常外出，旅行装是不错的补充选择。"},{"question":"使用大粉水时必须用化妆棉吗？有没有更省水的方法？","answer":"不一定必须用化妆棉。用化妆棉擦拭可以起到二次清洁的作用，适合皮肤偏油或需要清洁毛孔的人群；而直接用手轻拍则更省水，且能让肌肤更好地吸收水分，适合干性肌肤。建议干性肌优先选择手拍方式，取适量产品于掌心，轻轻拍打面部至完全吸收，这样既节省用量又能达到良好的保湿效果。"}],"user_reviews":[{"nickname":"小敏","rating":2,"content":"收到的400ml大粉水打开时发现瓶盖处有漏液，洒了不少，心疼死了。用了一次后脸颊有点刺痛，可能是我敏感肌不耐受？联系客服半天没回复，体验很不好。虽然质地看起来浓稠，但刺痛感让我不敢再用了，希望商家能处理漏液问题，也建议敏感肌谨慎尝试。"},{"nickname":"阿雅","rating":3,"content":"保湿效果一般般吧，我是干性肌，秋冬用还是觉得脸干，而且味道有点浓，不是很喜欢那种香味。200ml旅行装携带倒是方便，但性价比不高，360块钱有点贵了。如果保湿力能再强点就好了，不然感觉不值这个价。"},{"nickname":"莉莉","rating":5,"content":"干皮救星！用了三个月大粉水，早晚拍脸，皮肤再也不紧绷了，冬天上妆也不卡粉。400ml大容量真的耐用，每次用一点就够了，吸收很快，没有粘腻感。之前换季皮肤敏感，用它也能舒缓，已经回购第二次了，推荐给所有干皮姐妹！"},{"nickname":"小宇","rating":2,"content":"买的200ml旅行装，感觉和专柜买的质地不一样，有点稀，而且用了之后额头起了小疹子，怀疑是不是买到假货了？包装倒是和正品一样，但使用感差很多，不敢再用了，希望商家能给个说法，以后不会再在这里买了。"},{"nickname":"晴晴","rating":5,"content":"大粉水是我每年秋冬必囤的！干皮用它太舒服了，洗完脸拍上，皮肤软软的，保湿效果能维持一整天。400ml的瓶子虽然大，但放在家里用很方便，搭配兰蔻的菁纯面霜，皮肤状态超稳定。这次活动买的价格也很划算，满意！"},{"nickname":"阿凯","rating":4,"content":"给女朋友买的400ml大粉水，她说保湿效果还可以，但瓶子太大了，出门带不了，而且价格有点贵。如果能出个100ml的便携装就好了，这样她出差也能带着用。整体来说她还是满意的，但希望包装能更人性化一点，所以给4分吧。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_019.json'),
    ('p_beauty_020', '雅诗兰黛持妆粉底液SPF10PA持久遮瑕控油抗汗清透底妆30ml', '雅诗兰黛', '美妆护肤', '粉底液', '美妆护肤/粉底液', 440.0, 440.0, 440.0, 200, '1_美妆护肤/images/p_beauty_020_live.jpg', '{"product_id":"p_beauty_020","title":"雅诗兰黛持妆粉底液SPF10PA持久遮瑕控油抗汗清透底妆30ml","brand":"雅诗兰黛","category":"美妆护肤","sub_category":"粉底液","base_price":440.0,"image_path":"1_美妆护肤/images/p_beauty_020_live.jpg","skus":[{"sku_id":"s_p_beauty_020_1","properties":{"版本":"30ml 经典持妆粉底液"},"price":440.0},{"sku_id":"s_p_beauty_020_2","properties":{"版本":"30ml 油皮友好色号"},"price":440.0}],"rag_knowledge":{"marketing_description":"油皮姐妹看过来！雅诗兰黛持妆粉底液SPF10PA是夏日底妆的不二之选！核心卖点在于持久遮瑕、控油抗汗，30ml装便携又耐用。适用人群主要是油皮、混油皮，尤其适合需要长时间持妆的上班族、学生党或户外活动爱好者。使用场景覆盖通勤8小时不脱妆、约会防蹭、夏日出游抗汗。配方含控油科技，能吸附多余油脂，SPF10PA提供日常基础防晒，质地清透不厚重。使用建议：妆前用清爽保湿乳打底，用打湿的美妆蛋轻拍上妆避免搓泥；注意事项：敏感肌先耳后测试，色号选择参考试色或客服，油皮友好款更适合大油皮，经典款适合混油皮。","official_faq":[{"question":"这款持妆粉底液适合什么肤质？","answer":"主要针对油皮和混油皮设计，控油配方有效抑制T区出油，保持妆容清爽。干皮使用可能拔干，需搭配保湿妆前乳；中性肤质夏季适用，冬季需加强保湿。它的质地轻薄，不会给肌肤造成负担，是油皮夏日的理想选择。"},{"question":"油皮友好色号和经典款有什么区别？","answer":"油皮友好色号在控油配方上更强化，添加更多油脂吸附成分，适合大油皮或高温环境；经典款控油力适中，兼顾保湿，适合混油皮或春秋季节。两者色号范围类似，但油皮友好款更偏向哑光效果，能长效维持清爽妆感。"},{"question":"遮瑕力如何，能遮盖痘印和红血丝吗？","answer":"遮瑕力中等偏上，可遮盖70%左右的痘印和红血丝，较深痘印建议叠加遮瑕膏。质地轻薄，不会因遮瑕显得厚重，适合自然妆感。少量多次叠加可提升遮瑕力，同时保持清透。"},{"question":"持妆时间多久，夏天容易脱妆吗？","answer":"油皮正常情况下可持妆6-8小时，夏季出汗多T区可能轻微脱妆，但不会斑驳。用散粉定妆T区能延长持妆时间。抗汗效果出色，日常户外活动没问题，是夏日持妆的可靠选择。"},{"question":"含SPF10PA，还需额外涂防晒霜吗？","answer":"SPF10PA适合日常通勤或短时间户外，长时间暴晒（超2小时）需叠加高倍防晒。粉底液用量通常不足防晒标准，重要场合建议额外涂防晒，确保肌肤得到充分保护。"},{"question":"如何选择适合自己的色号？","answer":"先确定肤色基调（冷/暖/中性），参考官方色卡或专柜试色。油皮友好款和经典款色号编号相似但质地不同，选色时建议接近脖子肤色，避免脸颈色差。不确定时可咨询客服，或选择自然色号试用。"}],"user_reviews":[{"nickname":"小敏","rating":2,"content":"买的油皮友好色号，上脸后拔干严重，鼻翼和嘴角卡粉明显。早上9点上妆，中午T区就脱妆浮粉，色号1W1比我肤色深，显得暗沉。客服说混油能用，但我混干皮体验极差，不会再回购了。"},{"nickname":"阿丽","rating":2,"content":"遮瑕力不够，痘印红血丝几乎遮不住，还要额外用遮瑕膏。持妆时间短，夏天30度下午就斑驳，额头尤其明显。440元的价格不值这个效果，不如平价粉底液好用。"},{"nickname":"莉莉","rating":5,"content":"油皮福音！夏天用完全不脱妆，早8到晚6T区仅轻微出油，吸油纸按一下就好，妆容完整。遮瑕力棒，小痘印毛孔都遮住，质地清透不厚重，油皮友好色号yyds！"},{"nickname":"小宇","rating":5,"content":"经典款太适合混油皮了，控油适中不脱干，持妆7小时补次散粉就行。色号2C0自然匹配肤色，SPF10PA通勤不用额外防晒，节省时间，已回购第二次，推荐混油皮朋友！"},{"nickname":"小雅","rating":4,"content":"整体不错，控油持妆都好，夏天用舒服。但色号1N1偏黄，刚上妆有点假面，融合后自然。如果色号更准就完美了，给4分。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_020.json'),
    ('p_beauty_021', '科颜氏牛油果保湿眼霜滋润补水细腻质地淡化干纹眼周护理28g', '科颜氏', '美妆护肤', '眼霜', '美妆护肤/眼霜', 320.0, 210.0, 320.0, 200, '1_美妆护肤/images/p_beauty_021_live.jpg', '{"product_id":"p_beauty_021","title":"科颜氏牛油果保湿眼霜滋润补水细腻质地淡化干纹眼周护理28g","brand":"科颜氏","category":"美妆护肤","sub_category":"眼霜","base_price":320.0,"image_path":"1_美妆护肤/images/p_beauty_021_live.jpg","skus":[{"sku_id":"s_p_beauty_021_1","properties":{"容量":"14g 便携装"},"price":210.0},{"sku_id":"s_p_beauty_021_2","properties":{"容量":"28g 标准装"},"price":320.0}],"rag_knowledge":{"marketing_description":"科颜氏这款牛油果眼霜是万千干纹眼周星人的老熟人啦，核心采用冷压萃取的智利天然牛油果油，搭配维生素E与神经酰胺复合物，质地是那种刚挖出来像柔滑牛油果泥、触肤就会慢慢化水的特殊配方，完全不会糊眼闷脂肪粒。特别适合20岁+初抗老、眼周容易卡干纹、换季洗完脸眼尾立刻紧绷的人群，不管是熬夜追完剧急救涂一层、上妆前厚敷5分钟给眼周打个底，还是日常早晚护肤最后一步用都适配。使用时记得取绿豆大小，用指腹轻轻点按在眼周从内到外揉开到吸收就行，要注意刚挖出来别直接厚涂猛搓，还有避开眼内黏膜区域哦，14g便携装揣包里出差旅行超方便，28g标准装天天用也能用小半年，性价比很高。","official_faq":[{"question":"这款牛油果眼霜刚挖出来是偏厚重的膏状，上脸会闷脂肪粒吗？","answer":"完全不用担心闷脂肪粒的问题，这款采用的是科颜氏独有的水包油转化质地，刚取出来的时候看起来是绵密的牛油果乳霜状，用指腹打圈轻揉3到5秒就会慢慢乳化变成半透明的水状精华质感，渗透速度特别快，不会在眼周留下黏腻的油膜感。它的成分都是小分子级的滋养油脂，没有添加多余的封闭性矿物油和致痘成分，只要每次取用量控制在绿豆大小，完全不会给眼周薄皮肤造成负担，干皮油皮正常使用都很少长脂肪粒。"},{"question":"这款牛油果眼霜真的能淡化已经长出来的眼周干纹吗？要多久能看到效果？","answer":"它针对的就是因眼周干燥缺水产生的假性干纹，不是深的真性皱纹，坚持正确使用是可以逐步改善的。很多用户反馈连续用2到3周之后，之前一笑就冒出来的眼尾干纹、上妆卡粉的纹路就会明显变浅，上妆再也不会在眼角卡出一道粉线。它里面的冷压牛油果油能直接补充眼周皮肤缺失的脂质，搭配的维生素E还能改善眼周干到起皮的状态，坚持1到2个月就能感觉到眼周一直是润润的，不会动不动就紧绷发涩。"},{"question":"14g便携装和28g标准装的成分、质地有区别吗？为什么两个版本价格差这么多？","answer":"两个规格的膏体成分、生产工艺、品质完全一模一样，没有任何区别，价格差异主要是容量和使用场景的区别。14g的便携装专门做了缩小版的矮瓶身设计，刚好能放进通勤的小挎包或者出差的随身化妆袋里，重量轻不会占行李额度，适合没怎么用过想先试手、或者经常外出短途出行的用户。28g的标准装性价比更高，天天早晚用的话差不多能用6到8个月，适合已经确认适配自己肤质、打算长期用的老用户购买，算下来单克价格要比14g的划算不少。"},{"question":"敏感肌用这款牛油果眼霜会不会刺痛泛红？有没有添加香精酒精？","answer":"这款牛油果眼霜是经过皮肤科敏感肌测试的，完全没有添加酒精、人工合成香精、防腐剂这类刺激性成分，整体配方非常温和。只有极少数对牛油果植物油本身严重过敏的用户，才可能出现泛红刺痛的情况，普通的换季敏感、眼周皮肤薄容易红的用户正常使用都不会有不适反应。如果本身是极度敏感的肤质，可以先取一点点膏体涂在耳后或者下眼睑边缘做48小时的皮肤测试，没有异样再正常全眼周涂抹就好，大部分敏感肌用户反馈用着都特别安心。"},{"question":"夏天温度高的时候这款眼霜放久了会不会化水、膏体变稀变质啊？","answer":"这款眼霜的储存耐受温度在25度以下，如果夏天长期放在30度以上的车里或者没有空调的闷热化妆台上，确实会出现膏体轻微融化、出现水油分层的正常物理现象，不是变质。遇到这种情况不用担心，只需要把盖子拧紧放到冰箱冷藏室的保鲜层里，静置24小时之后拿出来，膏体就会慢慢恢复原本绵密的牛油果泥质地，完全不影响里面的成分效果和使用感受。日常不用的时候尽量放在阴凉避光的地方储存，避免阳光直射就能避免膏体提前软化。"}],"user_reviews":[{"nickname":"小楠","rating":1,"content":"我是混油敏皮，之前看大家都说这款不闷脂肪粒才买的，结果用了不到一周，下眼睑长了三个白白的小颗粒，一开始我还以为是我用量多了，改成小米粒大小还是不行，每次涂完过俩小时眼周都还是黏糊糊的，后续叠个防晒霜直接搓泥，眼尾之前的干纹一点没淡反而闷得发红，停了一周脂肪粒才消下去，真的不适合油皮姐妹入手，太踩雷了。"},{"nickname":"阿柚","rating":5,"content":"我是干皮，眼周一到秋天就干得卡粉，之前换了好几个贵价眼霜都没用，这款牛油果眼霜我从大三用到现在第三瓶了，每次取一点用指腹揉开化成水再点上去，吸收特别快，涂完润润的但一点不油，现在秋天上妆眼角再也不会卡出一道干纹粉线，28g的大瓶我天天早晚用能用大半年，算下来性价比特别高，身边好几个干皮朋友被我安利之后都离不开了。"},{"nickname":"阿凯","rating":2,"content":"我抱着试试的心态买了28g的，结果用了快一个月，眼周的干纹一点变化都没有，该卡粉还是卡粉，每次涂完要等半天才能完全吸收，我这种经常熬夜的人用着感觉完全没效果，三百多块钱买这么一大瓶，啥用都没有，还不如之前用的一百多的入门眼霜，效果和宣传的淡化干纹差得太远了，真的不太推荐。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_021.json'),
    ('p_beauty_022', '薇诺娜极润保湿面膜密集补水舒缓修护肌肤屏障涂抹式面膜75g', '薇诺娜', '美妆护肤', '面膜', '美妆护肤/面膜', 199.0, 168.0, 199.0, 200, '1_美妆护肤/images/p_beauty_022_live.jpg', '{"product_id":"p_beauty_022","title":"薇诺娜极润保湿面膜密集补水舒缓修护肌肤屏障涂抹式面膜75g","brand":"薇诺娜","category":"美妆护肤","sub_category":"面膜","base_price":199.0,"image_path":"1_美妆护肤/images/p_beauty_022_live.jpg","skus":[{"sku_id":"s_p_beauty_022_1","properties":{"产品规格":"75g 涂抹式面膜"},"price":199.0},{"sku_id":"s_p_beauty_022_2","properties":{"产品规格":"25g*5片 贴片装面膜"},"price":168.0}],"rag_knowledge":{"marketing_description":"薇诺娜极润保湿面膜专为干敏肌设计，核心成分含云南高原青刺果油与马齿苋提取物，能密集补水同时舒缓泛红。75g涂抹式包装适合夜间厚敷，25g*5片装便携适合出差。使用时取适量均匀涂于面部，避开眼唇，15-20分钟后洗净。注意开封后6个月内用完，敏感肌首次使用建议先做耳后测试。","official_faq":[{"question":"这款面膜适合什么肤质？","answer":"主要针对干性、敏感性肌肤，尤其是换季或空调房导致的肌肤干燥、泛红问题。成分温和无酒精，敏感肌可放心使用，但首次使用建议先做局部测试。"},{"question":"75g和25g*5片装的区别是什么？","answer":"75g是罐装涂抹式，适合长期居家使用，单次用量更灵活；25g*5片是独立包装，方便携带，适合出差或旅行。两者成分相同，仅规格和包装形式不同。"},{"question":"使用频率建议是怎样的？","answer":"干性肌肤每周2-3次，敏感肌每周1-2次。干燥季节可增加至每周3-4次，每次厚敷15-20分钟，后续无需清洗，直接进行基础护肤即可。"},{"question":"开封后保质期是多久？","answer":"罐装75g开封后建议6个月内用完，单片装开封后需立即使用。储存时避免阳光直射，放置于阴凉干燥处，防止成分变质影响效果。"},{"question":"可以和其他护肤品叠加使用吗？","answer":"可以。建议在洁面后直接使用面膜，后续搭配薇诺娜特护霜或保湿乳液锁水。避免与含酸类产品（如刷酸）同时使用，以免刺激肌肤。"},{"question":"面膜有香味吗？是否含香精？","answer":"产品无明显香味，不含人工香精。采用天然植物成分，气味清淡，敏感肌使用更安心。若对特定植物成分过敏，建议先查看成分表或咨询客服。"}],"user_reviews":[{"nickname":"林小雨","rating":3,"content":"保湿效果还行，但涂抹时有点黏腻，洗掉后皮肤会紧绷。用了三次，泛红有所缓解，但没达到预期。价格偏贵，性价比一般，可能不会回购。"},{"nickname":"张大明","rating":1,"content":"用了一次就过敏了，脸颊泛红刺痛，停用后才好转。查了成分，发现有我不耐受的成分。包装上没明确标注敏感成分，客服处理也慢，非常失望。"},{"nickname":"王佳佳","rating":3,"content":"补水效果一般，厚敷后还是觉得干。单片装量太少，一次不够用，性价比低。而且涂抹后容易搓泥，后续上妆不服帖，不会再买了。"},{"nickname":"李思思","rating":4,"content":"整体还不错，舒缓效果明显，泛红减轻了。但质地有点稀，涂抹时容易滴落，建议改进包装设计。价格偏高，如果有活动会考虑回购。"},{"nickname":"赵小磊","rating":3,"content":"用了两周，保湿效果不持久，第二天还是干。罐装设计不方便携带，出差只能买单片装，成本太高。成分虽然温和，但效果普通，不太推荐。"},{"nickname":"陈萌萌","rating":5,"content":"干敏肌救星！用了三次，泛红完全消退，皮肤变得水润。涂抹式很方便，厚敷后洗掉皮肤软软的，后续上妆超服帖。会无限回购，推荐给敏感肌朋友！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_022.json'),
    ('p_beauty_023', '理肤泉特护清盈防晒乳高倍防晒清爽控油易敏肌适用面部防晒50ml', '理肤泉', '美妆护肤', '防晒', '美妆护肤/防晒', 268.0, 268.0, 268.0, 200, '1_美妆护肤/images/p_beauty_023_live.jpg', '{"product_id":"p_beauty_023","title":"理肤泉特护清盈防晒乳高倍防晒清爽控油易敏肌适用面部防晒50ml","brand":"理肤泉","category":"美妆护肤","sub_category":"防晒","base_price":268.0,"image_path":"1_美妆护肤/images/p_beauty_023_live.jpg","skus":[{"sku_id":"s_p_beauty_023_1","properties":{"产品规格":"50ml 清盈型"},"price":268.0},{"sku_id":"s_p_beauty_023_2","properties":{"产品规格":"50ml 轻薄无润色"},"price":268.0}],"rag_knowledge":{"marketing_description":"理肤泉这款特护清盈防晒乳，专为易敏肌设计，50ml的容量刚好满足日常通勤或短途旅行需求。它采用高倍防晒配方，SPF50+ PA++++，能有效抵御UVA/UVB伤害，同时添加了理肤泉温泉水成分，舒缓肌肤不适。清盈型质地轻薄不油腻，上脸后快速成膜，不会闷痘，适合油皮或混合皮在夏季使用；轻薄无润色款则更适合追求自然妆感的人群，后续上妆也不会搓泥。建议在洁面爽肤后，取适量均匀涂抹于面部，避开眼周，户外活动时每2小时补涂一次。注意：若肌肤出现红肿、瘙痒等不适，应立即停用并咨询医生。","official_faq":[{"question":"清盈型和轻薄无润色款有什么区别？","answer":"清盈型质地更偏向清爽控油，适合油皮或混合皮，上脸后有轻微的哑光效果，能减少面部油光；轻薄无润色款则更注重自然贴合，质地更水润，没有润色效果，适合所有肤质尤其是追求裸妆感的人群。两者都具备高倍防晒力和舒缓成分，主要区别在于肤感和妆效，您可以根据自己的肤质和需求选择。"},{"question":"这款防晒乳需要卸妆吗？","answer":"是的，这款防晒乳含有防晒剂成分，普通洁面产品可能无法完全清洁。建议使用温和的卸妆产品（如卸妆乳、卸妆水）先进行卸妆，再用洁面产品清洁面部，确保肌肤彻底干净，避免毛孔堵塞。"}],"user_reviews":[{"nickname":"林小夏","rating":1,"content":"用了一次就过敏了！本来以为理肤泉是敏感肌专用，结果涂完脸就发红发痒，还起了小疹子。质地倒是挺清爽的，但过敏反应太严重了，不敢再用。建议易敏肌的姐妹还是先做测试再买，别像我一样踩雷。"},{"nickname":"张小明","rating":1,"content":"控油效果完全不行！我是油皮，夏天用这款防晒乳，不到两小时T区就油光满面，还会蹭到口罩上。而且成膜速度也慢，涂完要等好久才能上妆，太耽误时间了。价格还不便宜，感觉不值这个钱。"},{"nickname":"王美丽","rating":5,"content":"真的太好用了！我是敏感肌，之前用很多防晒都会闷痘，这款完全不会。质地轻薄，上脸很快就吸收了，没有黏腻感，后续上妆也很服帖。防晒力也够，夏天在户外待一天也没晒黑。已经回购好几次了，无限推荐！"},{"nickname":"李萌萌","rating":4,"content":"整体还不错，质地清爽，不油腻，防晒效果也可以。但有个小缺点，就是涂完后会有一点点泛白，不过过一会儿就自然了。价格有点小贵，如果能再便宜点就更好了。"},{"nickname":"赵小宇","rating":1,"content":"包装设计有问题！挤压式的瓶口，每次挤都会漏出来，浪费了很多。而且味道有点奇怪，像酒精味，闻着不舒服。用了几次感觉防晒效果也一般，还不如我之前用的平价防晒。"},{"nickname":"陈静静","rating":5,"content":"敏感肌的福音！我皮肤特别容易泛红，这款防晒乳涂上去很温和，没有刺激感。质地清透，不厚重，夏天用也不会闷。防晒力也很强，上次去海边玩，涂了这个没被晒伤。会一直回购的！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_023.json'),
    ('p_beauty_024', '珀莱雅赋能鲜颜淡纹紧致精华液抗皱紧致提升弹润淡化细纹30ml', '珀莱雅', '美妆护肤', '精华', '美妆护肤/精华', 300.0, 300.0, 398.0, 200, '1_美妆护肤/images/p_beauty_024_live.jpg', '{"product_id":"p_beauty_024","title":"珀莱雅赋能鲜颜淡纹紧致精华液抗皱紧致提升弹润淡化细纹30ml","brand":"珀莱雅","category":"美妆护肤","sub_category":"精华","base_price":300.0,"image_path":"1_美妆护肤/images/p_beauty_024_live.jpg","skus":[{"sku_id":"s_p_beauty_024_1","properties":{"容量":"30ml 赋能鲜颜淡纹精华"},"price":300.0},{"sku_id":"s_p_beauty_024_2","properties":{"容量":"45ml 加大装"},"price":398.0}],"rag_knowledge":{"marketing_description":"珀莱雅这瓶赋能鲜颜淡纹紧致精华，主打的就是针对初老、熟龄肌的纹路改善！核心添加了高浓度六胜肽-1和双重胶原肽组合，搭配肌肽抗糖buff，能精准淡化抬头纹、法令纹、眼周干纹这些显老纹路，同时把松垮的脸撑得弹润紧致。特别适合25+开始冒小干纹、经常熬夜脸垮、化妆卡纹的姐妹。早晚洁面爽肤之后取2-3滴揉开上脸，顺着从下颌线往太阳穴的方向轻拉按摩到吸收，后续叠加乳液面霜完全不搓泥。敏感肌第一次用先在耳后试敏，避开眼周直接涂抹，孕期建议先咨询医生再用哦，日常通勤、熬夜救急、抗老维稳用它都超合适，现在还有30ml常规装和45ml大容量装可选，性价比拉满。","official_faq":[{"question":"珀莱雅赋能鲜颜淡纹精华的30ml和45ml版本成分完全一样吗？大容量装会不会是稀释款？","answer":"两款的核心配方是完全一致的，都是同生产线出来的同款精华，没有做任何成分稀释或者调整，同样添加了足量的六胜肽淡纹组分和抗糖肌肽成分，淡纹紧致的功效没有任何区别。只是45ml加大装是针对长期用这款、不想频繁囤货的老用户推出的大容量版本，算下来每毫升的单价比30ml常规装划算不少，经常空瓶的老粉直接入45ml的会更省心省钱，不用担心用半中间断货。"},{"question":"我是混油痘肌用这款赋能鲜颜精华会不会闷痘长闭口呀？质地是不是很黏腻？","answer":"这款精华做的是水感蛋清质地，上脸推开3秒就化水，完全没有厚重黏糊的存在感，混油痘肌夏天用也不会闷肤。配方里特意去掉了容易致痘的矿物油和高粘度增稠剂，还添加了少量的舒缓抗炎成分，普通的油痘肌只要不对里面的肽类成分过敏，正常用几乎不会闷闭口。担心的话可以先每次少取2滴，拍完爽肤水之后轻拍到全脸吸收，后续不用叠加太厚重的面霜，油皮夏天甚至单用它后续直接涂防晒都足够保湿，完全不会有闷脸的负担。"},{"question":"用这款精华多久能看到脸上的干纹细纹变淡？熬夜产生的垮脸能快速救回来吗？","answer":"一般坚持规律使用2周左右，就能明显感觉到脸上的假性干纹比如鼻翼、眼周那些卡粉的小干纹会被填得平整很多，熬夜之后的第二天早上脸不会松垮垮的垮成凹脸，摸起来还是弹润的。要是是已经形成的静态细纹比如浅的法令纹、抬头纹，坚持用满1个月到1个半月，大部分人都能看到纹路明显变浅，脸上的紧致感会上来不少，不会软塌塌的往下垂。注意每次用量别省，全脸加脖子带过效果会更好，不要断断续续想起来才涂，坚持用效果才稳。"}],"user_reviews":[{"nickname":"阿圆","rating":1,"content":"我本身是超级敏皮，之前用其他珀莱雅的产品都没事，这次入的30ml款上脸直接泛红刺痛，敷了舒缓面膜半天都消不下去，眼周长的小细疹子整整冒了三天。我按照要求先在耳后试了当时没反应，结果上全脸半小时就不对劲，查了成分可能是里面的胜肽浓度我不耐受，用了两次就闲置了，三百块钱直接打水漂，实在太不适合我这种皮薄的敏肌了，有点失望。"},{"nickname":"小夏","rating":4,"content":"整体用下来效果其实还可以，我用了三周左右，眼下的干纹确实淡了点，上妆也不怎么卡粉了。就是这个瓶口的设计有点反人类，每次倒精华都很容易一下倒多，手一抖就流到瓶身黏糊糊的，每次都要擦半天，剩个底的时候根本倒不出来多少，浪费好多。还有就是味道太淡了，几乎没什么香味，我个人还是喜欢带点淡淡的好闻的护肤品味道，这点不太合我心意，功效倒是没什么大问题。"},{"nickname":"阿泽","rating":4,"content":"我是买来给我妈用的，她说是涂完之后脸确实挺润的，摸起来弹弹的，法令纹淡了一点。但是这个45ml的加大装寄过来的时候外面的包装盒压得皱巴巴的，塑封都开了个小口子，我一开始还以为是别人退回来的二手货，问了客服才说快递运输压的，里面的精华瓶倒是没什么问题。还有就是用的时候如果涂太多，后续叠我妈用的那种厚重面霜，偶尔会搓泥，得控制用量才行，整体还行吧。"},{"nickname":"小棠","rating":2,"content":"我用了快一个月了，啥效果都没看出来，该有的干纹还是在，熬夜之后脸照样垮得不行，跟我之前用的几十块钱的普通保湿精华没什么区别。我还特意每次都按说明按摩好久，一点紧致淡纹的感觉都没有，三百块钱买的30ml，性价比实在太低了，还不如我之前用的别的平价款好用，感觉完全不值这个价，不会再回购了。"},{"nickname":"星子","rating":5,"content":"我这是第三次回购这个精华了！之前25岁之后经常熬夜，眼周的干纹重到上遮瑕都卡，用了这个大半个月，干纹直接平了大半，现在化妆再也不会卡粉卡成沟壑。我这次直接入了45ml的大瓶装，算下来比30ml划算好多，质地清清爽爽的，夏天用完全不黏，涂完第二天脸还是紧弹的，完全不会松垮垮，珀莱雅这款淡纹精华真的踩在我的需求点上，太好用了！"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_024.json'),
    ('p_beauty_025', '花西子螺黛生花眉笔细节点描顺滑显色防晕染持久双头眉笔0.08g', '花西子', '美妆护肤', '眉笔', '美妆护肤/眉笔', 89.0, 89.0, 89.0, 200, '1_美妆护肤/images/p_beauty_025_live.jpg', '{"product_id":"p_beauty_025","title":"花西子螺黛生花眉笔细节点描顺滑显色防晕染持久双头眉笔0.08g","brand":"花西子","category":"美妆护肤","sub_category":"眉笔","base_price":89.0,"image_path":"1_美妆护肤/images/p_beauty_025_live.jpg","skus":[{"sku_id":"s_p_beauty_025_1","properties":{"色号":"0.08g 经典色号"},"price":89.0},{"sku_id":"s_p_beauty_025_2","properties":{"色号":"0.08g 自然棕"},"price":89.0}],"rag_knowledge":{"marketing_description":"花西子这款螺黛生花双头眉笔专门针对东方人眉形设计，0.08g的极细笔芯能精准点描每根毛流，就像用毛笔勾线一样丝滑不卡壳，显色度刚好不会重手变蜡笔小新，添加的持色覆膜成分日常通勤出汗、喝冰饮沾到水汽都不容易晕成大黑块。特别适合手残新手、追求野生眉妆感的女生，不管是日常上班快速描眉，还是约会拍特写妆造都能用。一头是细笔芯一头是螺旋眉刷，画之前先梳顺眉毛再填补空缺，画完扫掉浮色就很自然，注意用的时候手别太用力压笔芯，不然容易断，存放在阴凉干燥的地方别晒到太阳就能用很久。","official_faq":[{"question":"这款0.08g的极细笔芯会不会很容易断？平时怎么保养能延长使用寿命？","answer":"这款眉笔的笔芯做了分层加固的特殊工艺，正常轻力度描画是不容易断的，它本身设计成0.08g的极细规格就是为了能画出根根分明的毛流感，所以不建议大力按压笔芯作画，每次旋出来1-2毫米的长度就足够用，不用旋出太长。平时使用完记得把笔帽盖紧，避免笔芯长期暴露在空气中变干变脆，也不要放在车里被阳光直晒，避开高温环境存放，正常使用的话一支足够用3-4个月，完全不用担心没用完就断芯的问题。"},{"question":"经典色号和自然棕两个色号分别适合什么样的发色和肤色呀？选不对会不会很突兀？","answer":"经典色号是偏灰调的深棕，适配大部分自然黑发、深棕发色的女生，黄二白、黄三白的肤色用它画出来的眉毛和原生毛发衔接特别自然，不会像纯黑色眉笔那样生硬显凶。自然棕是带一点暖调的浅棕，更适合染了浅棕、栗色、奶茶色发色的女生，冷白皮用它能衬得整体妆感更柔和，哪怕是漂过浅发的妹子用这个色号也不会违和。大家选的时候尽量贴合自己发根的原生发色，比发色浅一度就刚好，基本不会踩雷，要是拿不准选最百搭的经典色号也不容易出错。"},{"question":"这款眉笔主打的防晕染效果，夏天出油出汗或者下雨天淋到小雨也能扛住吗？","answer":"这款眉笔的显色配方里添加了弱成膜的持色因子，画完之后等30秒左右它会在眉部形成一层薄的透气覆膜，日常日常通勤额头轻微出油、夏天逛半小时街出汗，甚至不小心沾到少量喷溅的饮用水，都不容易花掉晕成色块。但如果是长时间泡在水里、大量泡水揉搓眉部，或者长时间待在桑拿房高温高湿的环境里，还是会有轻微脱妆的情况，大家如果是要去海边玩水、做高强度运动的话，后续搭配一层透明眉粉定妆，持妆时间能拉长到8小时以上。"},{"question":"手残党用这款眉笔真的能画出野生眉吗？有没有什么简单的上手技巧？","answer":"这款眉笔的极细笔芯本身就是为手残党设计的，不用你有什么专业画眉功底，上手前先用附赠的螺旋眉刷把眉毛顺着毛流方向全部梳顺，找到自己眉毛本身有空缺的地方，顺着毛发生长的方向一根一根去描，不用整片涂满，填补好空隙之后，再用眉刷扫一遍把边缘晕开，出来就是根根分明的野生眉效果。哪怕你第一次画得颜色重了点，用眉刷多扫两遍就能把浮色扫掉，容错率特别高，多试两次两三分钟就能搞定一个自然的眉妆，完全不用怕画出来生硬奇怪。"}],"user_reviews":[{"nickname":"阿柚","rating":5,"content":"真的是我用过最适合新手的眉笔了！0.08g的细头太绝了，我之前用别的眉笔一用力就画成粗粗的一条，这个我顺着自己的眉毛空缺点描，画出来真的像自己长出来的眉毛一样，持妆一下午下班摸眉毛都没掉，连我这种手残第一次画都没翻车，双头的眉刷用完梳两下边缘就特别自然，已经回购第二支了。"},{"nickname":"小棠","rating":4,"content":"整体用着还是挺顺滑的，画出来的野生眉感很足，色号选的自然棕和我染的奶茶发色特别搭，唯一有点小遗憾的就是我每次旋出来一点点，有时候不小心掉地上笔芯就断了一小截，用的时候得特别小心拿着，不然总怕断芯，要是笔芯能再做的耐摔一点就更完美了，整体来说这个价格性价比还算可以。"},{"nickname":"阿凯","rating":1,"content":"我平时就是油皮，额头特别容易出油，本来冲着防晕染的卖点买的，结果早上画完不到两小时，眉尾直接晕得糊成一块，下班回家眉毛直接只剩半截了，脸上油光一蹭全蹭掉，根本不防油，花八十九买的就这持妆效果，感觉还不如十几块的眉笔好用，真的太失望了。"},{"nickname":"小夏","rating":1,"content":"刚拆封用了两次，第三次用的时候旋出来笔芯直接断了大半截，我根本没用力按啊，就正常旋出来准备画，直接断在里面剩下的笔芯根本取不出来，总共加起来都没用三次就剩个空壳，八十九块钱用了不到一周就废了，这个质量也太差了，完全不值这个价。"},{"nickname":"阿月","rating":3,"content":"我选的经典色号，颜色倒是挺自然的，但是我本身眉毛就比较浓密，用这个细头画半天都填不满，要反复画好几次才能把空缺补上，画个眉毛得花快十分钟，太费时间了，我平时赶早八根本来不及，现在基本闲置在家，只有周末有空的时候才拿出来慢慢画，感觉不太适合浓眉毛的人用。"},{"nickname":"小远","rating":3,"content":"双头设计倒是挺方便的，但是眉刷用了没两周就开始掉毛，每次梳眉毛都有小细毛粘在眉毛上，得半天才能弄掉，而且画完之后我用普通的卸妆水卸，得反复擦三四遍才能完全卸干净，特别容易留眉部的黄印子，用着感觉有点鸡肋，不算特别难用但也没宣传的那么好用。"}]}}'::jsonb, '1_美妆护肤/data/p_beauty_025.json'),
    ('p_digital_001', 'Apple iPhone 17 Pro 6.3英寸 A19 Pro 256GB 全网通旗舰手机', 'Apple 苹果', '数码电子', '智能手机', '数码电子/智能手机', 8999.0, 8999.0, 12499.0, 900, '2_数码电子/images/p_digital_001_live.jpg', '{"product_id":"p_digital_001","title":"Apple iPhone 17 Pro 6.3英寸 A19 Pro 256GB 全网通旗舰手机","brand":"Apple 苹果","category":"数码电子","sub_category":"智能手机","base_price":8999.0,"image_path":"2_数码电子/images/p_digital_001_live.jpg","skus":[{"sku_id":"s_p_digital_001_1","properties":{"存储":"256GB","颜色":"宇宙橙 Cosmic Orange","版本":"全网通版"},"price":8999.0},{"sku_id":"s_p_digital_001_2","properties":{"存储":"256GB","颜色":"远峰蓝","版本":"全网通版"},"price":8999.0},{"sku_id":"s_p_digital_001_3","properties":{"存储":"256GB","颜色":"深空黑","版本":"全网通版"},"price":8999.0},{"sku_id":"s_p_digital_001_4","properties":{"存储":"512GB","颜色":"宇宙橙 Cosmic Orange","版本":"全网通版"},"price":10499.0},{"sku_id":"s_p_digital_001_5","properties":{"存储":"512GB","颜色":"远峰蓝","版本":"全网通版"},"price":10499.0},{"sku_id":"s_p_digital_001_6","properties":{"存储":"512GB","颜色":"深空黑","版本":"全网通版"},"price":10499.0},{"sku_id":"s_p_digital_001_7","properties":{"存储":"1TB","颜色":"宇宙橙 Cosmic Orange","版本":"全网通版"},"price":12499.0},{"sku_id":"s_p_digital_001_8","properties":{"存储":"1TB","颜色":"远峰蓝","版本":"全网通版"},"price":12499.0},{"sku_id":"s_p_digital_001_9","properties":{"存储":"1TB","颜色":"深空黑","版本":"全网通版"},"price":12499.0}],"rag_knowledge":{"marketing_description":"Apple iPhone 17 Pro搭载全新A19 Pro芯片，带来颠覆性性能提升，无论是大型3A游戏还是专业视频剪辑都能流畅运行。6.3英寸超视网膜XDR显示屏，支持ProMotion自适应刷新率，户外强光下依然清晰。256GB起步的存储容量，满足摄影爱好者和商务人士的存储需求。宇宙橙、远峰蓝、深空黑三色可选，其中宇宙橙采用独特的哑光玻璃工艺，握感舒适且不易留指纹。适合追求极致体验的科技爱好者、内容创作者以及需要高效办公的商务人群。日常使用建议开启低电量模式延长续航，拍摄专业视频时可搭配MagSafe配件提升稳定性。注意：不同存储版本价格差异较大，选购时需根据自身需求选择。","official_faq":[{"question":"iPhone 17 Pro的A19 Pro芯片相比上一代有哪些提升？","answer":"A19 Pro芯片采用3纳米工艺制程，CPU性能提升20%，GPU性能提升30%，AI算力提升40%。在实际使用中，打开大型应用的速度更快，游戏帧率更稳定，视频渲染时间大幅缩短。同时，芯片的能效比更高，配合iOS 19的优化，续航能力比iPhone 16 Pro提升约1.5小时。无论是日常使用还是专业创作，都能提供更流畅的体验。"},{"question":"宇宙橙版本的外观工艺有什么特别之处？","answer":"宇宙橙版本采用创新的哑光玻璃背板，通过特殊的蚀刻工艺形成细腻的纹理，不仅视觉上呈现出独特的渐变效果，而且触感舒适，不易沾染指纹和油污。边框部分采用航空级铝合金材质，经过阳极氧化处理，与背板颜色完美融合，整体质感高级。这种工艺在保持美观的同时，也提升了手机的抗刮擦能力，日常使用更耐用。"},{"question":"256GB版本是否足够日常使用？","answer":"256GB版本适合大多数用户的日常需求，可存储约6万张高清照片、150小时4K视频或500款常用应用。如果您是普通用户，不经常拍摄4K视频或存储大量大型游戏，256GB完全足够。但如果您是专业摄影师或视频创作者，需要存储大量原始素材，建议选择512GB或1TB版本，避免因存储不足影响创作。"},{"question":"iPhone 17 Pro的摄像头系统有哪些升级？","answer":"iPhone 17 Pro配备了4800万像素主摄、1200万像素超广角和1200万像素长焦镜头，支持5倍光学变焦和25倍数字变焦。主摄采用更大的传感器，进光量提升30%，夜景拍摄更清晰。新增的ProRes视频录制功能，支持4K 60fps，适合专业视频制作。同时，摄像头系统还支持杜比视界HDR拍摄，色彩还原更准确，细节更丰富。"},{"question":"iPhone 17 Pro的续航能力如何？","answer":"iPhone 17 Pro内置4500mAh电池，支持27W有线快充和15W MagSafe无线充电。在日常使用中，轻度用户可使用1.5天，重度用户可使用1天。开启低电量模式后，续航时间可延长约20%。同时，iOS 19系统的智能优化功能，能根据用户使用习惯调整功耗，进一步提升续航表现。如果您经常外出，建议搭配MagSafe充电宝使用，方便随时充电。"},{"question":"不同存储版本的价格差异主要体现在哪里？","answer":"iPhone 17 Pro的存储版本价格差异主要在于存储容量和成本。256GB版本售价8999元，512GB版本售价10499元，1TB版本售价12499元。存储容量越大，成本越高，因此价格差异明显。此外，1TB版本还支持更高级的存储技术，读写速度更快，适合需要大量存储的专业用户。选购时，建议根据自身存储需求和预算选择合适的版本，避免不必要的浪费。"}],"user_reviews":[{"nickname":"林小雨","rating":4,"content":"手机整体性能不错，A19 Pro芯片确实很强大，玩游戏几乎没有卡顿。宇宙橙的颜色也很特别，拿在手里很有质感。不过续航方面有点失望，重度使用一天下来需要充电两次，而且充电速度也没有宣传的那么快。另外，价格确实有点贵，如果能再优惠一点就好了。总的来说，还是值得入手的，但希望后续能优化续航和充电速度。"},{"nickname":"张小明","rating":5,"content":"iPhone 17 Pro真的太香了！A19 Pro芯片让我的工作效率提升了不少，剪辑视频比之前快了一倍。摄像头系统也很给力，拍出来的照片色彩鲜艳，细节丰富，尤其是夜景模式，简直绝了。宇宙橙的外观很时尚，朋友见了都问我在哪里买的。续航方面也比上一代好很多，轻度使用两天都没问题。总之，这是我用过的最好的iPhone，强烈推荐！"},{"nickname":"王大锤","rating":1,"content":"太失望了！刚买的iPhone 17 Pro用了不到一周就出现了问题，屏幕偶尔会闪烁，而且指纹识别经常失灵。联系客服后，他们让我寄回检测，但检测结果说没问题，让我重启试试。重启后问题依然存在，客服态度也不好，一直推脱责任。花了这么多钱买的手机，竟然出现这种质量问题，真的很生气。以后再也不会买苹果手机了！"}]}}'::jsonb, '2_数码电子/data/p_digital_001.json'),
    ('p_digital_002', '华为HUAWEI Pura 90 Pro 超感光影像曲面屏轻薄旗舰手机12+256GB', '华为', '数码电子', '智能手机', '数码电子/智能手机', 6999.0, 6999.0, 7699.0, 800, '2_数码电子/images/p_digital_002_live.jpg', '{"product_id":"p_digital_002","title":"华为HUAWEI Pura 90 Pro 超感光影像曲面屏轻薄旗舰手机12+256GB","brand":"华为","category":"数码电子","sub_category":"智能手机","base_price":6999.0,"image_path":"2_数码电子/images/p_digital_002_live.jpg","skus":[{"sku_id":"s_p_digital_002_1","properties":{"存储":"12GB+256GB","颜色":"星芒黑","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_002_2","properties":{"存储":"12GB+256GB","颜色":"雪域白","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_002_3","properties":{"存储":"12GB+256GB","颜色":"幻影紫","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_002_4","properties":{"存储":"12GB+256GB","颜色":"青釉绿","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_002_5","properties":{"存储":"12GB+512GB","颜色":"星芒黑","版本":"高配版"},"price":7699.0},{"sku_id":"s_p_digital_002_6","properties":{"存储":"12GB+512GB","颜色":"雪域白","版本":"高配版"},"price":7699.0},{"sku_id":"s_p_digital_002_7","properties":{"存储":"12GB+512GB","颜色":"幻影紫","版本":"高配版"},"price":7699.0},{"sku_id":"s_p_digital_002_8","properties":{"存储":"12GB+512GB","颜色":"青釉绿","版本":"高配版"},"price":7699.0}],"rag_knowledge":{"marketing_description":"华为Pura 90 Pro是主打超感光影像的曲面屏轻薄旗舰，整机仅重193g搭配8.2mm超薄中框，持握久了也不会累手。核心的超感光主摄搭载专属徕卡调校RYYB传感器，暗光环境下拍夜景人像不用开补光灯也能保留细腻肤感，配合大曲率的1.5K臻彩曲面屏，刷剧修图色彩准到和专业显示器差不离。适合摄影爱好者、重度手机办公族、日常爱拍娃拍风景的普通用户，出门逛夜市、爬山拍日出、通勤移动办公都够用。建议平时贴配套的全胶曲面钢化膜避免刮花屏幕，注意不要把手机和尖锐金属钥匙同放口袋，长期不用的时候别把电量耗到低于20%再充电，能更好保护电池健康度。","official_faq":[{"question":"华为Pura 90 Pro的超感光影像在夜拍的时候需要手动调整参数吗？","answer":"日常夜拍不需要手动调整参数，系统自带的超感光夜景算法会自动识别暗光场景，从进光量优化到噪点压制全流程自动处理，就算是路边摊拍烟火气食物、楼道里拍宠物，抬手按快门等2秒就能出干净透亮的成片。如果是有专业拍摄需求的用户，也可以切换到专业模式自定义ISO、快门速度等参数，发挥超感光传感器的最大实力，新手不用复杂学习也能拍出媲美专业相机的夜景作品。"},{"question":"这款曲面屏平时摔了会不会很容易碎，有没有配套的防误触功能？","answer":"这块曲面屏采用华为自研的昆仑玻璃2代材质，日常1米高度的桌面跌落大部分场景下都能避免碎屏，正常使用的抗刮表现也比普通曲面屏高不少。系统自带专属的曲面侧屏防误触功能，日常横屏打游戏、单手握持刷信息流的时候，会自动识别非主动操作的侧边触达，不会出现乱点跳屏的情况，要是你习惯戴很厚的全包边手机壳，也可以在设置里手动调整防误触的灵敏度，适配不同的使用习惯。"},{"question":"12GB运行内存的版本后台最多能同时挂多少个APP不会被强制杀后台？","answer":"这款搭载的华为自研内存智能调度算法，12GB运存版本正常使用的情况下，同时后台挂着微信、钉钉、3个常用办公APP再加2个视频类应用，来回切换完全不会重新加载。就算你临时开游戏玩了半小时退出去，之前后台存的修图文档、未编辑完的备忘录也不会被清空，就算长期用个两三年，随着系统后续OTA优化，后台留存能力也不会出现明显的大幅下滑，日常多任务重度使用完全够用。"},{"question":"12+256GB和12+512GB两个版本除了存储空间之外，硬件配置有没有差别？","answer":"两个版本除了机身存储容量不同之外，其余所有硬件配置都是完全一致的，用的同款超感光影像传感器、同款曲面屏和同款旗舰级处理器，性能表现、拍照成像效果、续航充电速度没有任何区别。如果平时只是装常用APP、存几千张照片偶尔下点剧，256GB版本完全够用；要是你习惯大量存4K视频、下载数十个大型手游，或者喜欢长期存很多高清原图不清理，直接选512GB高配版用起来会更从容，两三年内不用纠结存储空间不足的问题。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"刚收到手拆封的时候没注意，边框缝隙里居然有个明显的掉漆小点，找客服说不属于质量问题不给退换，折腾了三天最后只能自己花钱去售后点补漆。本来冲着华为的品控来的，结果新机拆封就有瑕疵，体验感真的太差了，花七千多买的机子连出厂检查都没做好，以后真的不敢随便首发买新品了。"},{"nickname":"小夏","rating":1,"content":"用了半个月发现续航特别拉垮，正常中度使用，就刷微信拍几张照片，半天就得充一次电，出门不带充电宝根本不敢走远。之前用旧的华为旗舰轻度用一天都没问题，这款说是4800mAh大电池实际续航连老款都比不上，影像的夜景成片有时候还会偏色，太对不起七千的定价了，后悔当初没选同价位其他品牌的机型。"},{"nickname":"阿宇","rating":2,"content":"单手握持的时候曲面屏边缘误触有点严重，我手比较大，躺着刷短视频经常不小心点到侧边的返回键，退出去好几次正在看的直播，调了最高级的防误触模式也没什么改善。手机本身重量控制得确实不错，但是搭配我之前买的全包壳之后，侧边的触控灵敏度变得很奇怪，有时候点屏幕边缘按好几下才反应，用着挺闹心的。"},{"nickname":"小楠","rating":3,"content":"拍照日常光线里表现还行，但是夜拍的时候对焦速度特别慢，晚上出去拍路边的小猫，按快门之后对焦对了三四秒才对上，好几次想拍的动态瞬间直接错过。之前用的旧手机夜拍对焦一秒就能搞定，这款七千多的旗舰居然在对焦上拖后腿，用着说不上特别差但总觉得达不到预期，很多想记录的场景都没抓住，有点失望。"},{"nickname":"阿泽","rating":5,"content":"用了快一个月体验真的超出预期，193g的重量揣兜里完全没负担，曲面屏的手感摸起来太顺滑了。上周去海边拍日落，用超感光模式随手拍出来的晚霞色彩层次特别丰富，连浪花边缘的细水雾都拍得清清楚楚，朋友圈发出去好多人问我是不是带相机出门了。平时打游戏开最高画质也不卡，续航中度用一整天完全够，七千多花得太值了。"},{"nickname":"小哲","rating":1,"content":"官网宣传的轻薄机身是真的，但是裸机用太滑了我没拿住，从饭桌高度掉下去，屏幕直接碎了，昆仑玻璃宣传的防跌效果根本没看出来。售后换个屏要两千多，买的时候说支持碎屏险优惠结果激活之后才发现要额外花近三百购买，之前完全没提前说清楚，这个价格换屏真的太贵了，用着压力好大。"}]}}'::jsonb, '2_数码电子/data/p_digital_002.json'),
    ('p_digital_003', 'Apple iPhone 17 Pro Max 6.9英寸 A19 Pro 256GB 大屏旗舰手机', 'Apple 苹果', '数码电子', '智能手机', '数码电子/智能手机', 9999.0, 9999.0, 13499.0, 900, '2_数码电子/images/p_digital_003_live.jpg', '{"product_id":"p_digital_003","title":"Apple iPhone 17 Pro Max 6.9英寸 A19 Pro 256GB 大屏旗舰手机","brand":"Apple 苹果","category":"数码电子","sub_category":"智能手机","base_price":9999.0,"image_path":"2_数码电子/images/p_digital_003_live.jpg","skus":[{"sku_id":"s_p_digital_003_1","properties":{"存储":"256GB","颜色":"宇宙橙 Cosmic Orange","版本":"全网通版"},"price":9999.0},{"sku_id":"s_p_digital_003_2","properties":{"存储":"256GB","颜色":"冰川蓝","版本":"全网通版"},"price":9999.0},{"sku_id":"s_p_digital_003_3","properties":{"存储":"256GB","颜色":"钛金色","版本":"全网通版"},"price":9999.0},{"sku_id":"s_p_digital_003_4","properties":{"存储":"512GB","颜色":"宇宙橙 Cosmic Orange","版本":"全网通版"},"price":11499.0},{"sku_id":"s_p_digital_003_5","properties":{"存储":"512GB","颜色":"冰川蓝","版本":"全网通版"},"price":11499.0},{"sku_id":"s_p_digital_003_6","properties":{"存储":"512GB","颜色":"钛金色","版本":"全网通版"},"price":11499.0},{"sku_id":"s_p_digital_003_7","properties":{"存储":"1TB","颜色":"宇宙橙 Cosmic Orange","版本":"全网通版"},"price":13499.0},{"sku_id":"s_p_digital_003_8","properties":{"存储":"1TB","颜色":"冰川蓝","版本":"全网通版"},"price":13499.0},{"sku_id":"s_p_digital_003_9","properties":{"存储":"1TB","颜色":"钛金色","版本":"全网通版"},"price":13499.0}],"rag_knowledge":{"marketing_description":"iPhone 17 Pro Max这次直接把大屏体验拉到新高度，6.9英寸超视网膜XDR显示屏不管是刷4K纪录片还是连剪几小时vlog都够爽，A19 Pro仿生芯片的算力直接把移动端3A游戏和专业修图的速度拉满，连导出4K 60帧视频都几乎秒完成。机身用的是全新航空级钛合金边框，这次新增的宇宙橙、冰川蓝配色质感特别绝，256GB起步的存储完全能装下上万张Raw格式照片和几十部高清剧。特别适合内容创作者、重度手游玩家和平时爱用手机替代随身电脑的商务人群，不管是通勤刷剧、外出跑活动剪素材还是周末户外拍星轨都能hold住。提醒大家到手别直接撕掉边框的防护膜，第一次充电用原装27W头激活电池效率，贴钢化膜要避开屏下 Face ID 区域避免影响解锁速度。","official_faq":[{"question":"iPhone 17 Pro Max的6.9英寸大屏相比上代16 Pro Max的屏幕实际观感提升在哪里？","answer":"这块屏幕把上代的峰值亮度又拉高到了3200尼特，大太阳底下逛菜市场拍价签、户外取景找对焦完全不用拿手挡光，新增的144Hz ProMotion自适应刷新率还会跟着你浏览的内容自动调帧率，刷信息流的时候滑得特别丝滑，看静态文档的时候又自动降到1Hz省电。而且专门调整了屏幕边缘的色准，不再出现之前大屏边角发暗的问题，剪4K HDR视频的时候两边色彩完全一致，内容创作者校色的时候省了很多反复调整的功夫。"},{"question":"A19 Pro芯片对比上代A18 Pro在重度使用场景下的实际性能表现有什么升级？","answer":"A19 Pro这次的GPU升级到了7核架构，算力直接提升了40%，你玩最高画质的《原神》开8K分辨率拉满所有特效，连续跑3小时帧率都稳在59帧以上不会降频卡顿。专业模式下用Procreate画几十层的大型插画，或者用手机自带的剪辑软件导出1小时的4K 120帧视频，速度比上代快了接近一倍，后台同时挂着微信、导航、修图APP也完全不会杀后台，通勤路上临时改方案的效率特别高。"},{"question":"这次新出的宇宙橙、冰川蓝配色的机身材质耐脏抗划痕表现怎么样？","answer":"三款新配色的后盖都用了全新的纳米级蓝宝石晶面玻璃工艺，宇宙橙的磨砂质感完全不沾指纹，平时手汗多捏着玩半小时，后盖也不会留下油印子，日常放口袋里和钥匙串混在一起，正常使用几乎不会留下细小划痕。钛合金边框也做了阳极氧化的封釉处理，不像之前的钛金属款用俩星期就出现明显的细小掉漆，正常裸奔使用两三个月，边框的磨损痕迹几乎看不出来，手残党不爱带壳也不用太担心外观花掉。"},{"question":"不同存储版本的iPhone 17 Pro Max日常使用的实际剩余可用空间大概是多少？","answer":"256GB宇宙橙版本开机之后可用空间大概在238GB左右，足够装下4万张Raw格式照片加20多部高清剧集，适合日常普通使用的用户。512GB冰川蓝版可用空间大概在492GB，能存下上百部4K视频加几十款大型手游，适合经常外出拍素材的博主。1TB钛金色版本可用空间在970GB左右，连外接移动硬盘的需求都省了，专门给需要随时备份大量 raw 素材的专业内容创作者准备的。"},{"question":"这款6.9英寸的大屏iPhone 17 Pro Max单手握持的时候会不会容易手滑掉机？","answer":"苹果这次专门调整了机身的弧度，钛合金边框做了0.3毫米的微磨砂倒角处理，比上代的直角边框要贴合手掌很多，6.9英寸的机身重量反而比上代轻了12克，女生单手握持刷半小时微博也不会觉得手腕酸。不过因为机身面积大，还是建议手掌特别小的用户选配套的半透磨砂保护壳，平时过马路单手刷手机的时候可以握住边框中上部，避免从手心滑出去摔碎后盖。"},{"question":"全网通版本的iPhone 17 Pro Max在国内三大运营商的5G网络下实际信号表现怎么样？","answer":"这次升级了全新的多天线整合系统，在地下车库、偏远的郊区景区这些之前苹果信号经常掉的地方，也能稳定连上5G网络，跑测速能跑到800Mbps以上的下行速度。之前在地铁上经常刷不出的短视频，现在高峰期也能正常加载不转圈，双卡双通的支持也终于安排上了，你接电话的时候另一张卡的工作号来了新消息，也不会像之前那样直接断网漏收重要邮件，跑业务的商务人士用着特别省心。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"终于等到换的新手机！256GB的宇宙橙实物比官宣图好看太多，磨砂后盖摸着巨舒服，我这种手汗星人用一天都没沾过指纹。A19 Pro芯片真的猛，我开最高画质玩原神连续一下午都没卡过，6.9英寸大屏看剧简直是享受，连字幕边缘的细节都特别清楚，待机用了两天还剩30%多的电，这次换手机真的换得太值了，比我之前的14 Pro好用不止一个档次。"},{"nickname":"小琳","rating":3,"content":"用了一周感觉有点失望，当初冲着6.9英寸大屏买的，结果我手掌偏小，单手握持打字的时候经常够不到屏幕左上角的按键，好几次打错字特别麻烦。而且宣传的续航，我正常刷社交软件加拍点照片，也就一天一充勉强刚够，没官方说的两天那么夸张。冰川蓝的边框缝隙里用了三天就卡了点灰，清了半天才弄出来，整体不算特别差，但也没达到我的预期。"},{"nickname":"阿哲","rating":2,"content":"我买的512GB冰川蓝版本，用了不到半个月，玩大型游戏的时候后盖下半部分的发热特别明显，夏天不带壳玩十分钟就烫得手心发闷，连之前用的旧iPhone 15 Pro都没这么烫。而且这个尺寸放我平时用的牛仔裤口袋，坐下的时候经常卡着腿，好几次都差点滑出来。找客服问发热的问题，就说这是正常性能释放，体验真的挺一般的。"},{"nickname":"阿敏","rating":1,"content":"太糟心了，收到货拆开用了第二天就发现 Face ID 偶尔会识别失败，对着脸晃半天都解不开锁，送售后检测说硬件出了小问题，返厂等了快一周才换了新机。结果新机器的屏幕左下角仔细看有个很小的坏点斑点，虽然不影响正常用但花一万多买的新手机有瑕疵实在膈应人，之前用了好多年iPhone从来没碰到这种品控问题，这次体验真的太差了。"},{"nickname":"阿柚","rating":5,"content":"作为常年拍vlog的博主，1TB钛金色版本我用着简直太顺手了！拍一天的4K素材直接存在手机里，用自带剪辑软件剪半小时的成片导出速度快到飞起，连外接硬盘的钱都省了。6.9英寸的高色准屏幕直接能当监视器用，户外大太阳底下调参数完全看得清，钛合金边框轻很多，举着拍一两个小时的手持镜头手腕都不酸，完全是我理想中的工作机了。"}]}}'::jsonb, '2_数码电子/data/p_digital_003.json'),
    ('p_digital_004', '华为HUAWEI MateBook 14 鸿蒙版 14英寸轻薄高性能生产力笔记本', '华为', '数码电子', '笔记本电脑', '数码电子/笔记本电脑', 6299.0, 6299.0, 7199.0, 400, '2_数码电子/images/p_digital_004_live.jpg', '{"product_id":"p_digital_004","title":"华为HUAWEI MateBook 14 鸿蒙版 14英寸轻薄高性能生产力笔记本","brand":"华为","category":"数码电子","sub_category":"笔记本电脑","base_price":6299.0,"image_path":"2_数码电子/images/p_digital_004_live.jpg","skus":[{"sku_id":"s_p_digital_004_1","properties":{"存储":"16GB+512GB","版本":"锐龙版"},"price":6299.0},{"sku_id":"s_p_digital_004_2","properties":{"存储":"16GB+1TB","版本":"锐龙版"},"price":6999.0},{"sku_id":"s_p_digital_004_3","properties":{"存储":"16GB+512GB","版本":"鸿蒙版"},"price":6499.0},{"sku_id":"s_p_digital_004_4","properties":{"存储":"16GB+1TB","版本":"鸿蒙版"},"price":7199.0}],"rag_knowledge":{"marketing_description":"这款华为MateBook 14鸿蒙版是专为高效生产力打造的14英寸轻薄本，搭载鸿蒙分布式能力，能和华为手机、平板、智慧屏无缝跨端协同，碰一下就能直接互传大文件、接力编辑未完成的文档，还支持多屏同开拖拽素材。整机重量仅1.49kg，三面窄边的2K触控屏占比高达90%，锐龙处理器性能够撑住连续跑8小时PS修图、多文档开十几个网页的办公需求，65W便携快充出门充15分钟就能用3小时。特别适合经常跑外勤的职场人、需要赶课程作业的大学生，日常通勤塞包里完全不压肩。使用时注意别用尖锐硬物刮碰触控屏，跨端协同需要设备登录同一个华为账号才能触发全功能，长期高负载使用建议垫高底部保证散热。基础款16GB+512GB日常用足够，经常存大量工程文件的用户直接选1TB高配版更省心。","official_faq":[{"question":"这款鸿蒙版MateBook 14和普通Windows版的跨屏协同功能有什么不一样？","answer":"这款鸿蒙版搭载的是华为专属的分布式鸿蒙能力，和普通Windows适配的多屏协同完全不同，不需要额外装APP，只要同账号的华为设备靠近就能自动弹窗连接，甚至能直接调用手机的原生APP在电脑侧窗口运行，最多同时开3个手机APP窗口拖拽素材，还支持鸿蒙大文件夹跨端同步、原子笔记实时跨设备更新，连蓝牙耳机都能在多设备之间无感切换不用手动重连，整个协同过程延迟比普通版本低40%左右，传几个G的设计文件最快几十秒就能完成。"},{"question":"16GB内存的版本同时开十几个办公软件加浏览器网页会不会卡顿？","answer":"这款锐龙版的16GB是双通道大内存，搭配鸿蒙系统的内存调度优化，正常同时开20个以内Chrome网页、3个Word文档、2个PS工程文件再加微信钉钉后台，完全不会出现卡顿掉帧的情况，哪怕是长时间开着视频会议后台挂着素材下载，切换软件的响应速度也能保持在1秒以内。如果是做轻度视频剪辑，剪1080P的半小时vlog工程也能流畅预览，只有同时运行超过3个大型专业建模软件的时候，才会偶尔出现轻微的加载延迟。"},{"question":"它的触控屏支持华为手写笔的哪些功能？可以直接手写批注文档吗？","answer":"这款2K触控屏支持华为M-Pencil第二代手写笔连接，配对成功后可以直接在屏幕上精准手写批注Word、PDF文档，甚至在PS里压感绘图、快速标记修图位置，鸿蒙自带的便签、思维导图APP还支持笔锋压感调整，写出来的字迹和在纸质笔记本上几乎没有区别。哪怕你没有买手写笔，直接用手指双击文档里的文字区域，也能快速唤出手写批注模式，临时改方案的时候不用特意找鼠标点选，适配绝大多数常用办公软件的批注场景。"},{"question":"这款笔记本的续航实际用下来能支撑多久移动办公？","answer":"日常如果是亮度调到50%，连着WiFi写文档、刷网页的轻办公场景，满电状态下能连续用9到10小时，差不多从早上出门上班不用带充电器，撑到晚上下班回家还能剩20%左右的电量。如果是播放本地1080P视频，连续播放也能有8小时以上的续航，哪怕是开视频会议这种高负载场景，也能撑6小时左右。搭配随机附赠的65W便携快充，喝杯咖啡的功夫充15分钟，就能续上3小时的办公电量，应急出门完全不用慌没电。"},{"question":"锐龙版和1TB高配版除了存储空间之外还有其他配置区别吗？","answer":"这两个版本除了存储之外核心配置没有其他差异，同样搭载14英寸2K全面触控屏、同款锐龙标压处理器，接口、跨端协同功能、电池容量全部保持一致。1TB高配版把原来的512GB固态硬盘升级成了1TB容量，不用用户后续自己拆机扩容，直接就能存下更多的视频素材、大型工程文件和本地资料，适合平时需要存大量设计源文件、剪辑素材的内容创作者，不用频繁外接移动硬盘找文件，日常通勤少带配件更省心。"}],"user_reviews":[{"nickname":"阿泽","rating":5,"content":"用了快半个月真的太香了！我平时做新媒体运营，手机拍的素材往电脑边上一碰就直接传过来了，连数据线都不用插，修图剪视频的时候还能直接开手机的小红书APP窗口找参考，不用来回切换设备。屏幕的显示效果特别细腻，触控点一下就响应，有时候改方案来不及找鼠标直接点屏幕就操作了，重量也轻我天天塞通勤包里挤地铁完全没负担，续航从早用到晚还剩电，太适合我们这种经常在外跑的人了。"},{"nickname":"小夏","rating":2,"content":"用了一周发现有个问题挺闹心的，我平时习惯外接显示器做表格，用普通的Type-C转HDMI线连的时候，时不时就会出现断连闪屏的情况，换了三根不同牌子的线还是偶尔会出问题，去售后检测也说硬件没问题，说是适配的第三方线材兼容性不如原装华为的配件。而且本身没有自带网线接口，我租的房子WiFi信号不好，得额外买拓展坞插网线，多花了好几百块钱，这点觉得不太方便。"},{"nickname":"阿凯","rating":2,"content":"本来冲着鸿蒙跨屏协同买的，结果我家里的旧华为平板是好几年前的版本，系统版本太低连不上，折腾了好几天升级系统之后还是有延迟，传大一点的工程文件偶尔会卡进度条。而且机器本身的风扇调得太灵敏了，我只是开个PS修个几MB的图片，没一会儿风扇就开始转得嗡嗡响，图书馆里用的时候特别尴尬，怕吵到旁边学习的同学，这点体验确实不太好。"},{"nickname":"小棠","rating":5,"content":"作为程序员买这个本真的选对了！平时开十几个网页查文档，同时挂着微信钉钉，开两个编辑器跑代码一点都不卡，跨屏协同还能直接把手机上收到的需求文档直接拖到代码文件夹里，复制粘贴连扫码发文件的步骤都省了。键盘的手感也很舒服，敲一整天代码手指都不酸，快充也实用，有时候急着出门没电了，充十分钟就能撑到公司继续改bug，太适合我们这种经常赶工的人了。"},{"nickname":"阿柠","rating":5,"content":"大学生党真的狂喜！平时上课带它去记笔记，连上手写笔直接在课件PDF上批注，写完还能自动同步到我华为的手表上，路上坐地铁就能翻笔记复习。平时剪社团的活动视频、写几千字的论文完全不卡，下了课回宿舍躺床上也能抱着它刷剧，屏幕画质特别清楚，续航撑一整天满课不用带充电器，比之前我那个旧本重得要死还半天充不上电好用太多了，性价比真的很高。"},{"nickname":"大川","rating":1,"content":"用了不到三周就出现屏幕漏光的情况，左下角的背光明显不均匀，看全黑画面的时候特别明显，找售后说属于正常工艺范围不给免费换，得自己加钱换屏。而且我买的锐龙版运行大型建模软件的时候，散热压不住直接降频，渲染个简单的图花了快半小时，同价位别的笔记本早就渲染完了，花六千多买的本这个体验真的太不值了，找客服沟通了好几次都没给合理的解决方案，太糟心了。"}]}}'::jsonb, '2_数码电子/data/p_digital_004.json'),
    ('p_digital_005', '华为HUAWEI MatePad Pro Max 12.6英寸高刷屏多任务办公平板电脑', '华为', '数码电子', '平板电脑', '数码电子/平板电脑', 4999.0, 4999.0, 6399.0, 800, '2_数码电子/images/p_digital_005_live.jpg', '{"product_id":"p_digital_005","title":"华为HUAWEI MatePad Pro Max 12.6英寸高刷屏多任务办公平板电脑","brand":"华为","category":"数码电子","sub_category":"平板电脑","base_price":4999.0,"image_path":"2_数码电子/images/p_digital_005_live.jpg","skus":[{"sku_id":"s_p_digital_005_1","properties":{"存储规格":"8GB+256GB","网络版本":"Wi-Fi 版"},"price":4999.0},{"sku_id":"s_p_digital_005_2","properties":{"存储规格":"12GB+256GB","网络版本":"Wi-Fi 版"},"price":5299.0},{"sku_id":"s_p_digital_005_3","properties":{"存储规格":"8GB+512GB","网络版本":"Wi-Fi 版"},"price":5499.0},{"sku_id":"s_p_digital_005_4","properties":{"存储规格":"12GB+512GB","网络版本":"Wi-Fi 版"},"price":5799.0},{"sku_id":"s_p_digital_005_5","properties":{"存储规格":"8GB+256GB","网络版本":"全网通5G版"},"price":5599.0},{"sku_id":"s_p_digital_005_6","properties":{"存储规格":"12GB+256GB","网络版本":"全网通5G版"},"price":5899.0},{"sku_id":"s_p_digital_005_7","properties":{"存储规格":"8GB+512GB","网络版本":"全网通5G版"},"price":6099.0},{"sku_id":"s_p_digital_005_8","properties":{"存储规格":"12GB+512GB","网络版本":"全网通5G版"},"price":6399.0}],"rag_knowledge":{"marketing_description":"华为MatePad Pro Max 12.6英寸平板，核心卖点是适配办公需求的高刷大屏与多任务并行能力，12.6英寸高色域高刷屏拖滑无拖影，分屏最多同时开3个独立应用，侧边还能悬浮小窗回消息，彻底摆脱小屏平板办公的局促感。不管是经常要带设备开线上会的职场打工人，还是需要分屏查资料写文档的内容创作者，或是用来上网课做笔记的高校学生都适配。日常带出门赶方案、居家同时挂会议记笔记剪短视频都顺手，全金属机身握感扎实抗造，搭配M-Pencil使用延迟极低。使用建议平时开智能刷新率模式更省电，注意别让尖锐硬物直接刮到屏幕表面，Wi-Fi版不支持插SIM卡，出门在外需要提前备好手机热点哦。","official_faq":[{"question":"这款12.6英寸的MatePad Pro Max多任务功能具体支持多少应用同时并行，不会出现杀后台的情况吗？","answer":"这款平板的多任务能力是专门针对办公场景优化的，8GB+256GB版本日常可稳定同时运行3-4个大型办公应用，12GB+512GB版本最多支持6个常用APP并行，只要后台总占用内存不超出阈值就不会随便杀后台。你可以直接通过底部上滑停顿调出后台，拖拽应用到屏幕边缘开启最多三分屏布局，还能额外叠加2个悬浮小窗，同时开文档、查资料、回微信完全不用反复切换APP，办公效率提升特别明显。"},{"question":"这款12.6英寸的高刷屏日常看视频、刷文档的实际体验怎么样，会不会出现色域偏色的问题？","answer":"这块12.6英寸的屏幕支持最高120Hz自适应刷新率，日常刷文档拖滑、刷短视频完全没有卡顿拖影的问题，看2K分辨率的高清视频画面细腻度拉满，还覆盖了100% DCI-P3广色域，出厂前每台都做了校色处理，修图剪视频的时候颜色显示和专业显示器的偏差特别小。你还可以根据使用场景切换护眼模式，长时间开文档办公眼睛也不容易累，高刷设置成智能自适应模式，低刷场景自动降低刷新率还能省不少电。"},{"question":"这款Wi-Fi版的平板外出办公的时候，怎么快速和华为的笔记本、手机联动传输文件？","answer":"只要你的华为手机、笔记本和平板登录同一个华为账号，打开蓝牙和Wi-Fi之后就能自动触发多屏协同，手机的界面可以直接投屏到平板上操作，拖拽就能互传图片、文档，不需要走微信发文件的弯路。如果是搭配华为笔记本，还能开启超级终端，把平板直接当成笔记本的扩展屏，一边在笔记本上做演示，一边在平板上标注修改，外出见客户演示方案特别方便，哪怕没有公共网络也能正常使用联动功能，传输速度比普通蓝牙快很多。"}],"user_reviews":[{"nickname":"阿凯","rating":2,"content":"本来冲着12.6英寸大屏买的，结果没想到裸机拿在手里比我之前的旧重了快半斤，单手握持看半小时网页胳膊就酸，想装个全尺寸的办公套件存素材，256G版本实际可用空间才不到200G，存不了多少高清工程文件就得外接硬盘，这个价位的存储配置实在不太够，而且官方配套的键盘保护壳还要额外花大几百买，算下来总花费比一开始预想的高太多，体验有点失望。"},{"nickname":"小夏","rating":5,"content":"做新媒体内容的我真的挖到宝了！这个12.6英寸的高刷屏剪1080P的短视频完全不卡，三分屏同时开着文档找选题、后台挂着微信对接客户、旁边悬浮窗回评论，根本不用来回切APP，之前用小平板找资料要反复退后台，现在一天的工作量两小时就能做完，屏幕显示颜色特别准，修封面图的时候和我台式机显示器的颜色几乎没差，续航也够撑我开一下午线上会，太适合我们这种出门跑活动的内容人了。"},{"nickname":"阿泽","rating":5,"content":"作为每天要开三四场线上会的职场人，这个平板真的帮我大忙了，投屏到会议室的电视上画面特别清晰，高刷不会出现ppt翻页卡顿的情况，多任务开着会议界面的同时，分屏另一边直接开文档记笔记，不用额外带笔记本，揣包里就能直接带去开会，重量比起游戏本轻太多，上下班挤地铁背着完全不累，联动我的华为手机传会议记录点一下就过去，再也不用微信传文件丢画质了，太顺手。"},{"nickname":"小吕","rating":3,"content":"整体用下来中规中矩吧，多任务办公确实比普通小屏平板好用，但是续航没有宣传的那么顶，我开着高刷连开三小时文档加挂会议，电量直接掉了40%，出门不带快充头半天都撑不住，而且Wi-Fi版在外面要连手机热点特别麻烦，偶尔还会出现热点断连的情况，没有插卡版可选有点不方便，这个价格其实也算不上特别划算，勉勉强强能用，算不上特别满意。"},{"nickname":"阿宁","rating":5,"content":"读研用来写论文查资料太合适了！分屏一边放知网的文献，另一边直接开word敲字，再也不用在两个APP之间反复横跳，配个华为的手写笔直接在文献上标注重点，省了好多打印资料的钱，12.6英寸的大屏看扫描版的古籍资料也能看清小字，高刷滑动翻页的时候完全没有颗粒感和拖影，泡图书馆坐一下午看文献眼睛也没之前用小平板那么酸，这笔钱花的太值了。"}]}}'::jsonb, '2_数码电子/data/p_digital_005.json'),
    ('p_digital_006', 'Apple MacBook Pro 14英寸 M5 芯片 16GB 512GB 专业高性能笔记本电脑', 'Apple 苹果', '数码电子', '笔记本电脑', '数码电子/笔记本电脑', 13499.0, 13499.0, 17999.0, 1600, '2_数码电子/images/p_digital_006_live.jpg', '{"product_id":"p_digital_006","title":"Apple MacBook Pro 14英寸 M5 芯片 16GB 512GB 专业高性能笔记本电脑","brand":"Apple 苹果","category":"数码电子","sub_category":"笔记本电脑","base_price":13499.0,"image_path":"2_数码电子/images/p_digital_006_live.jpg","skus":[{"sku_id":"s_p_digital_006_1","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"16GB","固态硬盘容量":"512GB SSD","机身颜色":"深空黑"},"price":13499.0},{"sku_id":"s_p_digital_006_2","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"16GB","固态硬盘容量":"512GB SSD","机身颜色":"银色"},"price":13499.0},{"sku_id":"s_p_digital_006_3","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"16GB","固态硬盘容量":"1TB SSD","机身颜色":"深空黑"},"price":14999.0},{"sku_id":"s_p_digital_006_4","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"16GB","固态硬盘容量":"1TB SSD","机身颜色":"银色"},"price":14999.0},{"sku_id":"s_p_digital_006_5","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"24GB","固态硬盘容量":"512GB SSD","机身颜色":"深空黑"},"price":15499.0},{"sku_id":"s_p_digital_006_6","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"24GB","固态硬盘容量":"512GB SSD","机身颜色":"银色"},"price":15499.0},{"sku_id":"s_p_digital_006_7","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"24GB","固态硬盘容量":"1TB SSD","机身颜色":"深空黑"},"price":16999.0},{"sku_id":"s_p_digital_006_8","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 芯片","内存容量":"24GB","固态硬盘容量":"1TB SSD","机身颜色":"银色"},"price":16999.0},{"sku_id":"s_p_digital_006_9","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"24GB","固态硬盘容量":"512GB SSD","机身颜色":"深空黑"},"price":16499.0},{"sku_id":"s_p_digital_006_10","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"24GB","固态硬盘容量":"512GB SSD","机身颜色":"银色"},"price":16499.0},{"sku_id":"s_p_digital_006_11","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"24GB","固态硬盘容量":"1TB SSD","机身颜色":"深空黑"},"price":17499.0},{"sku_id":"s_p_digital_006_12","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"24GB","固态硬盘容量":"1TB SSD","机身颜色":"银色"},"price":17499.0},{"sku_id":"s_p_digital_006_13","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"32GB","固态硬盘容量":"512GB SSD","机身颜色":"深空黑"},"price":16999.0},{"sku_id":"s_p_digital_006_14","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"32GB","固态硬盘容量":"512GB SSD","机身颜色":"银色"},"price":16999.0},{"sku_id":"s_p_digital_006_15","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"32GB","固态硬盘容量":"1TB SSD","机身颜色":"深空黑"},"price":17999.0},{"sku_id":"s_p_digital_006_16","properties":{"屏幕尺寸":"14英寸","芯片型号":"M5 Pro 芯片","内存容量":"32GB","固态硬盘容量":"1TB SSD","机身颜色":"银色"},"price":17999.0}],"rag_knowledge":{"marketing_description":"这款14英寸Apple MacBook Pro搭载全新M5系列芯片，是面向专业创作者、程序开发者、高端商务人士的高性能生产力工具。核心配置覆盖16GB-32GB统一内存、512GB-1TB高速SSD，搭配Liquid Retina XDR显示屏，峰值亮度可达1600尼特，户外强光下剪辑HDR素材也能看清细节。机身采用全铝一体成型工艺，深空黑版本加入特殊纳米涂层抗指纹，连续视频剪辑续航最长可达18小时，外出跑项目一整天不用带充电器。适合4K视频调色、3D建模渲染、大型工程代码编译等重度工作场景，日常用来修图、做方案、线上会议也丝滑流畅。使用时建议尽量在官方适配的65W以上PD充电器下充电，不要用第三方廉价快充头，长时间高负载运行时别把机身放在被褥等软质不透气表面上，避免堵塞底部散热格栅影响性能释放。","official_faq":[{"question":"这款搭载M5芯片的14英寸MacBook Pro，16GB内存版本运行大型3D建模软件比如Blender的流畅度怎么样？","answer":"16GB统一内存版本的M5芯片MacBook Pro，运行Blender渲染中等复杂度的1080P 30秒动画工程时，速度比上一代M3同配置机型快40%左右，视口拖动预览几乎没有掉帧卡顿。如果是超大型的8K高精度场景，建议关闭后台多余的常驻软件再操作，避免内存占用满了出现闪退情况。日常做普通产品建模、角色绑定等轻中度3D工作，16GB版本完全可以满足需求，不需要额外升级内存版本也能获得很顺畅的使用体验。"},{"question":"不同SKU的M5系列14英寸MacBook Pro之间，实际使用的续航表现差距有多大？","answer":"基础款M5芯片16GB+512GB的深空黑版本，日常连续浏览网页、编辑文档的实测续航能达到17-18小时，在线观看4K流媒体视频能撑14小时左右。24GB+1TB银色版本的M5芯片机型，因为内存和存储容量提升，日常轻使用续航和基础款几乎没有差别，仅在高负载视频导出场景下功耗高5%左右，续航少半小时上下。而M5 Pro芯片32GB+1TB的深空黑版本，高负载运行时功耗更高，重度工作场景续航大概比基础款少2小时，轻使用场景续航差距几乎感知不到。"},{"question":"深空黑版本的M5 MacBook Pro的外壳纳米抗指纹涂层，日常清洁要注意什么？","answer":"深空黑版本专属的纳米抗指纹涂层，日常清洁不要用酒精、卸甲水这类含强有机溶剂的液体擦拭，很容易把涂层腐蚀掉留下不可逆的印子。平时沾了指纹用随机附赠的超细纤维擦镜布，蘸少量清水轻轻擦拭就能擦干净顽固污渍。如果不小心沾了油污，可以用稀释到浓度3%以下的中性洗碗液混合清水，蘸湿擦镜布拧到完全不滴水之后再擦，擦完立刻用干布把表面残留的水渍擦干，不会损伤涂层还能保持机身外观一直崭新。"},{"question":"这款M5芯片的MacBook Pro可以外接两台4K显示器同时工作吗？需不需要额外买转接配件？","answer":"基础款M5芯片16GB/24GB内存的版本，最多支持外接1台6K分辨率60Hz的显示器，想要同时接两台4K显示器的话，需要选购搭载M5 Pro芯片的32GB内存1TB的版本，它原生支持外接两台6K显示器，完全能满足多屏生产力的需求。如果你的外接显示器是HDMI接口，只需要买官方在售的USB-C转HDMI转接器就可以直连，不需要额外安装任何驱动，插上之后就能自动识别显示，还可以同时扩展连接外接硬盘、声卡等其他外设，不会出现带宽不够掉速的情况。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"做短视频剪辑的入手了16GB+512GB的深空黑款，用了快半个月太香了！之前旧电脑导出10分钟4K短片要等二十多分钟，这台M5芯片十来分钟就能跑完，而且机身几乎没什么明显的噪音。Liquid Retina XDR屏幕调色准到离谱，之前导出的视频在别的显示器看偏色，现在调完直接交付甲方都没提过改色要求。深空黑的质感巨高级，沾点指纹用布一擦就干净，出门带出去接活别人问了好几次型号，续航也顶，跑一下午外拍素材导进去处理都不用插电。"},{"nickname":"小宇","rating":3,"content":"冲着M5芯片的性能买的16GB版本，用了一周发现个挺闹心的问题。我平时习惯开十几个网页加微信、PS还有办公软件后台挂着，偶尔切的时候会出现小卡顿，问了客服才知道统一内存不能自己后期升级，早知道当时多加点钱上24GB版本就好了。还有包装里居然没有附送充电器，我之前用的旧Mac的充电器插上功率不够，充电速度慢得要死，还要自己额外花钱买个适配的67W充电器，这点感觉不太人性化，整体性能倒是没大问题，就是细节体验打折扣。"},{"nickname":"阿泽","rating":1,"content":"收到货拆开就发现机身C口边缘有个细小的磕碰划痕，找客服处理来回扯皮了三天才同意换货。换回来的新机器用了没一周，就出现屏幕偶尔闪一下绿线的情况，而且我平时用来外接2K显示器写代码，居然识别不到高刷模式，之前我旧的Intel老Mac都能完美支持的。更离谱的是用Pr导出长视频的时候居然闪退了两次，辛辛苦苦写的工程没保存损失了好几个小时的工作量，一万多买的机器体验还不如前两年的旧款，真的太失望了。"},{"nickname":"晚柠","rating":5,"content":"自由设计师入了24GB+1TB的银色款，用来做平面设计和轻量3D渲染太够用了。机身重量比我想象的轻很多，天天背着去咖啡店办公肩膀都不会酸，妙控键盘的敲字手感巨舒服，改方案改一整天手指都不疼。屏幕的色彩准确度完全符合印刷级要求，做的海报拿去打印店打出来的颜色和屏幕上几乎零色差，省了我之前校色的好多时间。续航真的太顶了，出门带满电的机器，从早上九点坐到下午六点处理工作，回家还剩20%多的电，太省心了。"},{"nickname":"阿哲","rating":5,"content":"程序员开发买的M5 Pro 32GB+1TB版本，用来跑大型项目编译速度比我之前用的Intel i9笔记本快了快一倍，开几十个Docker容器再加虚拟机跑服务都完全不卡。机身的散热表现特别好，连续高负载跑编译两个小时，底部摸起来只是温温的，不像旧笔记本烫得能煎鸡蛋。三个雷电接口同时插硬盘、扩展坞和调试设备都不会有带宽不够的情况，多外接一台4K屏写代码一边看文档一边敲代码，生产力直接拉满，一万七花得太值了。"}]}}'::jsonb, '2_数码电子/data/p_digital_006.json'),
    ('p_digital_007', '华为HUAWEI FreeBuds Pro 5 主动降噪真无线蓝牙耳机高解析音质', '华为', '数码电子', '真无线耳机', '数码电子/真无线耳机', 1699.0, 1499.0, 1699.0, 600, '2_数码电子/images/p_digital_007_live.jpg', '{"product_id":"p_digital_007","title":"华为HUAWEI FreeBuds Pro 5 主动降噪真无线蓝牙耳机高解析音质","brand":"华为","category":"数码电子","sub_category":"真无线耳机","base_price":1699.0,"image_path":"2_数码电子/images/p_digital_007_live.jpg","skus":[{"sku_id":"s_p_digital_007_1","properties":{"版本":"标准版","颜色":"典雅黑"},"price":1699.0},{"sku_id":"s_p_digital_007_2","properties":{"版本":"标准版","颜色":"冰霜银"},"price":1699.0},{"sku_id":"s_p_digital_007_3","properties":{"版本":"标准版","颜色":"羽沙白"},"price":1699.0},{"sku_id":"s_p_digital_007_4","properties":{"版本":"有线充基础版","颜色":"典雅黑"},"price":1499.0},{"sku_id":"s_p_digital_007_5","properties":{"版本":"有线充基础版","颜色":"冰霜银"},"price":1499.0},{"sku_id":"s_p_digital_007_6","properties":{"版本":"有线充基础版","颜色":"羽沙白"},"price":1499.0}],"rag_knowledge":{"marketing_description":"华为FreeBuds Pro 5是专为追求高音质和强降噪体验的数码爱好者、通勤族、办公党打造的旗舰级真无线耳机。搭载华为自研的超感知主动降噪系统，最高降噪深度可达55dB，搭配全新升级的高解析音频解码，能完整还原Hi-Res Audio标准的细节音效，哪怕是古典乐里的弦乐泛音、演唱会现场的现场感都能精准捕捉。单耳满电可支持6小时降噪模式播放，搭配充电盒总续航能到30小时，支持快充15分钟听歌4小时。机身采用贴合耳廓的人体工学半开放倾耳设计，典雅黑哑光不容易沾指纹，冰霜银磨砂质感高级。日常通勤挤地铁、办公室赶方案、居家沉浸式听歌都能用，使用时建议首次佩戴先在华为智慧生活APP里做贴合度检测，选择适配的耳塞套，不要在雷雨天气或者高水压的水下环境佩戴，避免元器件受潮损坏。","official_faq":[{"question":"华为FreeBuds Pro 5的高解析音质需要搭配特定的华为手机才能开启吗？","answer":"如果是搭载HarmonyOS 4.2及以上版本的华为手机，开盖配对后就能自动触发全链路高解析音频解码，无需额外复杂设置，就能直接输出接近无损的高清音效。如果是其他品牌支持LHDC 5.0协议的设备，也可以在蓝牙音频设置里手动开启高解析模式，只是部分非华为设备可能无法适配全部音频调校参数。要注意只有播放对应Hi-Res音质的音源文件，才能完整发挥这款耳机的音质优势，普通低码率音源没法体现出高解析的细节表现。"},{"question":"这款FreeBuds Pro 5的主动降噪可以根据不同场景自动调节吗？","answer":"是的，它搭载了华为最新的动态降噪适配算法，耳机内置的多传感器会实时监测你所处的环境噪音类型，比如你从安静的小区走到车流密集的主干道，系统会自动把降噪强度调整到适配交通噪音的档位，走到人声密集的商圈时也会自动优化降噪参数，既不会把外界必要的提示音完全屏蔽，也能有效过滤冗余噪音。你也可以手动在智慧生活APP里切换深度降噪、轻度降噪、智能透传、人声增强这几个固定档位，适配坐飞机、办公室开短会、过马路等不同的自定义需求。"},{"question":"华为FreeBuds Pro 5的触控操作和之前的FreeBuds系列耳机有什么不一样的地方吗？","answer":"它把之前的耳机柄按压触控改成了全新的滑动+轻敲双控制逻辑，你可以在耳机柄的触控区域上下滑动调节音量，轻敲两下耳机柄就能切换歌曲或者接听挂断来电，长按可以快速切换降噪档位，操作逻辑比之前更顺手，不容易出现戴耳机时误触按紧耳道产生的胀痛感。你还能在智慧生活APP里自定义每个触控手势对应的功能，比如双击触发语音助手、长按开启录音转写等专属功能，适配自己的日常使用习惯，不过注意触控区域沾水的时候灵敏度会下降，擦干后就能恢复正常。"}],"user_reviews":[{"nickname":"小宇","rating":2,"content":"用了快两周还是有点小失望，我耳朵属于偏小的类型，哪怕换了最小号的耳塞套，走路快走半小时耳机就会往下滑，之前用的旧款FreeBuds Pro戴着就很稳不会掉。而且开启全链路高解析音质之后，续航掉得比官方标的快很多，满电出门降噪加高清音质撑不到5小时就得找充电盒，降噪效果倒是还可以，但这个佩戴贴合度对小耳用户真的不太友好，感觉调校的时候更偏向大耳人群。"},{"nickname":"阿泽","rating":5,"content":"华为这次新出的Pro5真的超出预期！我平时坐地铁通勤单程要一个多小时，开了深度降噪之后地铁的轨道轰鸣声直接几乎全没了，连旁边人打电话的模糊杂音也滤得很干净。音质是真的顶，之前用的耳机听古典乐总觉得小提琴的声音发闷，这款能听到弦乐上细微的揉弦颤音，连歌手换气的小细节都清清楚楚，开盖连我的Mate 60 Pro秒连，智慧生活APP里的自定义功能也特别顺手，一千多花得太值了。"},{"nickname":"萌萌","rating":2,"content":"入手的冰霜银款，颜值确实没得说，但是耳机柄的触控区域太容易误触了，我有时候整理头发碰到耳机柄，突然就切歌或者直接呼出语音助手，好几次开会的时候突然公放出声特别尴尬。问了客服说可以调触控灵敏度，调完之后有时候要敲两三下才能触发操作，灵敏度过高过低都难适配，这个触控逻辑的调校感觉还不如上一代的按压式用着省心，用着有点闹心。"},{"nickname":"老周","rating":5,"content":"作为一个做了好几年音频的爱好者，这款FreeBuds Pro5的高解析音质真的太惊喜了，比我之前用过的很多同价位无线耳机声场宽太多，低频的下潜够深但完全不会轰头，中频人声贴耳，听流行歌简直是享受。平时我经常出差坐飞机，开了降噪之后连飞机发动机的持续嗡鸣都能滤掉大部分，长途飞行戴几个小时耳朵也不胀，快充功能太实用，临出门发现没电充15分钟，路上全程听歌都够，完全挑不出毛病。"},{"nickname":"阿凯","rating":1,"content":"用了不到一周右耳机突然就断连了，怎么重置配对都连不上，单独放回充电盒充电指示灯完全不亮，按照客服教的所有操作试了个遍都没用。我平时根本没摔过没沾过水，全新的耳机就直接出硬件故障，送售后检测说要返厂至少等一周，新买的旗舰耳机用几天就出问题，品控也太拉胯了，完全对不起这个一千多的定价，这次体验特别差，以后再也不敢盲入新款首发了。"}]}}'::jsonb, '2_数码电子/data/p_digital_007.json'),
    ('p_digital_008', '小米 17 Ultra 2K高刷屏潜望长焦澎湃芯片影像旗舰5G手机12+256GB', '小米', '数码电子', '智能手机', '数码电子/智能手机', 7499.0, 7499.0, 9299.0, 300, '2_数码电子/images/p_digital_008_live.jpg', '{"product_id":"p_digital_008","title":"小米 17 Ultra 2K高刷屏潜望长焦澎湃芯片影像旗舰5G手机12+256GB","brand":"小米","category":"数码电子","sub_category":"智能手机","base_price":7499.0,"image_path":"2_数码电子/images/p_digital_008_live.jpg","skus":[{"sku_id":"s_p_digital_008_1","properties":{"存储":"12GB+256GB","版本":"标准版"},"price":7499.0},{"sku_id":"s_p_digital_008_2","properties":{"存储":"16GB+512GB","版本":"高配版"},"price":8299.0},{"sku_id":"s_p_digital_008_3","properties":{"存储":"16GB+1TB","版本":"顶配版"},"price":9299.0}],"rag_knowledge":{"marketing_description":"这台小米17 Ultra是专为影像发烧友、手游重度玩家和职场精英打造的年度旗舰，搭载小米自研澎湃影像芯片+潜望长焦模组，配合2K超高刷新率的定制AMOLED屏，全链路5G网络适配各类高速场景。日常出门扫街拍远景不用带沉重的单反，随手就能拍出细节拉满的长焦成片；刷高帧影视、玩3A手游的时候画面丝滑不拖影。全系列LPDDR5X内存搭配UFS4.0闪存，多开办公软件也不会卡顿。使用建议是首次开机可在影像设置里开启澎湃芯片专属的夜景增强模式，长时间户外拍摄建议搭配官方散热背夹，注意不要用非原装快充头长时间充电，避免损伤内置电池寿命。","official_faq":[{"question":"小米17 Ultra的潜望长焦搭配澎湃芯片，实际暗光长焦拍摄效果有什么优化？","answer":"这套组合专门针对暗光长焦场景做了定向调校，澎湃芯片会独立处理长焦镜头采集的暗部raw数据，不用靠主摄像头裁切凑数，就算在夜间商业街拍对面高楼的店招，或是演唱会后排拍台上的表演者，成片噪点比同规格其他旗舰低40%左右，色彩还原度也更贴近肉眼所见，不会出现偏色发灰的情况，你可以直接在专业模式里开启「澎湃长焦夜景」开关，就能一键触发专属优化算法，出片效率特别高。"},{"question":"这块2K高刷屏日常使用可以调节哪些档位，会不会额外增加耗电？","answer":"这块屏幕提供三档刷新率调节，分别是60Hz省电模式、120Hz均衡模式和144Hz全速模式，系统会自动根据当前应用场景适配档位，比如浏览静态新闻的时候自动降到60Hz，刷短视频、玩游戏的时候自动拉升到144Hz。经过实验室实测，开启智能适配的情况下，2K屏的日常续航比上代16 Ultra只少了3%左右，完全不会出现大幅耗电的情况，你也可以自定义指定应用的刷新率，进一步平衡流畅度和续航表现。"},{"question":"不同存储版本的小米17 Ultra，在澎湃影像芯片的调度上有没有区别？","answer":"三个存储版本的澎湃影像芯片硬件规格是完全一致的，不会出现低配版砍影像性能的情况，区别只在后台缓存的 raw 照片临时存储空间大小，12+256G标准版最多同时后台缓存8张未处理的4800万像素 raw 长焦照片，16+512G高配版和16+1TB顶配版最多能缓存15张，多开修图APP的时候大内存版本也不用反复重载素材，经常长时间在外批量拍摄的用户更推荐选大存储版本，日常普通拍照发朋友圈的用户标准版完全够用。"},{"question":"小米17 Ultra支持的5G频段有没有针对国内三大运营商的优化？","answer":"这台手机全频段覆盖国内移动、联通、电信还有广电的所有5G商用频段，还额外针对高铁沿线、地下车库这类信号弱的场景做了信号增益调校，就算在时速350公里的高铁上刷4K直播，也很少出现卡顿断流的情况，同时支持双5G双卡双待，两张卡同时驻留5G网络，主卡接电话的时候副卡的流量也不会断开，不用额外切换网络，特别适合经常出差跑外勤的职场用户使用。"},{"question":"小米17 Ultra后续系统更新里，会新增更多澎湃芯片专属的影像玩法吗？","answer":"官方已经官宣未来24个月的大版本系统更新里，会陆续推送基于澎湃芯片算力开发的新影像功能，包括AI动态追焦拍飞鸟、一键生成4K长焦动态壁纸、多帧合成8K延时摄影这类专属玩法，这些功能因为调用的是独立芯片算力，不会占用主处理器资源，开启之后也不会让手机出现明显卡顿发烫的情况，用户只要在系统设置里开启自动更新，就能第一时间体验到新功能，不需要额外付费解锁。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"等了半个月终于拿到手了！上周去看演唱会坐在山顶位，用这台的潜望长焦直接把台上歌手的面部表情拍得清清楚楚，澎湃芯片处理完的照片连舞台灯周围的星芒都特别干净，完全没有之前用旧手机拍的那种糊成一片的情况。2K屏玩开放世界手游开全高特效也丝滑得不行，续航撑完我一下午外出拍摄加导航还剩30多电，这7499的标准版真的太值了。"},{"nickname":"小宇","rating":3,"content":"用了快一周整体不算太满意，本来冲着潜望长焦买的，结果夏天在户外大太阳下拍了二十分钟远景，摄像头区域烫得有点离谱，相机直接弹出过热提示强制退出了，等了快十分钟才恢复正常。还有2K高刷屏全开的时候，后台挂三个修图APP切来切去偶尔会闪一下屏，虽然不影响日常用，但八千多买的旗舰出现这种小bug还是有点膈应，希望后续系统更新能赶紧优化下。"},{"nickname":"阿晚","rating":5,"content":"作为常年扫街的摄影爱好者，这台手机真的戳中我所有需求！之前出门总要带个微单加长焦镜头，现在揣这台小米17 Ultra就够了，长焦拍路边的猫、远处的老建筑细节都拉满，澎湃芯片的色彩调校特别对我胃口，不用后期调太多就能直接发社交平台。而且2K屏修图的时候看色准特别准，导出的图在电脑上看色差几乎没有，太适合我们这种经常出门拍照的人了。"}]}}'::jsonb, '2_数码电子/data/p_digital_008.json'),
    ('p_digital_009', '小米 17 Max 大屏长续航高性能影音游戏5G智能手机12+256GB', '小米', '数码电子', '智能手机', '数码电子/智能手机', 6499.0, 6499.0, 7099.0, 400, '2_数码电子/images/p_digital_009_live.jpg', '{"product_id":"p_digital_009","title":"小米 17 Max 大屏长续航高性能影音游戏5G智能手机12+256GB","brand":"小米","category":"数码电子","sub_category":"智能手机","base_price":6499.0,"image_path":"2_数码电子/images/p_digital_009_live.jpg","skus":[{"sku_id":"s_p_digital_009_1","properties":{"存储":"12GB+256GB","版本":"标准版"},"price":6499.0},{"sku_id":"s_p_digital_009_2","properties":{"存储":"12GB+256GB","版本":"高配版"},"price":6699.0},{"sku_id":"s_p_digital_009_3","properties":{"存储":"16GB+512GB","版本":"标准版"},"price":6899.0},{"sku_id":"s_p_digital_009_4","properties":{"存储":"16GB+512GB","版本":"高配版"},"price":7099.0}],"rag_knowledge":{"marketing_description":"小米17 Max是专为影音游戏爱好者打造的大屏5G性能旗舰，搭配超窄边7英寸2K超清大屏，支持120Hz自适应高刷，峰值亮度达1800nit，户外强光下看剧刷攻略也清晰透亮。内置6800mAh超大容量长续航电池，搭配120W有线快充+50W无线快充，连续满帧玩3小时《原神》还剩62%电量，追完一整季24集连续剧都不用中途插电。搭载旗舰级骁龙8 Gen4处理器，配合满血版LPDDR5X运存，后台同时挂10个APP切换也不会杀后台。特别适合经常出差的通勤党、常驻宿舍的手游玩家、日常爱刷剧剪vlog的内容创作者使用。建议日常搭配官方附赠的全包边软壳使用，注意避免从1.5米以上高度直接掉落，虽然屏幕用了康宁大猩猩最新防刮玻璃，还是尽量不要和钥匙、硬币等硬物同放在裤袋边角摩擦哦。","official_faq":[{"question":"小米17 Max的大屏看4K HDR电影的时候会不会出现色彩偏色或者暗部细节糊的情况？","answer":"这款小米17 Max的屏幕出厂前都经过逐台校色，支持10bit色深和10.7亿色显示，色准Delta E值控制在0.8以内，几乎接近专业显示器的色彩表现，暗部区域还搭载了独立的像素级背光调节芯片，就算是看暗黑类电影的夜戏场景，也能清晰分辨画面角落的细节，不会出现死黑糊成一团的情况。你可以在系统显示设置里开启「影院模式」，就可以锁定原生的电影级色彩输出，不会出现自动偏暖的情况，完全还原影视创作者的调色意图。"},{"question":"我常玩的《原神》《星穹铁道》这类大型手游，长时间满帧运行小米17 Max会不会严重发烫降频？","answer":"小米17 Max内置了总面积达6200mm²的新一代超导石墨烯散热板，搭配边框的独立航空级铝合金导热中框，游戏场景下系统会自动开启「狂暴稳帧模式」，处理器的功耗调度会保持在合理区间，连续满帧运行2小时《原神》最高画质，机身背部最高温度不会超过41摄氏度，不会出现突然掉帧锁帧的情况。如果搭配官方的磁吸散热背夹使用，还可以进一步降低机身温度，即使长时间团战或者刷副本，也能全程保持稳定的帧率输出，不会出现因为发烫导致操作延迟的问题。"},{"question":"6800mAh的大电池日常重度使用，续航实际能撑多久，5G全程在线的情况？","answer":"在5G全程开启、屏幕亮度调至50%、日常高频刷短视频、聊微信、偶尔刷社交软件的重度使用场景下，小米17 Max能稳稳坚持接近13个小时，从早上出门满电出门，到晚上睡前还能剩下15%左右的电量，完全不用随身带充电宝。如果是轻度使用，只是接打电话、偶尔回复消息，甚至可以达到3天左右的待机时长，就算是连续开5G导航跨城自驾游，持续导航8小时之后，剩余电量还能剩下40%左右，不用中途找充电桩补电，出远门特别省心。"},{"question":"12GB运存和16GB运存两个版本，实际日常使用的体验差距大吗？该怎么选？","answer":"如果日常只是用来刷视频、聊微信、玩中型手游，12+256GB的标准版完全够用，后台同时保留五六个常用APP切换也不会重新加载，256GB的存储空间存下近百部高清剧集也没问题。如果你经常要同时开好几个游戏、后台挂着剪辑软件、聊天工具、工作文档，还喜欢存大量高清 raw 格式照片和4K视频，那更推荐选16+512GB的高配版，用个四五年也不会出现运存不够卡顿、存储空间满了要删东西的情况，使用周期会更长，长期来看性价比更高。"},{"question":"这款大屏手机单手握持会不会很累，有没有适配专门的单手操作功能？","answer":"小米17 Max虽然屏幕达到7英寸，但是机身做了专门的2.5D弧度收边处理，整机重量控制在228g，比同尺寸的其他大屏手机轻了近20g，适配了专门的小屏模式，你只要在屏幕边缘向内侧滑动停留半秒，就能把整个操作界面缩小到适合单手握持的4.5英寸区域，不管是点按左上角的返回键，还是下拉通知栏，不用换手就能轻松操作。就算手型偏小的女生，搭配自带的悬浮球功能，日常单手握持刷短视频的时间久了，也不会觉得手腕酸痛。"}],"user_reviews":[{"nickname":"小宇","rating":4,"content":"用了快一周整体还挺满意的，大屏看剧真的太爽了，之前的小屏手机对比起来完全没有沉浸感，续航也确实顶，我天天摸鱼刷短视频一整天下来回家还有剩电。就是有个小问题，这个手机尺寸确实偏大，我平时穿的普通牛仔裤小口袋塞进去特别挤，坐下来的时候总担心会把屏幕硌到，后来专门换了个大口袋的工装裤才解决，要是后续能在保持大屏的基础上把机身再做窄一点就更好了。"},{"nickname":"阿泽","rating":5,"content":"作为玩了五六年手游的老玩家，这次入手小米17 Max真的挖到宝了！之前的旧手机玩原神半小时就烫得能煎鸡蛋，还总掉帧，这款开最高画质连续玩一下午原神都稳得不行，帧率几乎没怎么波动，屏幕大视野看得特别清楚，打深渊找怪都比以前快好多。续航更是惊喜，上周去郊外露营没带充电器，连刷了7部电影回来还剩20%多的电，这台机子我估计至少能再战四五年。"},{"nickname":"小棠","rating":3,"content":"本来是冲着宣传的长续航买给家里老人用的，结果老人手小完全握不住，拿久了说胳膊酸，而且系统的很多功能默认都是给游戏党设计的，字体调到最大有些界面的文字还是显示不全。更糟的是我揣包里挤地铁的时候不小心蹭到扶手，屏幕边角直接碎了一道小缝，之前用的旧小屏手机摔好几次都没事，这个大屏的边角抗摔性确实比我预想的差很多，去官方问换屏幕要一千多，感觉性价比没那么高。"}]}}'::jsonb, '2_数码电子/data/p_digital_009.json'),
    ('p_digital_010', '小米 MIX Fold 5 内折大屏旗舰折叠屏手机多任务办公影音利器', '小米', '数码电子', '智能手机', '数码电子/智能手机', 9999.0, 9999.0, 11299.0, 400, '2_数码电子/images/p_digital_010_live.jpg', '{"product_id":"p_digital_010","title":"小米 MIX Fold 5 内折大屏旗舰折叠屏手机多任务办公影音利器","brand":"小米","category":"数码电子","sub_category":"智能手机","base_price":9999.0,"image_path":"2_数码电子/images/p_digital_010_live.jpg","skus":[{"sku_id":"s_p_digital_010_1","properties":{"存储配置":"12GB+512GB","版本":"标准版"},"price":9999.0},{"sku_id":"s_p_digital_010_2","properties":{"存储配置":"12GB+512GB","版本":"高配版"},"price":10499.0},{"sku_id":"s_p_digital_010_3","properties":{"存储配置":"16GB+1TB","版本":"标准版"},"price":10799.0},{"sku_id":"s_p_digital_010_4","properties":{"存储配置":"16GB+1TB","版本":"高配版"},"price":11299.0}],"rag_knowledge":{"marketing_description":"小米MIX Fold 5作为小米旗下最新的内折大屏旗舰折叠屏，专为高效办公和沉浸式影音体验打造。展开后超大的内屏支持最多4个应用同屏分栏显示，处理报表的同时还能开线上会议、查参考资料、回客户消息，职场移动办公效率直接拉满；日常刷4K高清剧集、玩大屏开放世界手游时，视野比普通直屏手机多出近60%。整机采用轻量化钛合金铰链，反复折叠数十万次也不容易出现折痕凸起，配装旗舰级骁龙最新移动平台，多任务后台同时运行也几乎不会卡顿。适合经常外勤的商务人士、影音发烧友、创意内容创作者入手，平时注意别用尖锐硬物直接划蹭内屏，合盖时避免夹到钥匙等硬物，能大幅延长屏幕使用寿命。标准版12GB+512GB足够日常使用，重度存资料拍素材的用户更推荐选16GB+1TB高配版。","official_faq":[{"question":"小米MIX Fold 5的多窗口分屏功能最多能同时开几个应用，支持不同应用之间拖拽内容吗？","answer":"这款机型展开内屏后最高支持4个应用同屏并行显示，你可以按需调整每个窗口的大小比例，完全不用局限于固定的对半分屏模式。系统原生支持跨应用拖拽操作，比如你在浏览器搜到的图片、在备忘录里写的文字段落，直接长按就能拖到正在编辑的WPS文档里，不用先保存再导入，处理办公素材的效率能提升不少。就算是第三方适配的小众应用，也基本能正常支持分屏悬浮操作，不会出现强制拉伸变形的情况。"},{"question":"小米MIX Fold 5的内屏铰链经过了多少次折叠测试，日常使用会很快出现明显折痕吗？","answer":"这款手机搭载的是小米自研的第三代微凹钛合金铰链，实验室环境下通过了超过60万次的反复折叠可靠性测试，按照普通人每天折叠开合手机80次来算，正常用个五六年铰链结构都能保持稳定。全新的屏幕基材搭配铰链的屏平优化调校，展开状态下的折痕几乎和周围屏幕区域持平，正常平视使用几乎感知不到明显凹陷，只有在强光斜着照射的时候才会看到淡淡的痕迹，完全不会影响日常看视频、打字操作的使用体验。"},{"question":"小米MIX Fold 5的标准版12GB+512GB和高配版16GB+1TB除了内存存储之外，还有其他配置差异吗？","answer":"两个版本除了运行内存和机身存储的规格不同之外，其他的处理器、屏幕参数、影像配置、电池容量、充电功率都是完全一致的。12GB运存的版本日常开微信、办公软件、短视频APP十几个后台基本也不会出现杀后台的情况，适合普通日常使用的用户。16GB大运存版本最多能同时保活近30个常用应用，就算连续一周不关机重启，多任务切换也几乎不会有卡顿重载的情况，1TB的超大存储空间也适合经常拍4K视频、存大量离线剧集和办公素材的用户使用。"},{"question":"小米MIX Fold 5合盖之后的外屏体验和普通直屏旗舰机比差距大吗，单手操作方便吗？","answer":"它的外屏采用的是几乎无挖孔的全尺寸6.56英寸比例屏幕，视觉观感和普通的旗舰直屏手机几乎没有差别，日常刷社交平台、回复消息、扫码支付完全不用特意展开内屏，单手就能稳稳握住操作。外屏也支持120Hz自适应高刷，滑动操作的流畅度拉满，重量控制在239g，比上一代折叠屏轻了不少，长时间单手握持接电话也不会觉得手腕酸，完全可以当成一台普通的主力直屏手机来日常高频使用。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"用了快三周实在忍不住来吐槽，这个内屏的保护膜居然是出厂就贴死的，我自己想换个钢化膜根本找不到匹配的，官方售后说换原装膜还要收89块。最坑的是上次我不小心把手机在桌面轻磕了一下，铰链旁边的中框直接掉了一小块漆，这个价位的旗舰机品控居然是这样。续航也没宣传的那么好，开着分屏办公两小时直接掉了40%的电，出门不带充电宝根本不敢走远。"},{"nickname":"小棠","rating":5,"content":"之前纠结了好久终于下手了高配版，用了快一个月真的香到不行！平时上班我一边开腾讯会议记笔记，一边拖资料到PPT里，不用来回切应用省了超多时间。周末窝在家里展开屏看新出的科幻大片，那个沉浸感完全不是普通小屏手机能比的，同事看到都问我要链接。折叠起来揣西装口袋也不鼓包，颜值质感完全拉满，这次小米的折叠屏真的做到位了，花一万多买的太值。"},{"nickname":"老周","rating":3,"content":"本来冲着多任务办公买的，结果用下来发现好多常用的办公软件适配根本不到位，我平常用的小众版工程图纸APP，开在内屏里直接被拉伸得画面变形，字都糊成一团。外屏打字的时候总觉得因为机身比普通手机厚一点，硌得慌，打半小时字指关节就酸了。最无语的是官方自带的壳居然是硬塑料的，没半个月边边角角就磨花了，又要花几百块买第三方的定制壳，隐性成本太高。"},{"nickname":"小夏","rating":3,"content":"首发抢的标准版，才用了十几天就发现问题了，折叠到半开的悬停状态的时候，屏幕偶尔会出现几秒钟的触控失灵，怎么点都没反应，非得合盖再重新展开才恢复。去线下售后检测说不是硬件问题，是系统适配bug，让我等后续更新。这个价位的旗舰机出现这种低级问题真的很难接受，早知道当初不如加钱买同价位的其他直板旗舰了，用着实在闹心。"},{"nickname":"阿哲","rating":3,"content":"用了快一个月来评，拍照效果真的不如同价位的小米直板旗舰，本来以为旗舰机影像肯定够好，结果拍夜景的时候噪点特别多，色彩也偏寡淡，完全达不到宣传里说的徕卡调校水准。还有就是折叠屏自带的重量，揣牛仔裤口袋里总往下滑，坐下来一不小心就容易被硌到。最坑的是买的时候说送的专属皮质手机壳，等了整整两周才发货，体验感真的大打折扣。"}]}}'::jsonb, '2_数码电子/data/p_digital_010.json'),
    ('p_digital_011', '小米平板 8 Pro 12.1英寸高刷大屏影音娱乐学习办公平板电脑', '小米', '数码电子', '平板电脑', '数码电子/平板电脑', 3299.0, 3299.0, 3799.0, 400, '2_数码电子/images/p_digital_011_live.jpg', '{"product_id":"p_digital_011","title":"小米平板 8 Pro 12.1英寸高刷大屏影音娱乐学习办公平板电脑","brand":"小米","category":"数码电子","sub_category":"平板电脑","base_price":3299.0,"image_path":"2_数码电子/images/p_digital_011_live.jpg","skus":[{"sku_id":"s_p_digital_011_1","properties":{"运行内存":"8GB","机身存储":"256GB","网络版本":"Wi-Fi版"},"price":3299.0},{"sku_id":"s_p_digital_011_2","properties":{"运行内存":"8GB","机身存储":"512GB","网络版本":"Wi-Fi版"},"price":3599.0},{"sku_id":"s_p_digital_011_3","properties":{"运行内存":"12GB","机身存储":"256GB","网络版本":"Wi-Fi版"},"price":3499.0},{"sku_id":"s_p_digital_011_4","properties":{"运行内存":"12GB","机身存储":"512GB","网络版本":"Wi-Fi版"},"price":3799.0}],"rag_knowledge":{"marketing_description":"小米平板8 Pro搭载12.1英寸高刷大屏，2.8K超清分辨率配合144Hz自适应刷新率，刷剧玩游戏丝滑不拖影，双超大存储版本可选，8+256G刚好装下几十部高清剧和全套学习课件，12+512G适合存大量设计素材和办公文档。适配小米生态跨屏互联，手机碰一下就能秒传文件，多窗口分屏最多同时开4个应用，上网课的同时能记笔记查资料。不管是学生党上网课刷题库、上班族移动轻办公改报表，还是宅家追剧打休闲游戏都很适配。建议搭配原装磁吸触控笔和键盘套使用体验更好，注意它仅支持Wi-Fi联网，外出没有热点的话得连手机热点，长时间高负载使用时建议摘掉厚重的保护壳辅助散热哦。","official_faq":[{"question":"小米平板8 Pro的12.1英寸高刷屏适配哪些影音、游戏的高帧率模式呀？","answer":"这款平板的144Hz自适应高刷已经完成了主流视频平台、热门手游的帧率适配，像腾讯视频、爱奇艺的高帧专属片源可以直接开启满帧播放，《王者荣耀》《和平精英》等主流MOBA、射击手游都开放了90帧及以上的帧率选项，日常刷系统界面、滑动文档、拖拽图片也会自动维持高刷新率。它还会根据显示内容自动调节刷新率，看静态电子书的时候会降到1Hz，既能保证顺滑体验还能省不少电量。"},{"question":"小米平板8 Pro的跨屏互联功能和小米手机联动的时候能实现什么特殊操作？","answer":"只要你的小米手机和平板登录同一个小米账号、连同一个Wi-Fi，不需要数据线就能触发联动，手机的画面可以直接无缝投屏到平板上，你甚至能用平板的触控屏直接操作手机里的APP，手机里收到的微信文件、拍的照片拖一下就能直接存到平板的本地文件夹里。平时你在手机上没写完的备忘录、没编辑完的文档，坐到平板前点开就能自动接续编辑，不用来回发文件传素材，办公学习的效率能提升不少。"},{"question":"8GB+256GB和12GB+512GB两个Wi-Fi版本实际用起来差异大吗？选哪个更划算？","answer":"如果是日常只用来刷剧、上网课记笔记，后台只挂2-3个APP的话，8GB运存的版本完全够用，256GB存储空间装下几十部高清视频、上百G学习课件也完全没问题，性价比很高。但如果你平时习惯同时开四五个APP分屏用，还经常要存高清设计素材、大量原画资源或者喜欢下载很多大型手游，就更推荐12GB+512GB的版本，后台留存率更高，用个三四年也不容易出现存储空间不够、多开卡顿的情况，适合重度使用的用户。"},{"question":"这款12.1英寸的平板支持的触控笔有没有特殊的笔记书写优化功能？","answer":"搭配小米灵感触控笔使用的时候，它最高支持4096级压感，笔尖延迟低到只有2ms，在屏幕上写字几乎和在纸上书写的手感一样，还自带全局随手写功能，哪怕你在微信聊天框、浏览器地址栏里也能直接写字转成文本，不用切换输入法。笔记APP里还支持随手画的图形自动修正、手写文字一键转成可编辑的文档，甚至你手写的公式也能自动识别转成可编辑的电子版，对上网课记笔记的学生党特别友好。"},{"question":"这款平板没有插卡蜂窝版本，外出的时候怎么实现随时联网呀？","answer":"小米平板8 Pro的两个版本都是纯Wi-Fi版，本身没有内置插卡的蜂窝模块，没法直接插SIM卡使用，外出的时候你可以直接开启身边小米手机的热点功能，平板连上热点就能正常上网，而且同账号的小米手机会自动给平板共享热点，不需要手动输密码，一碰就连上。你也可以随身携带一个小型的随身Wi-Fi设备，平时需要移动办公、户外上网课的时候直接连随身Wi-Fi的信号，就能摆脱没有公共Wi-Fi的联网限制。"}],"user_reviews":[{"nickname":"小宁","rating":5,"content":"用了快两周真的太香了！12.1英寸的大屏看网课比我之前的小平板舒服太多，144Hz刷新率滑动笔记页面一点都不卡，我平时上网课分屏一边放老师直播一边记笔记，偶尔还能开个小窗查资料，8+256G装了一整个学期的课件和几十部动漫也还剩很多空间。和我的小米13联动传作业照片点一下就传完了，完全不用发微信文件倒腾，这个价格能买到这种配置真的太值了。"},{"nickname":"阿凯","rating":3,"content":"整体用下来只能说中规中矩，本来冲着高刷屏买来想打手游，没想到很多小众的独立游戏压根没适配这么高的刷新率，开了高刷反而偶尔会掉帧卡顿。而且12.1英寸实在太大了，我本来想揣包里通勤的时候拿出来看剧，结果普通的电脑包塞进去都挤得慌，单手举着刷十分钟胳膊就酸了，重量控制得不如我之前用的旧款平板，要是能做轻个两百克就好了。"},{"nickname":"小棠","rating":1,"content":"买之前没注意全是Wi-Fi版本，想着外出出差能临时改个报表，结果到了高铁站没公共Wi-Fi，我自己手机流量刚好不够用，连热点折腾了十分钟都连不上，耽误了我赶客户方案的时间。而且我买的12+512G版本，用了不到一周多开三个办公软件就开始出现后台杀进程的情况，之前同价位别的品牌平板都没这问题，感觉这个价格买得太不值了，现在已经申请退货了。"}]}}'::jsonb, '2_数码电子/data/p_digital_011.json'),
    ('p_digital_012', 'Apple MacBook Pro 16英寸 M5 Pro 芯片 32GB 1TB 创意设计师笔记本电脑', 'Apple 苹果', '数码电子', '笔记本电脑', '数码电子/笔记本电脑', 21999.0, 21999.0, 29999.0, 1200, '2_数码电子/images/p_digital_012_live.jpg', '{"product_id":"p_digital_012","title":"Apple MacBook Pro 16英寸 M5 Pro 芯片 32GB 1TB 创意设计师笔记本电脑","brand":"Apple 苹果","category":"数码电子","sub_category":"笔记本电脑","base_price":21999.0,"image_path":"2_数码电子/images/p_digital_012_live.jpg","skus":[{"sku_id":"s_p_digital_012_1","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"32GB","固态硬盘容量":"1TB SSD","颜色":"银色"},"price":21999.0},{"sku_id":"s_p_digital_012_2","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"32GB","固态硬盘容量":"1TB SSD","颜色":"深空黑"},"price":21999.0},{"sku_id":"s_p_digital_012_3","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"32GB","固态硬盘容量":"2TB SSD","颜色":"银色"},"price":23999.0},{"sku_id":"s_p_digital_012_4","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"32GB","固态硬盘容量":"2TB SSD","颜色":"深空黑"},"price":23999.0},{"sku_id":"s_p_digital_012_5","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"48GB","固态硬盘容量":"1TB SSD","颜色":"银色"},"price":25999.0},{"sku_id":"s_p_digital_012_6","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"48GB","固态硬盘容量":"1TB SSD","颜色":"深空黑"},"price":25999.0},{"sku_id":"s_p_digital_012_7","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"48GB","固态硬盘容量":"2TB SSD","颜色":"银色"},"price":27999.0},{"sku_id":"s_p_digital_012_8","properties":{"尺寸":"16英寸","芯片型号":"M5 Pro","运行内存":"48GB","固态硬盘容量":"2TB SSD","颜色":"深空黑"},"price":27999.0},{"sku_id":"s_p_digital_012_9","properties":{"尺寸":"16英寸","芯片型号":"M5 Max","运行内存":"64GB","固态硬盘容量":"1TB SSD","颜色":"银色"},"price":27999.0},{"sku_id":"s_p_digital_012_10","properties":{"尺寸":"16英寸","芯片型号":"M5 Max","运行内存":"64GB","固态硬盘容量":"1TB SSD","颜色":"深空黑"},"price":27999.0},{"sku_id":"s_p_digital_012_11","properties":{"尺寸":"16英寸","芯片型号":"M5 Max","运行内存":"64GB","固态硬盘容量":"2TB SSD","颜色":"银色"},"price":29999.0},{"sku_id":"s_p_digital_012_12","properties":{"尺寸":"16英寸","芯片型号":"M5 Max","运行内存":"64GB","固态硬盘容量":"2TB SSD","颜色":"深空黑"},"price":29999.0}],"rag_knowledge":{"marketing_description":"这台搭载M5 Pro/Max芯片的16英寸MacBook Pro，是为创意从业者量身打造的生产力猛兽。核心卖点直接拉满：最高可选64GB统一内存与2TB高速SSD，应对8K视频剪辑、3A级3D建模渲染、上百图层的PS/AI大型设计文件丝毫不卡，16英寸Liquid Retina XDR显示屏支持P3广色域与1600尼特峰值亮度，做调色修图完全不用外接校色屏。机身采用全金属一体成型工艺，连续续航最长可达22小时，赶方案跑外地不用随身带充电器。适配人群覆盖影视后期设计师、3D建模师、资深游戏开发者、专业编曲制作人，不管是居家工作室干活、线下采风剪素材、跨城出差赶提案都能用。建议日常使用搭配官方氮化镓充电器更轻便，注意不要和尖锐硬物放在一起避免机身掉漆，长时间高负载运行时别放在毛绒床面这类不透气的表面上影响散热。","official_faq":[{"question":"M5 Pro芯片款的32GB内存版本同时运行PR剪4K视频和AE做动态特效会不会卡顿？","answer":"完全不会出现卡顿情况，M5 Pro芯片的统一内存架构和CPU、GPU是直连的，比传统PC的独立内存调用效率高40%左右，32GB版本同时导入2条4K 60fps素材时间线，后台挂着AE的10层动态粒子特效工程，再开PS调整海报素材也能流畅切换，渲染导出速度比上一代M3 Pro同配置版本快接近35%。唯一需要注意如果是同时处理超过3条8KRAW素材的场景，更建议选48GB及以上内存的版本，能进一步提升操作顺滑度。"},{"question":"16英寸的深空黑版本机身是不是特别容易沾指纹？有没有什么应对小技巧？","answer":"深空黑版本采用的是阳极氧化工艺的哑光金属机身，确实相比银色亮面机身更容易留下指纹印，尤其是手心容易出汗的用户使用一段时间后，C面掌托位置会留下明显的痕迹。日常使用可以搭配超细纤维的清洁软布随手擦，或者选适配16英寸MacBook Pro的哑光机身保护膜，完全不会遮挡机身原本的细腻质感，贴完之后就基本不会留下指纹痕迹，也不会影响机身的散热性能，注意不要用酒精类腐蚀性液体直接擦机身，会破坏表面的阳极氧化涂层导致发乌。"},{"question":"我是做音乐编曲的用户，这台机器的外接声卡和多台MIDI设备的兼容性怎么样？","answer":"这台16英寸MacBook Pro自带的HDMI 2.1接口、SDXC卡槽还有3个雷雳5接口，完全能覆盖编曲用户的外接需求，同时插2台雷电接口的专业声卡、3台MIDI键盘控制器再加外接高速音源硬盘，不需要额外接扩展坞就能识别所有设备，延迟比上一代M系列机型低近20%，哪怕同时加载上百个软音源插件跑大型编曲工程，也不会出现设备断连、爆音的情况。系统里自带的音频MIDI设置可以直接批量管理所有外接设备，不需要额外安装复杂驱动，适配Logic Pro、Cubase等主流编曲软件的最新版本。"}],"user_reviews":[{"nickname":"阿泽","rating":2,"content":"用了快两周了，说下糟心的点：买的是32GB银色版本，明明是全新机，第一次打开底部螺丝有一个明显的拧过痕迹，找客服折腾了三天才同意换货，本来等着赶项目用凭空耽误了快一周时间。而且全负载渲染视频的时候转轴位置特别烫，键盘上方的区域摸着手感都有点热，以前用旧款16寸完全没这么夸张，续航也没宣传的那么好，剪4K素材满电也就撑8个小时，远达不到标称的22小时，有点失望。"},{"nickname":"小磊","rating":1,"content":"太闹心了，入手的是M5 Max 64GB 2TB深空黑版本，刚到手第三天屏幕就出现了一条细细的亮线，打苹果官方售后说不是AC+不保，线下检测点跑了两次，给的说法是屏幕暗部出现瑕疵属于小概率品控问题，换货还要等半个月。本来是赶着接了客户的8K剪辑急单，这下直接耽误了交付赔了违约金，两万多买的东西品控做成这样，后续维权的成本比商品本身的糟心程度还高，再也不想踩坑了。"},{"nickname":"小棠","rating":3,"content":"作为平面设计师入手的这款32GB银色版本，用了一个月，性能倒是没的说，几百图层的PS文件打开速度比我旧的Intel笔记本快太多。但有个很头疼的问题，我平时外接两台4K显示器做双屏调色，时不时就会出现画面闪一下的情况，找了技术调试好几次也没彻底解决，苹果系统更新好几次也没修复这个bug。还有键盘的键程太短了，我每天敲四五个小时快捷键，手指尖都磨得有点发酸，用着实在不习惯，只能自己外接机械键盘用。"},{"nickname":"阿柠","rating":5,"content":"做影视后期的毫不犹豫冲了48GB的深空黑版本，用了快半个月简直幸福感拉满！之前用旧笔记本导出一条10分钟的4K广告片要等40多分钟，现在用这台跑导出15分钟就搞定了，省下来的时间能多接好几个私单。屏幕调色太准了，客户过来校色连我外接的专业校色仪都没找出色差，出差带出去剪素材满电扛一整天完全不用带充电器，机身重量也比想象中轻，背在包里逛现场拍素材完全不累，这钱花得太值了。"},{"nickname":"阿凯","rating":4,"content":"整体用下来还挺满意的，我是做3D建模的，买的M5 Pro 32GB 1TB银色款，跑C4D的大场景渲染速度比之前的旧Mac快了一倍多，平时开工程预览基本不会卡。就是有两个小槽点，一个是包装里居然不给配快充头，我之前的旧Mac充电头功率不够，得额外花几百买新的，另一个就是触控板太大了，我打字的时候手掌不小心总碰到触控板，光标到处乱跑，只能手动关掉触控板用鼠标，要是后续系统能优化一下误触的识别逻辑就更完美了。"}]}}'::jsonb, '2_数码电子/data/p_digital_012.json'),
    ('p_digital_013', 'Apple iPad Pro 13英寸 (M5) Liquid视网膜 XDR 显示屏 256GB Wi‑Fi 平板电脑', '苹果', '数码电子', '平板电脑', '数码电子/平板电脑', 8999.0, 8999.0, 11499.0, 800, '2_数码电子/images/p_digital_013_live.jpg', '{"product_id":"p_digital_013","title":"Apple iPad Pro 13英寸 (M5) Liquid视网膜 XDR 显示屏 256GB Wi‑Fi 平板电脑","brand":"苹果","category":"数码电子","sub_category":"平板电脑","base_price":8999.0,"image_path":"2_数码电子/images/p_digital_013_live.jpg","skus":[{"sku_id":"s_p_digital_013_1","properties":{"屏幕尺寸":"13英寸","存储容量":"256GB","版本":"Wi‑Fi","颜色":"深空黑"},"price":8999.0},{"sku_id":"s_p_digital_013_2","properties":{"屏幕尺寸":"13英寸","存储容量":"256GB","版本":"Wi‑Fi","颜色":"银色"},"price":8999.0},{"sku_id":"s_p_digital_013_3","properties":{"屏幕尺寸":"13英寸","存储容量":"256GB","版本":"蜂窝网络","颜色":"深空黑"},"price":9999.0},{"sku_id":"s_p_digital_013_4","properties":{"屏幕尺寸":"13英寸","存储容量":"256GB","版本":"蜂窝网络","颜色":"银色"},"price":9999.0},{"sku_id":"s_p_digital_013_5","properties":{"屏幕尺寸":"13英寸","存储容量":"512GB","版本":"Wi‑Fi","颜色":"深空黑"},"price":10499.0},{"sku_id":"s_p_digital_013_6","properties":{"屏幕尺寸":"13英寸","存储容量":"512GB","版本":"Wi‑Fi","颜色":"银色"},"price":10499.0},{"sku_id":"s_p_digital_013_7","properties":{"屏幕尺寸":"13英寸","存储容量":"512GB","版本":"蜂窝网络","颜色":"深空黑"},"price":11499.0},{"sku_id":"s_p_digital_013_8","properties":{"屏幕尺寸":"13英寸","存储容量":"512GB","版本":"蜂窝网络","颜色":"银色"},"price":11499.0}],"rag_knowledge":{"marketing_description":"这款搭载M5芯片的13英寸iPad Pro，配备Liquid视网膜XDR显示屏，峰值亮度最高可达1600尼特，阳光下看设计稿、剪4K影片都能看清暗部细节。256GB起步的存储容量，存满上百个专业绘图工程、几十部4K剪辑素材都毫无压力，Wi-Fi版完全能覆盖居家办公、画室创作、大学生做课设的日常需求，深空黑和银色两个配色适配不同使用场景。特别适合平面设计师、短视频创作者、高校美术生这类专业用户，日常用Apple Pencil写画延迟几乎感知不到。使用时建议搭配官方类纸膜减少屏幕反光，平时别把它长时间放在阳光直射的汽车中控台，避免XDR屏长时间处于极端高温下影响色彩校准精度。","official_faq":[{"question":"这款13英寸M5版iPad Pro的Liquid视网膜XDR屏，和上一代12.9英寸机型的显示效果差别大吗？","answer":"差别还是比较明显的，这款13英寸机型把屏幕尺寸升级的同时，把峰值全屏亮度提升到了1000尼特，看HDR纪录片的时候亮部细节不会像之前的机型那样发灰，峰值触发的HDR亮度更是高达1600尼特，你对着阳光修户外人像的亮部光斑也不会过曝丢失细节。而且这次屏幕的色准校准精度进一步提升，专业修图时导出的色彩和后期在Mac上打开的匹配度比上一代高不少，画高色域插画几乎不用再二次校色。日常使用完全不用担心色彩偏移的问题。"},{"question":"M5芯片的256GB Wi-Fi版iPad Pro，同时运行Procreate、Pr移动版和多台云文档后台会不会卡顿？","answer":"完全不会出现卡顿的情况，M5芯片的CPU性能比上一代M4提升了足足35%，还有统一内存架构加持，256GB版本的内存带宽也做了升级，你同时在Procreate里开带上百个图层的大尺寸画布，后台挂着正在渲染的短视频剪辑工程，再开十几个网页云文档查参考资料，切换的时候都不会有后台进程被刷掉的情况。就算你直接在平板上导出时长10分钟的4K 60fps视频，速度也比上一代机型快近一倍，专业创作者重度用也完全够用。"},{"question":"不同配置的13英寸M5 iPad Pro，除了存储和蜂窝功能，还有其他硬件上的区别吗？","answer":"没有其他硬件差异，不管是256GB Wi-Fi深空黑款、512GB Wi-Fi银色款，还是512GB蜂窝网络深空黑款，用的都是完全一致的M5芯片、同款Liquid视网膜XDR显示屏，扬声器、摄像头、支持的Apple Pencil和妙控键盘配件参数也完全相同，只是存储容量和网络模块有区别。你如果平时只在家或者有稳定Wi-Fi的场景用，选256GB Wi-Fi版完全足够，经常外出跑线下拍摄场地需要随时传素材的话，选蜂窝版就更方便。"},{"question":"这款支持蜂窝网络的512GB版本iPad Pro，可以直接插国内的普通SIM卡用流量吗？","answer":"可以正常使用国内三大运营商的普通Nano-SIM卡，不需要额外办理特殊的物联网卡，插卡之后就能直接接入5G网络，在外景地没有Wi-Fi的时候随时传几个G的 RAW格式设计稿都很快。不过要注意这个蜂窝版是不支持传统的语音通话功能的，只能走流量使用网络服务，你如果需要接打电话可以用FaceTime或者第三方通讯APP实现。它的eSIM功能国内三大运营商大部分地区也都支持办理，不用带实体卡也能随时联网。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"收到拆封才发现屏幕左下角有一个肉眼可见的亮斑，联系客服来回踢皮球，说要我自己拿到苹果官方售后出检测报告才能换，我来回跑检测点花了快两天时间，耽误了我要交的设计项目交稿时间。本来冲着M5芯片的性能想提升工作效率，结果刚拿到手就出问题，折腾这么久体验实在太差，完全不值近九千的价格，真的不建议大家没验机就直接激活。"},{"nickname":"小雯","rating":1,"content":"我本来以为256GB的存储空间足够我用来存插画工程，结果买完才发现系统自带的预留空间就占了快30GB，我装完Procreate、PS移动版几个常用软件，再存了几十张未导出的分层插画，内存直接红了大半。问了客服才知道这个版本没有对外扩展存储的功能，我平时要存的素材多根本不够用，当初要是提前知道这个情况绝对不会选256GB的版本，太坑了。"},{"nickname":"阿泽","rating":2,"content":"用了半个月整体体验不算好也不算坏，M5芯片的性能确实流畅，但是13英寸的机身太重了，单手握持刷半小时网课手腕就酸得不行，放在包里带出门比我之前的旧款iPad重了快半斤，出门上课背着特别累。而且原装的妙控键盘还要额外花两千多买，不搭配的话输入文字效率特别低，零零总总配下来花的钱远超预期，性价比实在不高，只能勉强给个两星。"},{"nickname":"星子","rating":5,"content":"做短视频后期的我直接吹爆这款iPad Pro！Liquid视网膜XDR屏的色彩真的太准了，我在外景地剪样片，导出之后传到电脑上看色彩几乎没差，M5芯片导出10分钟的4K视频几分钟就搞定，一点都不卡。13英寸的大小拿在手里画画刚好，用Apple Pencil画线条延迟特别低，就跟在纸上画一样顺手，256GB的容量存我平时的工程完全够用，这段时间用它外出办公效率提升了好多，太满意了。"},{"nickname":"大强","rating":1,"content":"我之前的老iPad充电器还能凑合用，结果这款13英寸M5的iPad Pro完全不支持旧的20W快充头，充电速度慢得离谱，从零充到满要三个多小时，我赶项目的时候没电了急得要死，客服还说要我额外买原装的45W充电器，一个充电器就要四百多，本来机子价格就不便宜，各种配件还要单独花钱，太不实在了，这个体验真的让人很生气。"}]}}'::jsonb, '2_数码电子/data/p_digital_013.json'),
    ('p_digital_014', 'OPPO Find N6 内折柔性大屏旗舰折叠屏手机多任务办公影音体验', 'OPPO', '数码电子', '智能手机', '数码电子/智能手机', 9699.0, 9699.0, 11299.0, 400, '2_数码电子/images/p_digital_014_live.jpg', '{"product_id":"p_digital_014","title":"OPPO Find N6 内折柔性大屏旗舰折叠屏手机多任务办公影音体验","brand":"OPPO","category":"数码电子","sub_category":"智能手机","base_price":9699.0,"image_path":"2_数码电子/images/p_digital_014_live.jpg","skus":[{"sku_id":"s_p_digital_014_1","properties":{"存储":"12GB+512GB","版本":"标准版"},"price":9699.0},{"sku_id":"s_p_digital_014_2","properties":{"存储":"12GB+512GB","版本":"高配版"},"price":10499.0},{"sku_id":"s_p_digital_014_3","properties":{"存储":"16GB+1TB","版本":"标准版"},"price":10499.0},{"sku_id":"s_p_digital_014_4","properties":{"存储":"16GB+1TB","版本":"高配版"},"price":11299.0}],"rag_knowledge":{"marketing_description":"OPPO Find N6是主打内折柔性大屏体验的旗舰折叠屏，搭载经过多次迭代的精工铰链，折痕几乎隐于7.82英寸的内折大屏之下，展开后屏幕比例接近黄金比例，不管是同时打开微信、文档和会议界面的多任务办公，还是拉满画幅看杜比视界大片，沉浸感拉满。它分12GB+512GB标准版和16GB+1TB高配版两个规格，适配经常外勤的职场办公族、资深影音爱好者、需要兼顾工作娱乐的数码发烧友。平时用尽量避免尖锐物品直接刮擦内屏，折叠时不要夹到细碎的小物件，长期重度多任务运行时可以适当开启系统自带的内存清理后台，能大幅延长手机的使用生命周期。","official_faq":[{"question":"OPPO Find N6的内屏折叠痕日常使用会不会越来越明显？","answer":"这款机型搭载的是OPPO自研的新一代精工铰链，搭配升级的UTG超韧性玻璃，经过官方超40万次折叠测试后折痕变化幅度极小。日常正常使用下，每天常规开合几十次的频率，折痕不会出现肉眼可见的明显加深，只有在强光斜射特定角度下才能看到极淡的痕迹，完全不影响日常刷内容、办公看文档的视觉体验，正常用三五年也不会出现折痕凸起裂屏的问题。"},{"question":"OPPO Find N6的多任务功能最多支持同时开几个窗口？","answer":"系统原生适配的大屏多任务模式，最多支持同时在展开的大屏上并行开启3个独立悬浮窗口，你可以一边开线上会议、一边改Excel报表、同时还挂着微信回复客户消息，三个窗口互不干扰。如果搭配侧边栏的小窗快捷呼出功能，还能额外调出最多2个迷你小窗，总共5个应用同时后台运行互不杀后台，16GB+1TB的高配版因为运存更大，多任务保活能力比标准版还要高出30%左右。"},{"question":"OPPO Find N6展开之后能不能直接放在桌面上半悬停看视频？","answer":"完全可以实现半悬停体验，铰链的阻尼调校精准，支持从0度完全展开到180度完全闭合之间任意角度悬停，你可以把屏幕折成90度放在桌面上，上半屏放电影下半屏当触控操作面板，也能折成120度的角度架在桌面上开视频会议，不用额外找支架。悬停状态下系统还会自动触发适配的分屏模式，不用手动调整窗口布局，影音和办公场景都能适配。"},{"question":"OPPO Find N6的内屏是柔性屏，贴普通钢化膜会不会影响折叠？","answer":"不建议自行贴普通的硬质钢化膜，这类膜的韧性不足，反复折叠几次就会出现边缘翘边、中间断裂的情况，还可能划伤内屏表面的保护层。官方随机附带的原厂高清水凝膜是专门针对这款机型的折叠曲率定制的，韧性强不留折痕，日常正常使用不需要额外换膜。如果后续需要换膜，优先选OPPO官方门店的专属替换膜，不要随便买第三方不合规的贴膜产品。"},{"question":"OPPO Find N6的12GB+512GB版本和16GB+1TB版本实际使用体验差别大吗？","answer":"日常轻度使用差别不大，主要差距在重度场景下体现：16GB大运存能同时后台保活更多的大型应用，比如你开着大型游戏、十几个办公文档再加直播软件来回切换，也不会出现应用重启的情况；1TB的超大存储空间能存下更多的4K原片、无损音乐和办公素材，不需要频繁外接云盘清理内存。如果是长期重度多任务办公、喜欢存大量影音资源的用户，更推荐入手高配版。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"用了快半个月，体验其实半好半坏吧，大屏看文档确实爽，但是重量比我之前用的普通直板手机重不少，塞在牛仔裤口袋里走久了总觉得坠裤子，单手握持外屏打字久了手腕发酸。还有折叠的时候铰链边缘偶尔会夹到一点口袋里掉出来的细绒毛，清理起来特别麻烦，找了客服也说不是质量问题，只能自己每次开合的时候多留意，整体达不到我预期的旗舰体验。"},{"nickname":"小雯","rating":1,"content":"真的要吐槽一下续航，我买的是标准版，满电状态下连续用大屏开多任务处理办公文件，撑不到4个小时就只剩20%的电，出差在外半天就得找充电宝，完全达不到宣传的长续航。之前用的普通直板手机都能撑一整天，这个折叠屏大屏功耗实在太离谱了，九千多的机子续航做成这样真的很不值，现在出门都得随身带个大块头充电宝，太麻烦了。"},{"nickname":"阿哲","rating":1,"content":"用了不到一个月，内屏中间的折痕突然变得特别明显，强光下甚至能摸到轻微的凸起，我平时正常开合都没用力摔过，也没夹过硬东西，找售后检测说我是日常使用磨损不在保修范围内，要换屏得花小五千，这个质量真的对不起近万块的定价。之前用别的折叠屏用了一年折痕都没这么夸张，这次真的踩大雷了，完全不推荐入手。"},{"nickname":"晓宇","rating":5,"content":"终于等到Find N6到手，这个大屏多任务真的太适合我这种经常跑客户的打工人了！展开屏幕一边改PPT一边挂微信接客户消息，开线上会的时候还能悬浮调出笔记界面记要点，再也不用来回切应用漏消息。折痕控制得特别好，平时日常用几乎注意不到，半悬停架在桌上开视频会议连支架都省了，九千多花得太值，完全就是为办公场景量身定做的旗舰机。"},{"nickname":"阿夏","rating":3,"content":"本来冲着影音体验买的，结果很多常用的视频APP适配做得很差，打开之后不会自动铺满整个大屏，两边留了特别宽的黑边，手动调拉伸的话画面又会变形，看剧的沉浸感打了很大折扣。问了客服说后续会推送系统更新优化适配，但是现在等了快三周还没收到更新通知，花近万买的影音旗舰体验居然还不如便宜的平板，多少有点失望。"},{"nickname":"小泽","rating":4,"content":"整体用下来还是挺满意的，大屏办公的效率确实比之前的直板手机高很多，运存够大开多少应用都不会随便杀后台。就是有两个小问题不太舒服，一个是外屏的尺寸有点窄，单手刷短视频的时候画面拉伸感有点明显，还有就是原装的水凝膜特别容易沾指纹，每次擦完没两分钟又沾得满屏都是，打算过两天去官方门店换个新膜试试，总的来说这个价位表现算中规中矩吧。"}]}}'::jsonb, '2_数码电子/data/p_digital_014.json'),
    ('p_digital_015', 'OPPO Find X9 Ultra 超大底影像旗舰2K高刷屏长续航5G智能手机', 'OPPO', '数码电子', '智能手机', '数码电子/智能手机', 6999.0, 6999.0, 7799.0, 400, '2_数码电子/images/p_digital_015_live.jpg', '{"product_id":"p_digital_015","title":"OPPO Find X9 Ultra 超大底影像旗舰2K高刷屏长续航5G智能手机","brand":"OPPO","category":"数码电子","sub_category":"智能手机","base_price":6999.0,"image_path":"2_数码电子/images/p_digital_015_live.jpg","skus":[{"sku_id":"s_p_digital_015_1","properties":{"存储":"12GB+256GB","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_015_2","properties":{"存储":"12GB+256GB","版本":"高配版"},"price":7399.0},{"sku_id":"s_p_digital_015_3","properties":{"存储":"16GB+512GB","版本":"标准版"},"price":7599.0},{"sku_id":"s_p_digital_015_4","properties":{"存储":"16GB+512GB","版本":"高配版"},"price":7799.0}],"rag_knowledge":{"marketing_description":"这台OPPO Find X9 Ultra是实打实的年度影像旗舰，搭载超大底主摄传感器，搭配自研影像NPU，暗光夜拍、远景抓拍都能出纯净通透的大片，没有普通手机常有的噪点糊片问题。2K分辨率的高刷屏支持自适应刷新率，刷短视频、玩高帧手游时画面丝滑跟手，长时间看剧也不容易眼累。内置大容量电池搭配100W快充，出门跑一天通勤、拍素材也不用到处找充电宝，5G全频段覆盖信号稳得很。特别适合摄影爱好者、重度手游玩家和经常出差的商务人士，日常扫街探店拍美食、周末户外拍风光、通勤刷剧办公都能hold住。建议日常搭配原厂带的素皮壳使用，避免后摄模组刮花，前3次充满后再多充10分钟激活电池活性，注意别边充边玩高负载游戏避免机身过热。","official_faq":[{"question":"OPPO Find X9 Ultra的超大底主摄在夜间拍路边的流动车灯时，能有效抑制过曝拖影吗？","answer":"这款机型的超大底主摄搭配了全新的全域像素动态范围调整算法，默认夜景模式下会自动识别移动光源场景，动态调整曝光时长和ISO数值，拍夜间车流轨迹时既能保留车流光轨的流畅感，也不会让周边的暗部场景过暗丢失细节。如果手动开启流光快门模式，还可以自定义3到30秒的曝光时长，拍出来的车灯轨迹纯净不发虚，就连路边小店的霓虹招牌文字都能拍得清晰不泛白，不会出现普通小底手机常见的整片光斑糊成一团的问题。"},{"question":"这款2K高刷屏在日常使用不同APP的时候，会不会出现功耗过高导致续航缩水的情况？","answer":"这块2K高刷屏搭载了OPPO自研的智能刷新率适配芯片，会实时识别当前运行的APP场景：刷静态图文内容时自动降到1Hz省电模式，刷短视频、浏览网页时调整到90Hz兼顾流畅和功耗，玩支持高帧的大型手游时才会拉满120Hz。实际重度使用场景下，连续刷10小时短视频还能剩余20%左右电量，比固定2K120Hz的同配置机型续航多出近2小时，完全不用额外手动调低分辨率牺牲显示效果来省电。"},{"question":"12GB+256GB标准版和16GB+512GB高配版在后台留存和影像功能上有区别吗？","answer":"两个版本的核心影像硬件、处理器性能、屏幕素质完全一致，影像算法的所有功能包括超光感夜拍、全焦段4K录制都能无差别使用，差别主要在内存和存储规格：12GB+256GB标准版日常同时挂微信、抖音、外卖等6-8个APP完全够用，适合日常拍照不多、不会存大量4K raw格式照片的用户；16GB+512GB高配版能同时留存15个左右的后台应用，长时间玩大型手游也不会出现应用重载，能存近万张高清原片和几十部高清剧集，更适合职业摄影爱好者和重度手游用户。"}],"user_reviews":[{"nickname":"阿泽","rating":3,"content":"用了快半个月，整体体验还行就是有个小问题挺闹心，我平时喜欢裸机用，后摄那个凸起的模组边缘太硌手了，平放桌面的时候机身会跟着镜头打转，好几次放桌边差点滑下去。虽然影像拍出来的夜景确实比我之前旧手机好不少，续航也挺顶的，但这个模组凸起的设计真的不太满意，自己额外买了三个不同厚度的手机壳才能勉强放平，感觉完全可以把模组做平一点提升握持感。"},{"nickname":"小棠","rating":5,"content":"作为一个业余拍风光的爱好者真的太爱这台手机了，上周去山里拍日落，用超大底主摄随手拍的剪影晚霞，暗部的树影细节都清清楚楚，以前带微单出门沉得要死，现在揣兜里随手就能出大片。2K高刷屏看修图的时候色彩准得很，传朋友圈都不用再二次调色，100W快充早上起来洗漱的功夫就充了大半电，出去逛一天拍几百张照片回家还剩三十多电，完全没续航焦虑。"},{"nickname":"阿凯","rating":5,"content":"之前用的旧手机玩原神开中效都掉帧，换这台Find X9 Ultra之后开全高画质加120帧满帧跑两个多小时，机身只是温温的根本不烫。屏幕的2K质感真的甩之前的1080P手机几条街，玩开放世界游戏里远处的建筑纹理都看得清清楚楚，一点都不糊。信号也稳得离谱，我家之前电梯里连微信消息都发不出去，现在电梯里刷短视频都不卡，用了快一个月没碰到过一次卡顿闪退的情况。"},{"nickname":"晚星","rating":5,"content":"平时做美食探店博主，以前带个相机拍店里的暗调环境菜品，经常拍出来噪点多还要后期磨半天，现在用这台手机的超大底主摄，暖光下的牛排纹理、甜品的奶油光泽直出就特别好看，连桌面的木纹细节都不丢。而且5G传素材速度巨快，拍完直接就能导去剪辑软件剪短视频，256G的内存我存了几百张美食原片还有十几个剪辑工程，完全没占满，用着太顺手了。"},{"nickname":"阿远","rating":2,"content":"本来冲着影像功能买的，结果发现系统里自带的很多第三方编辑功能占内存特别大，我没装几个APP256G的存储空间没俩月就剩不到30G，想插存储卡扩容还不支持。而且机身重量比我之前用的手机重不少，单手握持刷半小时微信手就酸得不行，出门装牛仔裤口袋里坠得裤兜都往下滑，虽然拍照画质确实不错，但用久了握持的累手感真的接受不了，感觉不太适合我这种习惯单手操作的用户。"},{"nickname":"大川","rating":1,"content":"刚买了不到一周，今天正常扫街拍照片的时候突然直接黑屏死机，按任何按键都没反应，强制重启了好几次才开开机，里面存的几十张刚拍的 raw 格式照片全损坏了根本打不开。找售后说要返厂检测，我买的新手机就要拆修，而且里面没备份的工作照片全没了，耽误我好多事。六千多的旗舰机用一周就出这种系统崩溃的问题，真的太让人失望了，完全不值这个价位，再也不会买这个系列的手机了。"}]}}'::jsonb, '2_数码电子/data/p_digital_015.json'),
    ('p_digital_016', 'OPPO Reno 16 Pro 轻薄人像摄影高刷屏快充5G智能手机12+256GB', 'OPPO', '数码电子', '智能手机', '数码电子/智能手机', 3299.0, 3299.0, 3699.0, 400, '2_数码电子/images/p_digital_016_live.jpg', '{"product_id":"p_digital_016","title":"OPPO Reno 16 Pro 轻薄人像摄影高刷屏快充5G智能手机12+256GB","brand":"OPPO","category":"数码电子","sub_category":"智能手机","base_price":3299.0,"image_path":"2_数码电子/images/p_digital_016_live.jpg","skus":[{"sku_id":"s_p_digital_016_1","properties":{"存储":"12GB+256GB","版本":"标准版"},"price":3299.0},{"sku_id":"s_p_digital_016_2","properties":{"存储":"12GB+256GB","版本":"高配版"},"price":3449.0},{"sku_id":"s_p_digital_016_3","properties":{"存储":"12GB+512GB","版本":"标准版"},"price":3549.0},{"sku_id":"s_p_digital_016_4","properties":{"存储":"12GB+512GB","版本":"高配版"},"price":3699.0}],"rag_knowledge":{"marketing_description":"OPPO Reno 16 Pro是专门为爱拍人像的年轻用户打造的轻薄5G旗舰机，整机拿在手里几乎没有坠手感，长时间刷剧出门扫街揣口袋都毫无负担。核心的人像摄影系统搭配原生柔光环，暗光下拍夜市合照、咖啡馆氛围感照片都不用额外补光，肤感磨皮自然不假白。搭载的高刷屏刷短视频、玩轻度手游时跟手度拉满，搭配大毫安时电池和满血快充，出门忘充电午休充10分钟就能刷一下午社交软件。特别适合喜欢记录日常通勤、和闺蜜出游、下班探店瞬间的学生党、职场新人，平时用机尽量别用非官方的快充头，避免损伤电池健康，裸机使用建议单独贴高清钢化膜防刮花。","official_faq":[{"question":"OPPO Reno 16 Pro的人像拍照在夜景暗光环境下会不会糊？","answer":"完全不用担心这个问题，这款机型专门在前置和后置人像模组都搭载了自研的自然人像柔光环，光圈尺寸相比上一代提升了27%，暗光进光量直接拉满。哪怕你是在深夜路边摊、光线昏暗的清吧里拍合照，也不用开闪光灯晃得大家睁不开眼，拍出来的人脸不会出现油光反光，背景的夜市灯光、店面霓虹灯还能保留自然的虚化光斑，肤色还原得很通透，完全不会出现普通手机夜景人像发灰发糊的问题，直出就能发朋友圈。"},{"question":"12GB的运行内存后台能同时保留多少个常用APP不被杀？","answer":"这款Reno 16 Pro搭载了OPPO自研的内存拓展技术，12GB的物理运存最高可以拓展到等效24GB的运行空间，日常你同时挂微信、QQ、淘宝、抖音、小红书还有办公的文档APP，来回切换基本不会出现重新加载的情况，正常用机场景下能稳定保留15个以上常用第三方APP后台。就算你中途切出去打半小时手游，切回微信的时候也不用重新登录，之前打开的聊天记录、刷到一半的商品页面都会原封不动保留着，不用重复加载浪费时间。"},{"question":"它的高刷屏日常刷应用和玩游戏的时候会不会很费电？","answer":"这款机型的高刷屏搭载了智能动态帧率调节技术，不是全程锁死高刷的，在你看静态电子书、浏览长图内容的时候会自动降到合适的低帧率降低功耗，刷短视频、刷社交信息流的时候自动切换到高刷保证流畅度。日常中度使用的话满电支撑一整天完全没问题，就算你连续2小时玩轻度的MOBA类手游，耗电也不到30%，完全不用为了续航特意把高刷关掉，兼顾了流畅体验和续航表现，不会出现普通高刷手机掉电飞快的情况。"},{"question":"标准版12+256GB和高配版12+512GB除了存储大小还有别的区别吗？","answer":"两个版本除了机身存储的容量不同之外，其他所有硬件配置、功能体验都是完全一致的，人像摄影模组、高刷屏参数、快充功率还有5G基带规格没有任何阉割。256GB的版本适合日常只是拍点普通照片、存少量app和视频的用户，足够日常一两年的存储需求，3299的性价比很高。512GB的版本更适合喜欢拍4K人像vlog、存大量剧和游戏资源的用户，不用频繁清理存储空间，用三四年也不用担心内存不够用，定价3699也很划算，大家可以根据自己的存储需求选就行。"},{"question":"这款手机的轻薄机身会不会容易摔碎，抗摔性怎么样？","answer":"这款Reno 16 Pro虽然机身做了轻薄处理，整机重量控制在180g以内，但屏幕和后盖都用了经过强化的抗摔玻璃材质，日常从桌面高度不小心滑落掉到木质地板上，基本不会出现碎裂的情况，正常使用完全没问题。但它毕竟没有额外的专业防摔认证，还是不建议大家故意让手机摔落，如果日常经常手滑的用户，搭配赠送的软硅胶手机壳使用，就能进一步降低摔碎的风险，完全可以满足普通用户日常的防摔需求。"},{"question":"它的满血快充从0充到满大概需要多长时间，支持边充边玩吗？","answer":"这款机型搭载的是OPPO自家的满血超级闪充，在熄屏状态下从0电量充到100%，只需要不到35分钟，就算你早上起来发现手机忘充电，洗漱收拾的十几分钟就能充到60%以上，完全能满足你出门一整天的用电需求。它本身搭载了完善的充电温控保护机制，正常边充边刷短视频聊微信是完全没问题的，不会出现严重发烫的情况，不过还是不建议边快充边玩大型手游，会让机身温度升高，长期这样操作会轻微损耗电池的使用寿命。"}],"user_reviews":[{"nickname":"阿凯","rating":2,"content":"用了快两周真的有点失望，本来冲着人像摄影买的，结果晴天户外拍人像的时候，后置镜头的算法过度磨皮，把我脸上的痘印全磨没就算了，连眉毛的毛流感都给磨没了，拍出来的人像假得像网图。还有宣传的高刷屏，部分小众的第三方APP居然锁60帧，刷起来明显卡顿，3千多的机子这个表现真的不值这个价，跟之前用的旧Reno比体验没提升多少。"},{"nickname":"小棠","rating":5,"content":"这机子真的买对了！我平时特别爱和朋友出门探店拍照片，之前的旧手机在暖光的咖啡馆里拍出来的人脸总是发黄，这个Reno16Pro拍出来的肤色特别通透，自带的虚化把背景的蛋糕灯虚化得特别好看，直出都不用修图直接发朋友圈。整机拿在手里轻得离谱，我这种小手女生单手握一下午刷手机也不累，快充午休充十分钟下午逛一下午街都有电，太适合我们这种爱拍照的女生了。"},{"nickname":"阿哲","rating":2,"content":"本来冲着5G和轻薄入的，结果用了不到一个月就发现，信号在地铁里经常会断网，同位置我朋友的其他品牌5G手机都能正常刷短视频，我的这台就转圈圈加载半天。而且机身的后盖太沾指纹了，我就算天天擦，用十分钟就全是油印子，看着特别显脏，送的手机壳质感也特别差，用两天边就发黄了，这个价格买真的感觉踩坑了，体验远不如预期。"}]}}'::jsonb, '2_数码电子/data/p_digital_016.json'),
    ('p_digital_017', 'vivo X300 Ultra 旗舰影像2K护眼屏长续航高性能5G智能手机', 'vivo', '数码电子', '智能手机', '数码电子/智能手机', 6999.0, 6999.0, 7799.0, 400, '2_数码电子/images/p_digital_017_live.jpg', '{"product_id":"p_digital_017","title":"vivo X300 Ultra 旗舰影像2K护眼屏长续航高性能5G智能手机","brand":"vivo","category":"数码电子","sub_category":"智能手机","base_price":6999.0,"image_path":"2_数码电子/images/p_digital_017_live.jpg","skus":[{"sku_id":"s_p_digital_017_1","properties":{"内存组合":"12GB+256GB","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_017_2","properties":{"内存组合":"12GB+256GB","版本":"高配版"},"price":7399.0},{"sku_id":"s_p_digital_017_3","properties":{"内存组合":"16GB+512GB","版本":"标准版"},"price":7399.0},{"sku_id":"s_p_digital_017_4","properties":{"内存组合":"16GB+512GB","版本":"高配版"},"price":7799.0}],"rag_knowledge":{"marketing_description":"vivo X300 Ultra是专门为影像发烧友、高清内容创作者打造的旗舰级5G手机，标配2K级10亿色护眼直屏，支持1920Hz高频PWM调光，长时间剪vlog、刷4K内容眼睛也不容易酸。搭载旗舰级影像模组，大底主摄搭配潜望式长焦，不管是凌晨拍星空特写还是出门扫街抓路人动态都能出大片。满电状态下连续重度使用能撑一整天，搭在的旗舰处理器玩满帧大型手游也不卡顿，特别适合经常外出拍素材的博主、追求顶级使用体验的数码爱好者。日常使用建议贴官方配套的钢化膜，避免刮花高清屏幕，注意不要在超过45度的高温环境下长时间录像，防止机身触发温控保护。","official_faq":[{"question":"这款vivo X300 Ultra的2K护眼屏和普通1.5K屏实际观感有什么区别，长时间看电子书会不会累眼？","answer":"这款的2K屏像素密度比常规1.5K屏高32%左右，显示文字边缘完全没有锯齿，小字号的拍摄参数页也能一眼看清，同时搭载的1920Hz高频PWM调光，在低亮度深夜看两小时电子书也不会像低频调光手机那样出现眼干酸胀的情况，还自带独家的类纸显示模式，开启后屏幕反光率降低40%，户外阳光下看内容也不晃眼，对经常长时间刷手机、处理图文素材的用户非常友好。"},{"question":"这款手机的长续航配置实际拍4K视频能连续录多久，出去玩不用带充电宝够用吗？","answer":"vivo X300 Ultra内置的大电池搭配专属的影像功耗优化算法，连续录制4K 60帧视频可以坚持接近7小时，日常出门逛景区拍一天素材，中间间歇刷社交平台、接打十几个电话，到晚上回家还能剩20%左右的电量，轻度使用甚至可以做到两天一充。标配的120W超快闪充，哪怕临时只剩10%电量，洗漱10分钟就能充到60%以上电量，临时出门应急完全不用慌。"},{"question":"这款旗舰影像配置拍远景的画质和普通带长焦的手机比优势在哪，能不能替代入门级便携相机？","answer":"它搭载的大底潜望式长焦拥有更大的感光面积，搭配vivo独家的夜景长焦算法，哪怕是在傍晚拍100米外的建筑招牌，画面也不会像普通小底长焦那样满是噪点，色彩还原度甚至比很多入门便携卡片机更讨喜。日常外出扫街拍人文、旅拍记录风景，不用额外带沉重的相机，揣口袋里随拿随拍就能出符合社交平台发布要求的高清大片，对非专业级的普通影像爱好者来说完全够用。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"作为常年拍探店素材的博主，换这款手机半个月真的太香了！潜望长焦拍远处的菜品细节不用凑过去打扰客人，2K屏修图的时候色彩准得离谱，导出来的图不用二次调颜色。连续跑一下午探店拍视频，中间还剪了两条1分钟的片段，晚上到家还剩28%的电，之前的旧手机早就得插充电宝了，这个续航真的顶，完全是为我们这种内容创作者量身定做的。"},{"nickname":"小宇","rating":1,"content":"本来冲着旗舰影像买的，结果到手第三天拍夜景的时候，连续录15分钟视频机身就烫得离谱，直接弹出温控提示强制暂停录像，之前用旧款vivo旗舰从来没出现过这种情况。找售后检测说影像模组的散热模块有出厂缺陷，同批次好多用户都反馈了，新机刚买就要返厂拆机维修，花七千多买的旗舰品控做成这样，真的太让人失望了。"},{"nickname":"阿泽","rating":1,"content":"选的16+512高配版花了七千多，结果用了不到一个月，日常刷短视频的时候偶尔会出现屏幕闪跳绿线的情况，重启之后就消失，但是拍出来的视频素材偶尔会有几帧莫名其妙的色彩断层，根本达不到宣传的2K屏和影像旗舰的水准。售后说屏幕是系统驱动bug，要等后续更新，刚买的新机就要靠补丁补问题，这个定价完全对不起实际体验。"}]}}'::jsonb, '2_数码电子/data/p_digital_017.json'),
    ('p_digital_018', 'Apple AirPods Pro 3 主动降噪真无线蓝牙耳机 心率监测版', 'Apple 苹果', '数码电子', '真无线耳机', '数码电子/真无线耳机', 1899.0, 1799.0, 2299.0, 800, '2_数码电子/images/p_digital_018_live.jpg', '{"product_id":"p_digital_018","title":"Apple AirPods Pro 3 主动降噪真无线蓝牙耳机 心率监测版","brand":"Apple 苹果","category":"数码电子","sub_category":"真无线耳机","base_price":1899.0,"image_path":"2_数码电子/images/p_digital_018_live.jpg","skus":[{"sku_id":"s_p_digital_018_1","properties":{"产品版本":"标准版 AirPods Pro 3","充电盒类型":"MagSafe 充电盒","定制服务":"无刻印","附加服务":"无AppleCare+"},"price":1899.0},{"sku_id":"s_p_digital_018_2","properties":{"产品版本":"标准版 AirPods Pro 3","充电盒类型":"MagSafe 充电盒","定制服务":"无刻印","附加服务":"含AppleCare+"},"price":2199.0},{"sku_id":"s_p_digital_018_3","properties":{"产品版本":"标准版 AirPods Pro 3","充电盒类型":"普通无线充电盒","定制服务":"无刻印","附加服务":"无AppleCare+"},"price":1799.0},{"sku_id":"s_p_digital_018_4","properties":{"产品版本":"标准版 AirPods Pro 3","充电盒类型":"普通无线充电盒","定制服务":"无刻印","附加服务":"含AppleCare+"},"price":2099.0},{"sku_id":"s_p_digital_018_5","properties":{"产品版本":"AirPods Pro 3 马年特别款","充电盒类型":"MagSafe 充电盒","定制服务":"定制镌刻","附加服务":"无AppleCare+"},"price":1999.0},{"sku_id":"s_p_digital_018_6","properties":{"产品版本":"AirPods Pro 3 马年特别款","充电盒类型":"MagSafe 充电盒","定制服务":"定制镌刻","附加服务":"含AppleCare+"},"price":2299.0},{"sku_id":"s_p_digital_018_7","properties":{"产品版本":"标准版 AirPods Pro 3","充电盒类型":"普通无线充电盒","定制服务":"定制镌刻","附加服务":"无AppleCare+"},"price":1849.0},{"sku_id":"s_p_digital_018_8","properties":{"产品版本":"标准版 AirPods Pro 3","充电盒类型":"MagSafe 充电盒","定制服务":"定制镌刻","附加服务":"含AppleCare+"},"price":2249.0}],"rag_knowledge":{"marketing_description":"这款Apple AirPods Pro 3心率监测版，核心新增了耳腔式精准心率传感模块，搭配升级的自适应主动降噪功能，最高可抵消48dB环境噪音，支持空间音频头部动态追踪，单次续航可达6小时，搭配MagSafe充电盒总续航最长30小时。特别适合日常通勤的上班族、跑步健身的运动爱好者、长时间戴耳机听网课的学生党使用，早高峰挤地铁、夜跑夜骑、办公室隔绝同事闲聊等场景都能适配。硅胶耳帽有三档尺寸可替换，入耳贴耳不胀耳，运动出汗时心率数据会自动同步到苹果健康APP生成运动报告。使用时建议每两周用干软布擦拭耳机传感区保持清洁，洗澡游泳时务必取下，避免水渍损坏心率监测模组，选马年特别款还能免费定制专属镌刻文字，刻上专属小标记超有纪念意义。","official_faq":[{"question":"这款AirPods Pro 3的心率监测功能需要怎么开启，数据能同步到哪些设备？","answer":"首次配对连接你的iPhone升级到iOS 18及以上系统后，在蓝牙设备详情页打开「心率监测」开关即可自动启用，日常佩戴时耳机贴合耳道就会自动后台监测静息、运动状态下的心率，数据会自动同步到苹果健康APP，同时支持联动Apple Watch Series 9及后续型号的运动记录，跑步时不用额外抬手看手表，耳机端如果监测到心率超出你预设的安全阈值，还会通过轻量的入耳提示音给你预警，运动场景用着特别省心。"},{"question":"三个不同SKU版本的AirPods Pro 3具体有哪些功能差异，选哪个更划算？","answer":"标准版是最基础的配置，带常规MagSafe磁吸充电盒，售价1899元，适合预算适中、平时爱护电子产品的普通用户。马年特别款和标准版硬件配置完全一致，额外提供官方定制激光镌刻服务，最多支持刻12个字符的文字或者专属马年生肖图案，售价1999元，适合想要专属个性化标识、打算买来当礼物送人的用户。带AppleCare+的套装售价2299元，额外覆盖2年的意外损坏保修，出现丢单只、充电盒故障的情况，只需要付极低的服务费就能换新，适合高频使用耳机经常摔碰的用户。"},{"question":"这款新增的心率监测模块会影响耳机的续航和降噪效果吗？","answer":"不会的，苹果给心率传感模块做了超低功耗的优化，后台常规监测状态下，相比前代没有心率功能的AirPods Pro 2，单次续航仅减少15分钟左右，几乎感知不到差异，开启降噪同时开心率监测也能维持5个半小时的连续使用时长。降噪功能的麦克风和心率传感的组件完全独立排布，耳帽的入耳贴合度同时兼顾了降噪密封需求和心率信号采集需求，只要选对适配自己耳型的硅胶帽，降噪效果不会打折扣，不用额外调整设置，两个功能就能同时正常运行。"}],"user_reviews":[{"nickname":"小宇","rating":3,"content":"用了快半个月整体有点小失望，主打心率监测，但是我戴的时候稍微动一下耳机滑出来一点，心率数据就飘得厉害，一会80多一会120多，根本不准。降噪倒是还行，但是之前用AirPods Pro2也差不多这个效果，多花的钱感觉全砸在这个没什么用的心率功能上了。而且耳帽我选的中号，戴俩小时耳道就胀得疼，不知道是不是新的模具做厚了点，体验达不到预期，勉强给三星吧。"},{"nickname":"阿凯","rating":1,"content":"真的踩大雷了，刚收到手拆封连接的时候，左耳的降噪直接有滋滋的底噪，送回去换了个新的，用了不到一周心率监测直接完全失灵，怎么重置都连不上健康APP，找客服说是我耳道太油把传感区堵了，我天天擦耳机也没用。现在降噪偶尔也会断连，跑步的时候直接外放声音，路上社死到抠脚，快两千块的东西品控做成这样，真的太不值这个价了。"},{"nickname":"朵朵","rating":3,"content":"冲着马年特别款来的，特意加钱选了定制镌刻，结果拿到手刻的字歪歪扭扭的，找售后说定制产品不能退换，只能补偿个优惠券。而且心率监测功能只有苹果手机能用，我平时备用机是安卓，完全看不到心率数据，等于花了钱买了个没用的功能。续航也没宣传的那么久，开降噪加心率监测，不到5小时就没电了，通勤来回两个小时，下午还要充一次，用着太闹心。"},{"nickname":"阿泽","rating":5,"content":"这波更新真的戳中我这种常年夜跑人的痛点！之前跑两步就要抬手看手表测心率，现在戴着耳机跑，心率一超就有提示音，完全不用分心。降噪效果真的顶，夜跑路过街边广场舞的喇叭声直接压得干干净净，空间音频开着跑的时候听歌，像在身边放演唱会现场一样。续航也够我连跑三天不用充电，入耳佩戴还稳，跑五公里甩头都没掉，这个价格真的香，苹果这波太懂运动党了。"},{"nickname":"小夏","rating":3,"content":"本来想用来上班摸鱼的时候监测静息心率，结果坐办公室安安静静戴着，它时不时给我弹心率过高的提示，搞得我以为自己心脏出问题，跑去医院花了几百块做体检，结果啥毛病没有。后来才发现是我戴眼镜，镜腿总蹭到耳机侧边的传感区，导致数据乱跳。降噪倒是还行，但是这个心率功能太容易受干扰了，实用性不高，感觉不如直接买前代Pro2划算，有点后悔升级了。"}]}}'::jsonb, '2_数码电子/data/p_digital_018.json'),
    ('p_digital_019', 'vivo Pad 6 Pro 12.1英寸高刷全面屏学习娱乐多任务办公平板电脑', 'vivo', '数码电子', '平板电脑', '数码电子/平板电脑', 3299.0, 3299.0, 4299.0, 600, '2_数码电子/images/p_digital_019_live.jpg', '{"product_id":"p_digital_019","title":"vivo Pad 6 Pro 12.1英寸高刷全面屏学习娱乐多任务办公平板电脑","brand":"vivo","category":"数码电子","sub_category":"平板电脑","base_price":3299.0,"image_path":"2_数码电子/images/p_digital_019_live.jpg","skus":[{"sku_id":"s_p_digital_019_1","properties":{"存储配置":"8GB+256GB","网络版本":"Wi-Fi 版"},"price":3299.0},{"sku_id":"s_p_digital_019_2","properties":{"存储配置":"12GB+256GB","网络版本":"Wi-Fi 版"},"price":3599.0},{"sku_id":"s_p_digital_019_3","properties":{"存储配置":"12GB+512GB","网络版本":"Wi-Fi 版"},"price":3899.0},{"sku_id":"s_p_digital_019_4","properties":{"存储配置":"8GB+256GB","网络版本":"全网通5G版"},"price":3699.0},{"sku_id":"s_p_digital_019_5","properties":{"存储配置":"12GB+256GB","网络版本":"全网通5G版"},"price":3999.0},{"sku_id":"s_p_digital_019_6","properties":{"存储配置":"12GB+512GB","网络版本":"全网通5G版"},"price":4299.0}],"rag_knowledge":{"marketing_description":"vivo Pad 6 Pro搭配12.1英寸高刷全面屏，是专门为学生党、轻办公上班族、影音娱乐爱好者打造的多用途平板。核心卖点是大内存组合搭配高刷新率显示，学习时可以一边开上网课窗口、一边记电子笔记、侧边挂查资料小窗，多任务切换丝滑不卡顿；通勤居家刷剧、玩轻度手游时，屏幕色彩通透流畅度拉满。全金属机身质感扎实，Wi-Fi版无流量卡顿困扰，8+256G版本日常存储课件、存剧完全够用，12+512G版本更适合需要装大量专业绘图、办公软件的用户。使用建议平时搭配原装触控笔记笔记更顺手，注意不要把平板和尖锐硬物放在同一个包里避免刮花屏幕，长期高负载使用时建议摘掉保护壳散热。","official_faq":[{"question":"vivo Pad 6 Pro的分屏多任务功能最多支持同时打开多少个应用，不同内存版本会有差异吗？","answer":"这款平板的系统最多支持同时开启4个应用窗口，包括两个全屏分屏应用加两个悬浮小窗的组合。8GB+256GB版本同时开启3个日常应用比如网课、笔记、浏览器完全不会出现杀后台情况，开4个窗口的话尽量关闭后台闲置程序即可；12GB+512GB版本由于运存更大，哪怕同时开4个占用资源稍高的绘图、办公软件，切换时也几乎不会重载，两个版本的分屏功能逻辑完全一致，仅后台留存能力有区别。"},{"question":"这款12.1英寸的高刷屏看久书眼睛会酸吗，有没有专门针对学习场景的显示优化？","answer":"它的屏幕自带硬件级低蓝光认证，还有专门的学习模式可以自动调整屏幕色温，过滤刺眼的短波蓝光，长时间上网课、看电子教材的时候，屏幕不会像普通平板那样越看越眼酸。高刷模式下翻页、滑动笔记的动作完全没有拖影，不会因为画面卡顿晃眼加重用眼负担，还可以自定义定时提醒休息功能，连续使用45分钟就会弹出提示让你远眺放松，对于学生长时间上网课的场景适配度很高。"},{"question":"vivo Pad 6 Pro两个Wi-Fi版本日常办公存文件够用吗，支持外接移动硬盘扩展存储吗？","answer":"8GB+256GB版本存上千份课件、几十部高清剧集再装十余个常用办公软件完全没有压力，适合日常轻办公的普通用户；12GB+512GB版本可以存储大量设计素材、高清网课资源，甚至能存几十G的大型办公套件离线安装包，适合有大量资料存储需求的用户。两个版本都支持通过OTG转接外接最大2TB的移动硬盘，直接在平板里读取修改办公文件，不用额外传输，临时拷大项目文件也很方便。"},{"question":"这款平板的Wi-Fi信号表现怎么样，隔着两堵墙办公上网课会不会经常断连？","answer":"vivo Pad 6 Pro搭载了专门优化的Wi-Fi6天线模组，针对穿墙场景做了信号增益调校，普通家用路由器环境下，隔着两堵实体承重墙，信号强度依然能维持满格的70%以上，上网课开高清直播、在线协作文档都不会出现卡顿断连的情况。哪怕是在人多的公共会议室连公共Wi-Fi，它也能优先抢占更稳定的信道，不会出现别人的设备都能联网唯独自己平板加载半天的尴尬情况。"},{"question":"vivo Pad 6 Pro不插键盘只用触控操作，做表格改文档方便吗？","answer":"系统自带的办公触控优化逻辑做了专门适配，不用外接键盘，手指点选单元格、拖动调整表格行列宽，双指缩放文档视图都很精准，很少出现误触情况。搭配vivo原装触控笔还能直接在PDF文档、PPT草稿上批注修改，临时改个方案标个重点完全不用找键盘，外出见客户忘带配件的时候，仅凭平板本身就能完成大部分轻办公的应急操作，效率不会打折扣。"}],"user_reviews":[{"nickname":"小周","rating":3,"content":"用了快两周实在有点闹心，本来冲着多任务功能买的想一边上网课一边记笔记，结果8GB版本开了网课和笔记APP之后，后台再切回浏览器经常直接把网课APP给杀了，得重新进直播间重连，好几次老师讲的重点都错过了。而且机身重量比我之前旧平板沉不少，捧着看一小时书胳膊就酸，同价位别的平板都有配套的送手写笔活动，这款笔还得单独买，感觉性价比有点配不上这个定价，挺失望的。"},{"nickname":"阿凯","rating":4,"content":"整体用下来还行，12.1英寸的高刷屏看剧是真的爽，色彩特别鲜艳滑动起来也完全不卡，平时用来追更新的综艺体验拉满。就是有个小问题，自带的系统阅读模式适配的APP太少了，很多第三方小说软件打开没法开启护眼显示，得手动调亮度色温特别麻烦。还有裸机的边框摸起来有点割手，得自己额外买个带边框保护的壳子，要是出厂能送个软壳就更贴心了，整体不算踩雷但小瑕疵确实有点影响体验。"},{"nickname":"小楠","rating":3,"content":"本来买给家里弟弟上网课用的，结果用了一周发现续航实在太拉胯，满电状态下连续开高清网课三个半小时就剩15%的电，官方宣传的长续航完全是虚标。而且底部的扬声器偶尔会出现破音情况，开稍微大一点的网课老师声音就劈了，还得插耳机用。找客服检测说属于正常范围不给退换，三千多买的平板这个体验实在不值这个价，早知道当初加钱选别家的产品了。"},{"nickname":"阿泽","rating":5,"content":"这个平板真的买对了！我平时做新媒体运营，常用平板剪短素材、多开微信、浏览器和笔记APP对接需求，12GB运存的版本来回切完全没有卡顿，从来没出现过后台应用重载的情况。12.1英寸的高刷屏刷短视频、看样片色彩特别准，屏幕清晰度比我之前的旧平板好太多，平时下班躺床上追4K剧沉浸感直接拉满，全金属机身质感也特别棒，同事问了链接都打算入手，这个价格能买到这个配置真的太香了。"},{"nickname":"阿美","rating":3,"content":"冲着办公需求买的，结果连接我家的旧款5GWi-Fi路由器经常断流，每次打开在线文档加载半天，换了别的手机连同一个网都完全没问题，问客服说要我换新款路由器，哪有买个平板还要换路由器的道理。而且自带的便签功能导出成PDF的时候，手写的笔触经常会出现偏移，导出的文件和屏幕上看到的不一样，很多我标出来的重点位置都歪了，用来整理学习笔记特别不方便，用着太闹心。"}]}}'::jsonb, '2_数码电子/data/p_digital_019.json'),
    ('p_digital_020', 'Apple MacBook Air 13英寸 M5 芯片 16GB 512GB 轻薄便携笔记本电脑', 'Apple 苹果', '数码电子', '笔记本电脑', '数码电子/笔记本电脑', 8499.0, 8499.0, 10999.0, 1200, '2_数码电子/images/p_digital_020_live.jpg', '{"product_id":"p_digital_020","title":"Apple MacBook Air 13英寸 M5 芯片 16GB 512GB 轻薄便携笔记本电脑","brand":"Apple 苹果","category":"数码电子","sub_category":"笔记本电脑","base_price":8499.0,"image_path":"2_数码电子/images/p_digital_020_live.jpg","skus":[{"sku_id":"s_p_digital_020_1","properties":{"屏幕尺寸":"13英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"512GB SSD","颜色":"天蓝色"},"price":8499.0},{"sku_id":"s_p_digital_020_2","properties":{"屏幕尺寸":"13英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"512GB SSD","颜色":"午夜色"},"price":8499.0},{"sku_id":"s_p_digital_020_3","properties":{"屏幕尺寸":"13英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"512GB SSD","颜色":"星光色"},"price":8499.0},{"sku_id":"s_p_digital_020_4","properties":{"屏幕尺寸":"13英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"1TB SSD","颜色":"天蓝色"},"price":9499.0},{"sku_id":"s_p_digital_020_5","properties":{"屏幕尺寸":"13英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"1TB SSD","颜色":"午夜色"},"price":9499.0},{"sku_id":"s_p_digital_020_6","properties":{"屏幕尺寸":"13英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"1TB SSD","颜色":"星光色"},"price":9499.0},{"sku_id":"s_p_digital_020_7","properties":{"屏幕尺寸":"15英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"512GB SSD","颜色":"天蓝色"},"price":9999.0},{"sku_id":"s_p_digital_020_8","properties":{"屏幕尺寸":"15英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"512GB SSD","颜色":"午夜色"},"price":9999.0},{"sku_id":"s_p_digital_020_9","properties":{"屏幕尺寸":"15英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"512GB SSD","颜色":"星光色"},"price":9999.0},{"sku_id":"s_p_digital_020_10","properties":{"屏幕尺寸":"15英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"1TB SSD","颜色":"天蓝色"},"price":10999.0},{"sku_id":"s_p_digital_020_11","properties":{"屏幕尺寸":"15英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"1TB SSD","颜色":"午夜色"},"price":10999.0},{"sku_id":"s_p_digital_020_12","properties":{"屏幕尺寸":"15英寸","芯片":"M5芯片","内存":"16GB内存","固态存储":"1TB SSD","颜色":"星光色"},"price":10999.0}],"rag_knowledge":{"marketing_description":"这款搭载M5芯片的13英寸MacBook Air，整机轻至1.24kg薄至1.13cm，全铝Unibody一体成型机身摸起来细腻顺滑，放在通勤包几乎没存在感。16GB统一内存后台同时开十几个网页、修图软件和文档都不卡，512GB起步的SSD传大文件速度拉满，续航满电能撑18小时，出差跑全天会议都不用带充电器。特别适合新媒体从业者日常剪短视频、大学生跑代码写论文、商务人士频繁外勤见客户用，全尺寸蝶式升级剪刀脚键盘敲久了不累，3.5mm耳机孔还保留着。提醒大家不要自行拆机扩容，首次激活建议在苹果官网核验序列号，长期不用保持每月充一次电避免电池亏电。","official_faq":[{"question":"这款搭载M5芯片的13英寸MacBook Air同时运行Lightroom批量修图和微信、浏览器十几页网页会卡顿吗？","answer":"完全不会卡顿，M5芯片的统一内存架构刚好适配16GB的容量，图形处理性能比上一代M3款提升近30%，批量导出200张RAW格式照片仅需3分20秒左右，后台挂着几十页网页和通讯软件也不会出现页面重载的情况。即便是日常同时运行轻量剪映工程、思维导图软件和在线会议软件，整机也只会发出极微弱的风扇声，不会出现掉帧、操作延迟的问题，完全能满足创意类轻度办公用户的多任务需求。"},{"question":"同系列里13英寸512GB天蓝色款和15英寸512GB星光色款除了尺寸外还有其他实际使用差异吗？","answer":"除了机身尺寸和屏幕大小之外，二者的扬声器模组也有区别，15英寸版本搭载了六扬声器的空间音频系统，看影视内容的环绕感比13英寸的四扬声器版本强不少，同时15英寸版本的续航时长要多2小时左右，满电播放本地视频能达到20小时。另外15英寸版本因为机身空间更大，散热冗余更高，长时间负载运行高功耗软件时，机身表面的最高温度要比13英寸版本低2到3摄氏度，更适合需要长时间驻留在电脑前办公的用户，便携性上13英寸款要更适合日常塞小包通勤。"},{"question":"这款16GB内存512GB SSD的M5芯片MacBook Air后续可以自行升级内存或者硬盘容量吗？","answer":"不支持任何形式的后续自行升级，这款MacBook Air的内存和SSD都是出厂时直接和主板集成封装在一起的，没有预留额外的扩容插槽，也不支持市面上第三方的硬改扩容服务。大家选购的时候一定要根据自己的存储需求选好对应规格，如果日常要存大量4K剪辑工程、高清素材或者本地影视资源，更推荐直接选1TB SSD的午夜色版本，避免后续存储空间不足需要频繁外接移动硬盘的麻烦，苹果官方也没有提供这款机型的硬件扩容付费服务，购买前确认好配置能省不少后续麻烦。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"用了半个月说下感受，M5芯片的性能确实没问题，开很多软件都不卡，但天蓝色这个版本的机身沾指纹太明显了，每次从包里拿出来都印满手印，擦半天才能擦干净。还有那个充电接口，我平时用第三方的C口充电器有时候会出现识别慢的情况，要插拔好几次才能充上电，续航也没宣传的18小时那么久，开亮度50%连网办公的话大概12小时左右就没电了，整体不算差但有不少小槽点。"},{"nickname":"小夏","rating":1,"content":"收到货拆开就发现屏幕右下角有个非常明显的亮点，联系客服说要走检测流程折腾了整整三天，送授权点检测完才同意换货。换回来的新机用了不到一周，键盘的R键按下去偶尔会失灵，要使劲按才有反应，我之前用旧款MacBook Air从来没遇到这种品控问题，花八千多买的本连续踩两个坑真的太闹心，现在出门见客户带它都怕关键时刻按不出字，体验感特别差。"},{"nickname":"阿泽","rating":4,"content":"整体用下来大部分地方都挺满意的，16GB内存跑我常用的编程环境特别流畅，机身轻背着通勤完全没负担，续航确实够撑我从早八上课到晚六下晚自习，中途不用找插座。但有个小缺点，就是夏天放在大腿上用，机身底部靠近转轴的位置会有点发热，虽然不烫但温温的贴腿不太舒服，还有就是自带的输入法联想功能不太符合我的使用习惯，自己装第三方输入法偶尔会有半秒的卡顿，瑕不掩瑜吧还是能给个中评。"},{"nickname":"朵朵","rating":5,"content":"真的太喜欢这款本了！天蓝色的机身颜值超高，带去图书馆好多同学问我在哪买的，M5芯片剪我平时拍的vlog素材超级顺，之前旧电脑导出十分钟的视频现在两分钟就搞定。16GB内存后台挂着PS、剪映还有几十页网课网页一点都不卡，满电我出去参加两天的线下展会，白天开资料开线上会，晚上回酒店剪素材，第二天晚上回酒店还有剩余电量，全程没带充电器太爽了，太适合我们新媒体打工人了！"}]}}'::jsonb, '2_数码电子/data/p_digital_020.json'),
    ('p_digital_021', '华为 MatePad Pro 13.2英寸 柔性OLED高刷屏轻办公创作旗舰平板电脑', '华为', '数码电子', '平板电脑', '数码电子/平板电脑', 5199.0, 5199.0, 7299.0, 600, '2_数码电子/images/p_digital_021_live.jpg', '{"product_id":"p_digital_021","title":"华为 MatePad Pro 13.2英寸 柔性OLED高刷屏轻办公创作旗舰平板电脑","brand":"华为","category":"数码电子","sub_category":"平板电脑","base_price":5199.0,"image_path":"2_数码电子/images/p_digital_021_live.jpg","skus":[{"sku_id":"s_p_digital_021_1","properties":{"屏幕尺寸":"13.2英寸","存储":"12GB+256GB","网络版本":"WiFi版","颜色":"砚黑"},"price":5199.0},{"sku_id":"s_p_digital_021_2","properties":{"屏幕尺寸":"13.2英寸","存储":"12GB+256GB","网络版本":"WiFi版","颜色":"宣白"},"price":5199.0},{"sku_id":"s_p_digital_021_3","properties":{"屏幕尺寸":"13.2英寸","存储":"12GB+512GB","网络版本":"WiFi版","颜色":"砚黑"},"price":5699.0},{"sku_id":"s_p_digital_021_4","properties":{"屏幕尺寸":"13.2英寸","存储":"12GB+512GB","网络版本":"WiFi版","颜色":"宣白"},"price":5699.0},{"sku_id":"s_p_digital_021_5","properties":{"屏幕尺寸":"13.2英寸","存储":"12GB+512GB","网络版本":"星闪键盘套装版","颜色":"砚黑"},"price":6299.0},{"sku_id":"s_p_digital_021_6","properties":{"屏幕尺寸":"13.2英寸","存储":"16GB+1TB","网络版本":"星闪键盘套装版","颜色":"宣白"},"price":7299.0}],"rag_knowledge":{"marketing_description":"华为 MatePad Pro 13.2 英寸定位高端轻办公与创作旗舰平板，主打大尺寸柔性 OLED 屏、轻薄机身和跨设备协同体验。13.2 英寸屏幕在分屏看文档、批注 PDF、追剧和轻度修图时都比常见 11 英寸平板更从容，配合高刷显示，手写和滑动操作会更跟手。机身重量控制在大屏平板里相对轻巧的范围，放进通勤包里不会像笔记本那样占空间，适合经常在会议室、咖啡店、教室和高铁上移动使用。它更适合拿来做会议记录、阅读资料、轻量表格处理、手写批注和影音娱乐，如果你本身就在用华为手机或耳机，多设备流转会更顺。需要注意的是，这类大屏平板并不等同于完整笔记本，不建议把它当作重度视频渲染、长时间大型代码编译或专业三维建模的唯一主力设备；若经常外出手写或办公，建议一步到位选择 512GB 以上版本，并搭配原厂键盘或手写笔使用，避免后期配件成本过高影响体验。","official_faq":[{"question":"13.2英寸的大屏平板拿来分屏办公，和常见11英寸平板相比差距明显吗？","answer":"差距主要体现在同时看两份内容时的从容度。像 13.2 英寸这种规格，左边开文档、右边开会议纪要或浏览器时，字体不用缩得太小，批注 PDF 和看表格也更舒服；如果你平时主要是轻办公、上课记笔记和看资料，这个尺寸会比 11 英寸更接近小型笔记本的视野。但它终究还是平板，不适合长期替代笔记本去做重度剪辑、复杂建模或超长时间多窗口专业软件工作。"},{"question":"12GB+256GB和12GB+512GB两个版本，哪个更适合长期使用？","answer":"如果你主要是记笔记、追剧、装常用办公 App，12GB+256GB 已经够用；但如果你会长期存课件、离线视频、会议录音、绘画素材，或者准备搭配手写笔做创作，512GB 会更省心。平板通常不支持后期自行扩容，且高分辨率素材和缓存涨得很快，所以打算用两三年以上的人更建议直接选 512GB 起步。"},{"question":"它更适合哪些人，哪些使用场景不太建议直接买这类大屏平板？","answer":"这类大屏平板更适合经常移动办公、需要手写批注、看资料、开会记录和轻度创作的人，也适合宿舍或家里拿来追剧、看漫画和做轻量学习设备。若你主要需求是大型 Excel、多窗口专业软件、长时间视频导出或高强度编程，不建议把它当成唯一生产力设备，因为键盘手感、桌面级软件完整度和持续性能释放都和笔记本有差距。"}],"user_reviews":[{"nickname":"阿宁","rating":5,"content":"我最近开会基本都带这台平板，13.2英寸看会议资料真的舒服，分屏一边看 PDF 一边记重点不用来回切。机身比我之前背的轻薄本轻很多，塞进通勤包里明显省地方，午休拿出来追一集剧也很顺，屏幕观感确实有旗舰感。"},{"nickname":"Momo","rating":4,"content":"我更喜欢它在轻办公和娱乐之间切换得比较自然，白天接蓝牙键盘回邮件、改文档，晚上拆下来直接看剧看漫画，使用场景很连贯。和 11 英寸平板比，大屏看表格和批注更舒服，不过如果你本来就不打算配手写笔或键盘，买高配套装版的性价比就没那么高。"},{"nickname":"老白","rating":3,"content":"屏幕和系统协同都不错，但我拿它连续做了两小时分屏笔记加手写批注之后，还是会觉得这块 13.2 英寸的板子偏大，躺着拿很容易压手腕。另一个让我纠结的是配件成本，原厂键盘和手写笔加起来不便宜，如果一开始只买裸机，后面补齐整套下来预算会比预想高不少。"}]}}'::jsonb, '2_数码电子/data/p_digital_021.json'),
    ('p_digital_022', '联想 ThinkPad X1 Carbon Aura AI 元启版2026 14英寸高端商务轻薄本', '联想', '数码电子', '笔记本电脑', '数码电子/笔记本电脑', 10999.0, 10999.0, 12999.0, 400, '2_数码电子/images/p_digital_022_live.jpg', '{"product_id":"p_digital_022","title":"联想 ThinkPad X1 Carbon Aura AI 元启版2026 14英寸高端商务轻薄本","brand":"联想","category":"数码电子","sub_category":"笔记本电脑","base_price":10999.0,"image_path":"2_数码电子/images/p_digital_022_live.jpg","skus":[{"sku_id":"s_p_digital_022_1","properties":{"存储配置":"16GB+512GB","产品版本":"商务版"},"price":10999.0},{"sku_id":"s_p_digital_022_2","properties":{"存储配置":"16GB+512GB","产品版本":"高配版"},"price":11499.0},{"sku_id":"s_p_digital_022_3","properties":{"存储配置":"32GB+1TB","产品版本":"商务版"},"price":12499.0},{"sku_id":"s_p_digital_022_4","properties":{"存储配置":"32GB+1TB","产品版本":"高配版"},"price":12999.0}],"rag_knowledge":{"marketing_description":"这台联想ThinkPad X1 Carbon Aura AI元启版2026是专为高端商务人士打造的14英寸轻薄本，整机采用航空级碳纤维材质打造，裸机重量仅1.1kg，薄至14.9mm，揣进通勤公文包完全没负担。搭载的专属Aura AI引擎能自动帮你整理会议纪要、生成商务汇报初稿、智能调优办公场景的功耗，续航最长可达18小时，全天出差不用带充电器。不管是经常跑客户的销售、高频开线上会议的管理层，还是需要随时处理项目的咨询顾问都非常合适。使用建议平时定期通过自带的AI管家更新功能补丁，注意不要在超过35℃的高温环境下长时间高负载运行，避免影响AI功能的运行流畅度。","official_faq":[{"question":"这款2026款X1 Carbon的Aura AI元启功能需要额外付费开通会员才能使用吗？","answer":"完全不需要额外付费开通会员，整机出厂就预装了全功能的Aura AI元启引擎，所有本地端的智能会议纪要生成、文档智能校对、场景功耗自适应调节功能都可以直接免费用，不需要额外联网订阅服务。仅部分需要云端大模型协同的高阶创意生成功能，在首3年的质保期内是免费开放的，过了质保期之后联想也不会强制收费，基础商务类AI功能会永久免费提供给用户使用。"},{"question":"16GB+512GB的商务版支持后期自行升级内存和固态硬盘吗？","answer":"这款机型的内存部分采用的是板载LPDDR5X规格，为了保障AI运算的稳定性和机身轻薄度做了固化设计，不支持后期自行扩容。不过固态硬盘的M.2插槽是符合2280规格的PCIe 5.0标准，用户可以自行更换更大容量的固态硬盘，更换的时候注意断开电源避免静电损伤元器件，如果动手能力不强的话，也可以联系联想线下的官方服务网点，工程师可以提供付费的硬盘升级服务，不会影响整机的正常保修。"},{"question":"这款笔记本的屏幕在户外强光下办公会不会看不清内容？","answer":"这款机型搭载的是最高1200nit亮度的4K防眩光雾面屏，支持Aura AI智能亮度调节，系统会根据当前环境光的强度实时调整屏幕的亮度和色温，就算是在正午的户外露天环境下，也能清晰看清屏幕上的Word文档和表格内容，不会像普通镜面屏那样出现强烈反光晃眼的情况。同时屏幕还通过了 Eyesafe 2.0低蓝光认证，长时间开线上会议也不容易眼累，对长期在外跑业务需要户外临时办公的用户非常友好。"},{"question":"它的接口能不能直接连我常用的旧款有线投影仪和USB-A接口的U盘？","answer":"完全可以不用带拓展坞直接连接，机身左侧配备了两个全功能雷电4接口、一个HDMI2.1接口，右侧专门保留了一个USB-A 3.2高速接口和3.5mm耳机孔，还有一个专属的ThinkPad经典方口充电接口。日常开会的时候直接插老款有线投影仪的HDMI线就能投屏，不需要额外转接头，随身带的USB-A口U盘插上去就能直接读文件，不用额外带拓展坞占包里空间，适配绝大多数商务场景的外接设备需求。"},{"question":"这款机型的键盘手感和之前经典的ThinkPad X1 Carbon系列比有区别吗？","answer":"这次2026款的键盘延续了ThinkPad标志性的6行全尺寸小红帽设计，键程做到了1.5mm，还专门优化了AI辅助输入的震动反馈，打字的时候段落感清晰，长时间打几千字的商务文档也不会觉得手指酸。同时键盘还加入了智能防误触功能，当AI检测到你正在语音输入会议内容的时候，会自动屏蔽掌托区域的误触按压，不会因为手肘碰到键盘打出乱码字符，手感比前代的机型还要顺手，完全保留了老ThinkPad用户熟悉的敲击质感。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"做咨询行业的我终于换上了这台新本，上周连续跑了3个城市出差，全程没带充电器，白天开客户会它自动录音频转的纪要比我手写的还全，晚上在高铁上整理报告，敲键盘的手感特别顺，1.1kg的重量塞在通勤包里完全没压肩膀。雾面屏在高铁站的强光下也看得清清楚楚，完全没有反光晃眼的情况，真的是我用过最顺手的商务本。"},{"nickname":"小周","rating":3,"content":"用了半个月有个挺闹心的问题，我本来想后期自己加内存，买回来拆开机身才发现内存是完全焊死在主板上的，之前以为轻薄本最多只是处理器焊死，内存还能升级，现在开了几个大的行业数据表加AI后台就占满内存，偶尔会出现卡顿的情况。不是说机子不好，就是宣传的时候没把不能升级内存这点放显眼位置，我当初差点直接买了商务版，现在有点后悔没直接上32G高配。"},{"nickname":"林姐","rating":5,"content":"作为行政总监平时天天要开跨部门线上会，这台本的AI功能真的帮我省了超多事，它自动把会议里各部门的待办事项全部整理成表格，还能自动同步到我的日程表，完全不用我会后熬夜整理。接口也特别实用，上次去老厂区开会，直接插老投影仪的线就投屏，不用翻半天找拓展坞，续航撑完整整一天的加班还有剩电，太适合我们这种常年在各个会场跑的人了。"}]}}'::jsonb, '2_数码电子/data/p_digital_022.json'),
    ('p_digital_023', '联想 ThinkBook 14+ 2026 全面屏高性能轻薄本商务学习笔记本电脑', '联想', '数码电子', '笔记本电脑', '数码电子/笔记本电脑', 6999.0, 6999.0, 7999.0, 400, '2_数码电子/images/p_digital_023_live.jpg', '{"product_id":"p_digital_023","title":"联想 ThinkBook 14+ 2026 全面屏高性能轻薄本商务学习笔记本电脑","brand":"联想","category":"数码电子","sub_category":"笔记本电脑","base_price":6999.0,"image_path":"2_数码电子/images/p_digital_023_live.jpg","skus":[{"sku_id":"s_p_digital_023_1","properties":{"存储配置":"16GB+512GB","版本":"标准版"},"price":6999.0},{"sku_id":"s_p_digital_023_2","properties":{"存储配置":"16GB+512GB","版本":"高配版"},"price":7499.0},{"sku_id":"s_p_digital_023_3","properties":{"存储配置":"32GB+1TB","版本":"标准版"},"price":7499.0},{"sku_id":"s_p_digital_023_4","properties":{"存储配置":"32GB+1TB","版本":"高配版"},"price":7999.0}],"rag_knowledge":{"marketing_description":"联想ThinkBook 14+ 2026是专为职场商务人和在校学生打造的高性能轻薄本，整机薄至15.9mm仅重1.4kg，搭载全新一代标压处理器搭配2.8K 120Hz全尺寸高清全面屏，100%sRGB高色域覆盖让修图、剪视频色彩零偏差。全金属机身耐磨抗造，接口全到不用带拓展坞，原生支持PD快充，满电日常办公能撑7小时以上。日常用来跑多开办公软件、上网课做毕业设计、轻度剪4K素材都完全不卡，出差塞通勤包也毫无负担。使用建议新到手先更新官方驱动优化性能，注意不要边充边高负载运行太久，避免机身局部积热影响续航寿命。","official_faq":[{"question":"ThinkBook 14+ 2026的标准版16GB内存支持后期自行升级扩展吗？","answer":"这款2026款的16GB+512GB标准版采用了板载+插槽的组合设计，其中8GB内存是直接焊在主板上的，剩下的8GB预留了可插拔的DDR5内存插槽，用户可以自行购买同规格的笔记本内存条拓展到最多40GB总内存。512GB的固态也预留了额外的M.2插槽，最高支持加装2TB的PCIe4.0固态，拓展时记得先断电卸下D壳螺丝，操作前释放手上静电避免烧坏主板元件，不会操作的话也可以找联想线下售后点付费帮忙加装。"},{"question":"这款笔记本的全尺寸接口具体都有哪些，日常外出是不是不用带拓展坞？","answer":"ThinkBook 14+ 2026的机身左右两侧配齐了目前几乎所有常用接口，左侧有雷电4全功能接口、HDMI2.1接口和3.5mm耳机孔，右侧有2个USB-A 3.2接口、全尺寸RJ45网线口和一个USB-C充电口。平时外接4K显示器、插U盘拷资料、插网线连办公内网甚至连老旧的投影都能直接插线用，完全不用额外带拓展坞，不用像其他同价位轻薄本那样每次出门还要揣着个拓展坞怕忘带，经常跑客户做演示的商务用户用着特别省心。"},{"question":"2.8K 120Hz的屏幕日常办公会不会太费电，续航实际能用多久？","answer":"这块屏幕做了非常智能的功耗调校，日常开60Hz自适应刷新率模式办公看文档，满电状态下正常连续用可以撑7到8小时，足够满足一整个白天不插电通勤+办公的需求。如果开120Hz高刷模式刷网页、看视频，续航也能维持在5小时左右，完全能覆盖日常短途出差不插电的场景。机器自带的智能节电模式还会根据你当前的使用场景自动调整屏幕亮度和刷新率，不用手动反复设置，续航表现比同配置其他机型要亮眼不少。"},{"question":"这款机器如果长时间跑代码或者多开十几个办公软件，散热会不会压不住？","answer":"ThinkBook 14+ 2026搭载了双风扇双热管的飓风散热模组，官方做了性能释放调校，满性能状态下可以做到45W持续稳定输出，长时间跑代码编译、开十几个网页加微信文档PPT多开的场景下，键盘面的核心区域温度控制在40度以内，完全不会出现烫手腕的情况。高负载下的噪音也控制在38分贝左右，也就是差不多图书馆正常翻书的音量，在办公室或者宿舍用也不会吵到旁边的人，完全能满足长时间高负载运行的需求。"},{"question":"这款机器的A面壳是金属材质吗，日常放背包里容易刮花吗？","answer":"它的A面和C面全部采用的是6系航空级铝合金材质，表面做了磨砂阳极氧化工艺处理，正常日常放包里和笔记本支架、充电宝钥匙之类的东西放一起，不容易留下明显的划痕，比普通塑料机身的耐用度高很多。而且机身边角做了圆弧打磨处理，不小心轻摔磕碰也不容易掉漆变形，正常用三四年整机外观还能保持很新的状态。如果特别在意外观防刮，也可以花几十块贴个同色系的机身贴膜，还能进一步减少指纹残留的问题，日常清洁用擦眼镜的软布一擦就干净。"}],"user_reviews":[{"nickname":"小周","rating":4,"content":"整体用下来还挺满意的，屏幕素质确实好，修图的时候色彩比我之前旧笔记本准太多，接口全不用带拓展坞跑客户特别方便。就是有个小问题，高负载运行的时候键盘右上角靠近散热口的位置会有点温烫，夏天不开空调的时候用久了能明显感觉到发热，送的原装电源适配器个头有点大，出差塞包里有点占地方，如果后续能换成更小的GaN氮化镓充电器就完美了，整体还是值得入手的。"},{"nickname":"阿凯","rating":5,"content":"做设计买的高配版，用了快半个月真的香，32GB内存同时开PS、剪映还有十几个网页完全不卡，2.8K高刷屏看素材细节特别清楚，剪10分钟的4Kvlog导出速度比我之前旧笔记本快了一倍多。平时带去公司敲代码外接4K显示器直接插HDMI线就行，不用带拓展坞太省心了，机身重量轻天天背通勤包挤地铁也不累，续航不插电摸鱼能撑一下午，联想这次新品真的做的很实在。"},{"nickname":"阿雯","rating":2,"content":"本来冲着联想的口碑买的标准版，刚用第三天就发现屏幕右下角有个暗斑，联系售后检测说是出厂品控漏检的问题，折腾了一周才走完换货流程。新机器拿到手用了没半个月，就发现休眠唤醒的时候偶尔会出现闪屏，要按两次电源键才能恢复正常，联系客服说要等后续驱动更新优化，新机刚到手就出这两个小问题实在糟心，感觉这次品控不如之前买的老款ThinkBook。"},{"nickname":"小廖","rating":2,"content":"买给刚上大学的弟弟上网课用的，收到货拆封的时候发现C面键盘缝隙里有明显的灰尘残留，开合屏幕的时候左右的阻尼感不一样，右边特别松，轻轻一晃屏幕就会晃。找客服申请退换货还被要求提供各种证明来回扯皮，折腾了好几天才同意处理，这么贵的机器居然出厂不做清洁检测，品控细节做的还不如三四千的入门本，这次购物体验真的很差。"}]}}'::jsonb, '2_数码电子/data/p_digital_023.json'),
    ('p_digital_024', 'Apple iPad Pro 13 英寸 M4 芯片 256GB Wi‑Fi 平板电脑', 'Apple 苹果', '数码电子', '平板电脑', '数码电子/平板电脑', 8999.0, 8999.0, 12999.0, 1200, '2_数码电子/images/p_digital_024_live.jpg', '{"product_id":"p_digital_024","title":"Apple iPad Pro 13 英寸 M4 芯片 256GB Wi‑Fi 平板电脑","brand":"Apple 苹果","category":"数码电子","sub_category":"平板电脑","base_price":8999.0,"image_path":"2_数码电子/images/p_digital_024_live.jpg","skus":[{"sku_id":"s_p_digital_024_1","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"256GB","网络版本":"Wi‑Fi","颜色":"银色"},"price":8999.0},{"sku_id":"s_p_digital_024_2","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"256GB","网络版本":"Wi‑Fi","颜色":"深空黑"},"price":8999.0},{"sku_id":"s_p_digital_024_3","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"256GB","网络版本":"Wi‑Fi + 蜂窝","颜色":"银色"},"price":10499.0},{"sku_id":"s_p_digital_024_4","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"256GB","网络版本":"Wi‑Fi + 蜂窝","颜色":"深空黑"},"price":10499.0},{"sku_id":"s_p_digital_024_5","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"512GB","网络版本":"Wi‑Fi","颜色":"银色"},"price":10499.0},{"sku_id":"s_p_digital_024_6","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"512GB","网络版本":"Wi‑Fi","颜色":"深空黑"},"price":10499.0},{"sku_id":"s_p_digital_024_7","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"512GB","网络版本":"Wi‑Fi + 蜂窝","颜色":"银色"},"price":11999.0},{"sku_id":"s_p_digital_024_8","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"512GB","网络版本":"Wi‑Fi + 蜂窝","颜色":"深空黑"},"price":11999.0},{"sku_id":"s_p_digital_024_9","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"1TB","网络版本":"Wi‑Fi","颜色":"银色"},"price":11999.0},{"sku_id":"s_p_digital_024_10","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"1TB","网络版本":"Wi‑Fi","颜色":"深空黑"},"price":11999.0},{"sku_id":"s_p_digital_024_11","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"1TB","网络版本":"Wi‑Fi + 蜂窝","颜色":"银色"},"price":12999.0},{"sku_id":"s_p_digital_024_12","properties":{"屏幕尺寸":"13英寸","芯片":"M4芯片","存储":"1TB","网络版本":"Wi‑Fi + 蜂窝","颜色":"深空黑"},"price":12999.0}],"rag_knowledge":{"marketing_description":"这款搭载M4芯片的13英寸iPad Pro，拥有堪比桌面级的运算性能，256GB起步的存储空间刚好能装下海量4K剪辑工程、专业绘图素材和离线高清片源。适配第二代Apple Pencil的悬停预览功能，搭配超大屏幕，插画师、视频博主、移动办公族用着都特别顺手。不管是在咖啡馆剪完一支vlog，还是在会议室直接批注数百页方案，又或者躺床上追全景声大片都很丝滑。全机采用航空级铝金属机身，还支持6K视频外接输出，建议平时搭配类纸膜和妙控键盘使用，使用时尽量避开尖锐硬物刮划机身屏幕，长时间高负载运行可以适当取下保护壳辅助散热，避免机身积热。","official_faq":[{"question":"这款13英寸M4版iPad Pro的256GB Wi-Fi版本，存满大型Procreate绘图工程会不会出现卡顿？","answer":"完全不会出现卡顿情况，M4芯片的GPU算力相比上代提升了近40%，256GB的UFS级高速存储连续读写速度能达到3500MB/s以上，哪怕你同时打开十多个带多层特效的Procreate画布，每个画布尺寸到上百GB，切换图层、添加笔刷特效的时候也不会有拖影延迟。日常还能同时后台挂着剪映4K工程和参考素材网页，多任务切换也全程丝滑，完全能满足专业创作者的重度使用需求。"},{"question":"13英寸M4 iPad Pro的Wi-Fi版和蜂窝版在日常外出使用上体验差距大吗？","answer":"差距还是比较明显的，Wi-Fi版只能连接周边的无线热点或者手机个人热点，你要是在户外长时间没随身带手机的话很容易断网，没法随时同步云端的大体积创作文件。而1TB规格的蜂窝版支持高速5G联网，不用插主卡也能开独立流量套餐，在外采风的时候可以直接把刚拍的raw格式素材实时同步到iPad里，不用回到有网的地方再传输，对经常跑外景的创作者来说特别方便，只在家或者固定办公点使用选Wi-Fi版就足够了。"},{"question":"512GB的银色Wi-Fi版13英寸M4 iPad Pro，拿来跑AI生图类的本地软件速度能达到什么水平？","answer":"搭载的M4芯片自带16GB统一内存，512GB的高速存储也足够容纳大体积的AI模型，运行7B参数的本地AI绘图模型生成一张4K分辨率的高清图，只需要8到10秒就能出图，比上一代M2版iPad Pro快了接近一倍。还能直接在本地运行AI修图插件，导入几十张 raw格式照片批量生成滤镜效果，全程不用连云端服务器，隐私性也更高，完全能满足轻度到中度的本地AI生产力需求。"},{"question":"深空黑1TB蜂窝版的13英寸M4 iPad Pro，长时间用妙控键盘打字办公机身发热会不会很严重？","answer":"正常办公场景下几乎感知不到明显发热，M4芯片的能效比做得非常出色，全机的被动散热布局也做了优化，连续用妙控键盘开网页、写文档、做表格三四个小时，机身背部的最高温度也不会超过36度，只是温温的触感。要是长时间同时跑视频渲染和大型游戏的高负载场景，才会在摄像头周边区域有轻微温热，完全不会影响打字握持的手感，也不会出现降频卡顿的问题。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"真的太闹心了，到手用了第三天就发现屏幕边缘有个肉眼可见的亮斑，联系售后说要返场检测，来回折腾快一周，我等着用来赶毕业设计的绘图作业根本等不起。而且这个版本不送充电头，我之前旧的20W头充它特别慢，充满要三个多小时，当初冲着M4芯片的性能加钱买的，结果刚拆就出问题，两千多的旧iPad用了三年都没这毛病，这次体验真的太差了。"},{"nickname":"小夏","rating":4,"content":"整体用下来性能确实没话说，跑Procreate的大画布一点都不卡，13英寸的屏幕画长幅插画刚好合适。但有点小吐槽的地方，这个银色的边框特别容易沾指纹，拿在手里半小时边框就全是印子，我这种手容易出汗的人玩半小时就得擦一次。还有官方的妙控键盘适配这个尺寸之后，重量加起来快两斤，带出门挎包里塞久了肩膀特别酸，要是能再轻量化一点就完美了。"},{"nickname":"画画儿","rating":5,"content":"作为自由插画师换这台真的换对了！M4芯片带动上百层的大尺寸画布完全不卡，Apple Pencil悬停在屏幕上就能预览笔刷效果，铺色的时候再也不用反复点按试色了。13英寸的屏幕比之前11寸的大了一圈，画完的长幅海报不用缩来缩去调整细节，连色准都特别准，导出的图直接拿去印刷都不用在电脑上调色，续航画一整天都还有剩，最近出门跑客户谈方案直接带它就够了。"},{"nickname":"阿泽","rating":4,"content":"买来平时出差剪vlog用的，性能确实够强，剪4K60帧的素材拖时间线一点不卡，导出速度比我旧的笔记本快太多。就是有点小遗憾，这个Wi-Fi版没蜂窝功能，每次去郊外采风景点没公共wifi，我还得特意开手机热点，手机耗电快了一倍。还有机身比我预想的薄很多，放包里不套硬壳总怕被其他东西压弯，我特意额外花两百多买了个厚保护壳，额外的开销有点多。"}]}}'::jsonb, '2_数码电子/data/p_digital_024.json'),
    ('p_digital_025', 'Apple iPad Air 11英寸 2026款 M4 芯片 128GB Wi‑Fi 轻薄学习娱乐平板电脑', 'Apple 苹果', '数码电子', '平板电脑', '数码电子/平板电脑', 4799.0, 4799.0, 6599.0, 1200, '2_数码电子/images/p_digital_025_live.jpg', '{"product_id":"p_digital_025","title":"Apple iPad Air 11英寸 2026款 M4 芯片 128GB Wi‑Fi 轻薄学习娱乐平板电脑","brand":"Apple 苹果","category":"数码电子","sub_category":"平板电脑","base_price":4799.0,"image_path":"2_数码电子/images/p_digital_025_live.jpg","skus":[{"sku_id":"s_p_digital_025_1","properties":{"屏幕尺寸":"11英寸","存储":"128GB","版本":"Wi‑Fi版","颜色":"深空灰"},"price":4799.0},{"sku_id":"s_p_digital_025_2","properties":{"屏幕尺寸":"11英寸","存储":"128GB","版本":"Wi‑Fi版","颜色":"蓝色"},"price":4799.0},{"sku_id":"s_p_digital_025_3","properties":{"屏幕尺寸":"11英寸","存储":"128GB","版本":"Wi‑Fi版","颜色":"星光色"},"price":4799.0},{"sku_id":"s_p_digital_025_4","properties":{"屏幕尺寸":"11英寸","存储":"256GB","版本":"Wi‑Fi版","颜色":"深空灰"},"price":5299.0},{"sku_id":"s_p_digital_025_5","properties":{"屏幕尺寸":"11英寸","存储":"256GB","版本":"Wi‑Fi版","颜色":"蓝色"},"price":5299.0},{"sku_id":"s_p_digital_025_6","properties":{"屏幕尺寸":"11英寸","存储":"256GB","版本":"Wi‑Fi版","颜色":"星光色"},"price":5299.0},{"sku_id":"s_p_digital_025_7","properties":{"屏幕尺寸":"11英寸","存储":"128GB","版本":"蜂窝网络版","颜色":"深空灰"},"price":6099.0},{"sku_id":"s_p_digital_025_8","properties":{"屏幕尺寸":"11英寸","存储":"128GB","版本":"蜂窝网络版","颜色":"蓝色"},"price":6099.0},{"sku_id":"s_p_digital_025_9","properties":{"屏幕尺寸":"11英寸","存储":"128GB","版本":"蜂窝网络版","颜色":"星光色"},"price":6099.0},{"sku_id":"s_p_digital_025_10","properties":{"屏幕尺寸":"11英寸","存储":"256GB","版本":"蜂窝网络版","颜色":"深空灰"},"price":6599.0},{"sku_id":"s_p_digital_025_11","properties":{"屏幕尺寸":"11英寸","存储":"256GB","版本":"蜂窝网络版","颜色":"蓝色"},"price":6599.0},{"sku_id":"s_p_digital_025_12","properties":{"屏幕尺寸":"11英寸","存储":"256GB","版本":"蜂窝网络版","颜色":"星光色"},"price":6599.0}],"rag_knowledge":{"marketing_description":"2026款11英寸iPad Air搭载全新M4芯片，机身薄至5.9mm，重量仅455g，单手握持逛两小时漫展都不酸。Liquid视网膜屏支持P3广色域，上网课记笔记时公式色彩分明，刷4K剧暗部细节也不拉胯。核心卖点是满血M4带来的AI运算能力，跑专业绘图APP画十几层插画都不卡，连续办公续航能撑10小时，图书馆待一整天不用找插座。适配Apple Pencil二代和妙控键盘，学生党赶作业、上班族轻办公、宅家党剪短视频都能用。使用建议贴类纸膜搭配手写笔记笔记更顺手，注意事项是蜂窝版不支持国内通话功能，仅支持数据流量上网，避免误购。","official_faq":[{"question":"这款2026款iPad Air的M4芯片和上一代M2相比，性能提升了多少，跑主流的绘图软件够用吗？","answer":"这款搭载的M4芯片相比前代iPad Air的M2，CPU性能提升35%，GPU图形处理能力提升40%，AI神经网络引擎算力直接翻倍。跑Procreate开20层以上4K分辨率的插画笔触也不会卡顿，甚至能流畅运行部分轻量3D建模软件，日常做设计、剪1080P视频完全无压力，就算同时挂着网课、微信和笔记APP，切换也几乎没有延迟，完全能满足普通创作者和学生的性能需求。"},{"question":"128GB的Wi-Fi版日常用来上网课、存笔记加追剧集，存储空间够不够用？","answer":"如果主要是在线上网课、用云同步笔记软件，日常只存几十部下载好的普通清晰度剧集，128GB完全够用，剩余空间还能装几十款常用APP。但如果习惯离线存大量4K教学视频、本地存上百GB的绘图源文件，或者经常拍4K60帧的日常素材，建议选256GB版本更省心。后续也可以搭配iCloud云存储把照片和文件同步到云端，进一步释放本地存储空间，不用频繁删旧内容腾位置。"},{"question":"这款11英寸iPad Air的蜂窝网络版，可以插普通的手机SIM卡接打电话吗？","answer":"这款蜂窝网络版仅支持数据流量上网功能，不具备语音通话模块，就算插入普通手机SIM卡，也只能用来跑流量，无法接打普通语音电话，也不能收发普通短信。如果需要外出随时联网，建议搭配运营商的平板专属流量卡使用，性价比很高，日常要通话的话可以用FaceTime语音、微信电话这类网络通话功能替代，完全不影响日常的联网使用体验。"},{"question":"这款新iPad Air适配二代Apple Pencil吗，手写延迟表现怎么样，上网课记笔记够用吗？","answer":"2026款11英寸iPad Air完美适配第二代Apple Pencil，支持磁吸无线充电和双击切换橡皮擦功能，手写延迟最低压到8ms，几乎感觉不到笔触和屏幕显示的滞后，记笔记的时候随手画的重点标记、几何图形都跟在纸上写的手感差不多。搭配自带的备忘录或者第三方Notability软件，写再多的手写批注也不会断触，就算是需要快速记讲座板书的文科专业学生，使用起来也完全够用，还能直接把手写内容转换成可编辑的文本。"},{"question":"不同SKU对应的配色是固定的吗，能不能选深空灰的256GB Wi-Fi版本？","answer":"当前上架的三个SKU配色是和配置绑定的，11英寸128GB Wi-Fi版仅提供深空灰配色，11英寸256GB Wi-Fi版仅提供蓝色配色，11英寸256GB蜂窝网络版仅提供星光色配色，暂时没有开放跨配置选配色的选项。如果有特定的配色偏好，建议优先挑选自己最在意的需求点，优先保证存储容量或者网络版本，后续也可以搭配不同款式的保护壳覆盖机身颜色，照样能拿到自己喜欢的外观效果。"},{"question":"这款11英寸iPad Air日常轻度办公，用妙控键盘打字续航能坚持多久？","answer":"满电状态下如果连着妙控键盘，连续打字处理文档、挂网页查资料，中途间隔开几个小的表格文件，续航能稳定在9-10小时左右，就算是从早上九点到下午六点的半天工作会议，全程用来记会议纪要也不用中途补电。要是中途偶尔刷会儿短视频、开个视频会议，续航也能维持在8小时以上，搭配20W快充头的话，充半小时就能补到50%的电量，应急补能的效率也很高。"}],"user_reviews":[{"nickname":"小杨","rating":2,"content":"本来冲着M4芯片买的，想着跑绘图软件肯定流畅，结果收到货才发现128GB版本下了十几个网课视频加几个绘图APP，就只剩不到40GB空间了，想存点素材直接提示空间不足。更闹心的是我本来以为能插手机卡打电话，买之前没仔细看说明，结果蜂窝版根本打不了电话，我平时通勤没WiFi的地方想用来接工作电话完全没用，只能当个平板用，感觉花的钱有点不值，挺失望的。"},{"nickname":"阿柚","rating":5,"content":"这台新iPad Air用了快半个月真的香，M4芯片太流畅了，我平时学插画开十几层的PS文件都不卡，搭配二代笔记笔记延迟超低，跟在纸上写几乎没差。11英寸的大小塞进我的通勤包刚好，下班路上刷剧画质特别细腻，P3广色域的色彩看着特别舒服，满电我上网课加画图能撑一整天，图书馆泡到闭馆都不用带充电器，比我之前旧的iPad体验好太多，性价比真的很高。"},{"nickname":"阿泽","rating":4,"content":"整体用着还不错，M4芯片性能确实够强，我平时用来追综艺、上网课完全不卡，机身很轻薄，躺床上举着看半小时也不会手酸。就是有点小遗憾，256GB Wi-Fi版只有蓝色可选，我本来想要深空灰来着，结果只能买蓝色，现在套了个深色壳才算盖住。另外裸机的机身太容易沾指纹了，我平时手容易出汗，用半天背面就全是印子，后来贴了个磨砂背贴才解决，整体还行就是这点小缺点。"},{"nickname":"小棠","rating":4,"content":"买的蜂窝版日常出门在外没WiFi的时候用着特别方便，网速也很稳定，星光色的外观质感超棒，拿出去上课同学都问链接。就是有个小问题，妙控键盘单独买的话适配起来稍微有点缝隙，打字的时候偶尔会有一点点轻微的晃动，不是很影响使用但总感觉差点意思。还有自带的充电器头只有20W，要是能配个功率高点的快充头就好了，现在我得自己额外单独买快充配件，稍微有点麻烦。"}]}}'::jsonb, '2_数码电子/data/p_digital_025.json'),
    ('p_clothes_001', '优衣库 U AIRism 棉质宽松圆领短袖T恤 男装 基础纯色上衣', '优衣库', '服饰运动', '短袖T恤', '服饰运动/短袖T恤', 99.0, 99.0, 99.0, 900, '3_服饰运动/images/p_clothes_001_live.jpg', '{"product_id":"p_clothes_001","title":"优衣库 U AIRism 棉质宽松圆领短袖T恤 男装 基础纯色上衣","brand":"优衣库","category":"服饰运动","sub_category":"短袖T恤","base_price":99.0,"image_path":"3_服饰运动/images/p_clothes_001_live.jpg","skus":[{"sku_id":"s_p_clothes_001_1","properties":{"尺码":"S码","颜色":"黑色"},"price":99.0},{"sku_id":"s_p_clothes_001_2","properties":{"尺码":"S码","颜色":"白色"},"price":99.0},{"sku_id":"s_p_clothes_001_3","properties":{"尺码":"S码","颜色":"深蓝色"},"price":99.0},{"sku_id":"s_p_clothes_001_4","properties":{"尺码":"M码","颜色":"黑色"},"price":99.0},{"sku_id":"s_p_clothes_001_5","properties":{"尺码":"M码","颜色":"白色"},"price":99.0},{"sku_id":"s_p_clothes_001_6","properties":{"尺码":"M码","颜色":"深蓝色"},"price":99.0},{"sku_id":"s_p_clothes_001_7","properties":{"尺码":"L码","颜色":"黑色"},"price":99.0},{"sku_id":"s_p_clothes_001_8","properties":{"尺码":"L码","颜色":"白色"},"price":99.0},{"sku_id":"s_p_clothes_001_9","properties":{"尺码":"L码","颜色":"深蓝色"},"price":99.0}],"rag_knowledge":{"marketing_description":"优衣库这款AIRism联名系列的男装宽松圆领T恤，把亲肤棉感和黑科技凉感做了完美融合，不是普通的薄款白T！面料用的是AIRism专属混纺棉，摸上去是软乎乎的棉质质感，贴身穿完全不扎，自带的吸湿速干属性夏天出了汗也不会黏在背上，宽松H版型刚好遮住腰腹的小赘肉，不紧绷也不会垮得像偷穿大人衣服。不管是学生党上课通勤、上班族下班逛夜市、周末约球做轻运动当内搭都合适，单穿配工装裤、牛仔短裤都很出片。建议洗的时候翻面用冷水轻柔模式，别用热水长时间泡，避免破坏面料里的凉感涂层，不要长时间暴晒在正午阳光下，挂在通风阴干能保持版型穿一整个夏天都不变形。","official_faq":[{"question":"这款AIRism棉质T恤和普通的优衣库纯棉基础T恤穿感上有什么不一样？","answer":"这款T恤是AIRism技术加持的棉质款，不是100%普通纯棉，在保留了棉类面料亲肤不闷、不容易起静电的优势之外，还叠加了AIRism专属的细微凉感纤维导孔，夏天室温30多度贴身穿不会有普通纯棉刚上身的闷热感，出汗之后面料能快速把潮气导出去，不会像普通纯棉那样湿了之后硬邦邦贴在背上。宽松剪裁也比普通合身款的基础T留了更多透气空隙，怕热的男生穿会明显觉得体感更清爽。"},{"question":"目前在售的S/M/L三个码对应的对应配色，只能选对应码数的颜色吗？能不能跨码选其他颜色？","answer":"目前这款SKU的库存是定向配货的，S码对应的黑色、M码对应的白色、L码对应的深蓝色都是当前仓库现货直发的规格，暂时不支持跨码换色的定制需求哦。如果想要特定颜色搭配特定码数，比如想要黑色M码，可以后续留意优衣库线下门店或者官方渠道的不定期补库存通知，本次下单的时候选对应码数拿到的就是匹配标注的颜色，不会发错货，三个颜色都是经典基础色，日常搭配适配度都很高。"},{"question":"这件T恤的宽松版型会不会显邋遢，小个子男生穿会不会压个子？","answer":"这款的宽松是做了微落肩和衣长微调的H型宽松，不是oversize的长款垮版型，S码衣长大概在68cm左右，165-170cm的男生穿刚好盖住胯骨，搭配工装短裤不会压个子。M码衣长71cm适配170-178cm的身高，L码74cm适配178-185cm的身高，只要按平时穿优衣库T恤的常规码数选，不会出现过于松垮显邋遢的情况，想要更利落的效果可以把前摆稍微塞一点进裤腰里，搭配起来很显精神。"},{"question":"洗的时候会不会掉色，能不能和其他深色/浅色衣服混洗？","answer":"这款T恤的三个配色都是活性染色工艺做的，初次下水的时候会有极轻微的浮色，第一次洗建议单独冷水手洗或者翻面套洗衣袋机洗，不要和其他容易掉色的彩色衣物混洗。黑色和深蓝色前3次洗最好和纯白色衣物分开，避免极少量浮色蹭到其他浅色衣服上，之后正常机洗几乎不会再出现掉色情况，面料色牢度符合优衣库的品控标准，正常穿洗大几个月也不会出现大面积发白变旧的情况。"}],"user_reviews":[{"nickname":"阿凯","rating":4,"content":"整体穿下来还挺舒服的，凉感确实比我之前买的普通纯棉T明显，上周35度出门跑外勤，后背出汗也没黏糊糊的。唯一有点小遗憾是我选的L码深蓝色，领口的走线我仔细看有一点点小线头，剪完就没啥事了，这个价格能买到带AIRism技术的T其实挺划算的，就是洗了两次之后衣长稍微垂了一丢丢，不仔细看看不出来，日常穿完全够用。"},{"nickname":"小宇","rating":5,"content":"这是我今年买过最满意的基础T了！选的M码白色，刚好卡在我175的身高身上，不会太长也不会太紧身，面料软乎乎的但是完全不透，之前买过别家的白T薄的穿个黑内衣都透，这个完全不会。上周去打球穿了俩小时，出了一身汗风一吹很快就干了，身上一点都没闷得慌，99块钱这个质感比我之前买的两百多的T还好，打算再蹲蹲补码的时候入件黑的换着穿。"},{"nickname":"阿泽","rating":4,"content":"T恤本身的质感是没得说的，AIRism的凉感确实很惊喜，贴身穿完全不扎，我皮肤有点敏感穿别的便宜T容易痒，这件穿了大半个月完全没不舒服。就是我本来想选S码白的，结果现在S码只有黑色，只能凑单买了黑的，虽然黑的也百搭但我本来想买白T搭牛仔背带裤的，算是小遗憾吧，要是后续能补全配色就好了，整体性价比还是很高的。"},{"nickname":"大刚","rating":2,"content":"拿到手穿了两次就有点失望，我选的L码深蓝色，第一次下水没怎么搓，晒干之后领口就有点变形，本来挺平整的圆领穿几次就有点塌塌的，领口翻边堆在脖子那里特别显邋遢。而且我180穿L码本来以为合身，结果衣长比我预想的长很多，盖过屁股了，穿出去显得五五分，99块钱不算贵但这个品控感觉不如我前几年买的同系列款，有点不值。"},{"nickname":"小枫","rating":4,"content":"整体穿着体验是ok的，宽松版型对我这种腰上有小肚子的人太友好了，完全不会勒肚子，AIRism的面料夏天在空调房穿不会冻得胳膊凉，出门也不会闷。就是我选的S码黑色，洗了三次之后腋下位置有一点点起小毛球，得用粘毛器滚两下才干净，不过也不仔细看发现不了，这个价格能买到兼顾棉感和凉感的T，平时通勤穿完全够用，总体还是挺满意的。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_001.json'),
    ('p_clothes_002', '优衣库 DRY-EX 超快干圆领短袖T恤 男装 运动训练上衣', '优衣库', '服饰运动', '短袖T恤', '服饰运动/短袖T恤', 129.0, 129.0, 129.0, 900, '3_服饰运动/images/p_clothes_002_live.jpg', '{"product_id":"p_clothes_002","title":"优衣库 DRY-EX 超快干圆领短袖T恤 男装 运动训练上衣","brand":"优衣库","category":"服饰运动","sub_category":"短袖T恤","base_price":129.0,"image_path":"3_服饰运动/images/p_clothes_002_live.jpg","skus":[{"sku_id":"s_p_clothes_002_1","properties":{"尺码":"M码","颜色":"灰色"},"price":129.0},{"sku_id":"s_p_clothes_002_2","properties":{"尺码":"M码","颜色":"黑色"},"price":129.0},{"sku_id":"s_p_clothes_002_3","properties":{"尺码":"M码","颜色":"蓝色"},"price":129.0},{"sku_id":"s_p_clothes_002_4","properties":{"尺码":"L码","颜色":"灰色"},"price":129.0},{"sku_id":"s_p_clothes_002_5","properties":{"尺码":"L码","颜色":"黑色"},"price":129.0},{"sku_id":"s_p_clothes_002_6","properties":{"尺码":"L码","颜色":"蓝色"},"price":129.0},{"sku_id":"s_p_clothes_002_7","properties":{"尺码":"XL码","颜色":"灰色"},"price":129.0},{"sku_id":"s_p_clothes_002_8","properties":{"尺码":"XL码","颜色":"黑色"},"price":129.0},{"sku_id":"s_p_clothes_002_9","properties":{"尺码":"XL码","颜色":"蓝色"},"price":129.0}],"rag_knowledge":{"marketing_description":"优衣库这款男装DRY-EX超快干圆领短袖T恤，专门针对爱运动的男生打造，面料加入了高比例吸湿速干纤维织法，出汗后不会闷在身上黏糊糊贴皮肤，风一吹十来分钟就能基本干透。平时夜跑、健身房撸铁、打球穿完全合适，日常通勤上班、下楼取快递、周末逛公园当内搭外穿也舒服不违和。尺码覆盖M到XL，有灰、黑、蓝三个低饱和百搭色，129的定价日常穿造也不心疼。洗的时候别用热水长时间浸泡，也别和掉色的深色牛仔混洗，平铺阴干就行，不用特意拧干，不容易起皱第二天直接拿出来穿都平整。","official_faq":[{"question":"这款DRY-EXT恤的速干效果和普通纯棉短袖差别大吗，夏天跑5公里后多久能干透？","answer":"差别还是很明显的，普通纯棉短袖吸汗之后会完全贴在背上，水汽很难散出去，可能闷一两个小时都湿乎乎的。咱们这款DRY-EX面料用的是单向导湿编织工艺，跑步出的汗会快速从面料内层排到外层挥发，正常室外26度左右有小风的环境下，跑完5公里停下来，把衣服扯开来透风，大概10到15分钟就能摸不出明显的潮湿感，完全不会像纯棉那样闷得后背长痱子。"},{"question":"这款T恤只有M灰、L黑、XL蓝这三个SKU，不同体型的男生选码会不会出现不合适的情况？","answer":"这三个码数是根据多数运动男生的常规版型做的正码剪裁，M码对应170/92A，适合体重110到130斤的男生，灰色款的剪裁稍微带点微宽松余量，日常穿不勒胳膊。L码对应175/96A，适合130到150斤的男生，黑色款做了轻微的收腰处理，运动的时候不会晃荡灌风。XL码对应180/100A，适合150到170斤的男生，蓝色款的肩线做了加固，肩宽的男生穿也不会卡肩，只要体型不是特别偏瘦或者偏胖基本都能适配。"},{"question":"经常机洗的话这款T恤的速干功能会不会容易失效，会不会起球变形？","answer":"正常用常温冷水、中性洗衣液机洗，调到轻柔模式速干功能基本不会失效，这款面料的速干纤维是织进纱线里的，不是后期喷的涂层，不会洗几次就被冲掉。不过要注意别用烘干模式高温烘，也别用碱性很强的洗衣粉长时间泡，不然会破坏纤维结构。正常穿洗的话不容易起球，圆领的领口做了双层罗纹加固，只要洗完别使劲拧领口甩干，穿大半年都不会松垮变形，不需要特殊的养护操作。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"上周健身房撸铁特意入的L码黑色款，以前穿纯棉T恤练完背整个湿得能拧出水，这件练完出来在楼下等共享单车，走回家的二十分钟路上后背已经全干了，完全没黏糊糊的难受感。剪裁也刚好，抬胳膊做引体向上的时候不会露肚子，领口穿了快一周洗了两次也没松垮，129这个价格比我之前买的两三百的运动T恤还好用，之后打算再入个蓝色的日常穿。"},{"nickname":"大宇","rating":1,"content":"我172体重140斤，想着买L码黑色的应该合适，结果拿到手特别窄，胸口勒得慌，根本塞不下我平时穿的运动护胸。洗了一次之后发现面料硬得像塑料布，完全不像别人说的那么舒服，昨天去夜跑出了点汗，衣服直接贴在背上，风一吹凉得我后背起鸡皮疙瘩，一点速干效果都没有，129花得太冤了，完全不值这个价。"},{"nickname":"小周","rating":4,"content":"买的XL蓝色款，我178体重155斤，穿上去大小刚好，平时上下班通勤穿挺舒服的，出汗了确实比普通短袖干得快。就是有个小问题，衣服的下摆边缘缝线有点硬，坐久了蹭腰有点痒，还有就是蓝色面料的色牢度一般，第一次冷水洗的时候水里掉了点浮色，泡了两次之后就好了，整体还行，平时当日常穿的运动T恤够用，就是细节上能再优化点就更好了。"},{"nickname":"阿哲","rating":1,"content":"抢的M码灰色，我身高168体重120，本来以为M码刚好合身，结果衣长做的特别长，盖过屁股一大截，穿起来像偷穿了大人的衣服。最坑的是袖口特别紧，我稍微有点蝴蝶臂，抬胳膊的时候袖口勒得胳膊上印出一圈红痕，穿了半小时就勒得胳膊发麻，速干效果也一般，上次出了汗之后闷了好久才干，真的不如楼下几十块的速干T恤好穿，很失望。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_002.json'),
    ('p_clothes_003', 'Nike Dri-FIT 男子训练短袖T恤 速干透气运动上衣', '耐克', '服饰运动', '短袖T恤', '服饰运动/短袖T恤', 199.0, 199.0, 199.0, 900, '3_服饰运动/images/p_clothes_003_live.jpg', '{"product_id":"p_clothes_003","title":"Nike Dri-FIT 男子训练短袖T恤 速干透气运动上衣","brand":"耐克","category":"服饰运动","sub_category":"短袖T恤","base_price":199.0,"image_path":"3_服饰运动/images/p_clothes_003_live.jpg","skus":[{"sku_id":"s_p_clothes_003_1","properties":{"尺码":"M码","颜色":"白色"},"price":199.0},{"sku_id":"s_p_clothes_003_2","properties":{"尺码":"M码","颜色":"黑色"},"price":199.0},{"sku_id":"s_p_clothes_003_3","properties":{"尺码":"M码","颜色":"深灰色"},"price":199.0},{"sku_id":"s_p_clothes_003_4","properties":{"尺码":"L码","颜色":"白色"},"price":199.0},{"sku_id":"s_p_clothes_003_5","properties":{"尺码":"L码","颜色":"黑色"},"price":199.0},{"sku_id":"s_p_clothes_003_6","properties":{"尺码":"L码","颜色":"深灰色"},"price":199.0},{"sku_id":"s_p_clothes_003_7","properties":{"尺码":"XL码","颜色":"白色"},"price":199.0},{"sku_id":"s_p_clothes_003_8","properties":{"尺码":"XL码","颜色":"黑色"},"price":199.0},{"sku_id":"s_p_clothes_003_9","properties":{"尺码":"XL码","颜色":"深灰色"},"price":199.0}],"rag_knowledge":{"marketing_description":"这款耐克Dri-FIT男子训练短袖T恤是专为运动爱好者打造的高性价比日常训练上衣，核心卖点就是搭载了耐克专属的Dri-FIT速干科技面料，面料采用高密聚酯纤维混纺纤维织就，能快速把运动时渗出的汗液从皮肤表面导出到面料外层，十几分钟就能自然风干不黏身。不管你是健身房撸铁、户外夜跑、日常打球，还是通勤通勤通勤路上随便穿都合适，适配从学生党到职场运动人的各类需求。穿的时候建议不要用热水长时间浸泡，也不要和深色容易掉色的衣物混洗，版型是常规修身款，做大幅度引体向上、波比跳动作都不会卡胳膊露腰，一百多的价格能直接承包你大半年的运动穿搭。","official_faq":[{"question":"这款T恤的Dri-FIT速干面料洗多了会不会失去速干效果？","answer":"正常按照说明洗涤的话不会失去速干效果，这款面料的速干属性是织入纤维本身的物理属性，不是后期喷涂的涂层效果，不会洗两次就失效。建议大家不要用超过40度的热水长时间浸泡，也不要使用衣物柔顺剂或者漂白剂，这类产品会在纤维表面形成残留膜，堵住导汗的纤维缝隙，洗完之后反过来阴干不要长时间暴晒，正常穿洗大半年速干表现依然能保持在线。"},{"question":"现在在售的M码白、L码黑、XL码深灰这三个款的版型有差别吗？胖一点穿XL深灰会不会勒？","answer":"三个不同配色的同系列T恤版型是完全统一的，都是耐克专为亚洲男士身材调整的标准版运动剪裁，不是欧版那种偏长偏窄的版型。XL码对应适合175到185身高，体重在160斤到190斤区间的人穿着，深灰色款的面料弹力和另外两个配色完全一致，宽松度足够做深蹲、扩胸这类大幅度动作，正常肩宽背厚的健身爱好者穿也不会有紧绷勒肩的情况，不用额外选大一号。"},{"question":"白色款的T恤会不会透？穿浅色内衣会不会印出来痕迹？","answer":"这款M码白色的T恤采用的是双层交织的密织工艺，不是那种薄透的单层平纹布，正常穿肤色或者白色的运动内衣、浅色内搭都不会出现明显透色的情况。只有当面料完全被汗水浸湿之后，才会有轻微的通透感，日常通勤或者轻度运动的时候完全不用担心透的尴尬，特意做了加密的领口和袖口位置，就算机洗拉扯多次也不会出现织线变松漏透的问题。"},{"question":"这件T恤的领口洗久了会不会变形垮掉？","answer":"这款T恤的领口采用的是2公分宽的双层罗纹包边，还做了三针四线的加固走线，比普通T恤的领口牢固度高很多，正常机洗加悬挂晾晒的情况下，穿3到6个月都不会出现领口松弛垮塌堆在脖子上的情况。注意洗的时候不要直接揪住领口用力拧水，晾晒的时候也不要单独把整个衣架的重量挂在领口位置，顺着衣身的受力点挂能进一步延长领口的使用寿命。"},{"question":"深灰色XL码的这款会不会容易粘毛？家里养猫日常穿掉毛会不会沾得满身都是？","answer":"这款深灰色用的是经过抗静电后处理的速干面料，本身的纤维静电吸附力很低，比起普通的纯棉深灰T恤粘毛情况要少很多，日常如果不是在满是猫毛的沙发上反复蹭，基本不会沾明显的浮毛。如果真的沾了少量宠物浮毛，用粘毛滚筒轻轻滚一遍就能全部清理干净，完全不会留下残留，对于养宠家庭日常外穿或者居家运动都很友好。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"我收到的这件L码黑色的，打开一看下摆侧边居然有个两厘米长的脱线口子，找客服说让我自己寄回去退换，来回折腾好几天我本来等着周末打球要穿的，直接耽误事。而且摸起来面料比我之前在实体店买的同款薄不少，出汗之后贴在背上闷得很，根本不像宣传的速干，打完球回家路上捂得后背全是湿的印子，一百多买这么个残次品真的太闹心了。"},{"nickname":"小周","rating":4,"content":"整体穿下来还行，速干效果确实不错，夜跑五公里汗湿之后二十分钟差不多就干了，我买的XL码深灰颜色也很耐脏。就是有个小问题，袖口的走线有点磨胳膊，我第一次穿去练胸，练了一小时二头弯举，大臂外侧被袖口磨得有点发红，之后我自己拿剪刀把袖口的多余毛边剪了才好点，要是出厂的时候能把毛边处理干净就更完美了。"},{"nickname":"大刘","rating":4,"content":"穿着去健身房撸铁挺合适的，弹力够大，做硬拉的时候抬手也不会露肚子，速干面料确实比我之前的纯棉T恤爽太多，不会湿乎乎贴在身上。就是白色M码的领口我洗了三次，现在有点轻微的松垮，不是之前那种紧紧贴脖子的感觉了，虽然还没垮到变形的程度，但还是有点小失望，平时我也没使劲拧领口，可能这个位置的面料确实不算特别耐用。"},{"nickname":"阿泽","rating":4,"content":"199这个价格能买到正牌耐克的速干训练T还是挺值的，我平时通勤穿也不突兀，配运动裤牛仔裤都能搭。就是快递包装太简陋了，就套了个塑料袋，收到的时候衣服表面有好几道压痕，我挂了一晚上才平，还有胸口那个小swoosh标，摸上去胶印不是特别牢，我穿了没几次标边上已经有点轻微起边了，希望能改进下包装和标印制的工艺。"},{"nickname":"阿浩","rating":1,"content":"我买的XL码深灰色，穿上之后才发现比我之前在店里试的同码小一圈，紧得勒肚子，我178/170斤本来以为XL能宽松点，结果穿上去做扩胸运动都卡。而且我洗了一次之后居然轻微掉色，我搭的白运动裤腰边被蹭上了一道灰印子，擦都擦不掉，找客服说这个批次就是这样，不给解决，这质量完全对不起耐克的牌子啊。"},{"nickname":"小宇","rating":5,"content":"这件T恤我已经穿了快三个月了，真的太好用了！平时一周去四次健身房，不管是跑步还是撸铁出一身汗，根本不会像纯棉T恤那样湿了之后沉乎乎贴在背上，不到半小时就干得差不多，身上一直是清爽的。我买的黑色L码特别耐脏，洗了七八次领口一点都没变形，颜色也没发旧，199的价格穿一整年都没问题，最近又给朋友也安利了一件，绝对是性价比拉满的运动刚需款。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_003.json'),
    ('p_clothes_004', 'adidas Essentials 三条纹 男子针织运动长裤 日常休闲收口裤', '阿迪达斯', '服饰运动', '运动长裤', '服饰运动/运动长裤', 299.0, 299.0, 309.0, 600, '3_服饰运动/images/p_clothes_004_live.jpg', '{"product_id":"p_clothes_004","title":"adidas Essentials 三条纹 男子针织运动长裤 日常休闲收口裤","brand":"阿迪达斯","category":"服饰运动","sub_category":"运动长裤","base_price":299.0,"image_path":"3_服饰运动/images/p_clothes_004_live.jpg","skus":[{"sku_id":"s_p_clothes_004_1","properties":{"尺码":"M码","配色":"黑色白三条纹"},"price":299.0},{"sku_id":"s_p_clothes_004_2","properties":{"尺码":"L码","配色":"黑色白三条纹"},"price":299.0},{"sku_id":"s_p_clothes_004_3","properties":{"尺码":"XL码","配色":"黑色白三条纹"},"price":299.0},{"sku_id":"s_p_clothes_004_4","properties":{"尺码":"M码","配色":"深蓝白三条纹"},"price":309.0},{"sku_id":"s_p_clothes_004_5","properties":{"尺码":"L码","配色":"深蓝白三条纹"},"price":309.0},{"sku_id":"s_p_clothes_004_6","properties":{"尺码":"XL码","配色":"深蓝白三条纹"},"price":309.0}],"rag_knowledge":{"marketing_description":"这条阿迪达斯Essentials经典三条纹男子针织运动长裤，采用亲肤透气的纯棉混纺针织面料，摸起来软而不塌不容易起球，侧边标志性白三条纹辨识度拉满，收口裤脚能牢牢贴合脚踝不容易往上滑。不管是日常出门取快递、约朋友逛gai，还是夜跑、去健身房练完换休息裤穿都合适，适配学生党、通勤打工人、日常爱运动的所有男生。洗的时候记得反面翻过来冷水手洗/轻柔机洗，别和深色掉色衣物混泡，不要长时间暴晒不然白条纹容易发黄，选码的时候注意如果喜欢宽松效果可以往大拍一码，久穿也不容易变形走样，百元出头的经典款穿两三年都不过时。","official_faq":[{"question":"这款阿迪达斯三条纹针织长裤的面料具体是什么成分，会不会洗几次就起球勾丝？","answer":"这款长裤采用68%棉+32%聚酯纤维的混纺针织面料，在保留纯棉亲肤透气特性的同时，加入聚酯纤维提升了抗皱性和耐穿度，正常穿着情况下不容易起球勾丝。日常清洗建议将裤身反面外翻，装入洗衣袋选择轻柔模式机洗，不要和带拉链、金属装饰的硬物衣物同洗，也不要使用硬毛刷大力搓揉裤身表面，就能很好地延长裤装的穿着寿命，减少不必要的面料磨损情况。"},{"question":"不同配色的同款长裤价格不一样，是材质做工有区别吗？","answer":"这款不同配色的长裤核心面料、剪裁、做工标准完全一致，价格差异是由配色的备货成本和工艺小细节导致的：M码、L码的黑底白条纹款基础定价299元，XL码的深蓝底白条纹款因为面料定色时的固色工艺成本略高，且该尺码深蓝款的备货量较少，所以定价为309元，不存在任何品质上的高低区分。大家可以根据自己喜欢的颜色和合适的尺码正常选购即可，不用顾虑品质差异问题。"},{"question":"这款收口运动长裤的裤脚弹力怎么样，穿久了会不会松垮垮的收不住脚踝？","answer":"这款长裤的收口位置采用了高弹的氨纶螺纹收口设计，弹力余量足，日常正常穿着拉扯的情况下，不容易出现松垮变形的情况。但要注意清洗的时候不要用热水长时间泡裤脚位置，也不要洗完之后直接使劲拧绞螺纹部分，晾晒的时候不要把裤脚挂在过重的衣架挂钩上拉长螺纹，正常护理情况下穿一两年都能保持很好的贴合度，日常运动或者走路的时候不会出现裤脚往上滑堆在小腿肚的尴尬情况。"},{"question":"这款裤子的侧边白三条纹是印花还是织上去的，会不会洗两次就掉了？","answer":"这款Essentials系列的侧边三条纹不是普通胶印，是采用同面料的针织织带直接车缝在裤身侧边的，牢固度比普通印花高很多，正常洗护根本不会出现掉纹、开裂的情况。只有长期用漂白剂、碱性极强的洗衣粉长时间浸泡条纹位置，才有可能导致白织带发黄变旧，日常清洗的时候避开漂白类洗护产品，反面洗护不要大力搓揉条纹部位，穿很久之后三条纹依旧能保持清晰挺括的状态，辨识度完全不会减。"},{"question":"这款男款运动长裤的选码要注意什么，比如178cm、75kg选哪个码合适？","answer":"这款长裤是常规偏宽松的运动裤剪裁，不是修身束脚的版型，正常喜欢合身效果的话按照平时穿的运动裤正码选就可以。如果是178cm、75kg的消费者，平时喜欢刚好不紧绷的效果选L码的黑底白条纹款就刚好，要是偏好oversize宽松感，或者平时穿的时候习惯在里面套秋裤，就可以选XL码的深蓝款。要注意这款不同配色的同尺码裤长腰围参数完全一致，不用因为换配色额外调整选码标准。"}],"user_reviews":[{"nickname":"小宇","rating":5,"content":"拿到手真的超惊喜，面料摸起来软乎乎的但完全不会薄透，侧边的白条纹是织上去的不是那种廉价印花，走线整整齐齐的没多余线头。我175穿L码刚好，收口的位置贴脚踝不勒腿，最近每天穿它去夜跑，跑完直接穿去楼下买宵夜也完全不违和，洗了三次也没起球没变形，这个价格能买到阿迪达斯的正牌经典款真的太值了，已经推荐给同寝室友一起凑单买了。"},{"nickname":"阿凯","rating":2,"content":"买的M码黑条纹款，穿了不到一周大腿内侧的位置就起了好几个小毛球，我平时也没穿它做剧烈运动，就是正常上下班通勤走路，摩擦多的地方起球起得太明显了。而且洗了一次之后白条纹居然有点轻微发黄，我明明是冷水单独手洗的，完全没碰漂白的东西，感觉这个质量配不上这个价位，之前买的别家同类型运动裤穿大半年都没这问题，有点失望。"},{"nickname":"大杨","rating":1,"content":"收到货拆开直接傻了，裤腰的位置居然漏缝了快两厘米的口子，走线歪歪扭扭的，侧边三条纹车缝的时候还皱成一团。找客服说只能退换不能补偿，我着急穿就自己找裁缝店花了二十块钱缝了，结果穿第一天坐下的时候，裆部位置直接崩开了个小口子，这品控也太离谱了，三百块的裤子做工连几十块的地摊货都不如，再也不会来买了。"},{"nickname":"阿泽","rating":3,"content":"整体版型其实还可以，上身后挺显瘦的，但我180穿XL码的深蓝款，裤长居然短了一截，收口位置直接卡在脚踝骨上面，露出一大截袜子特别丑，之前看详情页标注的裤长明明够的，结果实际到手短了快三厘米。而且面料比我之前买的同系列旧款薄很多，现在这个天气穿有点透风，冬天根本没法单穿，只能等开春升温之后再套一下，感觉性价比不算高。"},{"nickname":"小峰","rating":4,"content":"裤子整体质感是不错的，经典三条纹的款式搭卫衣搭T恤都好看，日常出门穿完全够用，面料亲肤度也够，贴身穿不扎腿。就是有个小缺点，裤腰的抽绳留得太短了，系完蝴蝶结剩下的绳头特别短，时不时会从裤腰的孔里缩进去，每次掏半天才能掏出来，要是抽绳能做长一点就完美了，整体还是过得去的，不算踩大雷。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_004.json'),
    ('p_clothes_005', '李宁 运动生活系列 男子连帽套头卫衣 基础Logo印花上衣', '李宁', '服饰运动', '卫衣', '服饰运动/卫衣', 259.0, 259.0, 269.0, 900, '3_服饰运动/images/p_clothes_005_live.jpg', '{"product_id":"p_clothes_005","title":"李宁 运动生活系列 男子连帽套头卫衣 基础Logo印花上衣","brand":"李宁","category":"服饰运动","sub_category":"卫衣","base_price":259.0,"image_path":"3_服饰运动/images/p_clothes_005_live.jpg","skus":[{"sku_id":"s_p_clothes_005_1","properties":{"尺码":"M码","颜色":"灰色"},"price":259.0},{"sku_id":"s_p_clothes_005_2","properties":{"尺码":"M码","颜色":"黑色"},"price":259.0},{"sku_id":"s_p_clothes_005_3","properties":{"尺码":"M码","颜色":"深蓝色"},"price":259.0},{"sku_id":"s_p_clothes_005_4","properties":{"尺码":"L码","颜色":"灰色"},"price":259.0},{"sku_id":"s_p_clothes_005_5","properties":{"尺码":"L码","颜色":"黑色"},"price":259.0},{"sku_id":"s_p_clothes_005_6","properties":{"尺码":"L码","颜色":"深蓝色"},"price":259.0},{"sku_id":"s_p_clothes_005_7","properties":{"尺码":"XL码","颜色":"灰色"},"price":269.0},{"sku_id":"s_p_clothes_005_8","properties":{"尺码":"XL码","颜色":"黑色"},"price":269.0},{"sku_id":"s_p_clothes_005_9","properties":{"尺码":"XL码","颜色":"深蓝色"},"price":269.0}],"rag_knowledge":{"marketing_description":"这款李宁运动生活系列男款连帽套头卫衣，核心卖点就是经典不挑人的基础大Logo印花+舒适耐穿的亲肤面料，日常出街、轻运动穿都完全不违和。面料是320g重磅精梳棉混纺定制款，摸起来软乎乎的但不容易起球，连帽做了加固走线，洗多少次帽型都不容易塌。适用人群覆盖18-40岁的男性，不管是学生党上课、上班族通勤顺路跑两公里，还是周末和朋友约球后散步穿都合适。使用建议：刚拿到手先反过来冷水轻柔洗，不要和深色掉色衣物混泡，印花部分不要直接大力搓洗就能穿很久。注意XL码的深蓝色款定价是269元，选码的时候可以对照详情页的肩围表，喜欢宽松感的朋友可以选比日常穿的大半码哦。","official_faq":[{"question":"这款李宁男款连帽卫衣的不同SKU定价不一样吗，具体差价是怎么来的？","answer":"这款卫衣不同SKU确实存在定价差异，其中M码灰色、L码黑色日常售价都是259元，XL码的深蓝色款定价为269元。主要是因为深蓝色属于该系列的限定热卖色号，面料预缩处理的工序多了一道固色环节，成本小幅上升所以定价略高，三个尺码对应的版型、面料克重、印花工艺都是完全一致的，大家可以根据自己的码数偏好和喜欢的颜色按需选择就行，不用担心不同价格的款式质量有区别。"},{"question":"衣服胸口的基础李宁Logo印花洗多了会不会开裂掉皮啊？","answer":"咱们这款卫衣用的是高固色水性胶浆印花工艺，不是市面上廉价的热转印胶，正常按照洗涤说明操作的话，反复机洗50次以上印花也不会开裂掉皮。洗涤的时候注意把卫衣翻面，不要用硬毛刷刷印花位置，也不要把印花部位直接挂在尖锐的晾衣架上拉扯，洗完之后不要长时间放在阳光下暴晒印花区域，就能最大程度延长印花的使用寿命，哪怕穿一整个春秋季Logo也能保持清晰完整的状态。"},{"question":"我178cm75kg选L码的黑色款会太贴身吗，平时里面还想套件薄T恤穿？","answer":"这款L码黑色款的实际衣长是70cm，胸围做的是112cm的宽松版型，你178cm75kg的身材穿完全不会贴身，里面叠穿一件薄款棉T恤甚至薄的打底速干衣都绰绰有余。如果你喜欢更oversize的落肩效果也可以考虑加钱选XL码的深蓝色款，整体衣长会多3cm，胸围多4cm，想要穿出街头松弛感的话选XL也没问题，日常运动抬手什么的都不会有束缚感，不会出现抬胳膊衣服往上跑的情况。"},{"question":"这款灰色M码的卫衣帽子里面有没有抽绳啊，风大的时候能不能拉紧？","answer":"咱们这款所有码数的卫衣都是配有同色系的高密度棉质抽绳的，灰色M码的抽绳是浅灰色和衣身完全同色，风大的时候完全可以拉紧收住领口，不会灌冷风进来。抽绳的末端还做了金属包边处理，不会用两次就出现脱线散边的情况，帽子的容量也足够，戴头上的时候不会压得头皮发闷，春秋降温的时候单穿戴帽子，冬天还能搭在羽绒服里面当内搭的连帽层，实用度非常高。"},{"question":"深蓝色XL款的卫衣会不会很容易掉色啊，洗的时候能和白T恤一起放洗衣机吗？","answer":"这款XL深蓝色款我们出厂前做了3次预洗固色处理，正常冷水下单独短时间机洗基本不会出现浮色掉色的情况，但前3次清洗的时候还是建议不要和浅色白色衣物混洗，避免极少量的新衣服浮色染到其他衣服上。尽量不要用超过40度的热水长时间浸泡衣服，也不要用漂白类的洗涤剂去搓洗深蓝色的衣身，正常护理的话穿很久颜色都能保持均匀鲜亮，不会出现局部发白的情况。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"太惊喜了！之前一直怕李宁的卫衣买小，选的L码黑色刚好合适，面料摸上去特别扎实，不是那种薄得透肉的便宜货。胸口的Logo印花质感特别好，不是那种硬邦邦的胶印，穿在身上完全不会硌胸口。上周穿去打羽毛球，出汗之后也没有贴在背上，洗完之后完全没变形没起球，连帽的抽绳也很有质感，这个价格买到真的比我之前买的杂牌卫衣值太多，已经推荐给室友了。"},{"nickname":"小峰","rating":2,"content":"这次购物体验挺糟心的，冲着深蓝XL款买的贵10块，结果收到货发现口袋边缘的走线有个小线头没处理就算了，第一次冷水手洗就掉了不少浮色，把我搭在一起洗的浅灰色运动裤给染蓝了一点。而且版型比我之前买的同码李宁卫衣短了小半指，穿上去盖不住胯部，我180cm穿上刚到腰线，完全没有想要的宽松效果，找客服还说属于正常工艺范围，这次挺失望的。"},{"nickname":"阿泽","rating":5,"content":"M码灰色款拿到手直接惊了，面料软乎乎的但是完全不塌，平时上课套个卫衣就出门特别省事，搭牛仔裤运动裤都好看。领口的罗纹做的特别密实，穿了快一个月了也没松垮变形，连帽部分的走线也很整齐，戴上去不会往下滑。昨天不小心溅了点奶茶在衣服上，搓两下就洗干净了，完全没留印子，李宁的基础款真的永远不会出错，性价比拉满，物超所值。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_005.json'),
    ('p_clothes_006', 'Nike Sportswear Club 男子针织运动长裤 基础休闲束脚裤', 'Nike', '服饰运动', '运动长裤', '服饰运动/运动长裤', 349.0, 349.0, 359.0, 600, '3_服饰运动/images/p_clothes_006_live.jpg', '{"product_id":"p_clothes_006","title":"Nike Sportswear Club 男子针织运动长裤 基础休闲束脚裤","brand":"Nike","category":"服饰运动","sub_category":"运动长裤","base_price":349.0,"image_path":"3_服饰运动/images/p_clothes_006_live.jpg","skus":[{"sku_id":"s_p_clothes_006_1","properties":{"尺码":"M码","颜色":"深灰色"},"price":349.0},{"sku_id":"s_p_clothes_006_2","properties":{"尺码":"L码","颜色":"黑色"},"price":349.0},{"sku_id":"s_p_clothes_006_3","properties":{"尺码":"XL码","颜色":"黑色"},"price":359.0},{"sku_id":"s_p_clothes_006_4","properties":{"尺码":"M码","颜色":"黑色"},"price":349.0},{"sku_id":"s_p_clothes_006_5","properties":{"尺码":"L码","颜色":"深灰色"},"price":349.0},{"sku_id":"s_p_clothes_006_6","properties":{"尺码":"XL码","颜色":"深灰色"},"price":359.0}],"rag_knowledge":{"marketing_description":"这款Nike Sportswear Club男子针织束脚长裤，专为追求舒适与日常质感的男性打造，采用细腻重磅针织毛圈面料，软而不塌上身不易起皱，侧边小绣标低调不浮夸，松紧腰头搭配内置抽绳可自由调节松紧，束脚口剪裁刚好收拢裤腿不堆在脚踝，既能遮住小腿多余线条又不会显得臃肿。日常通勤、楼下取外卖、周末约球热身、休闲探店穿都合适，搭配同品牌卫衣或基础白T都很出片。洗涤建议反面冷水轻柔机洗，不要长时间浸泡、不要用漂白剂，晾晒时拉直裤脚能最大程度保持版型，避免暴晒导致面料发硬变色。","official_faq":[{"question":"这款Nike Club针织束脚裤不同SKU的价格不一样，是面料有区别吗？","answer":"这款裤子所有在售SKU的面料、做工、细节设计都是完全一致的，价格差异仅来自尺码库存的成本差异，XL码黑色属于常年热门的畅销大码，备货和仓储的调配成本略高，所以定价为359元，其余M码深灰、L码黑色的日常定价都是349元，大家可以根据自己的尺码需求选择，不用担心不同价格的商品存在品质差异，全部都是官方同生产线正品。"},{"question":"这款针织束脚裤的面料是不是容易起球，春秋穿会不会太厚？","answer":"这款用的是280g左右的新疆棉混纺针织毛圈面料，表面做了磨毛抗起球预处理，正常穿着前提下日常通勤久坐摩擦、搭配运动鞋穿久了都不容易起球，春秋20度左右单穿刚好合适，不会闷汗也不会觉得凉，南方冬天搭配秋裤也能穿，北方零度以上单穿外出也完全没问题，不会像薄款运动裤那样透风，也不会像加绒款那样闷腿。"},{"question":"我178cm78kg选L码黑色会不会卡裆，束脚口会不会勒小腿？","answer":"这款L码黑色的官方净臀围是108cm，裤长是98cm，针对大部分175-180cm、体重70-80kg的男性做了裆部加深剪裁，正常站姿走路完全不会卡裆，束脚口的橡筋做了3cm宽的加宽处理，弹力富余3-5cm，正常小腿围40cm以内的人穿都不会有勒紧的压痕，要是你小腿肌肉特别发达可以选大一码，穿着空间会更宽松舒适。"},{"question":"深灰色M码的裤身会不会容易显脏，洗多了会不会发白？","answer":"这款深灰色M码的面料做了固色预处理，正常日常穿溅到咖啡、灰尘这些浅污渍，用湿纸巾一擦就能擦干净，不会留明显印子，按照说明冷水反面洗涤的话，正常穿洗二三十次都不会出现大面积发白的情况，只有长期暴晒或者用热水加漂白剂洗才会出现面料泛旧的问题，日常洗涤只要注意这些小细节，穿一整年颜色都能保持得很均匀。"},{"question":"这款裤子有没有隐形口袋，能不能放下6.7英寸的大手机不会掉出来？","answer":"这款裤子两侧的插袋做了18cm的加深处理，袋口内侧还做了隐形暗扣设计，正常放6.7英寸的iPhone 14 Pro Max这类大屏手机完全不会掉出来，哪怕你跑步快步走也不用担心滑落，后片还有一个单独的迷你贴袋，可以放门禁卡、交通卡这类小物件，不会晃来晃去磨得腿不舒服，日常出门不用带包也完全够用。"},{"question":"这款束脚裤能不能用来日常慢跑穿，面料会不会勾丝破洞？","answer":"这款针织面料的抗撕扯等级达到了运动服饰的国标A级标准，正常日常慢跑、跳操穿完全没问题，不会随便勾丝破洞，只要不是刻意蹭到尖锐的钢筋、铁丝这类锋利物件，正常穿个两三年都不会出现破洞的情况，不过它属于休闲基础款长裤，不是专业竞速跑步裤，高强度的马拉松训练还是更建议选专业速干运动裤，日常轻度运动穿完全足够。"}],"user_reviews":[{"nickname":"阿凯","rating":4,"content":"整体穿下来还行，版型确实很修饰腿型，我腿有点O型穿这个束脚款刚好遮得七七八八，面料也软乎乎的很舒服。就是刚拆包装的时候闻到点轻微的工业味，挂阳台吹了两天才散掉，腰头的抽绳留得有点长，走路的时候偶尔会滑出来蹭到鞋面上，其他地方都没啥大毛病，349的价格总体还是值得入手的。"},{"nickname":"小宇","rating":5,"content":"这已经是我买的第二条同款了，之前的旧款穿了快两年洗得有点发白才回购的，这次入的L码黑色刚好合身，175cm72kg穿上不用改裤长，束脚口刚好卡在脚踝上面一点，搭空军一号穿特别好看。面料摸起来厚实但不闷，春天二十多度穿完全刚好，口袋够深，我放Max手机跑着取快递都没掉出来，性价比拉满。"},{"nickname":"大张","rating":3,"content":"收到货穿了不到一周，后腰位置经常坐椅子摩擦的地方就起了好几个小毛球，用毛球器剃完没两天又长出来了，之前买的别家同价位针织裤都没这个问题。客服说这是正常针织面料的损耗，花三百多买的裤子感觉质量有点配不上价格，版型倒是挺好看的，就是面料抗起球的处理做得不到位，不太推荐久坐的上班族买。"},{"nickname":"阿泽","rating":5,"content":"买给我爸当生日礼物的，选的M码深灰色，他170cm65kg穿上特别合适，腰头的抽绳调节起来很方便，他平时跳完广场舞散散步穿都特舒服。裤子洗了三次都没掉色也没变形，侧边的小勾标绣得特别平整，没有多余的线头，我爸平时省得很说这是他买过最合心意的运动裤，让我再给他回购一条别的颜色。"},{"nickname":"阿远","rating":1,"content":"收到的XL码黑色明显是被人穿过退回来的二手货，裤脚位置有明显的污渍痕迹，腰头的橡筋都已经松垮没有弹力了，口袋里还留了半张别人的超市购物小票，找客服退货退了半天才同意，来回折腾了快一周才处理完，花359买条别人穿过的残次品体验感特别差，以后不会再来这家买东西了。"},{"nickname":"小辰","rating":5,"content":"最近健身天天穿这条裤子，练腿的时候深蹲完全不卡裆，面料弹力够大动作怎么做都不会紧绷，束脚口不会往上滑，撸铁完直接穿着去买饭也完全不尴尬，不用换别的外穿裤子。之前怕针织裤显胖，结果穿上身意外的显瘦，搭个基础白T恤就能出门，洗了好多次版型都没塌，349的价格能穿一整年太值了。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_006.json'),
    ('p_clothes_007', 'Nike Air Zoom Pegasus 41 男子缓震跑步鞋日常训练公路跑鞋', '耐克', '服饰运动', '跑步鞋', '服饰运动/跑步鞋', 899.0, 899.0, 949.0, 2200, '3_服饰运动/images/p_clothes_007_live.jpg', '{"product_id":"p_clothes_007","title":"Nike Air Zoom Pegasus 41 男子缓震跑步鞋日常训练公路跑鞋","brand":"耐克","category":"服饰运动","sub_category":"跑步鞋","base_price":899.0,"image_path":"3_服饰运动/images/p_clothes_007_live.jpg","skus":[{"sku_id":"s_p_clothes_007_1","properties":{"款型":"男款","尺码":"39码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_2","properties":{"款型":"男款","尺码":"40码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_3","properties":{"款型":"男款","尺码":"40.5码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_4","properties":{"款型":"男款","尺码":"41码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_5","properties":{"款型":"男款","尺码":"42码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_6","properties":{"款型":"男款","尺码":"42.5码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_7","properties":{"款型":"男款","尺码":"43码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_8","properties":{"款型":"男款","尺码":"44码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_9","properties":{"款型":"男款","尺码":"44.5码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_10","properties":{"款型":"男款","尺码":"45码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_11","properties":{"款型":"男款","尺码":"46码","鞋楦":"标准楦"},"price":899.0},{"sku_id":"s_p_clothes_007_12","properties":{"款型":"男款","尺码":"39码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_13","properties":{"款型":"男款","尺码":"40码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_14","properties":{"款型":"男款","尺码":"40.5码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_15","properties":{"款型":"男款","尺码":"41码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_16","properties":{"款型":"男款","尺码":"42码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_17","properties":{"款型":"男款","尺码":"42.5码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_18","properties":{"款型":"男款","尺码":"43码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_19","properties":{"款型":"男款","尺码":"44码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_20","properties":{"款型":"男款","尺码":"44.5码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_21","properties":{"款型":"男款","尺码":"45码","鞋楦":"宽楦"},"price":949.0},{"sku_id":"s_p_clothes_007_22","properties":{"款型":"男款","尺码":"46码","鞋楦":"宽楦"},"price":949.0}],"rag_knowledge":{"marketing_description":"这双Nike Air Zoom Pegasus 41男子跑步鞋是耐克飞马系列迭代到第41代的训练款，搭载前后掌分离式Zoom Air气垫，搭配全掌ReactX泡棉中底，缓震反馈比前代更韧不塌。工程网布鞋面做了加密透气孔设计，长时间跑脚不闷汗，标准楦型适配多数亚洲男性脚型。核心卖点是兼顾长距离公路跑的支撑性和日常压街的百搭感，适用人群覆盖每周跑量10-50公里的入门跑者、日常进行3-10公里路跑的健身爱好者，以及需要一双舒适通勤鞋的上班族。日常场景下不管是城市柏油马路训练、小区夜跑还是上班通勤穿都合适。使用建议选大半码更适配厚运动袜，注意不要穿着它去越野跑或进行剧烈对抗球类运动，避免鞋底纹路过度磨损和气垫被尖锐物扎破，雨天穿完及时擦干鞋面缝隙的积水能延长鞋的使用寿命。","official_faq":[{"question":"Nike Air Zoom Pegasus 41和前代Pegasus 40相比，缓震脚感上有什么具体区别？","answer":"Pegasus 41把原来的全掌React泡棉升级成了ReactX泡棉，整体软弹度提升了13%左右，上脚不会像前代那样初踩有点硬，跑起来前掌的Zoom Air气垫位置往足中部微调了2mm，蹬地推进的反馈更跟脚，不会出现前两代偶尔会有的脚掌扯拽感。后跟处额外加了2mm的环形泡棉加固，长距离跑到后半程的时候，后跟的支撑性更好，不会出现鞋脚分离的晃动感，日常通勤走久了也不会有后跟磨脚的情况，对初跑者的友好度比前代高不少。"},{"question":"这双鞋的标准楦版型，宽脚或者脚背高的男性能直接穿吗？需要选大多少码合适？","answer":"这款的标准楦是针对亚洲男性脚型调整过的正常宽楦，正常足围的脚按照日常穿的运动鞋正码选就完全没问题。如果是脚宽超过E级的宽脚，或者脚背偏高超过4cm的朋友，建议选大半码，比如平时穿42码的选42.5码就刚好，不会出现脚面被鞋面压得发麻的情况。特别注意如果是习惯穿加厚速干跑步袜的跑者，哪怕是正常脚型，也可以优先选大半码，跑步的时候脚掌充血微微胀开也不会挤脚，能避免长时间跑磨出水泡的问题。"},{"question":"平时每周跑3次每次跑10公里左右，这双鞋的中底大概能支撑多少公里的使用寿命？","answer":"按照每次跑10公里、每周3次的常规训练强度来算，正常体重在60-80公斤的跑者，这双Pegasus41的ReactX中底加上Zoom气垫组合，正常使用寿命大概在600-800公里左右。如果是超过90公斤的大体重跑者，中底损耗速度会快一些，大概在500公里左右就会感觉到明显的踩实感，缓震反馈变弱。平时不用的时候把鞋放在阴凉通风的地方，不要长期暴晒在太阳底下，能避免泡棉提前老化发硬，最多可以延长150公里左右的使用周期。"},{"question":"这双鞋的工程网面可以直接水洗吗？清洗的时候有什么需要注意的地方？","answer":"这款的工程网面是高密度编织的，可以进行水洗，但绝对不要直接整只鞋泡在水里超过1小时，也别用硬毛鞋刷大力蹭鞋面，很容易把细编织线勾出毛球，后续破洞的概率会变高。建议用软毛刷沾中性洗衣液轻轻刷脏的位置，刷完之后用大量清水冲干净，然后把鞋塞进报纸撑住鞋型，放在通风的阴凉处自然晾干，不要放在阳台大太阳底下暴晒，暴晒会让中底的泡棉快速老化发黄，也容易让鞋的开胶概率变高，正常这样清洗的话鞋面穿一两年也不会变形。"}],"user_reviews":[{"nickname":"跑者阿凯","rating":5,"content":"我每周大概跑4次每次8公里，穿这双鞋跑了快一个月了，脚感真的太惊喜了，前掌气垫蹬地的时候反馈特别干脆，完全没有拖沓的感觉，上周跑半马后半程脚也没怎么酸疼。网面透气性特别好，夏天30多度跑完全程袜子也只是微微潮，完全没有闷脚捂汗的情况，标准楦对我这种正常脚型太友好了，鞋跟卡得很稳完全不晃，之后训练就锁定这双飞马41了，太满意。"},{"nickname":"阿远","rating":3,"content":"我是典型的宽脚，当时看页面说标准楦适配宽脚就直接按正码买了42码，结果上脚挤得小脚趾发麻，跑了一次5公里下来外侧脚边直接磨红了，哪怕换薄袜子穿也还是挤脚。找客服问才说宽脚要选大半码，我穿了一次鞋底沾了灰也没法退换，只能闲置当拖鞋穿，感觉前期尺码指引做得太不到位了，完全没提前把宽脚的适配注意点标在显眼位置，白浪费小九百块。"},{"nickname":"小宇","rating":4,"content":"整体穿着感其实还不错，平时通勤上下班走路特别舒服，缓震很软，踩上去回弹感刚好不会塌。但我穿了大概两周，发现鞋头位置的网面不小心被路牙子刮了一下直接勾出了一根小线，虽然没破但看着很明显，编织的密度比我之前买的飞马39要薄一点。整体性价比还行，就是网面耐造程度有点低于预期，平时穿得稍微注意点别乱刮的话日常用还是完全够用的，给个四星吧。"},{"nickname":"大周","rating":3,"content":"我体重88公斤，本来冲着飞马系列缓震好买的，结果穿了还不到300公里，就明显感觉到后跟的中底硬得像踩砖一样，之前缓震的软弹感完全没了，下楼的时候脚震得后跟疼。之前穿旧款飞马40同样的跑量至少还能有回弹感，这款的ReactX泡棉好像损耗比前代快很多，感觉寿命比宣传的短了一半，这个价位的鞋不应该是这个品质，有点失望。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_007.json'),
    ('p_clothes_008', 'adidas Ultraboost 5 男子缓震跑步鞋针织鞋面日常慢跑训练鞋', '阿迪达斯', '服饰运动', '跑步鞋', '服饰运动/跑步鞋', 1399.0, 1399.0, 1399.0, 1100, '3_服饰运动/images/p_clothes_008_live.jpg', '{"product_id":"p_clothes_008","title":"adidas Ultraboost 5 男子缓震跑步鞋针织鞋面日常慢跑训练鞋","brand":"阿迪达斯","category":"服饰运动","sub_category":"跑步鞋","base_price":1399.0,"image_path":"3_服饰运动/images/p_clothes_008_live.jpg","skus":[{"sku_id":"s_p_clothes_008_1","properties":{"款型":"男款","尺码":"40码"},"price":1399.0},{"sku_id":"s_p_clothes_008_2","properties":{"款型":"男款","尺码":"40.5码"},"price":1399.0},{"sku_id":"s_p_clothes_008_3","properties":{"款型":"男款","尺码":"41码"},"price":1399.0},{"sku_id":"s_p_clothes_008_4","properties":{"款型":"男款","尺码":"41.5码"},"price":1399.0},{"sku_id":"s_p_clothes_008_5","properties":{"款型":"男款","尺码":"42码"},"price":1399.0},{"sku_id":"s_p_clothes_008_6","properties":{"款型":"男款","尺码":"42.5码"},"price":1399.0},{"sku_id":"s_p_clothes_008_7","properties":{"款型":"男款","尺码":"43码"},"price":1399.0},{"sku_id":"s_p_clothes_008_8","properties":{"款型":"男款","尺码":"43.5码"},"price":1399.0},{"sku_id":"s_p_clothes_008_9","properties":{"款型":"男款","尺码":"44码"},"price":1399.0},{"sku_id":"s_p_clothes_008_10","properties":{"款型":"男款","尺码":"44.5码"},"price":1399.0},{"sku_id":"s_p_clothes_008_11","properties":{"款型":"男款","尺码":"45码"},"price":1399.0}],"rag_knowledge":{"marketing_description":"这双adidas Ultraboost 5男子跑鞋是阿迪达斯专为慢跑爱好者打造的年度升级款，全新升级的Boost中底调校后回弹反馈比上代提升12%，轻量针织鞋面完全贴合脚面，久跑也不闷脚压脚。核心卖点就是软而不塌的缓震脚感，搭配稳定支撑鞋笼设计，既适配3-10公里日常慢跑、间歇训练，平时通勤逛街穿也完全不硌脚。适用人群覆盖入门跑者、日常有运动习惯的上班族，想要一双兼顾运动和出街的百搭鞋款的男生都合适。注意穿着时尽量避开尖锐硬物刮蹭针织面，清洁用软毛刷蘸温和洗涤剂轻刷即可，不要长时间泡水暴晒避免中底缓震性能提前衰减。","official_faq":[{"question":"Ultraboost 5的针织鞋面和上代相比透气性有没有升级，夏天30度以上长时间跑会不会闷脚？","answer":"这款Ultraboost 5的针织鞋面采用了全新的Primeknit 360织法，在脚背、足侧等易出汗的区域专门做了镂空透气织孔设计，相比上代Ultraboost 4的透气面积提升了近20%。正常30度左右的天气进行5-8公里慢跑，鞋内可以保持持续的空气流通，跑完鞋面不会大面积积汗，只有脚面接触鞋面的位置会有轻微湿润感，不会出现闷脚捂臭的情况。如果是长时间暴晒下跑半马以上的长距离，建议搭配速干运动袜进一步提升舒适感。"},{"question":"这款鞋的Boost中底日常穿久了会不会出现明显塌陷，正常使用的缓震寿命大概是多久？","answer":"这款Ultraboost 5的中底采用了高密度粒子发泡的Boost材料，粒子融合度更高，正常使用场景下不会出现部分旧款Ultraboost那种局部颗粒碎裂塌陷的情况。如果是每周3次、每次5公里左右的规律慢跑+日常通勤穿插穿着，缓震性能可以保持12-18个月左右不会有明显衰减。日常注意不要长时间整只鞋被重物压放、不要放在超过60度的高温环境比如暴晒的汽车后备箱里，就能最大程度延长中底的使用寿命，缓震脚感可以维持更久。"},{"question":"平时穿常规运动鞋42码刚好，这款Ultraboost 5的鞋楦偏窄吗，选码要不要往大买半码？","answer":"这款Ultraboost 5的鞋楦做了微宽优化，相比前几代Ultraboost的窄鞋楦对宽脚用户友好很多，正常足围、脚型不偏宽的跑者，按照平时穿阿迪达斯常规跑鞋的正码选就完全没问题。如果你的脚型是偏宽的瘦肥脚、或者跑步习惯穿厚款专业竞速袜的话，可以选大半码，避免长时间跑步后脚充血发胀出现挤脚趾的情况。现在在售的42码对应脚长是265mm，43码对应脚长是270mm，大家可以先量一下裸脚长度对照选择更准确。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"穿了快两周来评，刚上脚脚感确实软弹，但是我本身足弓有点低，跑了两次每次五公里，跑完足弓酸到不行，之前穿旧款Ultraboost3就完全没这情况。仔细摸了下才发现这款的足弓支撑做的比上代硬很多，不是那种自然贴合的弧度，我这种低足弓真的驾驭不了。而且针织鞋面我穿了第三次就不小心被路牙子蹭出个小勾丝，虽说没破但看着挺明显的，这个价位品控细节感觉有点不值。"},{"nickname":"阿泽","rating":5,"content":"这双鞋真的是我今年买到最满意的跑鞋了，平时我下班绕着江边跑个六七公里，脚踩上去的回弹感特别明显，落地完全没有硬震脚的感觉，跑完膝盖一点都不酸。针织鞋面贴脚又不勒，我脚属于偏瘦的款，包裹感刚刚好，夏天跑完全不会闷脚，出汗了也没有黏糊糊贴在脚上的感觉。平时不跑步穿去上班搭运动裤牛仔裤都好看，穿了快一个月鞋底都没什么明显磨损，太值了。"},{"nickname":"小宇","rating":5,"content":"之前纠结了好久ultraboost的新款，终于咬咬牙入手了43码，上脚第一秒就惊了，比我之前买的任何一双阿迪跑鞋都软弹，上周跑了个12公里的半马入门距离，全程脚都没磨泡，中底的支撑全程在线，没有跑到后半程脚酸的情况。鞋型也特别修饰脚型，我平时穿厚运动袜也完全不挤脚趾，洗完晾干速干特别快，第二天穿完全没味道，最近出门几乎天天穿。"},{"nickname":"大飞","rating":4,"content":"整体体验还是不错的，缓震脚感确实符合这个价位的水平，日常慢跑和通勤穿都挺舒服的，唯一有点小遗憾就是鞋底的纹路沾了点小石子之后卡的特别紧，每次跑完步都要抠半天石子有点麻烦。还有就是鞋面的针织材质太容易沾灰了，出门走一圈白色边缝就沾黑印，得经常用湿抹布擦，稍微有点费打理。其他方面都没毛病，两百斤的人穿跑跳都稳，包裹支撑都在线。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_008.json'),
    ('p_clothes_009', 'HOKA Clifton 9 男子缓震公路跑鞋厚底回弹日常长距离训练鞋', 'HOKA', '服饰运动', '跑步鞋', '服饰运动/跑步鞋', 1099.0, 1099.0, 1119.0, 1800, '3_服饰运动/images/p_clothes_009_live.jpg', '{"product_id":"p_clothes_009","title":"HOKA Clifton 9 男子缓震公路跑鞋厚底回弹日常长距离训练鞋","brand":"HOKA","category":"服饰运动","sub_category":"跑步鞋","base_price":1099.0,"image_path":"3_服饰运动/images/p_clothes_009_live.jpg","skus":[{"sku_id":"s_p_clothes_009_1","properties":{"款型":"男款","颜色":"经典黑","尺码":"40码"},"price":1099.0},{"sku_id":"s_p_clothes_009_2","properties":{"款型":"男款","颜色":"经典黑","尺码":"41码"},"price":1099.0},{"sku_id":"s_p_clothes_009_3","properties":{"款型":"男款","颜色":"经典黑","尺码":"42码"},"price":1099.0},{"sku_id":"s_p_clothes_009_4","properties":{"款型":"男款","颜色":"经典黑","尺码":"42.5码"},"price":1099.0},{"sku_id":"s_p_clothes_009_5","properties":{"款型":"男款","颜色":"经典黑","尺码":"43码"},"price":1099.0},{"sku_id":"s_p_clothes_009_6","properties":{"款型":"男款","颜色":"经典黑","尺码":"44码"},"price":1099.0},{"sku_id":"s_p_clothes_009_7","properties":{"款型":"男款","颜色":"云朵白","尺码":"40码"},"price":1099.0},{"sku_id":"s_p_clothes_009_8","properties":{"款型":"男款","颜色":"云朵白","尺码":"41码"},"price":1099.0},{"sku_id":"s_p_clothes_009_9","properties":{"款型":"男款","颜色":"云朵白","尺码":"42码"},"price":1099.0},{"sku_id":"s_p_clothes_009_10","properties":{"款型":"男款","颜色":"云朵白","尺码":"42.5码"},"price":1099.0},{"sku_id":"s_p_clothes_009_11","properties":{"款型":"男款","颜色":"云朵白","尺码":"43码"},"price":1099.0},{"sku_id":"s_p_clothes_009_12","properties":{"款型":"男款","颜色":"云朵白","尺码":"44码"},"price":1099.0},{"sku_id":"s_p_clothes_009_13","properties":{"款型":"男款","颜色":"雾霾蓝","尺码":"40码"},"price":1119.0},{"sku_id":"s_p_clothes_009_14","properties":{"款型":"男款","颜色":"雾霾蓝","尺码":"41码"},"price":1119.0},{"sku_id":"s_p_clothes_009_15","properties":{"款型":"男款","颜色":"雾霾蓝","尺码":"42码"},"price":1119.0},{"sku_id":"s_p_clothes_009_16","properties":{"款型":"男款","颜色":"雾霾蓝","尺码":"42.5码"},"price":1119.0},{"sku_id":"s_p_clothes_009_17","properties":{"款型":"男款","颜色":"雾霾蓝","尺码":"43码"},"price":1119.0},{"sku_id":"s_p_clothes_009_18","properties":{"款型":"男款","颜色":"雾霾蓝","尺码":"44码"},"price":1119.0}],"rag_knowledge":{"marketing_description":"HOKA Clifton 9男款跑鞋专为长距离跑者和日常爱逛人群打造，全掌加厚的全新EVA中底重量比前代轻了足足15%，踩着软但完全不塌，落地时的缓震感能把公路的硬震动直接卸掉大半，脚感像踩在软弹的云朵垫上。鞋面是 engineered 工程网布，孔眼排布疏密刚好，夏天跑10公里脚也不闷汗，侧边的支撑块还能稳住足弓不晃。不管你是每周要跑5次10公里的训练党，还是每天要走一万步通勤逛展的朋友都能穿，日常搭配运动装出街也超好看。建议初次上脚先穿普通棉袜走3天日常路再上长距离跑，刚穿不要直接跑半马挑战极限，注意不要踩尖锐碎石避免划破外底耐磨橡胶层。","official_faq":[{"question":"Clifton 9的厚底会不会重心不稳，初次穿厚底跑鞋容易崴脚吗？","answer":"这款鞋的中底做了加宽的底盘设计，前后掌过渡的坡度比前代调得更平缓，重心其实比普通厚底鞋稳很多，只要你不是完全零运动基础，上脚走个十几步就能适应。它的侧墙还做了微微的硬质包裹边，日常跑通勤甚至快走赶地铁都不容易晃脚，只有刚上脚的前半小时会稍微有点不习惯厚底的脚感，建议先穿它走1-2天日常通勤路，适应了缓震反馈再上跑道，基本不会出现崴脚的情况，完全不用担心适配问题。"},{"question":"这双鞋用来做日常5到10公里的长距离训练，后掌的回弹会越跑越泄力吗？","answer":"这款Clifton 9用的是全新调整的低密度EVA混合配方中底，经过品牌实验室的测试，连续跑300公里之后中底的回弹保留率还能达到80%以上，正常日常单次跑10公里完全不会出现后半程脚感塌软泄力的情况。很多长距离跑友反馈哪怕跑半马全程，脚感前半程软后半程弹，到最后几公里足弓也不会因为中底塌掉直接磕地面，完全能满足日常长距离训练的回弹需求，正常穿个小半年都不会有明显的脚感衰减。"},{"question":"平时穿普通运动鞋是42码，买这双Clifton 9需要选大半码吗？","answer":"这款男款Clifton 9的鞋楦是做了标准的正常宽度鞋型，针对亚洲男性的前掌偏宽的脚型做了小幅度优化，如果你是正常瘦脚或者普通宽度脚型，按平时穿的常规运动鞋码数选就完全没问题。但如果你是前掌特别宽的宽脚，或者跑步的时候习惯穿厚的专业跑步棉袜，跑步过程中脚会微微充血发胀，就建议选大半码更舒服，这次在售的42、43码都是标准码，平时穿42常规鞋选42就行，穿厚袜子跑觉得挤脚可以留好吊牌退换。"},{"question":"这双鞋的外底是防滑设计吗，下雨天跑柏油公路会不会打滑？","answer":"这款鞋的外底用的是分区防滑的耐磨橡胶，在足跟和前掌落地受力的重点区域做了细密的波浪形防滑纹路，干的柏油公路抓地力很强，哪怕是刚下过小雨的微湿柏油路，正常配速跑都不容易打滑。但要注意它的防滑纹路是针对公路跑鞋设计的，不要去踩铺了青苔的瓷砖地或者积满水的光滑大理石地面，那种极端湿滑场景下所有跑鞋都容易滑，日常雨天通勤跑、跑训练课走普通湿滑公路完全够用，外底耐磨度也够，正常穿跑四五百公里纹路都不会磨平。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"跑了快五年步，第一次穿缓震这么舒服的跑鞋，上周跑半马穿它全程脚都没酸，以前穿旧鞋跑到15公里足弓就开始疼，这双Clifton9踩着软弹但完全不卸力，厚底走路通勤也像踩云朵，网面透气特别好，三伏天跑完袜子脚面都没闷出多少汗，搭配运动短裤出街朋友还说鞋超好看，完全可以兼顾跑步和日常穿，一千出头这个价位真的买得太值了。"},{"nickname":"小宇","rating":3,"content":"穿了快三周来评价，脚感确实软是真的，但我脚型本身偏瘦，前掌部分感觉还是有点空，系紧鞋带跑的时候脚在鞋里微微打滑，跑长距离的时候前掌总觉得有点使不上劲，要是鞋楦能再收窄一点就好了。日常走路倒是挺舒服的，只是作为竞速训练鞋我穿着有点不对付，用来日常压马路没问题，偏瘦脚的朋友买之前最好先试试脚感。"},{"nickname":"大强","rating":5,"content":"之前一直穿旧款Clifton8，这次升级9真的提升太大了，中底明显轻了好多，以前穿8跑长距离后脚跟总觉得有点沉，这双9跑10公里下来脚轻得很，缓震反馈也更顺，落地蹬地的过渡一点都不卡脚，我这种每周四次长距离训练的人，穿了一个多月中底脚感完全没塌，日常上班通勤踩着走一万步膝盖也不酸，绝对是今年买的最值的跑步鞋。"},{"nickname":"阿哲","rating":1,"content":"收到货穿第一次出门跑5公里，前掌外侧的橡胶纹路没注意直接磨掉一小块，质量也太差了，我就是在普通柏油马路上跑的，又不是去跑砂石路，以前穿别的跑鞋从来没遇到过跑一次就磨坏外底的情况，找客服问也说这是正常磨损，刚买的新鞋直接就有瑕疵，一千多的鞋质量做成这样真的太让人失望了，完全不推荐大家买。"},{"nickname":"小远","rating":1,"content":"我平时运动鞋一直穿42码，特意按推荐选了42码，结果上脚挤得脚趾头顶得慌，穿厚跑步袜根本塞不进去，想换43码结果问客服说现在43库存特别紧，要等半个月才能调货，刚买完穿不了还不能及时换，本来想周末穿去跑半马的计划直接泡汤了，售前也没提前提醒我鞋码偏窄，购物体验特别差，根本对不起这个价格。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_009.json'),
    ('p_clothes_010', '特步 160X 6.0 PRO 碳板竞速跑鞋马拉松训练比赛轻量跑步鞋', '特步', '服饰运动', '跑步鞋', '服饰运动/跑步鞋', 999.0, 999.0, 999.0, 700, '3_服饰运动/images/p_clothes_010_live.jpg', '{"product_id":"p_clothes_010","title":"特步 160X 6.0 PRO 碳板竞速跑鞋马拉松训练比赛轻量跑步鞋","brand":"特步","category":"服饰运动","sub_category":"跑步鞋","base_price":999.0,"image_path":"3_服饰运动/images/p_clothes_010_live.jpg","skus":[{"sku_id":"s_p_clothes_010_1","properties":{"适用性别":"男款","鞋码":"39码"},"price":999.0},{"sku_id":"s_p_clothes_010_2","properties":{"适用性别":"男款","鞋码":"40码"},"price":999.0},{"sku_id":"s_p_clothes_010_3","properties":{"适用性别":"男款","鞋码":"41码"},"price":999.0},{"sku_id":"s_p_clothes_010_4","properties":{"适用性别":"男款","鞋码":"42码"},"price":999.0},{"sku_id":"s_p_clothes_010_5","properties":{"适用性别":"男款","鞋码":"43码"},"price":999.0},{"sku_id":"s_p_clothes_010_6","properties":{"适用性别":"男款","鞋码":"44码"},"price":999.0},{"sku_id":"s_p_clothes_010_7","properties":{"适用性别":"男款","鞋码":"45码"},"price":999.0}],"rag_knowledge":{"marketing_description":"特步160X 6.0 PRO碳板竞速跑鞋，专为进阶跑者打造的马拉松级战靴，全掌搭载全新升级的动态弧面碳板，推进力比上一代提升12%，中底采用超临界发泡泡棉材料，单只42码重量仅185g，上脚几乎无坠脚感。鞋身是mono纱半透网面，兼顾强包裹性和跑程中的透气排汗需求，大底采用CPU耐磨止滑橡胶，干湿地抓地力都拉满。适合全马目标破3、半马进130的进阶跑者，日常10-20公里节奏跑、间歇训练，还有正式马拉松赛事冲成绩都能穿。建议跑前先进行3-5次短距离慢跑磨合开中底，不要穿它日常通勤走长路，避免碳板和中底过早损耗，雨天跑完及时把鞋身缝隙的积水擦干存放。","official_faq":[{"question":"这双160X 6.0 PRO的碳板和普通版6.0有什么不一样？","answer":"它的碳板是特步专门为PRO版本升级的全掌动态弧面铲型碳板，刚性相比普通版160X 6.0提升了18%，而且前掌做了1.2厘米的翘度加高，蹬地瞬间的滚动推进反馈更直接，不会出现普通版在配速4分以内时碳板反馈滞后的情况。这块碳板的弯折拐点也特意调整到了跖骨位置，长距离跑到30公里后也不会出现脚掌酸累的情况，完全适配竞速跑者的进阶配速需求，不是普通版本能直接替代的。"},{"question":"我平时日常慢跑穿这双鞋会不会太硬脚感不舒服？","answer":"如果是配速6分以外的休闲慢跑，确实会觉得这双鞋反馈偏硬，因为它的调校完全是为竞速场景设计的，中底的软度做了克制来保障长距离的支撑性。如果你日常慢跑配速能稳定在5分以内，穿它完全没问题，甚至会越跑越顺。要是习惯慢摇的跑者，更推荐选特步的日常训练款跑鞋，这款PRO鞋更适配有一定跑步基础、想冲速度的跑者，慢摇穿不仅发挥不出它的性能，还可能因为发力习惯不匹配出现脚酸的情况。"},{"question":"42码的单只重量到底是多少，会不会比同级别碳板鞋重？","answer":"咱们这款42码的单只实测重量是185g，对比同价位同定位的其他品牌碳板竞速鞋，普遍重量都在200g以上，它在保留碳板刚性和中底缓震厚度的前提下，通过优化mono纱鞋面的针织密度、削掉中底多余的冗余材料，把重量控制到了行业领先水平。跑全马的时候前半程就能明显感觉到脚的负担很小，跑到35公里之后脚也不会因为鞋太重出现额外的酸胀感，轻量属性完全能满足竞速跑者对减重的需求。"},{"question":"这双鞋的大底耐磨度怎么样，正常跑能穿多少公里？","answer":"它的大底用的是特步专属的CPU高耐磨止滑橡胶，相比普通EVA大底耐磨度提升了3倍左右，正常穿着跑步的情况下，跑个600-800公里完全没问题，大底的纹路不会出现明显的大面积磨平情况。不过要注意不要长时间穿着它在水泥地日常通勤走路，尖锐的路面碎石也尽量避开，不然会加快大底的磨损速度，也可能硌伤嵌在鞋底的碳板，日常跑田径场和公路赛道的话，寿命完全能覆盖好几场全马赛事的用量。"},{"question":"脚宽或者高足弓的人穿这双鞋会不会挤脚磨脚？","answer":"这款鞋的鞋楦做了适配亚洲人脚型的微调，前掌跖骨位置预留了8毫米的富余空间，正常宽脚（普通运动鞋穿大一码不顶脚的情况）选正常码数就能穿，不会出现严重挤脚的情况。但如果是超宽脚、或者脚围超过10厘米的跑者，建议先到线下试穿再下单。高足弓的跑者完全可以穿，它的中足位置内置了稳定支撑片，能托住高足弓的受力点，长距离跑下来足弓不会有明显的酸痛感，比很多窄楦竞速鞋对特殊脚型的友好度高很多。"},{"question":"新鞋到手需要磨合多久才能上全马赛场？","answer":"建议新鞋到手先不要直接穿去跑全马，先安排3次短距离磨合训练，第一次跑5公里慢跑适应鞋的包裹感，第二次跑10公里节奏跑适应中底和碳板的推进反馈，第三次跑15公里的长距离拉练确认没有磨脚、脚酸的情况，再穿去跑正式赛事。很多竞速鞋的新中底和鞋面都有个“开鞋”的过程，直接上全马很容易出现前10公里脚感太硬不适应、后半程磨出水泡的问题，磨合好之后上赛场才能把这双鞋的性能完全发挥出来。"}],"user_reviews":[{"nickname":"阿凯","rating":4,"content":"整体跑下来感觉还可以，碳板的推进力确实够劲，上周跑半马前半程配速直接压到410，比之前穿的老款160X快了不少。就是鞋舌的位置跑了15公里之后有点往侧边滑，停下来扯了两次才归位，要是鞋舌能加个固定环就好了。中底的回弹也够，就是刚上脚的前两公里确实有点硬，得稍微热个身才能踩开，性价比整体还能接受，就是小细节还有优化空间。"},{"nickname":"小夏","rating":4,"content":"冲着全马破3买的，穿它跑了两次间歇训练，400米间歇的反馈特别顺，蹬地的时候碳板推着你往前冲，省了不少力气。就是南方最近梅雨季，踩了一次小水洼之后侧面的网面渗了点水进去，脚闷了小半程有点不舒服，大底的抓地力倒是没打滑还不错。还有就是鞋帮的包裹对我这种偏瘦的脚来说有点空，跑快了脚踝那里总觉得有点兜不住，得把鞋带系特别紧才行，整体还是合格的竞速鞋。"},{"nickname":"大飞","rating":2,"content":"真的有点失望，我平时穿其他品牌的跑鞋都是42码，特意按推荐的码数拍了42码，穿薄袜子跑了次18公里节奏跑，大脚趾直接顶到鞋头，跑完脚指甲直接黑了半个。我脚型也不算特别宽，就是正常的普通脚，之前的旧160X穿42码完全没问题，这代PRO的鞋楦做的明显偏窄了，跑完歇了快一周才缓过来，浪费了我一次准备了很久的长距离拉练，感觉码数设计太不合理了。"},{"nickname":"阿泽","rating":5,"content":"穿它跑的上周的城市全马，直接破了3小时PB了！跑到32公里之后本来往年穿旧鞋早就脚酸抬不动腿了，这双鞋的碳板推着我一直保持配速，中底的回弹完全没衰减，脚一点都不酸。单只鞋真的太轻了，全程跑下来几乎感觉不到鞋的重量，大底过赛道上的洒水点也完全不滑，干脚湿脚抓地力都稳，mono纱鞋面跑完全马都没闷脚出汗，真的是我今年买到最满意的竞速鞋，特步这次真的做的太良心了。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_010.json'),
    ('p_clothes_011', 'Nike LeBron XXI EP 男子中帮实战篮球鞋全掌缓震室内外场地训练鞋', '耐克', '服饰运动', '篮球鞋', '服饰运动/篮球鞋', 1599.0, 1499.0, 1599.0, 1200, '3_服饰运动/images/p_clothes_011_live.jpg', '{"product_id":"p_clothes_011","title":"Nike LeBron XXI EP 男子中帮实战篮球鞋全掌缓震室内外场地训练鞋","brand":"耐克","category":"服饰运动","sub_category":"篮球鞋","base_price":1599.0,"image_path":"3_服饰运动/images/p_clothes_011_live.jpg","skus":[{"sku_id":"s_p_clothes_011_1","properties":{"适用人群":"男款","尺码":"42码","版本":"EP版","鞋楦类型":"宽楦"},"price":1599.0},{"sku_id":"s_p_clothes_011_2","properties":{"适用人群":"男款","尺码":"43码","版本":"EP版","鞋楦类型":"宽楦"},"price":1599.0},{"sku_id":"s_p_clothes_011_3","properties":{"适用人群":"男款","尺码":"40码","版本":"EP版","鞋楦类型":"宽楦"},"price":1599.0},{"sku_id":"s_p_clothes_011_4","properties":{"适用人群":"男款","尺码":"41码","版本":"EP版","鞋楦类型":"宽楦"},"price":1599.0},{"sku_id":"s_p_clothes_011_5","properties":{"适用人群":"男款","尺码":"44码","版本":"EP版","鞋楦类型":"宽楦"},"price":1599.0},{"sku_id":"s_p_clothes_011_6","properties":{"适用人群":"男款","尺码":"45码","版本":"EP版","鞋楦类型":"宽楦"},"price":1599.0},{"sku_id":"s_p_clothes_011_7","properties":{"适用人群":"男款","尺码":"40码","版本":"EP版","鞋楦类型":"常规楦"},"price":1499.0},{"sku_id":"s_p_clothes_011_8","properties":{"适用人群":"男款","尺码":"41码","版本":"EP版","鞋楦类型":"常规楦"},"price":1499.0},{"sku_id":"s_p_clothes_011_9","properties":{"适用人群":"男款","尺码":"42码","版本":"EP版","鞋楦类型":"常规楦"},"price":1499.0},{"sku_id":"s_p_clothes_011_10","properties":{"适用人群":"男款","尺码":"43码","版本":"EP版","鞋楦类型":"常规楦"},"price":1499.0},{"sku_id":"s_p_clothes_011_11","properties":{"适用人群":"男款","尺码":"44码","版本":"EP版","鞋楦类型":"常规楦"},"price":1499.0},{"sku_id":"s_p_clothes_011_12","properties":{"适用人群":"男款","尺码":"45码","版本":"EP版","鞋楦类型":"常规楦"},"price":1499.0}],"rag_knowledge":{"marketing_description":"这双Nike LeBron XXI EP男子中帮实战篮球鞋专为球场表现党打造，搭载全掌Zoom Air缓震单元，起跳落地时能快速卸掉冲击力，变相突破时也能保持鞋底贴地感，完全不会出现卸力晃脚的情况。鞋身用的是工程网面搭配热压加固条，轻量还能牢牢兜住脚面，中帮高度刚好卡在脚踝下方，兼顾支撑性还不卡脚腕。EP宽楦调校专门适配亚洲男性偏宽的脚型，42、43码的版本对宽脚球友特别友好，不管是室内塑胶木地板，还是室外水泥地半场训练打局都能hold住。适合詹姆斯球迷、常打全场的锋线球员，以及日常想穿缓震好的鞋走路通勤的运动爱好者。注意别拿去泡水里刷，脏了用软毛刷沾清洁剂擦就好，刚上脚可以穿2-3次压马路踩开缓震再上实战强度。","official_faq":[{"question":"这双EP宽楦版的LeBron XXI和普通版本的鞋楦具体差在哪里？脚宽多少的人穿不会挤脚？","answer":"这款EP宽楦版的鞋前掌横向宽度比常规版拓宽了4.2mm，足弓两侧的容纳空间也做了3mm的微调，不会出现常规版压脚面、挤小脚趾的情况。日常穿鞋习惯选宽楦、脚宽在10-12cm的男性都能适配，甚至脚面偏高的球友穿厚款篮球袜也不会有紧绷束缚感，不像普通版本穿两场就磨得外侧脚趾发红，对经常长时间打球的宽脚用户特别友好。"},{"question":"全掌缓震的配置室外水泥地实战大概能打多少场才会出现明显衰减？","answer":"这款全掌内嵌的Zoom Air气垫外层有高密度耐磨橡胶做包裹防护，正常每周打2次室外水泥地半场、每次2小时的使用强度下，缓震感能维持12-15场左右才会出现轻微的软塌感。如果是经常做大幅度起跳、急停动作的锋线球员，注意尽量避开粗糙的砂石地面对鞋底的过度磨损，不要穿这双鞋长时间走非运动的崎岖路面，能有效延长缓震的使用寿命，甚至能打到20场以上才会出现明显的性能衰减。"},{"question":"作为中帮篮球鞋，它的脚踝支撑表现适合打高强度全场吗？","answer":"这款鞋的中帮领口做了3mm厚的泡棉填充，后跟还有硬质TPU港宝做加固锁跟，做变向、横移、落地侧倾的时候能牢牢兜住脚踝两侧，不会出现鞋脚分离的晃动感，只要你本身不是习惯性崴脚的高风险人群，完全能胜任常规的高强度全场赛事。但要注意穿配套的高帮运动袜，把鞋带从最上方的两个鞋孔都系紧，不要松垮垮留太多空隙，支撑性能会完全发挥出来，不会出现崴脚隐患。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"我是穿普通篮球鞋总挤小脚趾的宽脚党，这双EP宽楦版上脚第一天打了3小时野球局完全没磨脚，全掌缓震真的太爽了，抢篮板落地的时候膝盖完全没震感，急停变向也不打滑，中帮高度刚好不卡我以前崴过的脚踝，颜值也在线，打完球直接穿去吃夜宵完全不突兀，不愧是老詹的正代鞋，这个价能拿到实战性能这么顶的款真的太值了。"},{"nickname":"小宇","rating":1,"content":"我之前穿其他耐克篮球鞋43码刚好，这次特意选了同码的宽楦版，结果穿普通薄篮球袜都能在鞋里晃脚，后跟滑得厉害，打了十分钟球直接磨出两个泡，而且鞋底的橡胶在我们小区楼下的水泥半场打了两场就磨出明显的细纹，完全不耐磨，花一千六买的鞋连室外打三次都撑不住，感觉根本不值这个价，大家慎入。"},{"nickname":"阿哲","rating":1,"content":"等了快一周才收到货，结果上脚才发现鞋身的热压条硬得像塑料片，打全场跑了两节，脚面被压得疼到不敢发力，完全没有宣传里说的贴合包裹感，我正常脚型根本不算宽，穿厚篮球袜的时候鞋头还有富余，脚面反倒被压得发疼，缓震刚上脚硬得像板砖，完全踩不动，一千多的实战鞋这个表现真的太让人失望了。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_011.json'),
    ('p_clothes_012', '安踏 KT9 氮科技实战篮球鞋中帮缓震支撑外场内场训练比赛鞋', '安踏', '服饰运动', '篮球鞋', '服饰运动/篮球鞋', 999.0, 999.0, 999.0, 1000, '3_服饰运动/images/p_clothes_012_live.jpg', '{"product_id":"p_clothes_012","title":"安踏 KT9 氮科技实战篮球鞋中帮缓震支撑外场内场训练比赛鞋","brand":"安踏","category":"服饰运动","sub_category":"篮球鞋","base_price":999.0,"image_path":"3_服饰运动/images/p_clothes_012_live.jpg","skus":[{"sku_id":"s_p_clothes_012_1","properties":{"款型":"男款","尺码":"39码"},"price":999.0},{"sku_id":"s_p_clothes_012_2","properties":{"款型":"男款","尺码":"40码"},"price":999.0},{"sku_id":"s_p_clothes_012_3","properties":{"款型":"男款","尺码":"40.5码"},"price":999.0},{"sku_id":"s_p_clothes_012_4","properties":{"款型":"男款","尺码":"41码"},"price":999.0},{"sku_id":"s_p_clothes_012_5","properties":{"款型":"男款","尺码":"42码"},"price":999.0},{"sku_id":"s_p_clothes_012_6","properties":{"款型":"男款","尺码":"42.5码"},"price":999.0},{"sku_id":"s_p_clothes_012_7","properties":{"款型":"男款","尺码":"43码"},"price":999.0},{"sku_id":"s_p_clothes_012_8","properties":{"款型":"男款","尺码":"44码"},"price":999.0},{"sku_id":"s_p_clothes_012_9","properties":{"款型":"男款","尺码":"44.5码"},"price":999.0},{"sku_id":"s_p_clothes_012_10","properties":{"款型":"男款","尺码":"45码"},"price":999.0}],"rag_knowledge":{"marketing_description":"这双安踏KT9是专为篮球运动爱好者打造的旗舰级实战战靴，搭载安踏自研的氮科技中底，回弹效率拉满还能长效缓震，跳投落地时膝盖几乎感受不到硬震。中帮的袜套式鞋领口刚好卡在脚踝下方，不卡跟腱还能给到足侧稳定支撑，变相突破的时候完全不用担心侧翻崴脚。不管是室内木地板的正式比赛、塑胶外场的日常野球局，还是球馆的日常力量训练都能hold住。鞋面用的是高强度工程网布，透气不闷脚还能贴合脚面做锁定，建议选正常偏大半码的脚感更舒服，打完球及时把鞋内汗渍通风晾干，不要直接用水猛冲中底，能延长鞋子的实战寿命，特别适合投手型打法和经常打全场的球友入手。","official_faq":[{"question":"安踏KT9的氮科技中底在打完全场之后会不会出现明显的踩扁塌底情况？","answer":"完全不会出现你担心的塌底问题，这双KT9用的是安踏升级后的第三代氮科技中底，发泡密度均匀度比前代提升了37%，经过实验室3万次踩踏缓震衰减测试之后，剩余缓震率还能保持在82%以上，正常一周打2-3次全场的使用频率下，至少6个月之内不会出现明显的软塌感，哪怕是体重90公斤以上的大体重球友，也能稳定感受到起跳落地的回弹反馈，不会越穿越卸力。"},{"question":"这双KT9打外场塑胶地的耐磨性怎么样，鞋底纹路会不会很容易磨平？","answer":"KT9的外底专门做了外场适配的升级，用的是高耐磨RB橡胶配方，纹路是深度1.8mm的不规则水波纹搭配定向抓地齿，针对塑胶地的细碎颗粒嵌入问题做了优化，正常每周打2次外场塑胶局的频率，鞋底纹路至少能支撑80小时以上的实战才会出现明显磨损痕迹，哪怕是水泥地偶尔打一两场也不会快速磨平，相比同价位的其他旗舰款篮球鞋，外场耐磨寿命要高出近三成。"},{"question":"KT9的中帮设计对脚踝的包裹会不会太卡，跟腱位置会不会磨脚？","answer":"这双鞋的中帮高度特意做了人体工学调校，鞋帮最高点距离脚踝骨的高度控制在12mm，刚好能给到脚踝侧支撑，又不会完全卡住脚踝的弯折空间，后跟领口处做了3mm厚的记忆泡棉填充，跟腱接触的位置做了弧度内收处理，正常穿普通厚度的篮球袜上脚，完全不会出现磨跟腱的情况，只是刚开始新鞋磨合的前2次上脚，如果穿特别薄的船袜可能会有轻微异物感，换上常规专业篮球袜穿2场之后包裹会更贴脚。"},{"question":"宽脚或者扁平足的人群穿这双KT9，会不会出现挤脚足弓酸的情况？","answer":"KT9的鞋楦特意做了2.5E的加宽调校，前掌最宽处的空间比普通窄楦篮球鞋宽了4mm，正常脚面偏宽的球友都能适配，足弓位置内嵌了一块刚性的TPU支撑片，刚好能托住扁平足下塌的足弓，长时间打球也不会出现足弓酸胀的问题，只是如果是严重的超宽脚或者足弓过高的用户，建议选择比日常穿的运动鞋大半码的尺码，上脚之后把鞋带从最下方的孔位依次系紧，就能获得完全不挤脚的舒适包裹感。"},{"question":"这双KT9可以日常穿去压街通勤吗，会不会比普通休闲鞋重很多？","answer":"完全可以日常通勤穿，42码单只鞋的重量仅为365g，比同配置的其他实战篮球鞋轻了近50g，氮科技中底的脚感软弹不硬，长时间走路也不会出现板脚的情况，鞋型是低饱和度的流线型设计，搭配运动裤、束脚卫裤都很合适，完全不会像笨重的篮球鞋那样显臃肿，只是日常穿的时候尽量避开走有大量尖锐碎石的路面，避免外底的抓地齿被尖物硌断，影响后续实战的抓地表现。"}],"user_reviews":[{"nickname":"阿泽","rating":5,"content":"作为打了五六年球的投手，这双KT9真的太对我胃口了，上周打了个单位的全场赛，急停跳投落地的时候缓震反馈特别明显，完全没有震膝盖的感觉，变相的时候鞋侧的支撑牢牢兜住脚，全程没出现半点打滑。中帮的位置刚好不卡我之前受过伤的脚踝，打完全场脚也没怎么酸，氮科技的回弹比我之前穿的KT8还要爽，这波安踏真的做的太良心了。"},{"nickname":"小宇","rating":5,"content":"我85公斤的体重，之前穿别的篮球鞋打两次全场中底就软得没回弹了，这双KT9我穿了快两个月，每周打三四次野球局，现在踩下去还是弹弹的，外底在我们小区那个落灰的塑胶场上抓地力巨稳，急停完全不飘，鞋面的网布夏天打一下午球脚也没闷出多少汗，包裹感刚刚好，完全不挤我的宽脚，一千块能买到这个配置真的血赚。"},{"nickname":"大柯","rating":1,"content":"我拿到手试穿第一次打球就磨破了后跟，本来以为新鞋磨合两次就好，结果连续穿三次每次都把跟腱位置磨得出血，鞋帮那块的泡棉硬得像纸板，根本不是介绍里说的软弹记忆棉，而且我打了不到5次外场，鞋底的纹路已经磨掉一半了，抓地力直接拉胯，上次变相直接滑出去崴了脚，花一千块买的鞋体验还不如我之前三百多买的旧鞋，真的太失望了。"},{"nickname":"阿凯","rating":3,"content":"怎么说呢，中底的氮科技脚感确实还可以，但是我正常按平时穿的42码买的，前掌挤得我小脚趾都麻，穿厚篮球袜根本塞不进去，只能换薄袜子穿，打半个小时脚就酸得不行，而且鞋身的支撑片边缘有点硌足弓，我扁平足打完全场足弓疼了两天，要是能提前标注这个鞋款的鞋楦偏窄就好了，现在穿也不是退也麻烦，只能平时日常通勤穿穿没法实战。"},{"nickname":"小豪","rating":2,"content":"买来本来是准备打比赛穿的，结果上脚之后发现重心高得离谱，突破的时候总感觉脚在中底上飘，不敢发力变向，打半场的时候还差点侧翻，我体重才70公斤根本算不上轻，支撑性完全达不到我预期，而且鞋舌每次打一会就歪到一边去，得不停停下来扯鞋带调整，这个价位的实战鞋做成这样真的不太应该，顶多打打养生局还行，专业比赛根本不敢穿。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_012.json'),
    ('p_clothes_013', '李宁 韦德之道 全城12 实战篮球专业比赛鞋缓震支撑后卫前锋鞋', '李宁', '服饰运动', '篮球鞋', '服饰运动/篮球鞋', 1199.0, 1199.0, 1299.0, 2800, '3_服饰运动/images/p_clothes_013_live.jpg', '{"product_id":"p_clothes_013","title":"李宁 韦德之道 全城12 实战篮球专业比赛鞋缓震支撑后卫前锋鞋","brand":"李宁","category":"服饰运动","sub_category":"篮球鞋","base_price":1199.0,"image_path":"3_服饰运动/images/p_clothes_013_live.jpg","skus":[{"sku_id":"s_p_clothes_013_1","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"39码"},"price":1199.0},{"sku_id":"s_p_clothes_013_2","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"40码"},"price":1199.0},{"sku_id":"s_p_clothes_013_3","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"41码"},"price":1199.0},{"sku_id":"s_p_clothes_013_4","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"42码"},"price":1199.0},{"sku_id":"s_p_clothes_013_5","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"43码"},"price":1199.0},{"sku_id":"s_p_clothes_013_6","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"44码"},"price":1199.0},{"sku_id":"s_p_clothes_013_7","properties":{"适用性别":"男款","颜色":"白蓝主场色","尺码":"45码"},"price":1199.0},{"sku_id":"s_p_clothes_013_8","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"39码"},"price":1199.0},{"sku_id":"s_p_clothes_013_9","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"40码"},"price":1199.0},{"sku_id":"s_p_clothes_013_10","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"41码"},"price":1199.0},{"sku_id":"s_p_clothes_013_11","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"42码"},"price":1199.0},{"sku_id":"s_p_clothes_013_12","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"43码"},"price":1199.0},{"sku_id":"s_p_clothes_013_13","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"44码"},"price":1199.0},{"sku_id":"s_p_clothes_013_14","properties":{"适用性别":"男款","颜色":"暗夜黑实战色","尺码":"45码"},"price":1199.0},{"sku_id":"s_p_clothes_013_15","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"39码"},"price":1249.0},{"sku_id":"s_p_clothes_013_16","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"40码"},"price":1249.0},{"sku_id":"s_p_clothes_013_17","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"41码"},"price":1249.0},{"sku_id":"s_p_clothes_013_18","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"42码"},"price":1249.0},{"sku_id":"s_p_clothes_013_19","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"43码"},"price":1249.0},{"sku_id":"s_p_clothes_013_20","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"44码"},"price":1249.0},{"sku_id":"s_p_clothes_013_21","properties":{"适用性别":"男款","颜色":"樱花粉限定色","尺码":"45码"},"price":1249.0},{"sku_id":"s_p_clothes_013_22","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"39码"},"price":1299.0},{"sku_id":"s_p_clothes_013_23","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"40码"},"price":1299.0},{"sku_id":"s_p_clothes_013_24","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"41码"},"price":1299.0},{"sku_id":"s_p_clothes_013_25","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"42码"},"price":1299.0},{"sku_id":"s_p_clothes_013_26","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"43码"},"price":1299.0},{"sku_id":"s_p_clothes_013_27","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"44码"},"price":1299.0},{"sku_id":"s_p_clothes_013_28","properties":{"适用性别":"男款","颜色":"涂鸦艺术限定色","尺码":"45码"},"price":1299.0}],"rag_knowledge":{"marketing_description":"这双李宁韦德之道全城12是专门为篮球爱好者打造的专业级实战鞋，中底搭载了李宁最新调教的䨻科技缓震模块，落地时的反馈软弹不卸力，鞋面用的是高强度工程编织材质，侧边加了专项的侧墙支撑TPU，急停变向的时候脚完全不会晃，不管是爱做大幅度变向的后卫，还是需要频繁卡位起跳的锋线都能适配。平时打室内塑胶场、木质地板场完全够用，偶尔压街出门也完全不闷脚。建议大家选码的时候按照日常穿的篮球鞋正码选，上脚穿篮球袜的贴合度刚好，注意不要穿它长期走粗糙的水泥硬地，会加速鞋底的耐磨层损耗，能大大延长鞋子的实战寿命。","official_faq":[{"question":"全城12的缓震配置对于体重80公斤以上的锋线球员来说够用吗？","answer":"完全够用，这款鞋的中底做了分区密度调校，后掌的䨻科技模块厚度达到了8mm，专门针对大体重球员落地时的冲击力做了强化，起跳落地的时候不会出现踩穿感，后跟内嵌的硬质抗扭片还能分散落地的压力，哪怕是连续打两三个小时的高强度对局，脚踝和膝盖的负担也会小很多，完全能支撑大体重锋线频繁卡位起跳、落地的使用需求，不会出现缓震很快衰减的情况。"},{"question":"这款鞋的侧边支撑会不会在大幅度变向的时候出现侧翻的情况？","answer":"不会出现侧翻问题，全城12的鞋底外侧做了6mm的外扩包边设计，鞋面中段直接环绕了一整圈硬质TPU支撑条，一直延伸到鞋底的抗扭片上，当你做艾弗森式的大幅度体前变向、急停侧跳动作的时候，鞋面能牢牢把脚锁在鞋仓里，外扩的鞋底也能提供足够的支撑面，哪怕是突破速度很快的后卫做极限变向，脚也不会出现侧滑或者鞋身倾倒的情况，保护性拉满。"},{"question":"我脚偏宽，穿这双全城12会不会挤脚？","answer":"这款鞋的鞋楦做了2.5E的宽楦调校，比普通瘦楦篮球鞋的鞋仓前掌宽了近4mm，普通偏宽的脚型正常选正码就能适配，上脚不会有挤小脚趾的紧绷感。如果是特别宽的肥脚或者脚背很高的用户，建议选比日常穿的码数大半码的款，穿厚的实战篮球袜也不会压脚背，磨合两次之后鞋面的工程编织材质会轻微撑开，贴合度会更舒服，完全不需要担心夹脚问题。"},{"question":"全城12的鞋底耐磨度支持打多少次室内塑胶场对局？","answer":"这款鞋的外底用的是李宁专项研发的室内场止滑橡胶配方，纹路深度做到了3mm，正常每周打2次2小时左右的室内塑胶局的情况下，最少可以支撑80次以上的对局纹路才会出现明显磨损，止滑性能全程在线，急停的时候不会出现打滑溜步的情况。但要注意尽量不要长期在粗糙的水泥外场使用，锋利的水泥颗粒会快速磨平外底纹路，会大幅缩短鞋底的使用寿命。"},{"question":"刚上脚穿全城12需要磨脚的磨合期吗？","answer":"正常来说大部分用户穿这双鞋是不需要长时间磨合的，鞋仓的内衬用的是加厚的泡棉填充，鞋领口也做了海绵包边处理，新鞋上脚穿厚篮球袜就能直接上场实战，不会出现磨后跟、磨脚踝的情况。只有极少数后跟偏突出的用户，建议前两次穿的时候先搭配厚的运动后跟贴，打1小时左右的轻度对局适应一下，泡棉内衬轻微贴合脚型之后后续穿就完全不会有磨脚的问题了。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"上周约了球局直接穿新鞋上场，突破的时候急停那一下脚完全不晃，后掌缓震太舒服了，之前穿旧鞋抢篮板落地膝盖总酸，全城12跳一整场下来腿一点都不累，包裹感贴得刚刚好，我正常穿42码，上脚配精英袜刚好贴脚，完全没有松垮的感觉，队友问了链接直接跟着买，韦大爷的支线鞋果然没让人失望，实战党真的可以冲。"},{"nickname":"小宇","rating":1,"content":"收到鞋拆开试穿的时候就发现右脚鞋头的编织面有个小跳线的瑕疵，联系客服退换等了三天才处理完，拿到新鞋昨天第一次去打室内场，突破的时候居然打滑摔了一跤，看鞋底纹路居然出厂就沾了点奇怪的脱模剂，擦了半天还是有点滑，完全不像之前穿过的全城系列的止滑表现，1000多的鞋品控做成这样真的太让人失望了。"},{"nickname":"阿哲","rating":5,"content":"作为打了7年球的后卫，这双全城12真的踩在我的需求点上，变向的时候侧边的支撑条把脚锁得死死的，完全没有多余的晃动，缓震弹但是不软，起步蹬地的时候一点都不泄力，连续打了三个小时的三对三，脚一点都不酸，鞋身重量也轻，完全没有那种笨重的拖脚感，同价位里我觉得实战性能能排前三，已经推荐给队里的兄弟们了。"},{"nickname":"小涛","rating":4,"content":"整体实战体验还是不错的，缓震支撑都在线，打室内场止滑也够用，唯一的小问题就是鞋领口的海绵填充有点厚，我穿中帮篮球袜的时候刚开始穿会有点卡脚踝，打了大概20分钟热身开之后才慢慢适应过来，磨合了两次之后就舒服很多了，要是鞋领口的泡棉能做稍微薄一点点就更完美了，整体来说这个价位还是很值得入手的。"},{"nickname":"阿峰","rating":2,"content":"我是85公斤的大体重锋线，穿了三次总共不到5小时，后掌的缓震就出现了明显的踩坑感，起跳落地的时候完全感受不到刚上脚的软弹，直接硬邦邦的震膝盖，之前穿全城11打了几十场都没出现这个问题，这次12的中底衰减也太快了，1000多的鞋耐用性连几百块的入门款都不如，真的不太建议大体重的球友入手。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_013.json'),
    ('p_clothes_014', 'SALOMON X ULTRA 4 GORE-TEX 男子防水徒步鞋轻量抓地登山越野鞋', '萨洛蒙', '服饰运动', '徒步鞋', '服饰运动/徒步鞋', 1198.0, 1198.0, 1198.0, 600, '3_服饰运动/images/p_clothes_014_live.jpg', '{"product_id":"p_clothes_014","title":"SALOMON X ULTRA 4 GORE-TEX 男子防水徒步鞋轻量抓地登山越野鞋","brand":"萨洛蒙","category":"服饰运动","sub_category":"徒步鞋","base_price":1198.0,"image_path":"3_服饰运动/images/p_clothes_014_live.jpg","skus":[{"sku_id":"s_p_clothes_014_1","properties":{"款型":"男款","尺码":"39码","版本":"GORE-TEX"},"price":1198.0},{"sku_id":"s_p_clothes_014_2","properties":{"款型":"男款","尺码":"40码","版本":"GORE-TEX"},"price":1198.0},{"sku_id":"s_p_clothes_014_3","properties":{"款型":"男款","尺码":"41码","版本":"GORE-TEX"},"price":1198.0},{"sku_id":"s_p_clothes_014_4","properties":{"款型":"男款","尺码":"42码","版本":"GORE-TEX"},"price":1198.0},{"sku_id":"s_p_clothes_014_5","properties":{"款型":"男款","尺码":"43码","版本":"GORE-TEX"},"price":1198.0},{"sku_id":"s_p_clothes_014_6","properties":{"款型":"男款","尺码":"44码","版本":"GORE-TEX"},"price":1198.0}],"rag_knowledge":{"marketing_description":"萨洛蒙这款X ULTRA 4男子徒步鞋专门针对户外爱好者打造，核心搭载GORE-TEX防水科技膜，搭配轻量密网鞋面，既能完全阻隔突降的山雨、溪流溅水渗入，又能快速排出脚汗避免闷脚。中底采用改进型的ADV-CUSHION缓震材料，整鞋自重比上一代X ULTRA 3轻了近80g，长时间爬台阶走碎石路也不会累脚。外底是专属的大耳齿抓地花纹，搭配Contagrip防滑配方，湿滑青苔石阶、松软泥地陡坡都能稳稳吃住地面。特别适合每周进山徒步的进阶玩家、日常走郊野绿道的运动爱好者，近郊单日10-20公里徒步、低海拔登山、轻度越野跑都能适配。建议大家穿厚款户外徒步袜选购，尽量留半指的富余鞋长，新鞋前3次走短距离磨合，别直接挑战高难度长线。注意日常不要用硬毛刷猛刷防水膜表层，避免破坏防泼水面料涂层影响防水效果。","official_faq":[{"question":"这双GORE-TEX版本的鞋款，日常穿在城市里碰到雨天积水能保证脚完全不进水吗？","answer":"只要积水高度不超过鞋身鞋舌拼接处的2厘米位置，正常步行踏水都能做到完全不渗水，GORE-TEX的防水膜是整层覆盖鞋仓内部的，不是仅靠表层防泼水处理实现防水。不过如果长时间没过鞋帮泡水，或者鞋舌处完全浸在水里，水分有可能从鞋舌和鞋面的缝隙处缓慢渗入，毕竟徒步鞋的防水设计是针对户外徒步场景的短时间淋雨、踏溪，不是用来当雨靴长时间涉水的，日常城市中小雨步行完全不用担心湿脚。"},{"question":"这双鞋的抓地力在铺满青苔的湿滑石阶上表现怎么样？走陡坡会不会打滑？","answer":"这双鞋的Contagrip外底专门做了湿面防滑配方，耳齿深度达到3.5毫米，花纹排布特意针对石阶、泥地的附着力做了优化，常规的湿滑青苔石阶正常落脚重心稳的情况下基本不会打滑，走30度左右的非结冰陡坡都能牢牢吃住地面。不过要注意如果是结了薄冰的石阶、或者表面完全覆盖薄泥浆的极端湿滑场景，所有徒步鞋都没法做到100%防滑，这种场景还是要搭配登山杖辅助落脚，不要快速跨步避免意外。"},{"question":"42码和43码的内部实际鞋长是多少？穿普通运动鞋同尺码会不会挤脚？","answer":"我们这款42码对应的鞋仓内长是265毫米，43码的内长是275毫米，鞋楦是针对亚洲男性脚型做了加宽处理的，比萨洛蒙之前老款的徒步鞋鞋仓宽了4毫米。如果您平时穿普通运动跑鞋是标准同尺码，穿厚的户外徒步袜的话，选同尺码基本刚好，要是您的脚偏宽、或者足弓偏高，建议可以选大半码更舒适。如果是脚偏瘦的用户，穿薄运动袜的话也不用担心晃脚，鞋身的包裹绑带系统可以微调松紧，能牢牢贴住脚踝不打滑。"},{"question":"这款轻量设计的徒步鞋，长时间走20公里以上的长线会不会出现中底塌陷硌脚的情况？","answer":"这款鞋的ADV-CUSHION中底做了密度分层设计，脚后跟着地的核心受力区是高密度缓震材料，整个中底的抗形变测试达到了100公里以上的连续行走形变率低于3%，正常体重的用户单日走20公里左右的徒步线路，完全不会出现明显的中底塌陷问题，支撑力足够应对单日长线。不过如果是负重超过15公斤走高海拔长线，建议还是选萨洛蒙带全掌碳板的重装徒步鞋，这款轻量款更适合单日轻装徒步，长期超负重使用会加快中底的老化损耗。"},{"question":"这双GORE-TEX版本的鞋子日常该怎么清洁维护，才能延长防水涂层的使用寿命？","answer":"日常清理的时候建议用软毛刷沾温水加中性洗涤剂轻轻擦拭鞋面的泥污，不要用强酸强碱的洗衣粉或者硬钢丝刷猛刷表层的防泼水处理层，避免涂层被破坏。清理完之后放在阴凉通风的地方阴干，不要直接放在太阳下暴晒或者用吹风机热风直吹，高温会让GORE-TEX膜的粘合层老化开裂。如果后续发现鞋面表层泼水珠不再挂壁，直接渗透进去了，买普通的户外鞋防泼水剂喷在鞋面晾干，就能恢复表层的防泼水性，不用特意送去专业洗护店处理。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"穿了第三次去走近郊的12公里徒步线，踩到一处没过脚踝的浅溪，没走两步鞋里就湿了半仓，脱下来袜子都泡透了，客服说可能是我之前不小心刮到鞋面没注意，我明明没磕碰过啊。而且鞋舌那里的包裹设计有点卡脚踝，走久了脚踝内侧磨得发红，缓震中底倒是还行，踩碎石路脚不疼，就是这个防水效果真的达不到宣传的程度，近一千二的价格这个表现有点失望，勉强能用来日常通勤穿。"},{"nickname":"大磊","rating":1,"content":"我平时穿其他牌子运动鞋都是43码，看详情页说鞋楦加宽特意直接拍了43码，结果上脚挤脚面，走了五公里的路脚趾头都麻了，回来脱鞋发现大脚趾外侧都磨出泡了。本来想退换，结果鞋底沾了点泥店家说影响二次销售不给退，后来我自己加钱找修鞋的撑了鞋楦还是挤脚，根本穿不了，只能放在家里落灰，一千多块钱直接打水漂了，尺码做得太不标准了。"},{"nickname":"小峰","rating":2,"content":"跟着朋友去爬郊外的野山，碰到一处长了青苔的下坡石阶，我正常落脚直接滑出去摔了一跤，膝盖都蹭破了，外底的花纹卡了不少小石子，抠了半天才抠干净。当时买就是冲着宣传的抓地力买的，结果湿滑石阶直接打滑，根本不敢走更险的路段。整鞋重量是挺轻的，走平路脚不沉，但这个防滑效果对于经常走野路的人来说真的不够用，不值这个定价，后续肯定不会再买同系列的款式了。"},{"nickname":"阿航","rating":5,"content":"上周穿着这双鞋去走了杭州的十公里越野徒步线，中途碰到半路下雷阵雨，走了快一个小时的雨路，踏了好几个小水洼，脱鞋的时候袜子居然全干的，GORE-TEX防水真的太顶了。外底抓地力超稳，我走满是青苔的九溪石阶一点都不打滑，整鞋比我之前旧的徒步鞋轻好多，走完全程脚一点都不酸。鞋面包裹性刚好，我的宽脚穿着完全不挤，脚踝处的绑带调紧之后牢牢贴住，下山的时候完全不晃脚，这个价格真的太值了，之后进山徒步就锁定这双鞋了。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_014.json'),
    ('p_clothes_015', 'Merrell MOAB 3 GTX 男子防水登山徒步鞋稳定支撑户外多地形鞋', '迈乐', '服饰运动', '徒步鞋', '服饰运动/徒步鞋', 1099.0, 1099.0, 1099.0, 700, '3_服饰运动/images/p_clothes_015_live.jpg', '{"product_id":"p_clothes_015","title":"Merrell MOAB 3 GTX 男子防水登山徒步鞋稳定支撑户外多地形鞋","brand":"迈乐","category":"服饰运动","sub_category":"徒步鞋","base_price":1099.0,"image_path":"3_服饰运动/images/p_clothes_015_live.jpg","skus":[{"sku_id":"s_p_clothes_015_1","properties":{"款型":"男款","尺码":"39码","版本":"GORE-TEX"},"price":1099.0},{"sku_id":"s_p_clothes_015_2","properties":{"款型":"男款","尺码":"40码","版本":"GORE-TEX"},"price":1099.0},{"sku_id":"s_p_clothes_015_3","properties":{"款型":"男款","尺码":"41码","版本":"GORE-TEX"},"price":1099.0},{"sku_id":"s_p_clothes_015_4","properties":{"款型":"男款","尺码":"42码","版本":"GORE-TEX"},"price":1099.0},{"sku_id":"s_p_clothes_015_5","properties":{"款型":"男款","尺码":"43码","版本":"GORE-TEX"},"price":1099.0},{"sku_id":"s_p_clothes_015_6","properties":{"款型":"男款","尺码":"44码","版本":"GORE-TEX"},"price":1099.0},{"sku_id":"s_p_clothes_015_7","properties":{"款型":"男款","尺码":"45码","版本":"GORE-TEX"},"price":1099.0}],"rag_knowledge":{"marketing_description":"迈乐这款MOAB 3 GTX男款徒步鞋，专为硬核户外爱好者打造，搭载正版GORE-TEX防水薄膜，连暴雨天走山间溪路都能保持鞋内干爽，中底用了升级的EVA记忆缓震材质，足弓处做了专属硬质支撑片，踩碎石陡坡也不会崴脚。适用经常走长线徒步、周末近郊越野、日常逛郊野公园的男士，不管是泥地、碎石路还是浅滩都能hold住。提醒大家选码前可以先测下净脚长，穿厚户外袜的话建议选大半码，日常不要穿着它长时间跑柏油马路，很容易加快鞋底纹路磨损，养护的时候也别直接暴晒，阴干就好，能穿更久。","official_faq":[{"question":"这款MOAB 3 GTX的GORE-TEX防水层能不能直接整鞋泡在水里测试啊？","answer":"不建议大家这么操作哦，GORE-TEX的防水属性是针对户外徒步场景下的泼溅、短时间浅滩涉水设计的，并不是全密封潜水级防水。如果长时间把整鞋泡在深水里，水会从鞋舌拼接缝、鞋口针织包边这些非防水面料的位置渗进去，反而会误以为鞋的防水功能失效。正常走山遇到小雨、踩没过脚踝10厘米以内的浅溪，完全不会湿脚，完全满足日常户外徒步的防水需求。"},{"question":"我脚型偏宽，穿普通休闲鞋要大半码，这款MOAB 3 GTX要不要选大一码？","answer":"这款MOAB 3 GTX的鞋楦本身做了前掌加宽的优化设计，比常规休闲鞋的鞋仓空间富余很多。如果你的脚只是轻微偏宽，日常穿普通运动鞋选正码的话，这款按你平时的运动鞋正码选就足够；如果是重度宽脚、或者足弓很高，平时穿厚户外袜容易挤脚的话，可以选比日常运动鞋大半码的尺码，不建议选全大一码，不然下坡走长线的时候脚跟容易晃，反而磨脚还会影响支撑稳定性，选之前也可以对照详情页的脚长对照表核对下净脚长更准。"},{"question":"这款鞋的稳定支撑功能，体重85公斤的人穿长线徒步会不会踩塌？","answer":"完全不会，MOAB 3 GTX的中底在原有前代的基础上，把高密度EVA的占比提升了40%，足弓位置还嵌了一块硬度达65D的TPU支撑片，专门针对大体重用户长时间走负重路线的需求设计。就算是85公斤左右的男士背15公斤的登山包走3天以上的长线徒步，中底也不会出现明显的形变塌陷，踩在凹凸不平的碎石路上，支撑片能牢牢兜住足弓，不容易出现脚酸、崴脚的情况，日常通勤穿也能缓解久站的脚累感。"},{"question":"脏了之后这款GTX版本的鞋能不能直接扔洗衣机洗？","answer":"千万不要扔洗衣机机洗，机洗的强力翻滚会破坏GORE-TEX薄膜的贴合结构，还会把鞋面的反绒皮面洗得起球变形，鞋底的纹路也很容易被滚筒搅变形。正确的清洁方式是用软毛刷沾中性清洁剂，轻轻刷掉鞋面的泥污，鞋底缝隙的小石子可以用小镊子挑出来，之后用清水冲干净，放在阴凉通风的地方自然阴干，不要放在太阳下暴晒，暴晒会让鞋面皮面开裂，中底也会加速老化变脆，保养得好穿两三年都没问题。"},{"question":"这款MOAB 3 GTX和普通非GTX版本的MOAB 3外观上能看出来区别吗？","answer":"两者外观上是有明显区分点的，GTX版本的鞋身外侧靠近脚踝的位置，会缝有专属的GORE-TEX白色织标，鞋舌的标签上也会印上GTX的专属标识，鞋身拼接处的缝线也做了压胶密封处理，不会像非GTX版本那样露出外露的针孔。另外GTX版本的鞋面面料密度要比普通版本高很多，泼水上去会直接形成水珠滚落，普通版本的鞋面泼水之后很快就会洇湿，大家收到货可以对照这几个点检查，确认收到的是正牌GTX防水版本。"}],"user_reviews":[{"nickname":"阿凯","rating":2,"content":"穿了三次去近郊徒步，发现鞋面的反绒皮位置蹭到树枝之后特别容易留印子，擦都擦不掉，最糟心的是昨天走浅滩大概没过脚面10分钟，鞋尖位置居然渗进水了，袜子前半部分全湿了，本来就是冲着防水买的，体验感特别差。之前以为大牌的GTX不会出问题，现在走长线完全不敢穿它，只能拿来当普通休闲鞋穿，一千多的价格真的感觉不值这个价，有点失望。"},{"nickname":"阿峰","rating":5,"content":"上周跟着俱乐部走了浙西的三天长线，全程碰到两场阵雨还踩了好几次小溪，鞋里从头到尾都是干的，GORE-TEX的防水真的太靠谱了。足弓的支撑特别舒服，我体重82公斤背了16公斤的包，走下来脚都没像之前穿旧徒步鞋那样酸得难受，鞋底抓地力也绝，走湿滑的石阶完全没打滑，同行的朋友问了链接都要入，这双鞋真的是我近几年买到最满意的徒步鞋。"},{"nickname":"小宇","rating":4,"content":"整体穿着感还可以，支撑和抓地力徒步的时候都挺好用的，走碎石路脚不晃。就是刚上脚的时候鞋舌旁边的包边位置有点磨脚踝，我穿厚户外袜走了大概二十公里才把那块磨开适应过来，新鞋前几次穿最好提前贴个防磨贴会好很多。价格要是能再亲民点就更合适了，其他地方没什么大毛病，日常通勤穿也挺舒服的，除了刚开始磨脚之外没什么槽点。"},{"nickname":"大磊","rating":4,"content":"防水和支撑都符合预期，上周雨天去爬郊野的山全程脚都干爽，踩泥地里拔脚也不费劲。就是鞋身的反绒皮材质太容易沾灰了，我天天通勤穿，没到半个月鞋面就灰蒙蒙的，得每周都用鞋刷清理一次，打理起来有点麻烦。脚感是真的舒服，久站八小时脚也不疼，除了打理费点事之外，这个价位能买到这种性能的徒步鞋整体还是挺值的。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_015.json'),
    ('p_clothes_016', 'Lululemon Align 高腰紧身裤 25英寸 女士瑜伽裤柔软裸感运动裤', '露露乐蒙', '服饰运动', '瑜伽裤', '服饰运动/瑜伽裤', 880.0, 880.0, 880.0, 1600, '3_服饰运动/images/p_clothes_016_live.jpg', '{"product_id":"p_clothes_016","title":"Lululemon Align 高腰紧身裤 25英寸 女士瑜伽裤柔软裸感运动裤","brand":"露露乐蒙","category":"服饰运动","sub_category":"瑜伽裤","base_price":880.0,"image_path":"3_服饰运动/images/p_clothes_016_live.jpg","skus":[{"sku_id":"s_p_clothes_016_1","properties":{"款式":"女款","尺码":"2号","裤长":"25英寸","颜色":"黑色"},"price":880.0},{"sku_id":"s_p_clothes_016_2","properties":{"款式":"女款","尺码":"2号","裤长":"25英寸","颜色":"经典裸色"},"price":880.0},{"sku_id":"s_p_clothes_016_3","properties":{"款式":"女款","尺码":"2号","裤长":"25英寸","颜色":"象牙白"},"price":880.0},{"sku_id":"s_p_clothes_016_4","properties":{"款式":"女款","尺码":"2号","裤长":"25英寸","颜色":"海军蓝"},"price":880.0},{"sku_id":"s_p_clothes_016_5","properties":{"款式":"女款","尺码":"4号","裤长":"25英寸","颜色":"黑色"},"price":880.0},{"sku_id":"s_p_clothes_016_6","properties":{"款式":"女款","尺码":"4号","裤长":"25英寸","颜色":"经典裸色"},"price":880.0},{"sku_id":"s_p_clothes_016_7","properties":{"款式":"女款","尺码":"4号","裤长":"25英寸","颜色":"象牙白"},"price":880.0},{"sku_id":"s_p_clothes_016_8","properties":{"款式":"女款","尺码":"4号","裤长":"25英寸","颜色":"海军蓝"},"price":880.0},{"sku_id":"s_p_clothes_016_9","properties":{"款式":"女款","尺码":"6号","裤长":"25英寸","颜色":"黑色"},"price":880.0},{"sku_id":"s_p_clothes_016_10","properties":{"款式":"女款","尺码":"6号","裤长":"25英寸","颜色":"经典裸色"},"price":880.0},{"sku_id":"s_p_clothes_016_11","properties":{"款式":"女款","尺码":"6号","裤长":"25英寸","颜色":"象牙白"},"price":880.0},{"sku_id":"s_p_clothes_016_12","properties":{"款式":"女款","尺码":"6号","裤长":"25英寸","颜色":"海军蓝"},"price":880.0},{"sku_id":"s_p_clothes_016_13","properties":{"款式":"女款","尺码":"8号","裤长":"25英寸","颜色":"黑色"},"price":880.0},{"sku_id":"s_p_clothes_016_14","properties":{"款式":"女款","尺码":"8号","裤长":"25英寸","颜色":"经典裸色"},"price":880.0},{"sku_id":"s_p_clothes_016_15","properties":{"款式":"女款","尺码":"8号","裤长":"25英寸","颜色":"象牙白"},"price":880.0},{"sku_id":"s_p_clothes_016_16","properties":{"款式":"女款","尺码":"8号","裤长":"25英寸","颜色":"海军蓝"},"price":880.0}],"rag_knowledge":{"marketing_description":"这条Lululemon Align 25英寸高腰紧身裤，是专为喜爱轻运动和日常舒适感的女生打造的裸感神裤。采用品牌专属的Nulu裸感面料，摸上去像第二层皮肤一样软滑完全不磨肤，高腰宽腰头刚好卡在腰最细的位置，完全不卷边还能悄悄收住小肚腩，25英寸的裤长刚好落在脚踝上方两厘米处，对小个子也特别友好不堆裤脚。不管是做流瑜伽、普拉提这类需要大幅度拉伸的运动，还是配卫衣、长外套直接出门逛街、取快递、接娃都完全不尴尬，外穿也不显内裤边。建议洗的时候翻过来用冷水手洗或套洗衣袋轻柔机洗，别用柔顺剂，避免挂勾到尖锐物品勾丝，正常穿保养得当能保持大半年的裸感软弹状态。","official_faq":[{"question":"这款Align 25英寸的瑜伽裤会不会在做下犬式这类大幅度前屈动作的时候滑落露腰？","answer":"完全不会哦，这款专门做了3.5厘米宽的加高弹力腰头，内里还有隐形硅胶防滑条，搭配Nulu面料的高贴合回弹力，哪怕反复做下犬式、深度前屈这类大幅度动作，腰头也会稳稳贴住腰线，不会往下滑露出后腰，也不会卷边堆在肚子上，你运动全程都不用频繁伸手去扯裤腰调整，做瑜伽体式的时候完全没有束缚感。"},{"question":"这款25英寸的Align瑜伽裤会不会透色？穿浅色内裤会不会印出来痕迹？","answer":"咱们这款用的是高密织的Nulu面料，黑色和经典色款都做了高密磨毛处理，正常光线下完全不透，哪怕是穿浅粉色、米白色的普通内裤，也完全不会透出内裤的边缘轮廓和颜色。唯一要注意的是不要在强烈的直射太阳光下刻意凑近盯着看，日常运动、通勤出门的场景下完全不用担心透的问题，不用特意额外搭配同色丁字裤就能穿得自在又得体。"},{"question":"这款4码和6码对应的适合身材维度是多少呀，怕选小了勒腿选大了垮裆？","answer":"咱们这款的4码适合平时穿国内S码的女生，腰围大概在66-70cm，臀围在90-94cm，体重一般在90-105斤区间；6码适合穿国内M码的女生，腰围大概在71-76cm，臀围在95-100cm，体重在105-120斤区间。它的弹力余量很足，贴合但不勒，如果是喜欢特别裸感完全无压的效果，就算卡在临界维度选大一码也完全没问题，不会出现垮裆掉档的情况。"},{"question":"这款Align 25英寸的瑜伽裤和同品牌其他长度的Align款有什么区别？","answer":"25英寸是最适合亚洲女生的黄金裤长，刚好落在脚踝上方1-2cm，刚好露出最细的脚踝位置，既不像28英寸款那样容易堆在脚面显拖沓，也不像21英寸七分款那样容易卡在小腿肚最粗的位置显腿短。不管是搭配运动鞋、帆布鞋还是短靴都很适配，春秋单穿不冷不热，冬天套长靴里也不会多出一截裤脚皱在靴子里，适配的场景和季节都比其他长度的更灵活。"},{"question":"这款瑜伽裤洗的时候要注意什么才能一直保持裸感软的状态不起球？","answer":"洗的时候记得把裤子反过来内侧朝外，放进配套的细网洗衣袋里选冷水轻柔档机洗，或者直接冷水手洗，千万不要用热水泡，也不要加柔顺剂、漂白剂这类化学成分的洗剂，它们会破坏Nulu面料的纤维结构让面料变粗糙。洗完之后不要放烘干机高温烘，直接平铺在通风阴凉处阴干就好，别挂在衣架上扯着裤腰晾，不然很容易把腰头扯变形，避开和牛仔裤、带魔术贴的衣物混洗就能基本避免起球勾丝。"}],"user_reviews":[{"nickname":"小夏","rating":3,"content":"我按平时穿的运动裤尺码拍的6码，拿到手穿上胯部卡得特别紧，做几个瑜伽开胯动作就感觉裆部的缝线扯得慌，穿了两次大腿根的位置还磨出了一点小毛球。裸感的触感确实是舒服的，但这个价位品控感觉没跟上，我之前买的其他同类型瑜伽裤穿大半年都没磨毛，这次洗了一次之后膝盖位置的面料还稍微有点发松，不是很值这个价，有点失望。"},{"nickname":"阿柚","rating":5,"content":"真的是我穿过最舒服的瑜伽裤！我100斤选的4码刚好，25英寸的裤长我162穿刚好卡在脚踝上面，一点都不堆裤脚，面料软得像把云穿在腿上，昨天去上流瑜伽课做了整整一个小时的下犬、战士体式，腰头完全没滑也没卷边，穿浅色内裤也完全不透，下课直接套个长款卫衣去买奶茶都完全不尴尬，已经打算再入多一条经典色换着穿。"},{"nickname":"小桃","rating":4,"content":"整体来说还是挺满意的，裸感的舒适度确实没话说，高腰收小肚腩的效果也很好，我110斤选的6码穿着很贴合不勒，就是穿了大概半个月左右，我背的帆布包内侧有魔术贴，不小心蹭到裤腿侧面勾出来一根小细丝，虽然不明显但还是有点心疼。而且我洗的时候没注意和牛仔裤混洗了，裤脚位置沾了一点蓝色的浮色，介意的姐妹一定要单独洗或者套洗衣袋。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_016.json'),
    ('p_clothes_017', 'Arc''teryx Gamma Pant 男子软壳长裤耐磨弹力户外徒步攀爬长裤', '始祖鸟', '服饰运动', '户外裤', '服饰运动/户外裤', 1290.0, 1290.0, 1290.0, 500, '3_服饰运动/images/p_clothes_017_live.jpg', '{"product_id":"p_clothes_017","title":"Arc''teryx Gamma Pant 男子软壳长裤耐磨弹力户外徒步攀爬长裤","brand":"始祖鸟","category":"服饰运动","sub_category":"户外裤","base_price":1290.0,"image_path":"3_服饰运动/images/p_clothes_017_live.jpg","skus":[{"sku_id":"s_p_clothes_017_1","properties":{"版本":"男款","尺码":"28码"},"price":1290.0},{"sku_id":"s_p_clothes_017_2","properties":{"版本":"男款","尺码":"30码"},"price":1290.0},{"sku_id":"s_p_clothes_017_3","properties":{"版本":"男款","尺码":"32码"},"price":1290.0},{"sku_id":"s_p_clothes_017_4","properties":{"版本":"男款","尺码":"34码"},"price":1290.0},{"sku_id":"s_p_clothes_017_5","properties":{"版本":"男款","尺码":"36码"},"price":1290.0}],"rag_knowledge":{"marketing_description":"这款始祖鸟Gamma男款软壳长裤，采用自家专属Fortius 2.0弹力磨毛面料，兼顾强耐磨性与四面弹力，裤身做了DWR防泼水处理，细碎小雨、登山溅起的泥点都不容易沾身。臀部和大腿侧做了双层加固剪裁，攀爬、深蹲大动作完全不卡裆掉裆，内置的腰带卡扣不用额外配腰带，侧袋带拉链防止徒步时东西滑出。特别适合热爱周末单日徒步、岩壁攀援、日常近郊轻户外的男性玩家，平时通勤搭配速干衣也毫无违和感。使用建议选对腰围尺码，攀爬时不要刻意蹭尖锐岩壁锐角，日常清洁用中性洗衣液冷水机洗，别用柔顺剂，避免破坏面料的防泼水处理层。","official_faq":[{"question":"Gamma这款软壳长裤面料的弹力表现，在攀爬大跨度动作时会出现紧绷卡腿的情况吗？","answer":"不会出现卡腿紧绷的问题，这款用的Fortius 2.0面料自带4向弹力，延展度能达到原面料的30%左右，同时裤裆位置做了专属的立体插片剪裁，完全适配攀爬时劈腿、高抬腿跨障、深蹲探路这类大动作。我们实测过用户穿它完成15米传统攀岩全程，全程没有出现面料拉扯束缚感，哪怕是大腿围偏壮的用户，选对对应腰围尺码后，活动空间也足够富余，不会有勒腿的情况。"},{"question":"这款Gamma长裤的防泼水处理，日常清洗多少次之后效果会衰减？要怎么养护才能延长效果？","answer":"正常用中性洗衣液冷水机洗、不对面料做刻意破坏的情况下，DWR防泼水层能支撑至少30次水洗才会出现明显衰减。养护的时候千万不要用热水洗，也别加衣物柔顺剂，柔顺剂里的硅成分会直接堵死面料表面的防泼水孔隙，洗完之后也别用高温烘干机烘，挂在通风阴凉处阴干就可以。如果后续发现泼水滴不挂水了，买专门的户外软壳防泼水剂喷一喷低温熨烫一下，就能恢复大部分防泼水性能。"},{"question":"30码和32码的Gamma长裤对应的实际腰围是多少，适合什么样身材的人穿？","answer":"这款男款长裤的30码对应实际腰围是76厘米，也就是常规2尺3的腰，裤长是102厘米，适合身高170到175厘米、体重60到70公斤的用户；32码对应实际腰围是81厘米，也就是常规2尺45的腰，裤长是104厘米，适合身高175到182厘米、体重70到80公斤的用户。裤身是偏修身的直筒剪裁，腿上肌肉偏壮的徒步爱好者，选大半码的腰围也不会出现裤长过长堆在鞋面上的情况，适配大多数亚洲男性的常规身材。"},{"question":"这款Gamma软壳长裤适合冬天零下多少度的户外场景穿？要不要搭配内层保暖裤？","answer":"这款长裤本身面料带薄磨毛内里，零上5到15度的深秋徒步场景单穿完全没问题，体感不会冻腿。如果是零下5度左右的低温户外，在里面搭一条薄款抓绒裤或者始祖鸟的Phase内层裤就足够应对，哪怕是零下10度左右的攀冰场景，外层再套一层防风裤也完全能适配。它本身不是厚款加绒硬壳裤，不建议在长时间零下15度无额外保暖层的场景下单穿，避免体感温度过低影响活动体验。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"上周穿它去走了武功山两天线，淋了半小时细碎小雨，裤腿上的雨珠直接滑走完全没渗进去，路上蹭到好几次带刺的灌丛，也没勾丝破洞。之前穿别的软壳裤攀爬的时候总卡裆，这款做的立体裆片太友好了，跨石头的时候完全不勒，兜里面装的充电宝走全程也没晃出来，一千多买的真的比之前穿的杂牌耐造太多，以后徒步长裤就锁定它了。"},{"nickname":"大刘","rating":1,"content":"收到货拆吊牌才发现裤脚是预卷边收窄的，我平时徒步习惯把裤脚放下来盖着登山鞋鞋舌防进碎石，结果放下来之后发现卷边的位置压出了死褶，怎么熨都展不开。找客服说这是常规剪裁没办法处理，我买的32码我183穿裤长刚够，裁改裤脚就短了，退也退不了，一千多买的裤子只能平时通勤穿，完全没法拿来走长线，太闹心了。"},{"nickname":"小峰","rating":5,"content":"我玩运动攀快三年了，之前的旧Gamma穿了五年磨破了才换的新的，这款新版的弹力比老款好太多，上周爬5.10d的线，需要高抬腿够岩点的时候完全没感觉到面料拉扯。日常上班穿也完全不突兀，搭配工装靴也挺好看的，洗了快十次了防泼水性还和新的差不多，始祖鸟这个线的品控确实稳，贵是贵了点但真的经穿，算下来性价比反而高。"},{"nickname":"阿泽","rating":5,"content":"我17872公斤，买的32码刚好，腰上自带的卡扣调节太方便了，不用额外系腰带，徒步的时候出汗腰带也不会闷腰。上次走雨崩线，路上摔了一跤蹭在碎石路面上，裤子膝盖位置蹭得全是泥，拍一拍直接就掉了，连水都没怎么沾，完全没磨破，之前穿的别的裤子同款路况早就磨出毛边了，这质量真的没得说。"},{"nickname":"老周","rating":5,"content":"买之前还怕软壳裤子太硬穿着不舒服，收到之后摸到手就惊了，软乎乎的但摸上去就很有韧性，磨毛内里秋天穿在山里走一天腿上完全不会凉。侧面的拉链兜很深，我把车钥匙和手机放里面跳着走都没掉出来，之前买的别的户外裤兜浅，走两步东西就往下滑，这点设计真的太懂徒步的人了，穿了大半个月所有细节都很满意。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_017.json'),
    ('p_clothes_018', 'The North Face Borealis 28L 多功能通勤户外双肩背包', 'The North Face', '服饰运动', '背包', '服饰运动/背包', 1098.0, 1098.0, 1098.0, 300, '3_服饰运动/images/p_clothes_018_live.jpg', '{"product_id":"p_clothes_018","title":"The North Face Borealis 28L 多功能通勤户外双肩背包","brand":"The North Face","category":"服饰运动","sub_category":"背包","base_price":1098.0,"image_path":"3_服饰运动/images/p_clothes_018_live.jpg","skus":[{"sku_id":"s_p_clothes_018_1","properties":{"容量":"28L","颜色":"黑色 Black","版本":"通勤背包"},"price":1098.0},{"sku_id":"s_p_clothes_018_2","properties":{"容量":"28L","颜色":"白色 Gardenia White","版本":"通勤背包"},"price":1098.0},{"sku_id":"s_p_clothes_018_3","properties":{"容量":"28L","颜色":"灰色 Asphalt Grey","版本":"通勤背包"},"price":1098.0}],"rag_knowledge":{"marketing_description":"北面这台28L Borealis双肩包绝对是通勤党和轻户外爱好者的刚需宝藏！采用品牌专属的防泼水面料，溅到雨天积水、咖啡洒到表面擦一下就干净，主舱隔层专门适配16寸笔记本，侧边弹力兜能塞下500ml保温杯+折叠晴雨伞，背板的穿孔发泡棉自带透气缓冲，背三小时挤地铁都不会闷汗压肩。日常适合朝九晚五通勤族、高校走读生，周末近郊徒步、探店短途出行也完全够用。使用建议是装超过10斤重物时记得调整胸带分散压力，注意不要长时间把包泡在水里，尖锐刀锋类物品装进去最好套个小布袋避免刮蹭内层面料。三个配色不管是搭休闲装还是工装风都毫无违和感，颜值实用性双在线。","official_faq":[{"question":"这款28L的Borealis背包能不能放下16寸带保护壳的游戏本，放进去之后还能装下其他通勤物品吗？","answer":"完全可以，这款背包专门做了加厚绒面的16寸专属电脑仓，就算是套了厚硅胶保护壳或者散热底座的16寸游戏本也能轻松塞进去，不会出现合不上拉链的情况。剩余的主舱空间还能放下14寸平板、带壳的充电宝、通勤换的帆布鞋子和中午的便当盒，前置的小暗袋还能放门禁卡、 AirPods和口红这类小物件，28L的容量日常通勤完全够用，不会出现塞不下的尴尬情况。"},{"question":"这款背包的防泼水面料日常遇到小雨要怎么打理，脏了能不能直接扔洗衣机洗？","answer":"它的外层面料做了DWR防泼水处理，日常遇到突然飘的小雨不用慌，表层水珠会直接滚落不会渗进内层，雨停之后拿干布把表面水珠擦掉就可以正常使用。日常脏污建议用软毛刷沾中性洗衣液轻轻刷脏的部位，冲洗完之后挂在通风阴凉处阴干就好，千万不要直接扔进滚筒洗衣机搅，也不要拿去暴晒，不然会破坏表面的防泼水剂层，容易出现面料起球、防水效果下降的问题，也尽量不要用漂白类的清洁剂处理。"},{"question":"这款背包三个配色的面料材质有没有区别，不同颜色的耐脏程度差异大吗？","answer":"三个配色用的都是完全同款的防撕裂牛津纺面料，内部结构、五金配件的规格也完全一致，价格相同只是配色不同，不存在某一个版本偷工减料的情况。耐脏程度上黑色款最耐造，日常溅到污渍落灰基本看不出来，灰色款次之，落了浮灰拍一下就干净，白色款虽然颜值高但容易蹭到黑印子、奶茶渍，日常使用的时候要多注意避开容易脏的场景，要是选日常高频通勤用的话优先选黑灰两色，喜欢穿搭出片选白色也完全没问题。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"通勤用了快半个月真的太香了！之前背普通书包挤地铁总压得肩膀疼，这个的肩带软乎乎的，背15.6寸游戏本加一堆文件也不会勒肩，侧边兜塞我的保温杯刚好不晃，上周赶下班遇小暴雨，包表面的水一擦就没，里面的电脑一点没湿，黑的配色搭我工装外套巨好看，同事都问我链接，几百块能买到北面这个款真的太值了。"},{"nickname":"小夏","rating":1,"content":"刚收到背了三天侧边的弹力兜就开线了，我就放了个普通500ml的矿泉水瓶，根本没装重物，找售后说我是人为拉扯的不给退，一百多的包都不至于三天就坏啊，而且包的肩带填充物很薄，我装14寸笔记本背半小时肩膀就压出红印，防泼水效果也很一般，上次遇小雨内层就有点潮，花一千多买这个品控真的太不值了，非常不推荐。"},{"nickname":"阿泽","rating":3,"content":"整体只能说勉勉强强，我买的灰色款，颜值确实没话说，版型挺括不软塌，但是自重比我之前买的同容量背包重好多，空包拿着就有点沉，装满东西之后更坠肩，而且前置的小暗袋太浅了，我放门禁卡好几次都差点滑出来，走两步就要摸一下，一千多的价格这个细节处理真的不算好，算不上特别差但也完全不值这个价位。"},{"nickname":"圆圆","rating":5,"content":"选的白色款真的太适合搭我的通勤穿搭了！本来还担心容易脏，平时注意点擦一下基本都干净，电脑仓的绒面软乎乎的，放我的MacBook完全不怕刮，之前周末背它去近郊徒步，背板透气不闷汗，背了四个小时后背都没湿，各种小隔层分类放东西特别方便，再也不用乱翻找钥匙耳机，这个背包用大半年了五金也没掉漆，质感真的拉满。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_018.json'),
    ('p_clothes_019', 'Nike Heritage86 Futura Logo 经典刺绣棒球帽 可调节帽围', 'Nike', '服饰运动', '帽子', '服饰运动/帽子', 169.0, 169.0, 179.0, 600, '3_服饰运动/images/p_clothes_019_live.jpg', '{"product_id":"p_clothes_019","title":"Nike Heritage86 Futura Logo 经典刺绣棒球帽 可调节帽围","brand":"Nike","category":"服饰运动","sub_category":"帽子","base_price":169.0,"image_path":"3_服饰运动/images/p_clothes_019_live.jpg","skus":[{"sku_id":"s_p_clothes_019_1","properties":{"尺码":"均码","帽身颜色":"黑色","刺绣logo配色":"白勾","帽围类型":"可调节帽围"},"price":169.0},{"sku_id":"s_p_clothes_019_2","properties":{"尺码":"均码","帽身颜色":"黑色","刺绣logo配色":"黑勾","帽围类型":"可调节帽围"},"price":169.0},{"sku_id":"s_p_clothes_019_3","properties":{"尺码":"均码","帽身颜色":"白色","刺绣logo配色":"白勾","帽围类型":"可调节帽围"},"price":169.0},{"sku_id":"s_p_clothes_019_4","properties":{"尺码":"均码","帽身颜色":"白色","刺绣logo配色":"黑勾","帽围类型":"可调节帽围"},"price":169.0},{"sku_id":"s_p_clothes_019_5","properties":{"尺码":"均码","帽身颜色":"藏蓝色","刺绣logo配色":"白勾","帽围类型":"可调节帽围"},"price":179.0},{"sku_id":"s_p_clothes_019_6","properties":{"尺码":"均码","帽身颜色":"藏蓝色","刺绣logo配色":"黑勾","帽围类型":"可调节帽围"},"price":179.0}],"rag_knowledge":{"marketing_description":"这款Nike Heritage86 Futura刺绣棒球帽是日常出街的百搭刚需款，帽身用的是重磅水洗棉面料，软而不塌不会随便变形，正面经典Futura勾子是高密度立体刺绣，摸上去有明显凹凸感不是廉价热印。后面配的尼龙魔术贴调节扣，头围54到60厘米都能贴合适，不用怕卡头或者掉帽檐。学生党早八赶课遮乱发、健身跑街挡小太阳、出游搭运动服卫衣都适配，不用特意搭配就能出片。平时洗的时候建议手洗反过来搓刺绣部分，别长时间泡热水，挂在通风处阴干就好，别用洗衣机搅不然容易把帽檐衬布搅歪，戴个两三年质感都不会垮。","official_faq":[{"question":"这款帽子的魔术贴调节扣长时间用会不会起毛脱落？","answer":"咱们这款Heritage86的调节扣用的是Nike专属定制的高密尼龙魔术贴，背面的车线是双股锁边工艺固定在帽尾织带上，正常日常使用反复开合几千次都不会轻易脱线起毛。只要你平时不要刻意撕扯魔术贴的勾面，洗帽子的时候记得把魔术贴完全粘合在一起再清洗，就完全不会出现勾面勾挂其他面料起毛的情况，正常佩戴用个两三年都不会有调节失效的问题，完全能满足日常高频使用的需求。"},{"question":"三个不同配色的帽子面料厚度是一样的吗？为什么藏蓝色款要贵10块钱？","answer":"黑色白勾、白色黑勾两款用的是常规水洗棉面料，工艺和定价都是169元，藏蓝色白勾款用的是定染的固色重磅棉面料，染色的时候多做了3次锁色固色处理，长时间戴或者水洗之后不容易出现发旧泛白的情况，刺绣用的线也是专属的奶白色绣线，对比普通白勾更有柔和质感，成本比另外两个配色高出10块，所以最终定价是179元的，面料厚度上藏蓝色款会比另外两个配色略厚实一点，挺括度也更好。"},{"question":"头围61cm的大头能戴进去吗？戴久了帽檐会不会塌下来挡视线？","answer":"这款帽子的适配头围区间是54cm到60cm，如果头围刚好卡在61cm的话佩戴会有点紧绷，长时间戴可能会压头顶不太舒服，更建议选头围预留空间更大的硬顶款棒球帽。它的帽檐内部是做了硬衬定型处理的，不是完全软塌的款式，正常日常佩戴不刻意掰扯帽檐的话，用一两年都不会往下塌挡视线，要是你觉得帽檐弧度不顺，用手轻轻往回掰两下就能调整到你习惯的弧度，支撑性完全足够日常使用。"},{"question":"帽子上的刺绣标洗了之后会不会脱线掉线头？","answer":"这款Futura勾子刺绣用的是Nike品控标准的高密度涤棉绣线，每平方厘米有120针以上的针脚密度，边缘还做了锁边工艺，正常手洗轻轻搓揉完全不会出现脱线掉线头的情况。千万不要用硬毛刷直接大力刷刺绣表面，也不要放在洗衣机里搅拌拉扯，要是发现有浮出来的小线头用小剪刀剪掉就好，别直接用手拽，拽的话可能会带松周边的针脚，只要正常养护，戴两三年刺绣的饱满度都不会有明显下降。"}],"user_reviews":[{"nickname":"小棠","rating":5,"content":"真的太爱这款帽子了！我头围57选的黑勾白款，后面魔术贴调完刚好卡在最舒服的位置，不会压得太阳穴疼。刺绣勾子摸上去是凹凸的立体质感，完全不是那种廉价胶印，我上周戴去爬了一天山，汗浸了面料也没发臭变形，平时早八套个卫衣直接戴出门，油头直接遮得严严实实，已经把藏蓝色款也加入购物车准备再入一个换着戴。"},{"nickname":"阿凯","rating":3,"content":"整体来说不算太差，但和我之前在线下店试的同款式比差了点意思。我买的黑色白勾款，帽檐的弧度比线下的要平很多，我自己掰了好久都掰不出想要的弯度，戴上去显得脸特别方。刺绣倒是没什么问题，就是面料摸起来薄了点，三十多度的天戴倒是挺透气，但感觉戴不了半年就会软塌，性价比感觉没有预期那么高，只能说凑合用。"},{"nickname":"小夏","rating":1,"content":"收到货直接傻了，帽子正面的刺绣勾子歪了快两毫米，整个logo不在正中间，戴上去从正面看特别别扭，品控怎么能差成这样？找客服说不属于质量问题不给退，还说刺绣有手工误差很正常。我之前买的别的店的同款式刺绣都整整齐齐的，这个价格做出来这种做工真的太让人失望了，完全不值这个价，再也不会买了。"},{"nickname":"阿泽","rating":4,"content":"整体还是不错的，上身后搭我的运动服特别协调，白色款耐脏度比我想象中好，平时随便扔包里也没怎么起皱。就是有个小问题，我戴了快半个月之后，魔术贴的边缘开始起小毛了，不是很严重但看着有点闹心，不过一百多的价格买正品Nike刺绣款其实也还行，要是魔术贴能做的更耐用点就完美了，暂时凑合用没啥问题。"},{"nickname":"月月","rating":4,"content":"帽子本身的版型挺修饰脸型的，我脸圆戴上去显脸小一圈，藏蓝色的质感比图片看着还要好，固色也还行，洗了一次没掉色。唯一的小缺点就是帽身内里的汗带部分有点容易沾碎头发，我戴完每次摘下来都沾一堆小碎毛，得用粘毛器滚一下才干净，其他地方都没啥问题，平时出门遮阳遮乱发都挺好用的。"},{"nickname":"大宇","rating":1,"content":"真的太失望了，收到货之后刚拆封就发现帽檐侧边有一道两厘米左右的脱线，还沾了一大块不明的黄色污渍，像是别人试戴过没处理的二手货。找客服退换还要我自己出运费，说拆了塑封就不能走质量问题退换流程，一百多块钱买个残次品，做工和售后都稀烂，完全配不上Nike的品牌，以后绝对不会再来这家店买东西了。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_019.json'),
    ('p_clothes_020', '迪卡侬 KALENJI 男子跑步速干T恤轻薄透气基础训练短袖上衣', '迪卡侬', '服饰运动', '速干T恤', '服饰运动/速干T恤', 79.0, 79.0, 79.0, 2000, '3_服饰运动/images/p_clothes_020_live.jpg', '{"product_id":"p_clothes_020","title":"迪卡侬 KALENJI 男子跑步速干T恤轻薄透气基础训练短袖上衣","brand":"迪卡侬","category":"服饰运动","sub_category":"速干T恤","base_price":79.0,"image_path":"3_服饰运动/images/p_clothes_020_live.jpg","skus":[{"sku_id":"s_p_clothes_020_1","properties":{"适用性别":"男款","颜色":"纯净白","尺码":"S码"},"price":79.0},{"sku_id":"s_p_clothes_020_2","properties":{"适用性别":"男款","颜色":"纯净白","尺码":"M码"},"price":79.0},{"sku_id":"s_p_clothes_020_3","properties":{"适用性别":"男款","颜色":"纯净白","尺码":"L码"},"price":79.0},{"sku_id":"s_p_clothes_020_4","properties":{"适用性别":"男款","颜色":"纯净白","尺码":"XL码"},"price":79.0},{"sku_id":"s_p_clothes_020_5","properties":{"适用性别":"男款","颜色":"纯净白","尺码":"XXL码"},"price":79.0},{"sku_id":"s_p_clothes_020_6","properties":{"适用性别":"男款","颜色":"经典黑","尺码":"S码"},"price":79.0},{"sku_id":"s_p_clothes_020_7","properties":{"适用性别":"男款","颜色":"经典黑","尺码":"M码"},"price":79.0},{"sku_id":"s_p_clothes_020_8","properties":{"适用性别":"男款","颜色":"经典黑","尺码":"L码"},"price":79.0},{"sku_id":"s_p_clothes_020_9","properties":{"适用性别":"男款","颜色":"经典黑","尺码":"XL码"},"price":79.0},{"sku_id":"s_p_clothes_020_10","properties":{"适用性别":"男款","颜色":"经典黑","尺码":"XXL码"},"price":79.0},{"sku_id":"s_p_clothes_020_11","properties":{"适用性别":"男款","颜色":"深麻灰","尺码":"S码"},"price":79.0},{"sku_id":"s_p_clothes_020_12","properties":{"适用性别":"男款","颜色":"深麻灰","尺码":"M码"},"price":79.0},{"sku_id":"s_p_clothes_020_13","properties":{"适用性别":"男款","颜色":"深麻灰","尺码":"L码"},"price":79.0},{"sku_id":"s_p_clothes_020_14","properties":{"适用性别":"男款","颜色":"深麻灰","尺码":"XL码"},"price":79.0},{"sku_id":"s_p_clothes_020_15","properties":{"适用性别":"男款","颜色":"深麻灰","尺码":"XXL码"},"price":79.0},{"sku_id":"s_p_clothes_020_16","properties":{"适用性别":"男款","颜色":"藏青色","尺码":"S码"},"price":79.0},{"sku_id":"s_p_clothes_020_17","properties":{"适用性别":"男款","颜色":"藏青色","尺码":"M码"},"price":79.0},{"sku_id":"s_p_clothes_020_18","properties":{"适用性别":"男款","颜色":"藏青色","尺码":"L码"},"price":79.0},{"sku_id":"s_p_clothes_020_19","properties":{"适用性别":"男款","颜色":"藏青色","尺码":"XL码"},"price":79.0},{"sku_id":"s_p_clothes_020_20","properties":{"适用性别":"男款","颜色":"藏青色","尺码":"XXL码"},"price":79.0}],"rag_knowledge":{"marketing_description":"这是迪卡侬KALENJI系列专为男性跑者打造的基础训练速干T恤，整衣采用高密聚酯纤维蜂窝网眼面料，重量仅120g左右，上身几乎零负担。面料自带的导水沟槽结构能快速把运动产生的汗液从皮肤表面导出扩散，30℃以上天跑5公里也不会贴身黏糊，跑后半小时自然晾干完全不留汗味。专门适配夜跑的反光条嵌在衣摆侧边，傍晚沿江跑也能让来往车辆清晰注意到你。版型做了微宽松剪裁，不会紧勒胸口抬臂跑完全不卡肩。适合日常路跑、健身房力量训练、周末郊野徒步、日常通勤遛弯等多种场景，不管是刚入门的跑步新手还是日常保持训练的运动爱好者都能穿。洗涤建议用常温水手洗或轻柔机洗，不要用柔顺剂浸泡，会破坏面料的导汗结构，长时间暴晒也容易让速干层老化变硬。","official_faq":[{"question":"这款KALENJI男款速干T恤的导汗效果会不会洗几次就失效？","answer":"正常按照说明洗涤的话导汗效果可以维持至少2年不会明显衰减，我们这款速干功能不是靠后期涂层面料实现的，是直接在聚酯纤维纺丝阶段就做了异型截面的导槽设计，不是附着在面料表面的，不会因为日常洗涤摩擦就脱落。注意不要用衣物柔顺剂浸泡，柔顺剂里的阳离子成分会填住面料表面的导汗沟槽，洗完之后速干效果就会大打折扣，也不要用刷子大力搓揉衣身正面的面料就可以。"},{"question":"我身高175cm体重72kg选L码会不会太宽松影响跑步？","answer":"按照你提供的身高体重参数，穿这款的L码是刚好合适的状态，它的剪裁专门针对跑步动作做了优化，侧缝做了前短后长的调整，不会因为你抬臂摆腿动作往上跑露肚子，下摆两侧还有1cm的小开叉，跑大步的时候完全不会勒胯。如果是想要贴身一点的竞速感效果选M码也可以，但如果你跑步的时候习惯在腰后面放能量胶，选L码留出来的宽松余量会更方便塞小东西，日常日常穿也不会显得太紧绷，适配绝大多数男生的训练需求。"},{"question":"这件速干T恤夏天35度跑半马穿会不会闷后背？","answer":"完全不会有闷后背的情况，我们衣身的主体部分全部用的是20D的蜂窝网眼面料，每平方厘米就有上百个透气小孔，空气对流速度是普通纯棉T恤的3倍以上，就算你半马跑两个多小时全程出大量汗，汗液也会被快速导出到面料表层散开，不会积在皮肤和衣服之间。很多跑者夏天测试35度环境下跑完10公里，后背面料只会微微发潮，不会像纯棉那样湿成一块完全贴在背上，风一吹很快就凉下来，完全不会有闷汗捂得后背发疼的问题。"},{"question":"这件T恤的侧边反光条洗多了会不会掉？夜跑的时候亮度够不够？","answer":"这款衣摆侧边的反光条用的是高温热压烫印工艺贴合的，不是普通的胶粘款，正常机洗50次以上都不会出现起边脱落的情况，完全不用担心洗几次就掉的问题。它的反光颗粒亮度达到了运动服饰的二级反光标准，晚上在路灯不足的郊野道路上，距离150米开外的汽车灯光照过来就能清晰看到反光标识，完全满足日常夜跑的安全需求，只要不是长期用尖锐的东西去刮蹭反光条区域，基本可以和衣服同寿命使用。"},{"question":"这款速干T恤可以直接当居家休闲上衣穿吗？会不会运动感太奇怪？","answer":"完全可以当日常休闲上衣穿，这款就是KALENJI系列的基础训练款，没有夸张的大logo和花里胡哨的运动标识，整体就是极简的纯色设计，不管是搭运动短裤出街买东西，还是搭普通牛仔裤日常通勤都完全不违和。很多老用户日常不跑步的时候也会穿它，比普通纯棉T恤凉快很多，夏天出门出汗也不会黏糊糊贴身上，比普通休闲上衣穿着舒服不少，适配场景非常广，不用专门当成只能运动穿的单品。"},{"question":"这件T恤的面料会不会起球？穿久了袖口领口会不会变形松垮？","answer":"这款用的是高捻度的异型聚酯纤维纱线，抗起球等级达到了国家纺织品标准的4级，日常正常穿着和洗涤，正常和背包肩带之类的摩擦，基本不会出现明显的起球结毛情况。领口和袖口都做了双车线的加固罗纹边处理，不是那种薄软的松散边，连续穿3个月机洗几十次也不会出现领口垮塌变形、袖口卷边松垮的问题，只要你洗完之后不要用力拧干扯拽领口袖口，正常悬挂晾干就可以长期保持版型挺括。"}],"user_reviews":[{"nickname":"阿凯","rating":2,"content":"买的M码我172穿刚好合身，但是上次跑了个7公里出了满身汗，停下来走了不到5分钟，衣服凉得太快直接冻得我后背起鸡皮疙瘩，那天跑完直接感冒了。面料速干是真的快，但是秋天的傍晚穿真的太容易受凉了，不是衣服质量问题，就是对我这种容易感冒的人太不友好，大家入秋跑步还是得搭个外套，单穿这件真的有点扛不住停下来的风。"},{"nickname":"大磊","rating":1,"content":"穿了第三次机洗就发现胸口位置勾出了个小口子，我就是正常丢洗衣机里和运动裤一起洗的，套了洗衣袋的啊。这面料也太薄了吧，平时穿也没刮到什么尖锐的东西，跑了两次步还没怎么造就破了，79块钱也不算是特别便宜的速干衣吧，这个质量真的有点说不过去，找客服说不在质保范围内，以后还是买别家厚点的速干衣算了。"},{"nickname":"小宇","rating":5,"content":"这真的是我买过性价比最高的跑步T恤了，上周32度的天夜跑跑了6公里，后背出汗完全不贴身，以前穿纯棉T恤跑完衣服全湿了沉得慌，这件跑完几乎没什么重量，回家挂阳台吹了20分钟就全干了。侧边那个小反光条晚上跑江边步道，路过的电动车老远就能注意到我，安全多了，版型也舒服，抬臂摆臂完全不卡肩，以后训练就认准这件了。"},{"nickname":"阿哲","rating":3,"content":"整体穿着还行速干效果确实不错，就是我买的纯黑色款，穿了两次发现腋下位置起了不少小毛球，我也没背什么重的包啊，就是跑步的时候正常摆臂摩擦的位置。起球倒也不影响穿，就是看着有点显旧，这个价位的速干衣，这个质量感觉也就中规中矩，要是纱线再做密一点抗起球做好点就完美了，也不算特别差就是达不到预期吧。"},{"nickname":"浩子","rating":1,"content":"我178买的L码，结果衣长短得离谱，跑起来抬几次胳膊直接露整个肚子，我腰上放了个运动手机臂包都卡不住下摆。之前买别家同尺码的速干衣衣长都够，这件短了快5厘米，我平时跑长距离都怕腰吹风着凉，想着退换货嫌麻烦，直接拿来当居家睡衣穿了，完全没法当跑步训练服穿，版型设计太不合理了。"},{"nickname":"阿鸣","rating":5,"content":"作为跑步新手第一次买专业速干衣，真的太惊喜了，上周跟着跑团组织第一次跑10公里，全程出了超多汗，以前穿普通棉T黏在身上闷得后背都长痱子，这件全程都是清爽的，风一吹凉丝丝的完全不闷。79块钱还要啥自行车啊，版型微宽松也不显肚子，我这个刚减肥的大肚子穿起来完全不紧绷，训练穿太合适了，已经又囤了一件换着穿。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_020.json'),
    ('p_clothes_021', 'Nike Dri-FIT Miler 男子速干短袖跑步上衣轻薄透气公路训练T恤', '耐克', '服饰运动', '速干T恤', '服饰运动/速干T恤', 249.0, 249.0, 249.0, 2000, '3_服饰运动/images/p_clothes_021_live.jpg', '{"product_id":"p_clothes_021","title":"Nike Dri-FIT Miler 男子速干短袖跑步上衣轻薄透气公路训练T恤","brand":"耐克","category":"服饰运动","sub_category":"速干T恤","base_price":249.0,"image_path":"3_服饰运动/images/p_clothes_021_live.jpg","skus":[{"sku_id":"s_p_clothes_021_1","properties":{"版本":"男款","颜色":"经典黑","尺码":"S码"},"price":249.0},{"sku_id":"s_p_clothes_021_2","properties":{"版本":"男款","颜色":"经典黑","尺码":"M码"},"price":249.0},{"sku_id":"s_p_clothes_021_3","properties":{"版本":"男款","颜色":"经典黑","尺码":"L码"},"price":249.0},{"sku_id":"s_p_clothes_021_4","properties":{"版本":"男款","颜色":"经典黑","尺码":"XL码"},"price":249.0},{"sku_id":"s_p_clothes_021_5","properties":{"版本":"男款","颜色":"经典黑","尺码":"XXL码"},"price":249.0},{"sku_id":"s_p_clothes_021_6","properties":{"版本":"男款","颜色":"纯净白","尺码":"S码"},"price":249.0},{"sku_id":"s_p_clothes_021_7","properties":{"版本":"男款","颜色":"纯净白","尺码":"M码"},"price":249.0},{"sku_id":"s_p_clothes_021_8","properties":{"版本":"男款","颜色":"纯净白","尺码":"L码"},"price":249.0},{"sku_id":"s_p_clothes_021_9","properties":{"版本":"男款","颜色":"纯净白","尺码":"XL码"},"price":249.0},{"sku_id":"s_p_clothes_021_10","properties":{"版本":"男款","颜色":"纯净白","尺码":"XXL码"},"price":249.0},{"sku_id":"s_p_clothes_021_11","properties":{"版本":"男款","颜色":"深麻灰","尺码":"S码"},"price":249.0},{"sku_id":"s_p_clothes_021_12","properties":{"版本":"男款","颜色":"深麻灰","尺码":"M码"},"price":249.0},{"sku_id":"s_p_clothes_021_13","properties":{"版本":"男款","颜色":"深麻灰","尺码":"L码"},"price":249.0},{"sku_id":"s_p_clothes_021_14","properties":{"版本":"男款","颜色":"深麻灰","尺码":"XL码"},"price":249.0},{"sku_id":"s_p_clothes_021_15","properties":{"版本":"男款","颜色":"深麻灰","尺码":"XXL码"},"price":249.0},{"sku_id":"s_p_clothes_021_16","properties":{"版本":"男款","颜色":"藏青色","尺码":"S码"},"price":249.0},{"sku_id":"s_p_clothes_021_17","properties":{"版本":"男款","颜色":"藏青色","尺码":"M码"},"price":249.0},{"sku_id":"s_p_clothes_021_18","properties":{"版本":"男款","颜色":"藏青色","尺码":"L码"},"price":249.0},{"sku_id":"s_p_clothes_021_19","properties":{"版本":"男款","颜色":"藏青色","尺码":"XL码"},"price":249.0},{"sku_id":"s_p_clothes_021_20","properties":{"版本":"男款","颜色":"藏青色","尺码":"XXL码"},"price":249.0}],"rag_knowledge":{"marketing_description":"这款Nike Dri-FIT Miler男子速干短袖T恤，专为公路跑、日常路跑训练打造，采用耐克专属Dri-FIT速干科技面料，能快速把运动时体表的汗液导流到面料外层挥发，跑完全程后背也不容易闷出黏腻感。整体面料做了轻量化处理，比普通棉T恤轻将近一半，上身几乎零负担，肩部和侧缝的剪裁做了优化，大幅度摆臂时完全不会卡胳肢窝。特别适合日常有3-10公里公路跑训练需求的跑者，也能用来做健身房有氧、夜骑、日常通勤穿搭。建议手洗或轻柔机洗，不要用漂白剂浸泡，晾晒时避免长时间暴晒，能更好保留面料的速干性能，不要穿着它长时间泡在水里，避免影响使用寿命。","official_faq":[{"question":"这款Dri-FIT Miler跑步T恤和耐克普通的休闲速干T恤速干速度差多少？","answer":"这款是专门针对公路跑步场景调校的专业训练款，速干效率比普通休闲速干T恤高出约30%，我们在实验室模拟25℃、湿度60%的常规户外跑步环境下，同分量的汗液洒在面料上，这款大概20分钟就能完全干透，普通休闲款往往要半小时以上。而且它的面料织法做了特殊的导湿沟槽设计，汗液不会在体表大面积聚成水膜，跑步过程中就能边运动边挥发，不会跑后半程后背凉飕飕的，很适合长时间户外路跑穿。"},{"question":"平时穿其他品牌运动T恤M码刚好，这款Nike Dri-FIT Miler的M码会不会偏码？","answer":"这款T恤是专门为亚洲男性跑者调整的剪裁，整体偏略微修身的运动版型，不是宽松的落肩款。如果您平时穿其他常规运动品牌的M码合身，身高在170-175cm、体重在60-70kg区间，选这款M码完全没问题；要是平时跑步习惯在里面额外搭一件压缩衣，或者喜欢留更多活动余量的宽松感，选大一码的L码会更舒服。不建议选比自己日常码数小的尺寸，不然长时间摆臂的时候侧缝容易勒腋下。"},{"question":"这款T恤洗多了之后速干性能会不会明显下降？平时打理要注意什么？","answer":"正常按照洗护说明洗涤的情况下，机洗30次左右速干性能只会有不到5%的损耗，几乎不会影响日常使用。打理的时候注意不要用热水超过40℃洗涤，也不要用衣物柔顺剂长时间浸泡，柔顺剂会堵住面料表面的导湿微孔，洗完之后速干速度就会明显变慢。晾晒的时候不要直接放在正午的太阳下暴晒超过2小时，也不要用烘干机高温烘，平铺阴干或者挂在通风处晾干就可以，能最大程度延长T恤的使用周期。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"真的太失望了，我跑了不到两公里，后背出了点汗直接就贴身了，黏糊糊的贴在背上风一吹特别凉，以前买的别的杂牌速干衣都比这个强。我洗了两次之后面料直接发硬，腋下的走线没几天还开了个小口子，两百多块钱的东西质量做成这样真的不值，完全对不起耐克这个牌子的定价，大家别踩坑。"},{"nickname":"大刘","rating":1,"content":"拿到手就感觉不对，面料薄得像一层纱窗，我身高173选的M码，衣长短得离谱，稍微抬个胳膊整个后腰都露出来了。跑了两次领口直接变形垮得不行，松松垮垮的贴在脖子上，跑起来磨得后颈疼，两百多买了个一次性的感觉，还不如楼下三十块钱的T恤耐穿，绝对是我近几年买过最亏的运动T恤。"},{"nickname":"小远","rating":5,"content":"穿去跑半马的，全程21公里下来后背居然没怎么湿乎乎的，出汗之后很快就散掉了，全程都很干爽。面料轻得像没穿一样，摆臂的时候腋下一点都不卡，风一吹还凉丝丝的特别舒服。洗了五六次了速干性能一点没降，洗完挂阳台十分钟差不多就半干了，第二天接着穿完全没问题，经常路跑的兄弟真的可以闭眼入。"},{"nickname":"阿哲","rating":3,"content":"整体感觉中规中矩吧，速干效果是还行，但是面料真的太薄了，穿白色的话稍微出点汗就透得能看见里面的内衣，出门跑步太尴尬了。而且领口的螺纹质量一般，穿了三次就有点松垮，两百多的价格这个表现感觉性价比不高，不如加点钱买同系列的高端款，要是对透的问题不在意的话日常穿倒是也能用。"},{"nickname":"小江","rating":2,"content":"期待挺高的结果有点失望，我正常175穿L码，结果这个L码比我之前买的耐克其他款紧好多，跑的时候腋下勒得慌，我之前跑10公里完全不会磨，这次穿这个直接磨出红印子。速干效果倒是还行，但是这个剪裁完全不适合我这种胳膊维度稍微大一点的，两百多块钱只能闲置了，只能说不太适合普通人日常高强度训练穿。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_021.json'),
    ('p_clothes_022', 'adidas Originals 三叶草 男子连帽卫衣 经典logo套头上衣', '阿迪达斯', '服饰运动', '卫衣', '服饰运动/卫衣', 459.0, 459.0, 479.0, 600, '3_服饰运动/images/p_clothes_022_live.jpg', '{"product_id":"p_clothes_022","title":"adidas Originals 三叶草 男子连帽卫衣 经典logo套头上衣","brand":"阿迪达斯","category":"服饰运动","sub_category":"卫衣","base_price":459.0,"image_path":"3_服饰运动/images/p_clothes_022_live.jpg","skus":[{"sku_id":"s_p_clothes_022_1","properties":{"尺码":"M码","颜色":"黑色","logo配色":"白logo"},"price":459.0},{"sku_id":"s_p_clothes_022_2","properties":{"尺码":"L码","颜色":"黑色","logo配色":"白logo"},"price":459.0},{"sku_id":"s_p_clothes_022_3","properties":{"尺码":"XL码","颜色":"黑色","logo配色":"白logo"},"price":459.0},{"sku_id":"s_p_clothes_022_4","properties":{"尺码":"M码","颜色":"藏蓝色","logo配色":"白logo"},"price":479.0},{"sku_id":"s_p_clothes_022_5","properties":{"尺码":"L码","颜色":"藏蓝色","logo配色":"白logo"},"price":479.0},{"sku_id":"s_p_clothes_022_6","properties":{"尺码":"XL码","颜色":"藏蓝色","logo配色":"白logo"},"price":479.0}],"rag_knowledge":{"marketing_description":"这款adidas Originals三叶草男款连帽套头卫衣，是街头潮流爱好者的刚需款，核心卖点就是胸口的经典三叶草白底刺绣logo，复古辨识度拉满不撞款。面料用的是320g重磅亲肤毛圈棉，不薄不透、贴身穿软乎乎的还不容易起球，连帽处的抽绳做了同色系加固设计，洗多少次都不会变形。不管是日常上课、通勤遛弯，还是约兄弟去球馆热身、周末逛潮展穿都适配。版型是偏宽松的落肩剪裁，微胖男生穿也能藏住小肚腩不显臃肿。选码建议日常穿常规码数选对应码数就行，喜欢oversize风可以拍大一码，注意不要用热水长时间浸泡，反面翻过来洗能最大程度保护logo不会脱落。","official_faq":[{"question":"这款不同颜色尺码的卫衣价格不一样吗？","answer":"咱们这款卫衣目前在售的SKU里，M码和L码的黑色款配白色三叶草logo，日常售价是459元；XL码的藏蓝色款配白色三叶草logo，售价是479元哦。定价差异是因为藏蓝色批次的面料做了轻微的磨毛升级，抗起球效果比普通黑色款更好，大码的面料用料也更充足，大家可以根据自己平时的穿衣尺码和喜欢的颜色来选，库存实时更新，遇到喜欢的款没货可以等后续补货通知。"},{"question":"胸口的三叶草白logo会不会洗几次就开裂掉皮？","answer":"这点大家完全不用担心，咱们这款的白logo不是胶印工艺，是高密度的棉质刺绣，针脚密实整齐没有多余的线头，正常机洗或者手洗都不会出现开裂、掉皮的情况。只要你洗的时候不要用硬毛刷直接对着logo位置使劲刷，尽量把卫衣反面翻过来丢洗衣袋里洗涤，哪怕穿一整个冬天logo的白颜色也不会发黄发暗，刺绣边缘也不会脱线，能保持和刚买的时候一样的完整度。"},{"question":"这款连帽卫衣的落肩版型，偏胖的男生穿会不会紧绷？","answer":"咱们这款做的是专为亚洲男士身形调整的宽松落肩版型，不是那种欧美版偏窄的剪裁，肩线做了外移2cm的处理，哪怕是肩宽偏宽、有小肚腩的男生穿也不会有紧绷勒身的感觉。M码适合170-175cm、体重120-140斤的男士，L码适合175-180cm、体重140-160斤的男士，XL码藏蓝款适合180-185cm、体重160-180斤的男士，大家对照自己的身高体重选就好，想要更松弛的效果也可以选比平时穿的码数大半码到一码。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"上周刚收到这件黑色L码的，上身太惊喜了！面料是那种厚实质感的毛圈棉，现在十几度的天气单穿刚好，不冷也不闷汗，胸口的三叶草刺绣摸上去凸凸的特别有质感，完全不是廉价胶印的感觉。我178cm150斤，穿L码宽松度刚好，搭运动裤牛仔裤都好看，昨天出门搭工装裤被好几个朋友问链接，洗了一次也没掉色没变形，这个价位买三叶草正品真的太值了。"},{"nickname":"小宇","rating":3,"content":"我选的XL码藏蓝色款，本来冲着升级面料买的，结果穿了三天发现袖口的螺纹处有点起小毛球，我也没穿去干粗活啊就是日常通勤穿。而且我平时一直穿阿迪的XL码，这件穿上身感觉比我之前买的同码卫衣短了个两三厘米，盖不住腰，抬手的时候有点露肚子。价格比黑色款贵20块，但实际体验感觉差别不大，有点小失望，希望品控后续能更严格点吧。"},{"nickname":"阿泽","rating":5,"content":"给男朋友买的M码黑色款当生日礼物，他收到开心得不行！他平时就爱收集三叶草的经典款，这件的白logo配黑底色巨百搭，他这周几乎天天穿，上课、打球热身都套身上。面料摸上去软乎乎的，连帽的抽绳做工都很扎实，领口的包边也整齐，完全没有多余的线头，洗了好几次领口也没垮掉，他说比之前买的其他潮牌卫衣耐穿多了，性价比真的很高。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_022.json'),
    ('p_clothes_023', '优衣库 男装 DRY 速干运动短裤 轻薄透气训练裤', '优衣库', '服饰运动', '运动短裤', '服饰运动/运动短裤', 149.0, 149.0, 159.0, 900, '3_服饰运动/images/p_clothes_023_live.jpg', '{"product_id":"p_clothes_023","title":"优衣库 男装 DRY 速干运动短裤 轻薄透气训练裤","brand":"优衣库","category":"服饰运动","sub_category":"运动短裤","base_price":149.0,"image_path":"3_服饰运动/images/p_clothes_023_live.jpg","skus":[{"sku_id":"s_p_clothes_023_1","properties":{"尺码":"M码","颜色":"黑色"},"price":149.0},{"sku_id":"s_p_clothes_023_2","properties":{"尺码":"M码","颜色":"深灰色"},"price":149.0},{"sku_id":"s_p_clothes_023_3","properties":{"尺码":"M码","颜色":"藏蓝色"},"price":149.0},{"sku_id":"s_p_clothes_023_4","properties":{"尺码":"L码","颜色":"黑色"},"price":149.0},{"sku_id":"s_p_clothes_023_5","properties":{"尺码":"L码","颜色":"深灰色"},"price":149.0},{"sku_id":"s_p_clothes_023_6","properties":{"尺码":"L码","颜色":"藏蓝色"},"price":149.0},{"sku_id":"s_p_clothes_023_7","properties":{"尺码":"XL码","颜色":"黑色"},"price":159.0},{"sku_id":"s_p_clothes_023_8","properties":{"尺码":"XL码","颜色":"深灰色"},"price":159.0},{"sku_id":"s_p_clothes_023_9","properties":{"尺码":"XL码","颜色":"藏蓝色"},"price":159.0}],"rag_knowledge":{"marketing_description":"优衣库这款男士DRY速干运动短裤，采用品牌专属的高密透气速干面料，摸上去是薄而有韧劲的肌理感，完全不闷汗不贴腿，走步带风的轻薄感夏天穿特别舒服。核心卖点是运动后10分钟左右就能把表层汗气全散掉，不会像普通棉短裤那样湿乎乎贴在腰胯上难受。特别适合日常晨跑、健身房力量训练、室内篮球半场局穿，日常下楼取快递、遛弯买菜、居家当睡裤也完全合适。面料是经过抗起球预处理的，机洗不容易起毛边，洗完挂晾半小时差不多就能干透。使用建议选比平时穿的休闲裤大半个码更宽松，运动做大幅度踢腿动作也不会卡裆，注意不要和带尖锐装饰的牛仔裤同洗，避免勾丝，浅色款久穿轻微泛黄可以用中性洗衣液轻轻搓揉就能恢复，不用大力拧扯面料。","official_faq":[{"question":"这款优衣库DRY速干运动短裤的三个不同SKU码数对应的颜色定价不一样，尺码选择上有没有偏码的情况？","answer":"这款短裤的尺码是按照优衣库常规男装运动版型做的，不会偏码，M码黑色适合腰围76-84cm的身材，裤长大概在48cm，小个子男生穿也不会显腿短；L码深灰色适配腰围84-92cm的身材，日常做深蹲动作裤身余量很足；XL码藏蓝色调整了腰头的橡筋宽度，面料克重略微提升一点所以定价是159元，适合腰围92-100cm的微胖男生，跑跳的时候腰头也不会滑下来，大家按照自己平时穿优衣库运动裤的码数选就可以。"},{"question":"这款速干短裤的速干效果能支撑高强度的有氧训练吗？会不会运动完闷出异味？","answer":"完全可以支撑日常一小时左右的慢跑、动感单车这类高强度有氧训练，面料的纤维缝隙经过了DRY技术处理，汗液刚渗进面料就会快速被导到外层蒸发，不会在短裤内层留存，运动完坐半小时吹吹风基本就全干了，不会像普通棉短裤那样湿黏贴腿捂得腿根泛红。面料还添加了轻微的抑味助剂，大量出汗后短时间内也不会产生明显的汗酸味，不过要是长时间穿超过两天的话还是建议正常清洗，更符合卫生习惯。"},{"question":"这款运动短裤有没有做口袋设计，日常出门放手机钥匙会不会掉出来？","answer":"这款短裤两侧都做了加深的隐形斜插口袋，深度大概有18cm，装6.7英寸以内的大屏手机完全不会掉出来，口袋边缘还做了暗缝的包边处理，不会放重东西就扯得变形。后腰位置还藏了一个迷你的贴边小口袋，可以放公交卡或者家门钥匙，避免钥匙在侧袋晃来晃去硌腿。唯一要注意的是口袋没有做拉链，跑跳幅度特别大的高强度篮球运动时，还是建议不要把贵重物品放在侧袋里，避免动作太大滑出来。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"冲着优衣库的速干口碑买的M码黑色，整体穿着感倒是还行，轻薄是真的轻薄，但腰头的橡筋刚穿了三次就有点松垮，我平时腰围才78，蹲下来系个鞋带腰头就往下滑。而且口袋没有衬布，放硬壳手机的时候，边缘直接磨得大腿侧面有点发痒，149的价格这个质量感觉不算特别值，也不算完全不能穿，就是细节设计没跟上预期。"},{"nickname":"小宇","rating":5,"content":"上周健身房练腿特意穿的这条L码深灰色，太惊喜了！练完腿出了一身透汗，换衣服的时候短裤几乎没怎么湿，风一吹两分钟就凉丝丝的完全不粘腿，裤长刚好到大腿中部，做硬拉的时候也不会卡到大腿根磨得慌。之前买过别家速干裤闷得腿根起痱子，这个穿一下午都清爽，149的价格比我之前买的两三百的运动裤还好穿，已经给男朋友又囤了一条。"},{"nickname":"大张","rating":1,"content":"太坑人了，我拍的XL码藏蓝色花了159，刚收到洗了一次就发现裤脚边缘抽丝了，明明我就是用洗衣袋正常机洗的，连洗衣液都是用的温和的中性款。找客服说不属于质量问题不给退差价，159的价格连洗一次就坏，还不如路边几十块钱的运动短裤耐造，这质量完全配不上优衣库的品牌名气，以后再也不会买他家速干裤了。"},{"nickname":"阿泽","rating":5,"content":"夏天遛弯和夜跑全靠这条短裤，太舒服了！M码黑色我穿刚好，面料轻得像没穿一样，傍晚跑三公里出一身汗，停下来走两步短裤就全干了，坐共享单车座位上也不会湿乎乎的尴尬。侧袋放我的14Pro完全不晃，后腰小口袋放钥匙刚好，不会硌屁股，洗了快十次了一点都没起球变形，性价比真的拉满，已经推荐给跑团的好几个兄弟了。"},{"nickname":"阿明","rating":1,"content":"买的L码深灰色，我正常穿优衣库的运动裤都是L码，这条穿上之后裤身特别紧绷，我178/75kg平时穿同品牌的运动裤活动自如，这条深蹲直接卡裆，抬腿就感觉裤边要崩开，面料也不是宣传的那种透气感，出点汗直接贴在大腿上闷得慌。找客服退换还说我选码没问题是我自己体型的问题，这售后态度真的太差了，完全不推荐买。"},{"nickname":"小豪","rating":5,"content":"买的XL码藏蓝色给我185的胖哥哥穿，他平时买运动裤总卡裆磨腿，这条穿上居然特别宽松舒服，面料是那种滑溜溜的速干质感，他最近天天穿去打羽毛球，出一身汗也没闷出红疙瘩，之前穿棉短裤每次打完球腿根都磨红。159的价格能买到这么合适的大码速干裤真的太难得，腰头橡筋弹力很大，肚子上有肉也不会勒得慌，性价比超高。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_023.json'),
    ('p_clothes_024', 'The North Face Horizon 轻量速干运动鸭舌帽防晒透气户外遮阳帽', '北面', '服饰运动', '帽子', '服饰运动/帽子', 199.0, 199.0, 199.0, 500, '3_服饰运动/images/p_clothes_024_live.jpg', '{"product_id":"p_clothes_024","title":"The North Face Horizon 轻量速干运动鸭舌帽防晒透气户外遮阳帽","brand":"北面","category":"服饰运动","sub_category":"帽子","base_price":199.0,"image_path":"3_服饰运动/images/p_clothes_024_live.jpg","skus":[{"sku_id":"s_p_clothes_024_1","properties":{"尺码":"均码","帽围调节方式":"可调节","颜色":"经典黑"},"price":199.0},{"sku_id":"s_p_clothes_024_2","properties":{"尺码":"均码","帽围调节方式":"可调节","颜色":"米白色"},"price":199.0},{"sku_id":"s_p_clothes_024_3","properties":{"尺码":"均码","帽围调节方式":"可调节","颜色":"藏青色"},"price":199.0},{"sku_id":"s_p_clothes_024_4","properties":{"尺码":"均码","帽围调节方式":"可调节","颜色":"浅灰色"},"price":199.0},{"sku_id":"s_p_clothes_024_5","properties":{"尺码":"均码","帽围调节方式":"可调节","颜色":"森林绿"},"price":199.0}],"rag_knowledge":{"marketing_description":"这款北面Horizon系列轻量速干运动鸭舌帽，专门为户外出行和日常运动打造，帽身采用北面专属的速干针织面料，整体重量不到80g，上头顶着几乎没负担。面料自带细密透气网眼结构，长时间佩戴也不会闷出满头汗，还自带UPF50+的防晒力，能挡住大部分正午直射的紫外线，避免脸侧和后颈被晒红。后脑勺是可调节的魔术贴设计，不管头围54cm到61cm的男女都能调到最贴合的松紧度，不会跑跳两下就掉。不管是周末徒步登山、日常夜跑晨练、通勤骑车买咖啡，还是去海边露营逛景点都能用。平时戴完随手塞包里也不占地方，脏了直接冷水手洗阴干就行，别用热水泡也别扔烘干机烘，不然会破坏速干面料的防晒涂层。","official_faq":[{"question":"这款北面Horizon鸭舌帽的速干面料具体是什么材质，洗多了会不会失去速干效果？","answer":"这款帽子的帽身主体采用的是78%聚酯纤维+22%氨纶混纺的定向导速干面料，出厂前就做了长效的拒水导汗涂层处理，正常手洗20次以内基本不会影响速干性能。要注意别用含漂白剂的洗衣液浸泡，也不要用高温烘干机烘干或者长时间放在太阳下暴晒，不然会破坏面料表面的导汗涂层，后续汗渍就容易残留在面料上干得变慢，日常清洗后挂在通风阴凉处阴干就可以很好地保留速干属性。"},{"question":"这款可调节的北面鸭舌帽，最大可以适配多少厘米的头围，戴久了魔术贴会不会起毛勾头发？","answer":"这款均码可调节款的适配头围范围是54cm到61cm，大部分成年男性和女性的常规头围都能覆盖到，头围偏大的用户把魔术贴调到最外侧的档位也能贴合不勒头。它的魔术贴用的是北面定制的软勾面，不是普通硬塑料勾面，正常使用半年以内不会大面积起毛，佩戴或者摘戴的时候稍微注意点，顺着头型的方向摘，基本不会勾扯到头发。要是日常不小心勾到起了小毛，用小剪刀轻轻剪掉浮毛就可以正常继续用。"},{"question":"这款帽子的防晒性能是真实的吗，长时间在户外待着后帽檐会不会变软塌下垂？","answer":"这款帽子的防晒等级达到了国家UPF50+的标准，经过专业纺织检测机构认证，能够阻隔98%以上的UVA和UVB紫外线，日常在户外待4到6个小时也能有效防护脸侧和额头不被晒伤。帽檐内部嵌入了定制的薄型PP支撑骨，正常使用情况下不容易变软塌，哪怕是淋了小雨或者出了汗浸湿帽檐，晾干之后也能快速恢复原本的挺括造型，只要不用力反复对折帽檐，基本不会出现长期下垂变形的情况。"},{"question":"我平时戴眼镜，戴这款鸭舌帽的时候会不会帽檐卡眼镜腿，侧面会不会漏阳光晒到太阳穴？","answer":"这款帽子的帽身侧边做了向内收的弧度剪裁，刚好给戴眼镜的用户留出了眼镜腿的佩戴空隙，正常佩戴的时候不会出现帽檐边卡着眼镜腿把眼镜往上顶的情况。帽檐的横向延伸宽度做到了12cm，比普通运动鸭舌帽宽出1.5cm左右，正常调整好帽子的佩戴角度，基本能把太阳穴位置完全遮住，日常跑步或者快走的时候哪怕有侧方的阳光，也不容易直接晒到太阳穴的皮肤，不用额外反复调整帽子的位置。"},{"question":"这款轻量的鸭舌帽可以折叠塞进冲锋衣的衣兜里吗，折叠之后会不会留下很难消的死褶？","answer":"这款帽子整体重量不到80g，帽身没有硬支撑结构，是可以随意折叠的，折叠之后的体积差不多和手掌心差不多大，完全能轻松塞进常规冲锋衣的侧兜或者牛仔裤口袋里，出门通勤或者户外徒步不想戴的时候随手塞进去非常方便。它用的速干面料自带抗皱属性，正常折叠放几个小时拿出来之后，抖两下或者轻轻拍一拍，大部分褶皱都会自然散开，几乎不会留下很难平复的死褶，要是有小部分残留的褶皱，用手顺着面料捋两下就能恢复平整。"},{"question":"运动出汗多的时候戴这款帽子，会不会头前额的汗直接顺着帽檐流到眼睛里？","answer":"这款帽子在内侧额头接触的位置，专门加了一层1cm宽的吸汗亲肤条，是用高密度的毛圈面料做的，能快速吸附前额流下来的汗水，短时间大量出汗的时候也不会直接让汗顺着帽檐往下淌。它的导汗设计是把额头的汗水往帽子两侧的面料里导，通过侧面的透气网眼快速散出去，正常日常慢跑或者中等强度的徒步运动，基本不会出现汗水流进眼睛的情况，要是做马拉松这类长时间高强度的运动，建议每隔1个小时左右稍微把帽子摘下来透透气，能进一步提升佩戴的舒适感。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"整体其实还算过得去，就是戴了大概半个月之后发现后脑勺的魔术贴位置边缘开始起小毛絮，有时候摘帽子还会勾住几根头发，体验有点糟。我头围是59cm，调到最紧的档位跑起来还是有点点晃，不是特别贴合。而且我上次洗了一次之后，帽子正面北面的小logo边缘居然有点轻微脱胶，虽然不仔细看看不出来，但两百块的帽子这个品控确实有点不太符合预期，只能说勉强能用，算不上特别值这个价。"},{"nickname":"小夏","rating":3,"content":"本来冲着速干的卖点买的，上周去徒步出了超多汗，帽子内侧是干得挺快的，但是帽檐位置淋了点小雨之后居然软塌了，半天都挺不起来，低头的时候帽檐直接垂下来挡视线，我走山路的时候好几次都看不清脚下的台阶，特别麻烦。而且我戴了两天之后发现，耳朵上方的位置面料有点硬，蹭得耳后皮肤有点发红发痒，可能是我肤质比较敏感？这个佩戴舒适度确实没达到我的预期，只能给个中差评。"},{"nickname":"阿泽","rating":5,"content":"这款帽子真的是我今年买到最满意的运动配饰了！上周连续三天去溯溪爬山，全程大太阳晒着，戴它跑跳全程稳得一批，速干面料出了汗十分钟就全干了，头上一点都不闷，之前戴别的帽子半天就闷得满头痘，这次完全没长痘。帽檐的防晒力也绝，我待在户外大半天，额头脸侧一点都没晒黑，魔术贴调松紧特别方便，我头围57cm调完特别贴合，平时通勤骑车也戴着，塞包里完全不占地方，两百块能买到北面这么实用的帽子真的太值了，已经推荐给一起徒步的朋友了。"},{"nickname":"大宇","rating":1,"content":"我收到货拆开就发现帽子的帽檐是歪的，左右两边不对称，一边高一边低，戴上去特别奇怪，正面看帽檐往左边歪得很明显，完全没法正常戴。找客服说退换，还让我自己出寄回去的运费，折腾了快一周才处理完。重新寄过来的货味道特别大，放在阳台晾了三天还是有刺鼻的化工味，洗了一次之后速干的面料摸起来硬邦邦的，logo直接掉了一半，两百块买了个残次品，真的太失望了，以后再也不想在这家买北面的东西了。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_024.json'),
    ('p_clothes_025', 'Osprey DAYLITE PLUS 日光+ 20L 户外多功能双肩背包轻量通勤包', 'Osprey', '服饰运动', '背包', '服饰运动/背包', 699.0, 699.0, 699.0, 400, '3_服饰运动/images/p_clothes_025_live.jpg', '{"product_id":"p_clothes_025","title":"Osprey DAYLITE PLUS 日光+ 20L 户外多功能双肩背包轻量通勤包","brand":"Osprey","category":"服饰运动","sub_category":"背包","base_price":699.0,"image_path":"3_服饰运动/images/p_clothes_025_live.jpg","skus":[{"sku_id":"s_p_clothes_025_1","properties":{"容量":"20L","版本":"通用款","颜色":"黑色"},"price":699.0},{"sku_id":"s_p_clothes_025_2","properties":{"容量":"20L","版本":"通用款","颜色":"都市蓝"},"price":699.0},{"sku_id":"s_p_clothes_025_3","properties":{"容量":"20L","版本":"通用款","颜色":"星尘灰"},"price":699.0},{"sku_id":"s_p_clothes_025_4","properties":{"容量":"20L","版本":"通用款","颜色":"户外绿"},"price":699.0}],"rag_knowledge":{"marketing_description":"这款Osprey日光+20L双肩包绝对是轻量出行的刚需款，主身用的是高密度防泼水面料，整包自重才不到0.7kg，背久了也不会压肩。核心卖点就是兼顾户外徒步和日常通勤双场景适配，正面带快取仓可以直接塞公交卡和口罩，侧面弹力网兜能插下500ml水杯和折叠遮阳伞，主仓内层有专门的15.6寸电脑隔层，分区特别清晰。不管是周末单日近郊徒步的驴友，还是每天挤地铁的通勤族、出门逛展的学生党都能用。平时背的时候尽量别装超过10kg的重物，不要长时间泡在水里，虽然防泼溅但大雨里还是建议套个防雨罩，能用好多年都不变形。","official_faq":[{"question":"这款20L的日光+背包能不能放下常规的15.6寸游戏本啊？","answer":"完全可以的，我们专门在主仓靠后背的位置做了加厚绒垫的独立电脑隔层，最大适配尺寸就是15.6寸的常规游戏本，哪怕是带厚原厂电源适配器，也能塞在隔层旁边的副收纳区。不过要注意如果是特别厚的17寸大游戏本就塞不下了，放电脑的时候建议先套个内胆包，避免和隔层里的魔术贴勾到刮花机身，日常通勤取放电脑过安检也特别顺手。"},{"question":"这款背包的肩带会不会太薄，装多点东西就勒肩膀啊？","answer":"完全不会勒，这款日光+的肩带是用的Osprey专门调校的镂空透气软垫，厚度有1.2cm，表面是速干网布，夏天背也不会闷汗，哪怕你装个电脑加几瓶水再带点徒步装备，重量也会均匀分摊到整个肩带接触面，不会像薄肩带那样勒出红印。不过我们还是建议总承重别超过7kg，毕竟它主打轻量出行，装太重反而浪费了它本身轻量化的设计优势，也会缩短肩带的使用寿命。"},{"question":"这款背包的防泼水性到底怎么样，下小雨的时候需要特意套防雨罩吗？","answer":"它的面料本身做了DWR防泼水处理，日常突遇的小雨、路上的洒水车溅水、不小心泼到的矿泉水，落到包面上都会直接凝成水珠滑走，短时间走十几分钟不用怕里面的东西湿。但要是遇到持续的中大雨或者长时间在雨里走，包的缝线处和拉链缝隙还是会慢慢渗进水，这种情况就建议用我们随包附赠的收纳式防雨罩，直接整个包套住就能完全防水，别直接把包泡进水里就行，毕竟它不是专业溯溪背包。"},{"question":"这款背包能不能折叠收纳塞进自己的随身行李箱里当备用小包啊？","answer":"当然可以，这款的面料是高弹抗皱的尼龙材质，没有硬支撑骨架，你可以直接把它从下往上卷起来，塞进正面的小快取仓里，折完之后也就一个手掌大小，重量还不到700g，出差旅游放行李箱里完全不占地方，走到哪想临时出门逛景点、买东西拿它特别方便。不过折叠的时候别硬扯拉链，也别长时间长期压着折叠，不然面料上会留折痕，摊开放一两天就能自己恢复平整，不影响使用。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"通勤背了快半个月真的太香了！以前的旧包塞个15寸电脑就沉得要死，这个Osprey日光+自重特别轻，肩带的网布夏天背也不闷汗，正面的小仓塞口罩门禁卡随手就能掏，不用翻主包找半天。昨天周末背去近郊走徒步路线，侧兜塞水杯和登山杖也稳当，防泼溅面料碰到点小雨点直接滑走，分区做的太对胃口了，两百多花的特别值，身边好几个同事都被我种草了。"},{"nickname":"小夏","rating":1,"content":"特别失望，我收到包的第二天背去挤地铁，肩带靠近卡扣的位置居然开线了，我包里就装了个电脑加一把伞总重都不到5kg，这质量完全配不上这个价位。找客服售后还拖了三天才回复，说我是人为拉扯的不给换，只能自己找裁缝店缝，花快七百买的包刚背就出这种问题，品控也太拉胯了，完全不值这个价，以后再也不会随便买这个牌子的日常款背包了。"},{"nickname":"阿泽","rating":2,"content":"用了一周实在说不上好，那个正面的快取仓做的特别浅，我放个大一点的手机直接露半截出来，走路的时候晃来晃去特别怕掉。而且后背的软垫太薄了，我背硬壳的电脑包没有垫内胆，走久了后背直接被电脑硌得慌，699的价格连个最基础的胸扣都没有，背包装稍微重点就往下坠，压得肩膀特别酸，跟之前买的同价位其他牌子背包比差远了，感觉性价比很低。"},{"nickname":"小晚","rating":2,"content":"这个包的面料特别容易勾丝，我第一次背去户外徒步，路过灌木丛刮了一下侧面就勾出好几个丝，扯也不敢扯拉也拉不平，好好的新包直接变旧包。而且它的拉链特别紧，主仓的拉链每次拉开都要费好大劲，戴着手套户外用的时候根本拉不动，随包说送的防雨罩我找了半天都没找到藏在哪，问客服才说要自己掏侧边的暗兜拿，设计特别反人类，用起来处处都是小麻烦。"},{"nickname":"大刘","rating":2,"content":"本来冲着Osprey的品牌买的通勤包，实际用下来特别不满意，20L的容量看着大实际特别不实用，我想塞个14寸电脑再加个午饭便当盒就塞不下了，分区的隔层做的特别窄，连个A4大小的文件夹塞进去都露个角折边。而且包的底部没有硬支撑，装了东西直接软塌塌堆在地上，根本站不住，放工位底下特别容易倒，这个价格买个能站得住的通勤包不好吗，感觉完全是买了个户外噱头的包。"},{"nickname":"阿柚","rating":5,"content":"太喜欢这个小背包了！我平时既要上下班通勤，周末还要去爬城市周边的小山，之前一直找不到兼顾两种场景的包，这个日光+20L刚好完美适配，自重轻得跟没背东西一样，背一整天肩膀都不酸，电脑隔层的绒垫特别软，我的游戏本放进去完全不会晃。折叠起来塞行李箱里带去旅游也特别方便，逛景点背它装水装防晒刚好，细节设计全在刚需点上，用了三个月越用越顺手。"}]}}'::jsonb, '3_服饰运动/data/p_clothes_025.json'),
    ('p_food_001', '三顿半 数字星球系列 超即溶精品咖啡1-6号 18颗装精品速溶咖啡', '三顿半', '食品饮料', '咖啡', '食品饮料/咖啡', 138.0, 128.0, 258.0, 1400, '4_食品生活/images/p_food_001_live.jpg', '{"product_id":"p_food_001","title":"三顿半 数字星球系列 超即溶精品咖啡1-6号 18颗装精品速溶咖啡","brand":"三顿半","category":"食品饮料","sub_category":"咖啡","base_price":138.0,"image_path":"4_食品生活/images/p_food_001_live.jpg","skus":[{"sku_id":"s_p_food_001_1","properties":{"口味":"1号","数量":"18颗","包装":"礼盒装"},"price":128.0},{"sku_id":"s_p_food_001_2","properties":{"口味":"2号","数量":"18颗","包装":"礼盒装"},"price":128.0},{"sku_id":"s_p_food_001_3","properties":{"口味":"3号","数量":"18颗","包装":"礼盒装"},"price":128.0},{"sku_id":"s_p_food_001_4","properties":{"口味":"4号","数量":"18颗","包装":"礼盒装"},"price":128.0},{"sku_id":"s_p_food_001_5","properties":{"口味":"5号","数量":"18颗","包装":"礼盒装"},"price":128.0},{"sku_id":"s_p_food_001_6","properties":{"口味":"6号","数量":"18颗","包装":"礼盒装"},"price":128.0},{"sku_id":"s_p_food_001_7","properties":{"口味":"1-6号混合","数量":"18颗","包装":"礼盒装"},"price":138.0},{"sku_id":"s_p_food_001_8","properties":{"口味":"1号","数量":"36颗","包装":"加大装"},"price":238.0},{"sku_id":"s_p_food_001_9","properties":{"口味":"2号","数量":"36颗","包装":"加大装"},"price":238.0},{"sku_id":"s_p_food_001_10","properties":{"口味":"3号","数量":"36颗","包装":"加大装"},"price":238.0},{"sku_id":"s_p_food_001_11","properties":{"口味":"4号","数量":"36颗","包装":"加大装"},"price":238.0},{"sku_id":"s_p_food_001_12","properties":{"口味":"5号","数量":"36颗","包装":"加大装"},"price":238.0},{"sku_id":"s_p_food_001_13","properties":{"口味":"6号","数量":"36颗","包装":"加大装"},"price":238.0},{"sku_id":"s_p_food_001_14","properties":{"口味":"1-6号混合","数量":"36颗","包装":"加大装"},"price":258.0}],"rag_knowledge":{"marketing_description":"三顿半数字星球系列的超即溶咖啡，把6种不同烘焙度的精品咖啡装进迷你小杯，从浅烘带柑橘花香的1号，到深烘有可可焦香的6号，不用专业器具也能一秒冲出门店级口感。选用100%阿拉比卡精品豆，通过低温冻干锁留住豆子原有的风味，没有额外添加糖和植脂末。不管是早八赶时间的上班族、需要提神的学生党，还是爱尝不同风味的咖啡爱好者都适配：早上配冰牛奶做拿铁，下午兑气泡水做特调，出门塞两小杯在包里完全不占地方。建议开封后3天内喝完风味最佳，平时放在阴凉干燥处避光保存，别放在冰箱容易受潮影响溶解速度。","official_faq":[{"question":"数字星球1-6号的风味差别具体是什么，怎么选适合自己的款？","answer":"1号是浅度烘焙，主打明亮的柑橘、白花风味，酸质清爽；2号中浅烘，有坚果和焦糖的柔和香气，酸感更低；3号中烘，平衡度很好，带点蜂蜜甜感；4号中深烘，有烘焙榛果和黑巧的醇厚感；5号深度烘，焦香明显带点炭烧余韵；6号是超深烘，苦味突出带烟熏感。新手想尝鲜可以直接入18颗装礼盒，各拿3颗慢慢试，喜欢喝奶咖推荐2-4号，喜欢清咖推荐1、5、6号，都能适配不同冲泡方式。"},{"question":"这款超即溶咖啡除了冲热水，还能做哪些不同的饮品？","answer":"它的冻干粉冷热水都能秒溶完全不结块，玩法特别多：怕苦的可以直接倒进冰牛奶/燕麦奶里，晃两下就是丝滑拿铁，完全不用搅拌。想喝清爽款就倒气泡水加两片柠檬，秒出门店售价三十多的果味气泡美式。赶时间的时候直接倒进常温的矿泉水瓶里，塞包里摇两下出门路上就能喝。甚至还可以挖一小勺撒在冰淇淋上，做成阿芙佳朵的简易版，风味层次比普通速溶好太多，完全不会有粉感残留。"},{"question":"18颗装和36颗加大装的风味配比是一样的吗，会不会有重复款？","answer":"两款的风味配比逻辑是统一的，都是1-6号各占对应数量，18颗装是每个数字款各3颗，刚好覆盖全风味线，适合第一次尝试想摸底风味的用户，或者平时每天喝1杯的人喝半个多月。36颗加大装是每个数字款各6颗，没有额外的特殊隐藏款风味，适合已经试过数字星球系列，确定自己喜欢多尝不同风味、不想单款大量囤的老用户，性价比也比单买两盒18颗装更高，算下来单颗价格省了差不多3毛多。"},{"question":"这款咖啡的冻干小杯是可回收的吗，有什么环保处理的方式？","answer":"数字星球系列的小杯外壳是食品级PP材质，喝完之后把内部残留的咖啡粉冲干净，撕掉顶部的铝箔片就可以投入可回收物桶。三顿半官方也有推出「返航计划」活动，大家攒够空杯之后可以在每年固定的返航日带到线下指定站点，兑换新的咖啡周边或者限定风味的试饮装，攒的空杯数量多还能换限定的咖啡器具。小杯也可以自己DIY改造成桌面收纳盒，放回形针、小耳钉这类小零碎特别合适，不用浪费直接扔掉。"},{"question":"如果开封之后没喝完，咖啡粉受潮结块了还能正常喝吗？","answer":"如果只是轻微受潮、没有出现霉变或者哈喇味，冲热水完全溶解之后是可以正常饮用的，只是原本的明亮风味会流失一部分，香气会比全新开封的淡很多，不会有食品安全问题。但如果结块特别硬，打开之后闻到霉味或者油脂氧化的油耗味，就不建议喝了，说明咖啡粉已经变质。平时大家收到货之后，一定要把整盒放在阴凉避光的干燥区域存放，不要放在厨房灶台边、窗边这类容易受潮晒到的位置，每颗小杯都是独立密封的，没开封的情况下保质期是12个月。"}],"user_reviews":[{"nickname":"小柚","rating":2,"content":"之前刷到很多人推荐才下单的，收到之后拆了两颗试，浅烘的1号酸味特别尖锐，我平时喝惯了普通速溶根本接受不了，而且18颗装价格快一百四，算下来一颗快八块钱，性价比真的太低了。冲完之后杯底还留了点细细的粉渣，不知道是不是我冲的方式不对，完全没喝到宣传里说的柑橘香，整体感觉不值这个价，剩下的大半盒估计要闲置了。"},{"nickname":"阿野","rating":5,"content":"真的是挖到宝了！之前买过别家的速溶总觉得有股焦苦味，这款1号冲冰水都能完全化开，加两片橙子兑气泡水喝，完全就是咖啡店卖的手冲级别的果味美式，一点都没廉价速溶的粉感。18颗装的小礼盒摆在家里的咖啡角特别好看，出差的时候塞两颗在包里也不占地方，最近天天早上用2号兑热燕麦奶，醒神又好喝，已经回购36颗的加大装了。"},{"nickname":"小棠","rating":4,"content":"整体喝着还是不错的，不同号的风味区分度确实挺明显，深烘的6号做冰拿铁香气特别足，我这种喝不了太酸的人也能接受。就是价格对我这种天天要喝咖啡的人来说还是有点小贵，36颗的虽然性价比高点但喝得快。还有就是小盖子打开的时候有时候会沾一点咖啡粉在边缘，洒得桌子上都是，要是能把密封设计再优化下就更完美了，整体还是推荐喜欢尝鲜的人试试。"},{"nickname":"阿凯","rating":1,"content":"这次收到的货不知道是不是放太久了，拆了三颗有两颗的小杯里面的粉都结硬块了，冲开之后有一股奇怪的油耗味，喝了一口直接反胃。找客服说我存放不当，可我明明刚收到就拆了，盒子上的保质期标着还有大半年才到期，体验感特别差，花一百多买的大半盒根本不敢喝，以后不会再买这个系列了。"},{"nickname":"粒粒","rating":3,"content":"本来是冲着颜值买的，包装确实特别好看，摆在桌面上像小星球似的。但实际喝下来感觉风味没宣传的那么惊艳，浅烘的几款酸得太突兀，深烘的又有股糊味，还不如我常买的三十多块钱一大罐的冻干咖啡口感顺滑。一百多18颗的价格实在是溢价有点高，喝个新鲜还行，不会长期复购，觉得更像卖包装的网红产品。"}]}}'::jsonb, '4_食品生活/data/p_food_001.json'),
    ('p_food_002', '雀巢咖啡 1+2原味 三合一速溶咖啡粉100条装即冲奶香咖啡饮品', '雀巢', '食品饮料', '咖啡', '食品饮料/咖啡', 60.0, 30.0, 68.0, 400, '4_食品生活/images/p_food_002_live.jpg', '{"product_id":"p_food_002","title":"雀巢咖啡 1+2原味 三合一速溶咖啡粉100条装即冲奶香咖啡饮品","brand":"雀巢","category":"食品饮料","sub_category":"咖啡","base_price":60.0,"image_path":"4_食品生活/images/p_food_002_live.jpg","skus":[{"sku_id":"s_p_food_002_1","properties":{"单条净含量":"13g","内含条数":"100条","包装类型":"家庭装"},"price":60.0},{"sku_id":"s_p_food_002_2","properties":{"单条净含量":"13g","内含条数":"50条","包装类型":"小包装"},"price":35.0},{"sku_id":"s_p_food_002_3","properties":{"单条净含量":"13g","内含条数":"50条","包装类型":"家庭装"},"price":30.0},{"sku_id":"s_p_food_002_4","properties":{"单条净含量":"13g","内含条数":"100条","包装类型":"小包装"},"price":68.0}],"rag_knowledge":{"marketing_description":"这款雀巢1+2原味三合一速溶咖啡，是很多老粉喝了十几年的经典款！每一条精准配比了阿拉比卡咖啡粉、进口奶源和白砂糖，冲开就是入口丝滑的奶香咖啡味，完全没有焦苦感，不用额外加奶加糖超省心。不管是朝九晚五的打工人早八醒神、学生党熬夜赶作业，还是朋友小聚想快速调出一杯暖饮，撕开包装用150ml左右的85℃热水冲开搅两下就搞定，3秒就能出杯。咱们有两个规格可选：50条小包装适合独居上班族尝鲜，100条家庭装性价比更高，放办公室茶水间、家里储物柜都合适。注意开袋后要马上冲饮，没喝完的整条要放在阴凉干燥处避光保存，别放冰箱容易受潮结块哦。","official_faq":[{"question":"这款1+2原味速溶咖啡的具体配比是什么，会不会太甜？","answer":"咱们这款雀巢1+2原味是严格按照多年经典配方调配的，每13g小条里包含约1.8g深度烘焙阿拉比卡+罗布斯塔拼配咖啡粉、约4g植脂末和约7g白砂糖，剩下的是其他合规食品添加剂。整体甜度是大众接受度最高的黄金比例，苦度极低，奶香盖过大部分焦苦味，大部分用户反馈是刚好的甜度，如果怕甜的话也可以多加20-30ml热水稀释，或者加半盒纯牛奶调成拿铁风味也完全不违和。"},{"question":"13g的小条包装一次冲多少水口感最好？可以加冰喝吗？","answer":"官方测试的最佳冲调比例是1条13g配150ml左右的80-90℃热水，冲出来的浓度刚好丝滑不寡淡，也不会太稠挂杯。完全可以做冰饮，先倒30ml左右的温水把咖啡粉搅到完全融化，再倒满冰块或者加120ml常温凉白开，摇两下就是冰奶香咖啡，夏天喝超爽。不建议直接用开水冲，容易让咖啡里的芳香气挥发掉，喝起来会有一点点焦糊的涩感，影响整体口感。"},{"question":"100条家庭装的包装是什么样的，容易受潮吗？","answer":"咱们100条的家庭装是采用外层加厚食品级纸盒+内部独立铝箔覆膜小条的包装，每一条小包装都做了密封阻氧处理，正常放在25℃以下的阴凉干燥处，不开封的情况下保质期内完全不会受潮。要是开封之后整条的纸盒，大家可以找个密封罐把剩下的小条装起来，别放在厨房灶台边或者卫生间这种潮湿的地方，哪怕剩下几十条放三个月也不会结块变味，独立小条也方便随手塞包里带出门。"},{"question":"这款咖啡和雀巢其他款的1+2咖啡有什么区别？","answer":"咱们这款经典原味是雀巢1+2系列里销量最高的基础款，奶香和甜味的占比最高，咖啡的苦感最低，适配绝大多数人的口味，不像特浓款咖啡粉占比高很多，入口会有明显的焦苦味，也不像奶香款加了更多奶粉甜味更淡。这款的定位就是大众适配的入门级速溶咖啡，不管是之前没怎么喝过咖啡的新手，还是喝了十几年雀巢老粉，都能喝到熟悉的经典味道，不会有任何踩雷的可能。"},{"question":"家里有孕妇或者小孩可以喝这款咖啡吗？","answer":"咱们这款每一条的咖啡因含量大概在15mg左右，远低于一杯现磨美式的100mg左右的含量，但还是不建议孕妇和12岁以下的小朋友饮用。孕期对咖啡因摄入有严格的标准限制，小朋友的神经也还没发育完全，喝咖啡容易出现心跳加快、失眠兴奋的情况。如果是普通的成年人日常用来提神，一天喝个2-3条完全没问题，不会出现摄入过量咖啡因心慌的情况，对咖啡不耐受的朋友可以先试半条看看自己的接受程度。"}],"user_reviews":[{"nickname":"阿泽","rating":4,"content":"整体还是熟悉的老味道，喝了好多年了，这次买的100条装价格也确实划算，办公室同事分着买的，拆开喝了大半都没问题。就是有三四条的边缘小包装压得有点皱，拆开的时候粉撒了一点在袋子外面，稍微有点小麻烦，其他都没毛病，味道和之前线下超市买的一模一样，冲出来奶香很浓，早八来一杯刚好醒神，下次有活动还会考虑回购的。"},{"nickname":"小棠","rating":5,"content":"太开心了！收到货整整两大袋不对，是整整一整盒100条，数了下真的一个不少，比我家楼下超市单买便宜快二十块！我本来就是雀巢原味的死忠粉，上学的时候就天天泡，现在上班每天早上到公司先冲一杯，奶香味特别足，完全不苦，我不爱喝苦咖啡的朋友上次来我家一口气连喝了两条。现在放工位抽屉里，摸鱼的时候来一杯，整个人都舒服多了，绝对是无限回购的款。"},{"nickname":"阿凯","rating":1,"content":"这次收到货真的太糟心了，快递盒子直接被压变形了，拆开之后里面有七八条咖啡的包装都破了，咖啡粉漏得一盒子都是，黏糊糊的根本没法要。找客服说只能给补五块钱的优惠券，我这漏了半袋的咖啡粉根本没法用，之前在别家买从来没出过这种问题。味道虽然还是熟悉的，但这个品控和快递包装真的太差了，不会再来买了，太影响体验了。"},{"nickname":"阿眠","rating":3,"content":"冲出来喝着感觉味道比之前在超市买的淡一点，我特意对比了下包装，好像版本不一样，同样放150ml水冲出来没有之前的浓，喝起来偏甜，奶香也淡了点。问客服说是新老配方随机发，我买的时候根本没提前说明，冲了两条感觉都不太对，剩下的现在放着没怎么动，说不上难喝但就是不是我熟悉的那个经典味，有点小失望，下次还是直接去超市买算了。"},{"nickname":"朵朵","rating":5,"content":"本来是买给我爸当生日礼物的，他喝这个雀巢原味喝了快二十年，家里从来没断过，这次买的100条装他特别开心，说够他喝小半年了。我跟着蹭了好几杯，冲的时候用热牛奶泡比用热水冲还香，早上配个面包当早餐超合适。独立小条揣包里出差带着也方便，上次我带去高铁上，接杯热水搅两下就好了，比高铁站卖的三十多一杯的咖啡好喝多了，性价比拉满。"}]}}'::jsonb, '4_食品生活/data/p_food_002.json'),
    ('p_food_003', '农夫山泉 东方树叶 无糖乌龙茶饮料500ml 瓶装茶饮低糖替代方案', '东方树叶', '食品饮料', '茶饮', '食品饮料/茶饮', 4.0, 4.0, 55.0, 200, '4_食品生活/images/p_food_003_live.jpg', '{"product_id":"p_food_003","title":"农夫山泉 东方树叶 无糖乌龙茶饮料500ml 瓶装茶饮低糖替代方案","brand":"东方树叶","category":"食品饮料","sub_category":"茶饮","base_price":4.0,"image_path":"4_食品生活/images/p_food_003_live.jpg","skus":[{"sku_id":"s_p_food_003_1","properties":{"容量":"500ml","包装":"单瓶装"},"price":4.0},{"sku_id":"s_p_food_003_2","properties":{"容量":"500ml","包装":"15瓶整箱"},"price":55.0}],"rag_knowledge":{"marketing_description":"喜欢纯茶味又怕甜腻的朋友看过来！东方树叶无糖乌龙茶是农夫山泉旗下火了十多年的经典款，整瓶完全不含额外添加糖，热量几乎为0，用的是真乌龙茶萃取液，没有多余香精勾兑，入口是炭火焙香的醇厚茶味，回甘清润不会发涩发苦。特别适合控糖人群、健身党、上班摸鱼想解腻的打工人，还有爱喝奶茶又怕长胖的姐妹当低糖替代。上班放工位摸鱼喝，吃重油重盐的外卖配它解腻解辣，出门健身塞包里随时补水解渴都合适。建议阴凉处存放，开封后尽量24小时内喝完，冰镇之后茶香味会更突出，注意未开封的状态下别放在阳光直晒的地方久放，避免风味流失哦。","official_faq":[{"question":"这款东方树叶无糖乌龙茶真的完全不含糖吗？配料表具体有什么？","answer":"这款500ml装的东方树叶无糖乌龙茶是完全零添加糖的，配料表非常干净，只有水、乌龙茶叶、维生素C、碳酸氢钠，没有额外添加白砂糖、果葡糖浆、甜味剂这类成分，整体热量不到1大卡，属于真正的无糖茶饮。怕甜怕胖的控糖人群、健身期朋友都可以放心喝，哪怕是平时戒糖的人，入口也只会喝到乌龙茶本身的自然焙香味道，完全不会有突兀的甜味。"},{"question":"整箱15瓶装的东方树叶乌龙茶发过来会不会有漏液、破损的情况？","answer":"咱们整箱500ml*15瓶的包装都做了两层防护，外层是加厚的快递专用瓦楞纸箱，内层瓶身之间还有定制的缓冲珍珠棉隔层固定，避免运输过程中瓶子互相碰撞挤压。正常快递运输过程中极少出现漏液破损的情况，如果大家收到货之后发现有瓶子漏液、瓶盖裂开变形、饮品变质的问题，只要在签收24小时内联系客服拍照反馈，我们会直接按破损的瓶数给你全额退款或者补发，完全不用你承担损失。"},{"question":"这款乌龙茶的茶味会不会特别浓涩？平时很少喝纯茶的人能适应吗？","answer":"这款东方树叶的乌龙茶萃取工艺做了专门的优化，是用恒温低温萃取技术提取的乌龙茶汤，去掉了普通劣质泡出来的浓茶会有的明显涩味和清苦味，入口是淡淡的炭火焙香，后调带一点乌龙茶本身的清甜回甘，茶味不会特别冲。平时很少喝纯茶的人第一次喝也不会觉得难接受，冰镇之后喝起来口感会更清爽，哪怕你之前习惯喝甜饮料，慢慢喝两次也能适应这种无负担的纯茶香气。"},{"question":"买整箱装的这款东方树叶乌龙茶保质期是多久？发的是不是临期产品？","answer":"咱们这款茶饮的未开封保质期是12个月，仓库发出的产品全部都是最近3个月内生产的新鲜批次，绝对不会发距离保质期不足1个月的临期产品，大家收到货可以直接看瓶身喷印的生产日期，清晰可查。如果有特殊需求想要指定新鲜生产批次的朋友，下单的时候可以备注，客服会尽量优先给你发最近两周刚生产的新货，囤货喝也完全不用担心很快过期的问题。"},{"question":"这款无糖乌龙茶和自己在家泡的乌龙茶有什么区别？茶底用的是什么品种的乌龙？","answer":"这款茶底用的是福建安溪的浓香型焙火乌龙，萃取的时候严格控制萃取时间和温度，不会析出过多的茶单宁导致喝着涩口，同时保留了乌龙本身的焙火香气，不用你自己洗茶、烧水、等冲泡，开瓶就能直接喝，非常方便。自己在家泡的乌龙茶浓度不好控制，放久了容易变涩，这款工业化标准化生产的每一瓶口感都完全一致，出门带也不怕漏的到处都是，适配各种出门的场景。"},{"question":"喝这款无糖乌龙茶会不会像喝浓咖啡一样晚上睡不着觉？咖啡因含量高吗？","answer":"这款500ml装的无糖乌龙茶整瓶的咖啡因含量大概在25mg到35mg之间，只有普通一杯美式咖啡的三分之一不到，含量非常温和，大部分人正常下午喝也不会影响晚上的睡眠，对咖啡因耐受度特别低的朋友，建议下午三点之后就尽量不要喝了，避免少数情况下出现轻微的神经兴奋情况。平时怕咖啡太猛睡不着、想补点咖啡因提精神的朋友选它也很合适，喝了不会有心慌手抖的不适感。"}],"user_reviews":[{"nickname":"阿柠","rating":5,"content":"我真的是东方树叶乌龙茶的死忠粉！之前健身之后不敢喝甜饮料，偶然买了一瓶喝直接爱上了，入口完全没有那种工业香精的怪味，就是很正的焙火乌龙香，回甘清润，吃火锅吃重油外卖的时候配它，解腻效果特别绝，500ml的瓶子揣包里大小刚好，上班放工位一下午喝一瓶也没啥负担，这次直接囤了整箱，算下来单瓶比超市便宜五毛，太划算了！"},{"nickname":"小夏","rating":2,"content":"这次收到的整箱货太让人无语了，打开之后发现有两瓶的瓶盖边缘不知道怎么被磕裂开了，虽然没完全漏光，但是瓶身湿乎乎的黏了好多灰，联系客服半天才回复，最后只给退了这两瓶的钱，没有任何补偿。而且这批货的日期虽然没临期，但已经是5个月前生产的了，我之前在超市买的都是1个月内新产的，喝起来总觉得这批的茶香味淡了一点，没有之前喝的香。"},{"nickname":"阿泽","rating":1,"content":"这次购物体验真的太差了，快递送过来的时候纸箱直接被泡湿了大半，打开之后里面至少有6瓶都漏了半瓶多，黏糊糊的整箱流的到处都是，地板都擦了半天。找客服反馈等了快一天才理我，说快递的问题不归他们管，推三阻四半天最后只同意退一半的钱，剩下的半箱漏了的根本没法放，搞的整个储物架都是黏的，以后再也不敢在网上买整箱的饮料了，太闹心。"},{"nickname":"小桃","rating":5,"content":"戒糖之后找了好久合适的茶饮，终于挖到这款宝藏了！完全没有奇怪的代糖苦味，一口下去就是纯纯的乌龙茶香气，冰镇之后喝特别清爽，我现在每天上班都带一瓶，之前下午总犯困，喝它提精神比喝甜奶茶健康多了，喝完嘴里也不会发腻发齁，15瓶整箱的算下来单瓶还不到4块钱，比楼下便利店卖的便宜好多，已经回购第三次了，太适合我们这种控糖的打工人了！"}]}}'::jsonb, '4_食品生活/data/p_food_003.json'),
    ('p_food_004', '元气森林 0糖0脂0卡 白桃味气泡水480ml 碳酸饮料即饮苏打型饮品', '元气森林', '食品饮料', '碳酸饮料', '食品饮料/碳酸饮料', 4.5, 4.5, 65.0, 200, '4_食品生活/images/p_food_004_live.jpg', '{"product_id":"p_food_004","title":"元气森林 0糖0脂0卡 白桃味气泡水480ml 碳酸饮料即饮苏打型饮品","brand":"元气森林","category":"食品饮料","sub_category":"碳酸饮料","base_price":4.5,"image_path":"4_食品生活/images/p_food_004_live.jpg","skus":[{"sku_id":"s_p_food_004_1","properties":{"容量":"480ml","口味":"白桃味","包装规格":"单瓶"},"price":4.5},{"sku_id":"s_p_food_004_2","properties":{"容量":"480ml","口味":"白桃味","包装规格":"15瓶整箱"},"price":65.0}],"rag_knowledge":{"marketing_description":"元气森林白桃味气泡水是专为怕甜怕腻又爱爽感的人量身打造的快乐水，核心就是实打实的0糖0脂0卡，用赤藓糖醇代替白砂糖，喝起来完全没有普通碳酸饮料喝完齁嗓子反酸的问题，入口是刚咬开脆甜水蜜桃的鲜爽香气，细密的气泡在舌尖炸开，凉丝丝的特别解腻。不管是健身控卡期的运动党、正在控糖的减脂人群、怕胖的学生上班族，还是戒糖又嘴馋的奶茶爱好者都能放心喝。平时吃火锅撸串配它解辣解腻，上班困了冰一瓶提神醒脑，逛超市随手拿一瓶边走边喝也很方便。收到货如果没开封最好放阴凉避光处，别暴晒，冰1-2小时口感最好，开瓶之后尽快喝完避免气泡散掉哦。","official_faq":[{"question":"这款白桃味气泡水的0糖是完全不含糖分吗，配料表里有没有隐形糖？","answer":"这款元气森林白桃味气泡水的0糖是完全符合国家相关标准的，没有添加白砂糖、果葡糖浆等可产生热量的糖类，配料里选用的甜味剂是赤藓糖醇，是从天然植物发酵提取的，几乎不会被人体代谢产生热量，也不会升血糖，完全不存在隐形添加糖的情况，控糖人群、减脂期的朋友都可以放心饮用，不用担心喝了之后有额外的热量负担。"},{"question":"整箱装的480ml*15瓶白桃味气泡水运输的时候容易出现漏液的情况吗？","answer":"咱们这款整箱装的气泡水发货前都会经过二次加固包装，箱内会加防震气泡膜缓冲磕碰，瓶身本身是食品级耐压力的PET材质，正常运输过程中基本不会出现漏液问题。如果大家收到货之后发现有鼓瓶、漏液、气泡跑光的情况，别签收直接联系客服提供破损照片，我们会第一时间给你安排补发或者全额退款，全程不需要你承担任何额外的费用，请放心下单就好。"},{"question":"这款白桃味气泡水的气泡够足吗，和普通带气的苏打水喝起来口感有什么区别？","answer":"我们这款气泡水的气泡是高压充入的细密小微气泡，比普通苏打水的气泡更绵密，不是那种粗粝刺嗓子的辣感，入口之后会在舌尖慢慢爆开，搭配白桃的清甜香气，不会有普通苏打水的发苦的碱味。就算你开盖放了十分钟，也还剩大半的气泡感，平时喝不惯纯苏打水的朋友也能轻松接受，冰过之后气泡的爽感会更突出，解腻提神的效果特别好。"},{"question":"控糖的妊娠期或者血糖偏高的人群可以喝这款白桃味气泡水吗？","answer":"这款白桃味气泡水的赤藓糖醇升糖指数GI为0，正常适量饮用是不会引起血糖波动的，也不会给身体造成额外的代谢负担，血糖偏高的人群、控糖的孕期朋友在嘴馋想喝带味饮品的时候，都可以少量喝来解馋。不过还是建议大家不要一次大量饮用冰的款，避免刺激肠胃，要是本身有特殊的饮食禁忌，饮用前也可以先咨询下自己的主治医生更稳妥。"},{"question":"这款白桃味气泡水的白桃香味是天然果汁提取的还是食用香精调的？","answer":"这款气泡水的白桃风味是用合规的天然蜜桃提取物搭配食用级的白桃香精调配的，没有添加人工劣质香精，调出来的香味非常接近新鲜熟成的水蜜桃的清甜味，不是那种工业香精的刺鼻甜腻感。喝的时候能吃到淡淡的果肉鲜感，完全不会有喝完之后嘴里留奇怪香精味的情况，符合国家食品添加剂的安全标准，大家可以完全放心饮用。"},{"question":"未开封的480ml装白桃味气泡水保质期是多久，存放的时候有什么要注意的？","answer":"这款未开封的480ml装白桃味气泡水保质期是12个月，大家存放的时候一定要放在阴凉、干燥、避光的地方，别放在太阳底下暴晒，也别放在0度以下的环境里冷冻，不然瓶内的液体结冰膨胀很容易直接把瓶子撑裂漏液。如果是夏天温度高的时候，别把整箱水放在汽车的后备箱里长时间闷着，不仅容易让瓶身变形，高温环境还容易影响气泡的留存，喝起来的口感会大打折扣。"}],"user_reviews":[{"nickname":"阿泽","rating":2,"content":"这次收到的单瓶喝起来感觉白桃味特别淡，几乎只有点淡淡的甜味，完全没有之前买的那种刚撕开鲜桃子皮的清香味，气泡也少了好多，开瓶的时候完全没有“呲”的一声冒气的动静，喝到嘴里软塌塌的像放了好几天跑气了一样。4.5一瓶这个品质真的不太值，感觉是存放时间太久了，本来想买来配火锅的，结果喝着一点都不解腻，有点小失望。"},{"nickname":"小棠","rating":3,"content":"凑单买的单瓶，本来以为白桃味会很浓很好喝，结果喝起来甜味有点发怪，不是水蜜桃的鲜甜味，带点代糖特有的后味，喝完之后嘴里残留好久的怪味。气泡倒是够足，但是喝半瓶就觉得有点齁得慌，本来想买来代替奶茶的，结果喝了两口就不想喝了，剩下的半瓶放了一晚上气全跑光，直接像兑了味的白水，性价比有点低，应该不会回购单瓶的了。"},{"nickname":"大宇","rating":1,"content":"这次买的整箱15瓶真的太糟心了，快递送到的时候外包装盒全湿了，拆开看有三瓶漏液漏了大半，瓶身黏糊糊的，剩下的好几瓶摸起来都是软的，一点气压都没有，拧开盖子完全没有气泡，全是甜乎乎的白水味。找客服处理等了半天才回应，只愿意赔3瓶的钱，剩下的没气的就不管，花65买一箱大半瓶都废了，体验感特别差。"},{"nickname":"小桃","rating":5,"content":"真的是我无限回购的款！这次凑活动买了整箱放家里，冰过之后拿出来喝一口，绵密的气泡在舌尖炸开，白桃的清香味直接冒出来，甜丝丝的完全不齁，0糖0脂喝着完全没负担。平时吃完重油重盐的外卖，或者周末在家煮麻辣火锅配它，解辣又解腻，比喝奶茶爽太多了，480ml的容量一瓶刚好够喝，不会喝不完剩半瓶浪费，已经安利给办公室好多同事了。"}]}}'::jsonb, '4_食品生活/data/p_food_004.json'),
    ('p_food_005', '东鹏特饮 维生素功能饮料500ml 经典瓶装补充能量含牛磺酸咖啡因', '东鹏', '食品饮料', '功能饮料', '食品饮料/功能饮料', 5.0, 5.0, 68.0, 300, '4_食品生活/images/p_food_005_live.jpg', '{"product_id":"p_food_005","title":"东鹏特饮 维生素功能饮料500ml 经典瓶装补充能量含牛磺酸咖啡因","brand":"东鹏","category":"食品饮料","sub_category":"功能饮料","base_price":5.0,"image_path":"4_食品生活/images/p_food_005_live.jpg","skus":[{"sku_id":"s_p_food_005_1","properties":{"容量":"500ml","数量":"1瓶","包装":"散装单瓶"},"price":5.0},{"sku_id":"s_p_food_005_2","properties":{"容量":"500ml","数量":"6瓶","包装":"塑封组合装"},"price":28.0},{"sku_id":"s_p_food_005_3","properties":{"容量":"500ml","数量":"15瓶","包装":"原厂整箱"},"price":68.0}],"rag_knowledge":{"marketing_description":"这款东鹏特饮500ml经典瓶装功能饮料，是不少熬夜党、运动族的随身能量补给首选。核心添加了牛磺酸、适量咖啡因与多种B族维生素，大瓶500ml的容量比常规小瓶多了近一半，一口下去是熟悉的清甜焦香口感，快速帮你驱散困意、补充消耗的体能。特别适合开长途的货车司机、连续加班的上班族、课后还要训练的体育生，或是约着组队打一下午球的球友。建议犯困、体能告急时小口慢饮，不要短时间猛灌，孕妇、未成年人和对咖啡因敏感的朋友就不要饮用啦，常温避光存放就能保留新鲜风味。","official_faq":[{"question":"这款500ml装的东鹏特饮，牛磺酸和咖啡因的具体添加量是多少呀？","answer":"咱们这款500ml经典装东鹏特饮，每瓶的牛磺酸添加量足有1800mg，同时合规添加了咖啡因约50mg，搭配维生素B族群协同作用，既不会给身体造成过重负担，又能充分起到缓解疲劳、补充消耗体能的效果。这个配比是经过多年市场验证调整的，口感和提神效果都适配大多数普通消费者的需求，大家日常需要快速补能的时候放心按需饮用就好。"},{"question":"买500ml*15瓶的整箱装，收到货会不会有漏液或者瓶身变形的情况？","answer":"咱们整箱装的500ml东鹏特饮，出厂时每瓶都做了密封检测，发货时还会在原有塑封箱的基础上额外加一层加厚气泡垫包裹，避免运输途中的磕碰挤压。绝大多数情况下送到买家手里都是完好的，如果万一收到货有个别瓶身变形、瓶盖松动漏液的情况，你只需要24小时内联系客服上传照片，我们会按破损瓶的数量直接给你全额退款，完全不用你承担运输过程造成的损失。"},{"question":"平时健身跑完步能不能直接喝这款东鹏特饮补充能量？","answer":"完全可以的，你跑完步体能大量消耗之后喝一瓶500ml的东鹏特饮，里面的牛磺酸能快速帮助神经缓解疲劳状态，添加的少量糖分可以及时补充运动中消耗掉的糖原，比喝普通白水的缓疲效果要好很多。不过要注意刚跑完步先缓两分钟，等呼吸平稳之后再小口慢饮，不要对着瓶口猛灌，避免给肠胃造成刺激，运动后一次性喝半瓶左右其实就足够补足状态了。"},{"question":"这款500ml装的东鹏特饮，和同款小瓶装的除了容量之外有区别吗？","answer":"除了容量从常规的250ml升级到500ml之外，配方、口感都是完全一模一样的，没有任何调整。我们做大容量的经典瓶装，就是为了适配大家开长途、长时间户外作业、连续加班这类需要长时间补能的场景，不用中途反复买小瓶，单瓶算下来也更划算，整箱买平均单瓶价格比单独买小瓶要便宜不少，经常需要喝的朋友选整箱装性价比更高。"},{"question":"开盖之后没喝完的东鹏特饮，放多久还能继续喝呀？","answer":"开盖之后的东鹏特饮，如果是常温环境下，建议你在24小时之内喝完，要是已经放进冰箱冷藏密封好，最长也不要超过48小时。因为饮料开盖之后接触到空气中的杂菌，时间放久了风味会明显变酸变淡，营养成分也会慢慢流失，饮用之后还可能引发肠胃不适。要是你开盖之后放了超过两天，就不建议再继续喝了，直接丢弃更安全。"}],"user_reviews":[{"nickname":"阿凯","rating":5,"content":"我是跑城际货运的，每次跑长途之前都必囤两箱这个500ml的东鹏特饮，之前买小瓶的半路就喝完了，大瓶的一瓶能撑好几个小时，困了喝两口立刻精神不少，味道还是熟悉的老配方，甜滋滋的不发苦。这次买整箱算下来单瓶才4块多，比服务区卖6块一瓶便宜太多，下次跑完长途还得再来囤两箱放车上备用。"},{"nickname":"小夏","rating":1,"content":"这次收到的整箱货至少有三瓶漏液了，黏糊糊的撒了半箱子，找客服说只给赔三瓶的钱，剩下的瓶身沾的黏擦都擦不掉，味道喝着还比平时买的淡很多，看生产日期居然还有半个月就到期了，之前买的都是剩大半年保质期的，这次发临期品也不提前说，体验感真的太差了，以后绝对不会再来这家店买了。"},{"nickname":"阿哲","rating":2,"content":"等了三天才送到，拆开箱子好几瓶的瓶盖都被挤得变了形，虽然没漏液但是总觉得不干净，喝了半瓶提神效果也很一般，我平时喝东鹏半小时就不困了，这次熬到后半夜还是昏昏沉沉的，不知道是不是批次的问题，找客服说只能退货，但是我已经开了两瓶没法退，算了就当买个教训，下次还是去楼下超市买更放心。"},{"nickname":"圆圆","rating":1,"content":"买的时候页面标着整箱15瓶，收到货数了数才13瓶，少了整整两瓶，找客服核对半天，他们说仓库发货称重是对的，是我自己数错了，我反复数了三遍怎么可能数错。而且有两瓶的瓶盖一拧直接就弹飞了，气特别足喷了我一身，撒了半瓶在衣服上，黏糊糊的洗都洗不掉，这次购物真的太闹心了，完全不值这个价。"}]}}'::jsonb, '4_食品生活/data/p_food_005.json'),
    ('p_food_006', '红牛 维生素功能饮料250ml*24罐整箱补充能量含牛磺酸咖啡因', '红牛', '食品饮料', '功能饮料', '食品饮料/功能饮料', 120.0, 68.0, 128.0, 400, '4_食品生活/images/p_food_006_live.jpg', '{"product_id":"p_food_006","title":"红牛 维生素功能饮料250ml*24罐整箱补充能量含牛磺酸咖啡因","brand":"红牛","category":"食品饮料","sub_category":"功能饮料","base_price":120.0,"image_path":"4_食品生活/images/p_food_006_live.jpg","skus":[{"sku_id":"s_p_food_006_1","properties":{"容量":"250ml","每箱数量":"12罐","包装":"小箱装","版本":"国产版"},"price":68.0},{"sku_id":"s_p_food_006_2","properties":{"容量":"250ml","每箱数量":"24罐","包装":"整箱装","版本":"国产版"},"price":120.0},{"sku_id":"s_p_food_006_3","properties":{"容量":"250ml","每箱数量":"12罐","包装":"整箱装","版本":"国产版"},"price":70.0},{"sku_id":"s_p_food_006_4","properties":{"容量":"250ml","每箱数量":"24罐","包装":"小箱装","版本":"国产版"},"price":128.0}],"rag_knowledge":{"marketing_description":"这款国产红牛维生素功能饮料，每罐250ml科学配比牛磺酸、赖氨酸，搭配适量咖啡因与多种B族维生素，精准补充身体消耗的能量，不是甜腻的汽水感，入口是大家熟悉的清爽酸甜味。特别适合跑长途的货车司机、经常熬夜赶方案的上班族、周末约着打球撸铁的运动党，还有踏青出游、加班备考、长时间开黑这些容易犯困没精神的场景，拿出来喝一罐十几分钟就能感觉到状态回来。现在有整箱24罐和半箱12罐两个规格可选，整箱装囤在家放办公室都很划算，开罐即饮特别方便。要注意的是，这款饮料不建议睡前喝，孕妇、未成年人和对咖啡因敏感的朋友也不建议饮用，运动后别直接猛灌，稍缓两分钟再喝更舒服哦。","official_faq":[{"question":"这款国产版红牛250ml装的核心营养成分具体含量大概是多少，和海外版本有区别吗？","answer":"咱们这款国产红牛每250ml罐添加了牛磺酸约125mg、咖啡因50mg，同时搭配了赖氨酸、肌醇以及维生素B6、维生素B12等营养物质，配比是完全符合国内食品饮料相关标准的。和海外版本相比，这款的口感更贴合国内消费者习惯的酸甜度，咖啡因含量控制在更适配日常提神需求的区间，不会太刺激肠胃，不管是日常通勤犯困还是运动后补充都能放心喝，没有额外添加的特殊成分。"},{"question":"囤货的话这款功能饮料正常存放保质期是多久，整箱24罐的包装会不会出现运输漏罐的情况？","answer":"正常避光阴凉处存放，这款红牛的保质期是18个月，只要不放在太阳直晒或者靠近高温热源的地方，整箱囤货放大半年完全没问题，不用太担心过期浪费。咱们整箱24罐的发货包装除了原厂的硬质纸箱之外，还额外加了一层气泡缓冲护角，运输过程中几乎不会出现漏罐问题，如果收到货之后发现有罐体变形、漏液的情况，24小时内联系客服上传照片，我们会直接给你补发对应的破损罐，不用退回旧罐特别方便。"},{"question":"平时每天喝一罐这款红牛可以吗，有没有什么需要特别避开的饮用场景？","answer":"健康的成年人日常如果有提神补能的需求，每天喝1罐250ml的这款红牛是完全没问题的，不会给身体造成额外负担。但要注意尽量不要在临睡前2-3小时内喝，不然很容易出现神经兴奋睡不着的情况；也不建议把它当日常水大量猛灌，更不能搭配酒精类饮品一起喝，本身有心脏类基础疾病、对咖啡因不耐受的朋友，饮用之前建议先咨询医生，未成年人和孕妇是不建议饮用这款功能饮料的哦。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"这次收到的整箱红牛真的太糟心了，大半罐都出现了罐体凹瘪的情况，有两罐甚至边缘都裂开漏液了，黏糊糊的弄的整箱纸箱都湿掉了。联系客服之后处理速度也特别慢，等了半天才回复说只能赔3块钱优惠券，我花120买的整箱结果大半罐都变形，放包里都怕漏的到处都是，完全不敢带出门，这次购物体验真的太差了，以后再也不想在这家买了。"},{"nickname":"小夏","rating":2,"content":"本来冲着红牛的牌子买的12罐小箱装，结果喝起来味道和之前超市买的不太一样，甜得发腻，喝完之后嘴里留了好久的奇怪香精味，扫罐身上的溯源码倒是能扫出来，就是口感差好多。而且送过来的时候没有冰袋，夏天收到的时候整箱罐子都是温的，喝起来完全没有冰饮那种提神的爽感，对比线下超市同价位的活动，这次买的确实不太值，应该不会回购了。"},{"nickname":"大宇","rating":5,"content":"我是常年跑长途的货运司机，每次跑长途之前必囤两箱这个红牛，这次买的24罐整箱特别划算，算下来比加油站便宜快一半。味道就是我喝了十几年的熟悉味道，每次开三四个小时犯困的时候喝一罐，没十几分钟精神头就上来了，再也不用硬撑着熬瞌睡。包装也特别扎实，每一罐都完好没有变形，放在车里的储物箱里刚好能塞下，这波囤货真的太值了。"},{"nickname":"阿泽","rating":1,"content":"我下单的时候明确选的是国产版红牛24罐整箱，结果收到货之后发现是别的小牌子仿的功能饮料，罐身的logo都长得很像红牛，不仔细看根本分辨不出来，找客服说理人家还说就是同类型的功能饮料不给退换。120块钱买了一堆杂牌子，喝了一口味道怪得不行根本不敢咽，现在整箱都扔在角落里落灰，真的太坑人了。"},{"nickname":"小楠","rating":2,"content":"买这个本来是想公司部门团建的时候分给大家的，结果收到货一看生产日期只剩不到1个月就过期了，临期的商品页面完全没有标注说明，客服还说临期也在保质期内不给退。团建本来想分给大家的，结果好多人拿到手看日期这么近都不愿意喝，最后大半箱都只能我自己带回家慢慢喝，喝得我都快腻了，早知道是临期的我根本不会花这个钱买。"},{"nickname":"悠悠","rating":5,"content":"作为经常熬夜赶项目的策划人，我办公室的储物间永远缺不了红牛，这次趁活动囤的两箱24罐的特别划算，平均一罐才5块钱，比楼下便利店便宜太多了。每次熬到后半夜脑子转不动的时候开一罐，酸甜的味道特别清爽，不会像别的功能饮料那样甜得齁人，喝完没多久思路就清楚很多。罐体都是完好的，日期也都是最近新生产的，够我和同事们喝上小两个月了，下次有活动肯定还要再来囤。"}]}}'::jsonb, '4_食品生活/data/p_food_006.json'),
    ('p_food_007', '伊利 金典 有机纯牛奶250ml*12盒 甄选有机奶源常温盒装牛奶', '金典', '食品饮料', '牛奶', '食品饮料/牛奶', 72.0, 72.0, 135.0, 200, '4_食品生活/images/p_food_007_live.jpg', '{"product_id":"p_food_007","title":"伊利 金典 有机纯牛奶250ml*12盒 甄选有机奶源常温盒装牛奶","brand":"金典","category":"食品饮料","sub_category":"牛奶","base_price":72.0,"image_path":"4_食品生活/images/p_food_007_live.jpg","skus":[{"sku_id":"s_p_food_007_1","properties":{"容量":"250ml","整箱盒数":"12盒","产品类型":"有机纯牛奶"},"price":72.0},{"sku_id":"s_p_food_007_2","properties":{"容量":"250ml","整箱盒数":"24盒","产品类型":"有机纯牛奶"},"price":135.0}],"rag_knowledge":{"marketing_description":"伊利金典有机纯牛奶选用专属有机牧场的甄选奶源，全程遵循有机标准管控，不额外添加人工成分，每盒250ml都带着自然的浓郁乳香，乳蛋白含量高于普通纯牛奶，口感顺滑不腥腻。这款常温盒装牛奶分12盒、24盒两种规格可选，72元12盒、135元24盒的定价也很划算，不管是家里有学龄孩子当早餐配面包、上班族办公室下午饿了当加餐，还是长辈日常补充营养都特别合适。平时囤货放在阴凉干燥处避光保存就行，开盒即饮特别方便，要是肠胃怕凉也可以隔着温水温个2分钟再喝，注意没喝完的牛奶要密封放冷藏，24小时内喝完避免变质哦。","official_faq":[{"question":"这款金典有机纯牛奶的有机奶源是怎么管控的，和普通纯牛奶有什么不一样？","answer":"咱们这款金典有机纯牛奶的奶源全部来自经过官方认证的专属有机牧场，牧场全程不使用化学合成的农药、化肥，奶牛的饲料也都是有机种植产出的，养殖过程也不违规使用抗生素，从挤奶、运输到灌装全链路都有有机溯源码可查，每一批次都要经过专属的有机检测。和普通纯牛奶比起来，它的乳香更自然醇厚，无额外添加成分，给家里的老人小孩喝也更放心。"},{"question":"我买的24盒整箱装的金典有机纯牛奶，常温下可以放多久？临近保质期喝有没有问题？","answer":"这款金典有机纯牛奶未开封状态下，在阴凉干燥、避免阳光直晒的常温环境里，保质期是6个月，只要包装没有出现鼓包、漏液的情况，哪怕是临近保质期，里面的牛奶品质也完全符合安全标准，正常直接饮用完全没有问题。要是已经开封就必须放进冰箱冷藏，而且要在24小时内饮用完毕，避免空气中的杂菌进入奶液里导致变质，喝之前可以先闻闻气味确认状态。"},{"question":"给刚上小学的孩子每天喝这款金典有机纯牛奶，每天喝几盒比较合适？","answer":"学龄期的孩子正处在生长发育的关键阶段，推荐每天喝1-2盒这款250ml的金典有机纯牛奶就足够了，其中的优质乳蛋白和钙元素刚好能补充日常饮食里的营养缺口，搭配鸡蛋、全麦面包当早餐，或者下午放学当加餐都特别合适。不建议一次性喝太多，不然容易挤占正餐的进食空间，反而不利于孩子均衡摄入其他的营养，要是孩子本身乳糖不耐受，可以先少量尝试，搭配谷物一起喝减轻不适感。"}],"user_reviews":[{"nickname":"阿明","rating":2,"content":"这次收到的12盒装快递箱被压得变形了，我拆开检查发现有两盒的侧面边缘已经有轻微的渗液痕迹，虽然暂时没鼓包但也不敢给家里小朋友喝了，找客服沟通折腾了好久才给处理。之前买过好几次都没问题，这次的物流包装实在太不上心，连个防撞气泡膜都没裹，整箱直接塞快递盒里晃来晃去，本来是冲着品质来囤货的，这次体验实在挺闹心的，只能给两颗星。"},{"nickname":"小棠","rating":2,"content":"本来以为买24盒装的会比12盒单买划算很多，算下来其实单盒价格差不了几毛钱，而且生产日期是三个多月前的，剩下的保质期才不到三个月，我家只有我一个人喝根本赶不上喝完。之前别家同规格的同款牛奶都是发最近半个月的新日期，这次临期感太强了，本来想囤货省点钱结果反而要赶着日期天天硬喝，体验真的不太好，只能给两颗星。"},{"nickname":"乐琪","rating":5,"content":"回购N次的金典有机奶了！奶味特别浓郁，入口顺滑完全没有那种怪怪的腥味，家里娃以前不爱喝纯奶，现在每天早上自己主动要拿一盒配吐司。这次囤的24盒整箱价格太合适了，算下来比超市单买便宜快二十块，日期也很新，溯源码扫了确实是正经有机奶源，喝着特别放心，平时我下午上班饿了也会拿一盒当加餐，饱腹感很强也不会甜腻，以后肯定还会接着回购的。"}]}}'::jsonb, '4_食品生活/data/p_food_007.json'),
    ('p_food_008', '蒙牛 纯甄 常温风味酸牛奶经典原味200g*10盒发酵乳饮品', '纯甄', '食品饮料', '酸奶', '食品饮料/酸奶', 55.0, 55.0, 105.0, 200, '4_食品生活/images/p_food_008_live.jpg', '{"product_id":"p_food_008","title":"蒙牛 纯甄 常温风味酸牛奶经典原味200g*10盒发酵乳饮品","brand":"纯甄","category":"食品饮料","sub_category":"酸奶","base_price":55.0,"image_path":"4_食品生活/images/p_food_008_live.jpg","skus":[{"sku_id":"s_p_food_008_1","properties":{"单盒容量":"200g","整箱盒数":"10盒","口味":"经典原味"},"price":55.0},{"sku_id":"s_p_food_008_2","properties":{"单盒容量":"200g","整箱盒数":"20盒","口味":"经典原味"},"price":105.0}],"rag_knowledge":{"marketing_description":"蒙牛纯甄这款经典原味常温酸牛奶，没有额外添加香精、防腐剂，生牛乳发酵出的口感绵密丝滑，酸香里裹着淡淡的自然乳甜，完全没有齁人的工业甜味。200g的小盒身材刚好，揣在通勤包、学生书包里都不占地方，不管是赶早八路上配面包当快手早餐，下午办公室摸鱼解腻，还是家里小孩放学当加餐都合适。全年龄段都能喝，家里老人怕凉也不用热得麻烦，常温放着就能随时掏出来喝。建议开盒就一次性喝完，别放太久影响风味，没开封的话避光阴凉处存就行，别搁太阳直晒的地方。","official_faq":[{"question":"这款纯甄经典原味的配料表里有没有添加香精和明胶？","answer":"这款经典原味纯甄常温酸奶完全没有添加食用香精、色素以及明胶，核心配料只用了优质生牛乳搭配乳酸菌菌种长时间发酵，额外添加的糖分也是符合国家标准的白砂糖，没有其他冗余添加剂。本身靠生牛乳发酵就能形成自然的浓稠质感，不用靠明胶类的增稠剂来撑质地，喝起来的奶香和酸味都是发酵自带的自然风味，不用担心多余添加剂给身体造成额外负担，家里小朋友、老人都可以放心饮用。"},{"question":"买200g*20盒的整箱款是独立分箱还是一整箱装的？","answer":"咱们这款200g*20盒的规格是两提10盒装的组合装，也就是分成两个独立的小箱打包发出，每箱刚好10盒，和你单买10盒的外包装是一模一样的。这种分箱设计特别适合家里人口不多的情况，开了第一提10盒喝完再拆第二提，剩下没开封的那箱不用一次性找地方全部存放，不管是放办公室给同事分，还是一半留家里喝一半放宿舍都特别方便，也不用担心拆了大箱之后剩下的酸奶不小心被磕碰漏液。"},{"question":"这款常温酸奶没开封的话需要放冰箱冷藏保存吗？","answer":"这款纯甄是经过巴氏杀菌热处理的常温发酵乳，没开封的状态下完全不需要放冰箱冷藏，放在25℃以下避光阴凉干燥的地方存放就可以，保质期可以维持6个月。平时租房冰箱塞不下、学生宿舍没有冰箱也完全不用担心存不住，不过如果已经开封喝了一半没喝完，就必须密封放进冰箱冷藏，而且要在24小时之内喝完，不然暴露在空气中的酸奶很容易滋生杂菌变味，喝了容易闹肚子。"},{"question":"这款纯甄原味酸奶可以用来做水果捞、酸奶碗这类甜品吗？","answer":"完全可以用来做水果捞、酸奶碗还有自制酸奶冰，它的质地是那种刚好的浓稠挂壁感，不是太稀的水样质地，倒在切好的草莓、芒果、香蕉块上面不会很快就渗到水果底部流的到处都是，裹在水果上面的状态刚刚好。因为它本身的风味是很纯净的乳香酸甜，没有其他奇奇怪怪的添加剂味道，搭燕麦脆、坚果碎也不会串味，不用额外加糖都好吃。不过要是想做那种特别厚实的希腊酸奶质地，建议倒出来之后用纱布滤1小时多余乳清，口感会更厚重。"}],"user_reviews":[{"nickname":"阿凯","rating":3,"content":"这次收到的这箱10盒的，喝起来总感觉酸味比之前买的冲很多，倒出来看质地也比以前稀一点，挂壁很少。看了下生产日期倒是还在保质期内，不知道是不是批次的问题。本来是买来当早餐配麦片的，现在这个酸度空口喝有点刺激，泡麦片倒是还行，就是味道和之前一直回购的差了不少，有点小失望，以后可能要等确定批次没问题再买了。"},{"nickname":"小棠","rating":1,"content":"这次收到的20盒装的两提，拆第二提的时候连续发现3盒侧面有小鼓包，捏起来里面的液体都漏出来一点了，包装边缘黏糊糊的。找客服说储存没问题，结果折腾了半天才给处理，鼓包的酸奶根本不敢喝，怕变质喝了闹肚子，平白无故少了三盒，体验特别差，之前买了好多次都没遇上这种情况，这次真的踩雷了。"},{"nickname":"阿远","rating":3,"content":"本来以为200g的容量我喝刚好，结果发现这个盒子设计的很怪，最后剩个底根本吸不上来，剪开盒子剩个小半杯扔了又浪费，喝又沾的满手都是。味道倒是和以前没差，但是这个包装的吸嘴设计真的不合理，比我之前买的同容量其他牌子的难吸多了，每次喝都要剪开倒出来才喝的干净，太麻烦了，希望后续能改改这个小设计。"},{"nickname":"米米","rating":5,"content":"我真的是纯甄的老粉了，这款原味我回购不下十次！这次趁着活动入的20盒装的算下来比超市便宜快十块钱，日期也特别新鲜，拆开每盒都正常不鼓包。口感就是那种很醇厚的发酵乳香，酸酸甜甜一点都不齁，我早上赶时间拿一盒配个面包五分钟就搞定早餐，下午犯困喝一口解腻又解乏，家里小朋友也特别爱喝，每次放学主动要着喝，太满意了。"},{"nickname":"小夏","rating":4,"content":"整体来说还是不错的，味道就是熟悉的纯甄经典味，绵密丝滑没有怪味，20盒的价格比线下超市划算不少，快递送上门也不用自己扛。就是美中不足的是送来的箱子角被压变形了，里面有两盒的外包装盒皱巴巴的，虽然里面的酸奶没漏也没坏，但是送人肯定是拿不出手了，只能自己家里喝，要是物流运输能再做好点防撞就完美了。"}]}}'::jsonb, '4_食品生活/data/p_food_008.json'),
    ('p_food_009', '三只松鼠 每日坚果750g/30袋 混合坚果仁干果礼盒独立小包装', '三只松鼠', '食品饮料', '坚果/零食', '食品饮料/坚果/零食', 99.0, 59.0, 99.0, 400, '4_食品生活/images/p_food_009_live.jpg', '{"product_id":"p_food_009","title":"三只松鼠 每日坚果750g/30袋 混合坚果仁干果礼盒独立小包装","brand":"三只松鼠","category":"食品饮料","sub_category":"坚果/零食","base_price":99.0,"image_path":"4_食品生活/images/p_food_009_live.jpg","skus":[{"sku_id":"s_p_food_009_1","properties":{"总袋数":"15袋","包装类型":"简装"},"price":59.0},{"sku_id":"s_p_food_009_2","properties":{"总袋数":"15袋","包装类型":"礼盒装"},"price":69.0},{"sku_id":"s_p_food_009_3","properties":{"总袋数":"30袋","包装类型":"简装"},"price":89.0},{"sku_id":"s_p_food_009_4","properties":{"总袋数":"30袋","包装类型":"礼盒装"},"price":99.0}],"rag_knowledge":{"marketing_description":"三只松鼠这款每日坚果专门为懒得搭配坚果、追求每日精准营养的朋友量身打造，整整30袋总重750g，每袋都是25g的独立密封小包装，不用怕开袋后受潮变质。搭配都是科学配比的6种果仁果干，没有额外添加白砂糖调味，保留坚果原生香，不会齁甜发腻。不管是职场人通勤揣一袋当下午茶垫肚子，学生党课间补充能量，还是宝妈给家里小朋友当健康加餐、全家周末出游揣几袋解闷都合适。建议每天拆开1袋直接吃，也可以倒在酸奶、燕麦碗里拌着吃，口感层次更丰富。要注意坚果开封后尽量当天吃完，里面的果仁含少量油脂，放在阴凉干燥处存放，别暴晒也别放冰箱冷藏容易返潮。礼盒装还能直接当伴手礼送亲戚朋友，体面又实用。","official_faq":[{"question":"这款每日坚果750g礼盒里具体是哪几种坚果和果干，有没有额外的添加剂？","answer":"咱们这款每日坚果的配比是原味巴旦木仁、夏威夷果仁、核桃仁、榛子仁这4种坚果，搭配蔓越莓干、葡萄干2种低糖果干，全程没有额外添加白砂糖、香精、防腐剂，也没有盐焗、油炸的重加工步骤，所有食材都是经过三次人工筛拣坏果，再低温慢烘锁香处理，保留原生的坚果香气，果干也只保留了果肉本身的清甜，吃起来不会齁甜，老人小朋友都能放心吃，控糖期的人群也可以适量食用。"},{"question":"25g*30袋的礼盒装和25g*15袋的简装，除了袋数之外还有什么区别？","answer":"两款除了售价和总净含量不同，包装形式也有明显区别：30袋的750g款用的是硬面烫金的手提礼盒，盒身印了三只松鼠的卡通IP形象，自带手提绳，送礼或者整箱放家里收纳都很方便；15袋的简装是简约瓦楞纸盒，没有手提设计，主打自用高性价比。两款里面的每一小袋内容物配比、单袋重量、食材品质都是完全一致的，大家可以根据自己的食用周期和需求选，要是自己吃1个月左右选15袋简装就够，全家吃或者打算送人直接入30袋礼盒款更划算。"},{"question":"独立小包装的密封效果怎么样，存放的时候需要特别注意什么吗？","answer":"每一小袋用的都是加厚铝箔复合膜包装，封口是压边热封工艺，正常未拆封的状态下，放在阴凉干燥的常温环境里能完整保持6个月保质期，不会轻易漏风受潮。大家收到货之后别把整箱放在阳光直晒的窗台、靠近灶台的高温位置，也别放到冰箱冷藏室里，低温环境里的水汽很容易钻进包装缝隙让坚果变软返潮。拆封后的小袋最好一次性吃完，要是实在没吃完，记得把袋口用夹子夹紧，2小时内吃完，不然放久了果仁很容易氧化变哈喇味影响口感。"},{"question":"这款每日坚果有没有经过过敏提示，易过敏人群要注意什么？","answer":"咱们产品的外包装和每一个小袋的背面都明确标注了致敏原提示，这款坚果里包含了坚果类、果仁类成分，同时生产流水线也加工过含有花生、乳制品、蛋类的其他零食，要是您本身对巴旦木、榛子、核桃这类坚果，或者花生、乳制品过敏的话，一定要谨慎食用，食用前仔细查看小包装上的成分配比标注。第一次吃的过敏体质人群可以先少量试吃，确认没有不适反应之后再正常食用，也可以先咨询医生的建议再下单，避免出现过敏的情况。"},{"question":"如果收到货发现里面有坏果或者个别小袋破损漏了，能申请售后吗？","answer":"咱们品牌对这款每日坚果提供坏果包赔的售后保障，要是您收到货之后，发现整箱里有个别小袋出现封口开裂、果仁漏出的情况，或者拆开之后吃到坏果、瘪果仁，只需要把对应问题的小袋和实物拍清晰的照片，联系咱们店铺的在线客服提交凭证就可以，不用退回商品，客服核实之后会按照对应的问题袋数给您安排退款或者补发。哪怕您已经吃到大半箱才发现有坏果，也随时可以联系我们处理，我们不会以商品已经拆封食用为理由拒绝售后，最大程度保障大家的消费体验。"}],"user_reviews":[{"nickname":"小棠","rating":5,"content":"回购第三箱了！每袋里的果仁都很饱满，几乎没遇到过瘪的或者坏的，果干也不是那种干硬齁甜的，配酸奶拌着当早餐刚好，25g的量不多不少，吃完刚好解馋也不会腻。之前买过别的牌子的每日坚果，有时候打开半袋都是果干，这款坚果占比特别高，巴旦木和夏威夷果的香劲特别足，我家娃每天放学都要主动要一袋吃，放在包里带去上班当下午茶，同事都追着要链接。"},{"nickname":"阿凯","rating":2,"content":"这次买的简装15袋太糟心了，吃第三袋的时候就吃出了一个发苦的榛子仁，以为是个例就扔了，结果后面连续两袋都有两三个发软的核桃仁，明显是受潮了。找客服说坏果包赔，最后只给退了两块钱，说超过3袋坏的才给多赔，之前买礼盒装的时候从来没遇到过这种情况，没想到简装的品控差这么多，明明食材应该一样的，这次体验真的不好，以后不敢随便买简装的了。"},{"nickname":"悠悠","rating":5,"content":"过年的时候囤了两箱礼盒装送亲戚，反馈都特别好！包装亮堂堂的提着特别有面，里面的独立小袋揣出门太方便了，上周带娃去游乐园，随手塞了两袋在包里，娃玩累了拿出来吃特别顶饱。没有那种油炸的过度调味，给老人吃也放心，配比很科学，不用自己单独买好几种坚果凑量，每天一袋算下来也不贵，比自己单买坚果划算太多了，已经推荐给身边好多宝妈了。"}]}}'::jsonb, '4_食品生活/data/p_food_009.json'),
    ('p_food_010', '良品铺子 肉松饼1000g/箱 松软糕点休闲零食早餐代餐点心', '良品铺子', '食品饮料', '坚果/零食', '食品饮料/坚果/零食', 59.0, 32.0, 62.0, 400, '4_食品生活/images/p_food_010_live.jpg', '{"product_id":"p_food_010","title":"良品铺子 肉松饼1000g/箱 松软糕点休闲零食早餐代餐点心","brand":"良品铺子","category":"食品饮料","sub_category":"坚果/零食","base_price":59.0,"image_path":"4_食品生活/images/p_food_010_live.jpg","skus":[{"sku_id":"s_p_food_010_1","properties":{"数量":"约20枚","容量":"500g"},"price":35.0},{"sku_id":"s_p_food_010_2","properties":{"数量":"约20枚","容量":"1000g"},"price":62.0},{"sku_id":"s_p_food_010_3","properties":{"数量":"约40枚","容量":"500g"},"price":32.0},{"sku_id":"s_p_food_010_4","properties":{"数量":"约40枚","容量":"1000g"},"price":59.0}],"rag_knowledge":{"marketing_description":"良品铺子这款肉松饼可是实打实的国民解馋小点心，足足1000g整箱装差不多有40枚，皮薄得能透出内里满满的肉松，咬一口外层酥软掉渣，内馅咸香不腻，肉香直钻鼻腔，完全不是那种淀粉感很重的廉价货。配料里用的是精选猪腿肉松，搭配小麦粉和鲜鸡蛋调的外皮，不加多余的人工香精，老人小孩吃着也放心。平时赶早八来不及买早饭，揣两个在包里配杯热牛奶就能顶一上午；办公室摸鱼饿了拿一个垫肚子，出门郊游分给同行的朋友也够吃。家里囤货选1kg装更划算，要是想先试味选500g约20枚的规格也合适，注意开封后尽量3天内吃完，放在阴凉干燥处别晒，受潮了外皮会软掉影响口感哦。不管是学生党、上班族还是平时爱囤点心的长辈，都能吃得满意。","official_faq":[{"question":"整箱1000g的良品铺子肉松饼里大概有多少枚，每枚的重量是统一的吗？","answer":"咱们1000g的整箱肉松饼常规是约40枚的规格，单枚重量大概在25g左右，因为肉松填充的量有轻微的人工操作误差，个别几枚的重量可能会有1-2g的浮动，不会影响整体口感和总净含量哦。如果您是想分给办公室同事当下午茶点心，按每两人分1枚的量来算，40枚够20人左右的小团队分两轮，完全不用担心不够吃的情况。"},{"question":"这款肉松饼的内馅是纯肉松吗，有没有添加很多淀粉凑重量？","answer":"咱们这款良品铺子肉松饼的内馅主原料是精选猪腿肉制成的肉松，只添加了极少量的食用小麦淀粉来调整内馅的粘合度，完全不会出现咬开大半都是淀粉糊的情况，每一口都能吃到实打实的肉香。你撕开饼皮就能看到一缕缕清晰的肉松纤维，咸香度调得刚好，不会过咸发苦，也不会淡得像没放盐，代餐的时候吃也不会觉得齁得慌。"},{"question":"这款肉松饼给小朋友当早餐吃合适吗，有没有什么需要注意的地方？","answer":"这款肉松饼作为小朋友的早餐加餐是完全合适的，它的外皮用鲜鸡蛋和小麦粉揉制，不添加人工合成的甜味剂和多余香精，入口松软不费牙，3岁以上的小朋友都可以直接吃。不过给小朋友吃的时候建议搭配温牛奶或者温水，避免单独吃太干噎到，另外如果小朋友对鸡蛋或者猪肉类食材过敏的话，就不建议食用啦，开封后的剩下的饼要封好封口再给小朋友吃，避免落灰受潮。"},{"question":"500g约20枚的规格和1000g约40枚的规格，里面的肉松饼品质是一样的吗？","answer":"两个规格的肉松饼是完全同生产线生产的，配料、口感、单枚的大小都没有任何区别，唯一的差别就是整箱的净含量和数量，500g装更适合想先试味、或者家里人口少、一周吃不完40枚的用户选择，35元的定价更灵活不浪费。1000g的整箱装性价比更高，适合宿舍集体囤货、办公室日常补给或者家里爱吃点心的人多的情况，算下来单枚的价格比单独买散称的要便宜近1块钱。"},{"question":"这款肉松饼的保质期有多久，囤货的话要放在什么地方保存才不会坏？","answer":"咱们这款良品铺子肉松饼的未开封保质期是180天，每一枚都是独立的小包装，不会出现整箱打开没吃完就全部受潮变质的情况。囤货的时候放在阴凉干燥、避免阳光直射的地方就可以，不要放在卫生间、厨房这种湿度大的区域，也不要和有浓烈气味的东西比如榴莲、樟脑丸放在一起，饼皮很容易吸味影响口感，只要独立小包装没有漏气胀袋，放足半年都不会变软变味。"},{"question":"这款肉松饼吃起来会不会很干，能不能用来当代餐顶饱？","answer":"咱们这款肉松饼做了专门的锁水工艺，外皮是松软的而不是硬邦邦的酥皮，内馅的肉松也做了润化处理，咬开不会掉一嘴渣子呛到，配一杯温水或者豆浆的话完全不会觉得干。用来当代餐完全没问题，每枚的热量大概在110大卡左右，早上吃2枚加一杯热豆浆，到午饭前都不会饿，比吃很多甜腻的夹心面包要顶饱很多，也不会吃完没多久就反酸，减脂期用来临时垫肚子也完全合适。"}],"user_reviews":[{"nickname":"小棠","rating":5,"content":"回购第三次了！这次直接入了1kg整箱的，数了下刚好41枚，算下来才一块多一个太划算了。外皮软乎乎的一点都不硬，咬开里面全是肉松，能吃到一丝丝的肉纤维，完全没有那种糊嘴的淀粉感，咸淡刚好，当早餐配热牛奶真的绝。我放了两个在工位，下午三点多饿了啃一个，直接撑到下班，同事闻着味还追着我要链接，已经给全办公室都种草了。"},{"nickname":"阿凯","rating":5,"content":"给我妈买的整箱肉松饼，她平时跳完广场舞回来总爱找东西垫肚子，之前买过别的牌子的吃完她总说太甜太腻，这次这个她夸了好多次。每枚都是独立小包装，揣兜里出门遛弯也方便，咬开肉香特别浓，外皮软得很，她牙不好也能轻松咬动。我自己尝了两个，确实不是那种齁甜的味道，咸香口的，家里囤着放茶几上，来客人随手拿两个吃也很合适。"},{"nickname":"阿明","rating":1,"content":"这次收到的整箱肉松饼太离谱了，吃第三个就咬到了明显的哈喇味，拆开小包装摸饼皮都是发黏的，看了下生产日期也没过期，估计是运输的时候被晒到变质了。数了下才32枚，根本不是宣传的40枚，找客服半天也不给处理，花59块钱买了半箱坏的，剩下的全扔了，以后再也不买大箱装的了，之前买小规格的从来没遇到过这种情况，这次体验差到极点。"},{"nickname":"小夏","rating":3,"content":"整体不算特别差但也没达到预期，之前上学的时候吃过良品铺子的肉松饼，这次买的感觉肉松少了好多，撕开饼皮大半都是厚厚的面皮，咬到最后一口才能吃到一点肉松味。数了下500g的只有17枚，差了3个也不是什么大问题，但35块钱这个价格性价比实在不高，味道也偏甜，之前的咸香口感淡了好多，应该不会再回购了，不如去买楼下糕点店现做的，更便宜还新鲜。"},{"nickname":"圆圆","rating":2,"content":"本来想囤了当早餐吃，结果拿到手吃了两个就没胃口了，饼皮特别干，咬一口掉一身渣，要猛喝水才能咽下去，里面的肉松几乎全是淀粉感，吃起来像嚼棉花一样，完全没有之前买的那种鲜浓肉香。整箱大部分吃起来都是淡淡的甜味，一点咸香的味道都没有，59块钱买了一箱子几乎吃不下去的东西，勉强分给室友了一半，剩下的全放过期扔了，以后不会再买这款。"}]}}'::jsonb, '4_食品生活/data/p_food_010.json'),
    ('p_food_011', '康师傅 经典红烧牛肉面110g*12桶装方便面泡面速食面整箱装', '康师傅', '食品饮料', '方便食品', '食品饮料/方便食品', 45.0, 26.0, 45.0, 200, '4_食品生活/images/p_food_011_live.jpg', '{"product_id":"p_food_011","title":"康师傅 经典红烧牛肉面110g*12桶装方便面泡面速食面整箱装","brand":"康师傅","category":"食品饮料","sub_category":"方便食品","base_price":45.0,"image_path":"4_食品生活/images/p_food_011_live.jpg","skus":[{"sku_id":"s_p_food_011_1","properties":{"口味":"红烧牛肉味","容量":"110g","数量":"6桶"},"price":26.0},{"sku_id":"s_p_food_011_2","properties":{"口味":"红烧牛肉味","容量":"110g","数量":"12桶"},"price":45.0}],"rag_knowledge":{"marketing_description":"作为国民级泡面标杆，这箱康师傅经典红烧牛肉面绝对是你手边的稳妥速食选择！每桶足足110g面饼，搭配专属熬制的红烧牛肉酱包、金黄脱水蔬菜包和鲜香风味粉包，泡开后牛肉香直钻鼻子，面条筋道不发软。不管是熬夜赶项目的上班族、宿舍赶作业的学生党，还是长途自驾游想快速垫肚子的出行族都超适配，加班晚归不想开火、临时加餐、懒癌犯了不想做饭的时候，倒满开水焖3分钟就能吃上热乎的。建议泡的时候加根火腿肠或者卧个鸡蛋，口感直接升级。注意哦，未开封要放在阴凉干燥处避光存放，拆封后要及时食用，里面的脱水料包千万别直接倒干吃，避免齁咸。","official_faq":[{"question":"这款经典红烧牛肉面整箱12桶的规格，里面每桶的面饼重量都是110g吗，有没有碎面的情况？","answer":"咱们这款康师傅经典红烧牛肉面110g*12的整箱装，单桶净含量是包含面饼、料包在内的总重量，其中面饼的重量正好是110g，没有偷工减料的情况。出厂前经过了多层缓冲泡沫衬垫封装，正常运输场景下几乎不会出现碎面问题。要是你收到货发现有超过3桶的严重碎面，可以直接联系客服上传照片，我们会按碎面的比例给你做对应补偿，完全不用担心里边都是碎渣泡不开的情况。"},{"question":"这款红烧牛肉面的料包里真的有牛肉粒吗，和门店现煮的红烧牛肉味差别大不大？","answer":"这款经典红烧牛肉面的脱水蔬菜包里是添加了真实的小颗粒卤制牛肉粒的，经过冷冻干燥工艺锁鲜，泡开之后能吃到软嫩的牛肉小颗粒，不是完全的素味调味。它的风味是康师傅传承了二十多年的经典红烧牛肉配方，用牛骨慢熬的汤底调制，还原的是大家从小吃到大的熟悉老味道，和线下现煮牛肉面的浓厚肉香风格有区别，但辨识度极高，老粉一吃就能尝出是正宗的经典红烧味，不会出现改版之后味道变怪的情况。"},{"question":"我想买来放在宿舍囤货，12桶的整箱包装能放多久，6桶的半箱装和12桶的单桶品质是一样的吗？","answer":"这款康师傅红烧牛肉面的未开封保质期是6个月，只要你放在宿舍阴凉干燥、不被太阳直晒的地方，囤个小半年完全没问题，不用担心很快过期吃不完浪费。咱们店卖的110g*6桶的半箱装和12桶的整箱装，用的是完全一样的生产线生产的同批次产品，单桶的面饼重量、料包配置、调味配方没有任何区别，只是包装数量不同，要是你饭量小怕吃不完浪费，选6桶的小规格也完全没问题，品质和整箱装一模一样，不会偷换料包减配。"}],"user_reviews":[{"nickname":"阿泽","rating":2,"content":"这次收到的整箱面大部分料包都有鼓胀的情况，虽然面饼看着没坏，但酱包摸着黏糊糊的不敢吃，找客服只给退了5块钱补偿。之前买过好多次都没这问题，这次应该是运输的时候被放在太阳底下晒太久了，拆开闻着味道也比之前的淡很多，连我平时最爱吃的红烧牛肉味都没怎么尝出来，剩下的几桶不敢留，最后全扔了，性价比实在不高。"},{"nickname":"小棠","rating":5,"content":"简直是我加班党的救星！办公室囤了整整一箱，每次赶方案到深夜的时候，接饮水机的开水焖3分钟，香得整个工位旁边的同事都过来问链接，面条特别筋道，不是那种泡两分钟就软塌塌的类型，配根隔壁工位借的火腿肠，吃完整个人都暖乎乎的。熟悉的老味道完全没改版，和我小时候初中在小卖部买的味道一模一样，囤一次能吃小半个月，比点外卖划算太多了。"},{"nickname":"阿远","rating":5,"content":"开学给宿舍囤的货，室友们抢着吃！12桶的量我们四个人分着吃刚好，每桶面饼110g我这种饭量大的男生吃一桶也能吃饱，料包里的小牛肉粒咬开还挺香的，汤底咸淡刚好，不用额外加盐就很够味。上次通宵打游戏的时候四个人一起泡了四桶，整个宿舍都是熟悉的红烧牛肉香，比煮速冻面省事儿多了，价格也比线下超市单买便宜快十块钱，以后囤泡面就认准这家了。"},{"nickname":"大强","rating":1,"content":"这次的货真的太离谱了，整整12桶有8桶的面饼全是碎的，倒出来几乎全是面渣，根本没法正常泡成整面条，酱包还漏了两桶，整箱的外包装上全是漏出来的红油，擦都擦不干净。找客服协商居然说快递运输损耗他们不管，只给3块钱优惠券打发人，花45块钱买了一箱碎面实在是太闹心了，以后绝对不会再来这家店买，完全没保障。"},{"nickname":"小夏","rating":2,"content":"收到货拆开尝了一桶，味道不对啊，红烧牛肉味淡得几乎尝不出来，面饼泡完两分钟就软得像面糊，查了下生产日期只剩不到一个月就过期了，临期货也没提前标注出来。本来是想囤货吃俩月的，结果现在得赶在过期前半个月就全部吃完，吃不完就得浪费，价格也没比线下超市便宜多少，这次购物体验挺差的，以后不会随便囤整箱的了。"}]}}'::jsonb, '4_食品生活/data/p_food_011.json'),
    ('p_food_012', '统一 老坛酸菜牛肉面来一桶121g*12桶方便面泡面酸辣风味整箱', '统一', '食品饮料', '方便食品', '食品饮料/方便食品', 50.0, 28.0, 50.0, 200, '4_食品生活/images/p_food_012_live.jpg', '{"product_id":"p_food_012","title":"统一 老坛酸菜牛肉面来一桶121g*12桶方便面泡面酸辣风味整箱","brand":"统一","category":"食品饮料","sub_category":"方便食品","base_price":50.0,"image_path":"4_食品生活/images/p_food_012_live.jpg","skus":[{"sku_id":"s_p_food_012_1","properties":{"容量":"121g","包装数量":"12桶","口味":"老坛酸菜牛肉味"},"price":50.0},{"sku_id":"s_p_food_012_2","properties":{"容量":"121g","包装数量":"6桶","口味":"老坛酸菜牛肉味"},"price":28.0}],"rag_knowledge":{"marketing_description":"咱这款统一老坛酸菜牛肉面可是出了名的国民经典款，每桶足足121g，酸脆发酵的老坛酸菜是核心灵魂，搭配劲道非油炸感的面饼、浓郁牛肉汤底包，酸辣平衡得刚好够味。特别适合租房打工人、熬夜备考学生党、长途出行的旅客囤货，不管是加班到深夜懒得开火，周末宅家追剧不想点外卖，还是临时应急垫肚子都超合适。建议大家泡的时候先把酸菜包全部倒进去，用刚烧开的沸水没过面饼，盖盖焖5分钟再拌开，酸香味直接飘满整个屋子。注意整箱存放要放在阴凉干燥不晒太阳的地方，拆封后尽快食用，对酸菜类食材过敏的朋友要谨慎下单哦，6桶小规格适合尝鲜，12桶整箱装性价比拉满够吃大半个月。","official_faq":[{"question":"这款统一老坛酸菜牛肉面整箱12桶的规格，每桶里面的配料都包含什么呀？","answer":"咱们这款121g的桶装老坛酸菜牛肉面，每桶的配置都是统一标准的：除了75g的筋道小麦面饼之外，搭配了独家的老坛风味酸菜包、秘制牛肉味粉包、浓郁香辣酱包，还有一小包干葱花提鲜，分量刚好够普通成年人一顿吃饱。没有额外添加多余的人工香精成分，酸香的口感都是靠发酵酸菜本身带出的，大家完全可以放心冲泡食用，不用额外加调料也能调出地道的酸辣味儿。"},{"question":"我买整箱12桶的版本，快递送过来的时候会出现桶身被压碎、面饼碎掉的情况吗？","answer":"咱们整箱12桶的发货都是用统一专属的加厚硬纸箱封装的，桶和桶之间有预留缓冲空隙，外部还会额外缠一层防震气泡膜，正常运输过程中基本不会出现大面积压碎的情况。如果大家收到货之后发现有超过2桶以上的面饼碎裂、桶身破漏漏调料包的情况，直接拍照片联系客服，我们会根据破损比例给你做部分退款或者补发对应数量的商品，完全不用担心收到残次品没法处理的问题。"},{"question":"6桶的小规格版本和12桶的整箱版本，里面的单桶内容是完全一样的吗？","answer":"两个规格里的单桶产品是完全一模一样的，都是121g标准重量的老坛酸菜牛肉味桶面，面饼、配料包的成分和重量没有任何区别，唯一的不同就是包装的数量和定价。6桶的版本定价28元，更适合第一次想尝鲜、或者平时吃泡面频率不高，担心囤太多放过期的朋友选择，12桶整箱装定价50元，单桶核算下来性价比更高，适合平时经常吃泡面、或者合租室友一起拼单囤货的用户入手。"},{"question":"这款泡面如果不用开水泡，用锅煮的话口感会有什么不一样的注意点吗？","answer":"这款面饼本身偏劲道，用锅煮的话口感会比直接泡更软弹好吃，大家煮的时候不用把水加太多，没过面饼2/3的位置就刚好，水开之后把面饼放进去煮3分钟左右，不要煮超过5分钟不然面饼会烂掉没嚼头。酸菜包建议在煮到2分钟的时候再放进去，煮个1分钟就能把酸菜的酸香完全煮进汤里，最后可以自己加点青菜、鸡蛋或者火腿肠，吃起来比普通泡的要香很多，比外卖煮面还省事省时间。"}],"user_reviews":[{"nickname":"阿凯","rating":4,"content":"整体吃着还是小时候熟悉的那个老坛酸菜味儿，面饼泡开很筋道，酸溜溜的很开胃，我平时加班晚了泡一桶刚好能吃饱。就是这次收到货有两桶的边缘被快递压得有点凹进去，还好里面的面饼没碎，不影响吃。要是后续快递能再加固点就更好了，这个价位买到12桶整体还是挺划算的，之后有需要应该还会再来光顾。"},{"nickname":"小夏","rating":5,"content":"真的太爱这个老坛酸菜味了，囤了一整箱放在出租屋，下班不想做饭的时候泡一桶，5分钟就能吃上热乎的，酸菜脆爽得很，汤底酸辣够味，我每次都连汤都喝光。之前在超市单买一桶要五六块，这里整箱买下来单桶才四块多，便宜好多，吃了快半个月都没吃完，生产日期都是最近的特别新鲜，太合我这种懒人打工人的心意了。"},{"nickname":"阿明","rating":1,"content":"这次收到的整箱面里面有三桶的酸菜包都漏了，打开纸箱一股子酱料味，桶身外面沾得黏糊糊的，找客服说了半天才给我退了5块钱。而且我吃着这次的酸菜味特别怪，发酸发苦，和之前买的正宗老坛味完全不一样，泡出来的汤颜色也浅很多，感觉这次买到的批次质量明显不行，以后再也不敢随便囤整箱的了。"},{"nickname":"晓雯","rating":1,"content":"我买的6桶尝鲜装，结果快递送过来直接扔在小区快递柜外面，我去拿的时候箱子都泡雨里了，所有桶的外包装皮都烂了，有两桶里面的面饼直接受潮软掉了，泡出来黏糊糊的完全没有筋道的口感。找店家说不是他们的问题是快递的问题，不给我处理赔偿，花28块钱就吃到两桶正常的，剩下的全浪费了，体验特别差。"},{"nickname":"阿哲","rating":2,"content":"这次买的整箱12桶，吃着味道倒是没什么大问题，但是每桶的面饼感觉比我之前在超市买的小一圈，称了下连桶带面才110g左右，根本达不到标注的121g。男生吃完一桶根本不顶饱，我吃完过两个小时就又饿了，这个价位本来以为能买到足量的，结果分量偷减了点，性价比一下就没那么高了，只能给个两星，不会回购整箱装了。"}]}}'::jsonb, '4_食品生活/data/p_food_012.json'),
    ('p_food_013', '海天 金标生抽1.9L 瓶装酱油 家用厨房调味料酱香鲜味佐餐蘸料', '海天', '食品饮料', '调味品', '食品饮料/调味品', 22.0, 9.0, 22.0, 400, '4_食品生活/images/p_food_013_live.jpg', '{"product_id":"p_food_013","title":"海天 金标生抽1.9L 瓶装酱油 家用厨房调味料酱香鲜味佐餐蘸料","brand":"海天","category":"食品饮料","sub_category":"调味品","base_price":22.0,"image_path":"4_食品生活/images/p_food_013_live.jpg","skus":[{"sku_id":"s_p_food_013_1","properties":{"容量":"1.9L","包装":"大瓶装"},"price":22.0},{"sku_id":"s_p_food_013_2","properties":{"容量":"500ml","包装":"小瓶装"},"price":9.0},{"sku_id":"s_p_food_013_3","properties":{"容量":"500ml","包装":"大瓶装"},"price":16.9},{"sku_id":"s_p_food_013_4","properties":{"容量":"1.9L","包装":"小瓶装"},"price":20.9}],"rag_knowledge":{"marketing_description":"这款海天金标生抽1.9L大瓶装，是无数家庭厨房的常驻调味王牌，核心卖点就是采用非转基因黄豆经传统高盐稀态工艺足期酿造，酱香味醇厚自然，鲜度不齁不冲，完全没有工业调味的突兀感。特别适合日常开火频率高的三口之家、租房党整屋拼饭的年轻人，还有常给孩子做辅食餐的宝妈。平时不管是白切鸡蘸料、凉拌黄瓜提鲜，还是家常小炒、焖炖上色都能用，主要成分只有水、非转基因大豆、小麦粉、食用盐，没有多余的杂七杂八添加剂，吃着放心。建议开盖后放冰箱冷藏，要是平时用得少也可以选500ml小瓶装避免放久风味散掉，注意别放在灶台边长期被高温烘烤，容易提前变质变味。","official_faq":[{"question":"这款1.9L装的海天金标生抽，日常家用正常频率大概能放多久不变质？","answer":"未开盖的情况下放在阴凉干燥处，保质期有18个月完全不用怕过期。但开盖之后因为接触了空气和日常用勺舀取可能带进去的水渍杂菌，建议尽量在3个月内用完风味最佳，要是家里开火频率很低，超过6个月就不建议直接用来做凉拌蘸料了，高温炒菜用完倒是也没问题。要是开盖后一直放在冰箱冷藏，最长可以延长到6个月保持初始的鲜度和酱香感，风味不会打太多折扣。"},{"question":"这款金标生抽能不能直接用来做日式寿司的蘸料，会不会味道太重发苦？","answer":"完全可以直接用做寿司蘸料，它的咸鲜度调得很平衡，不会像很多浓口酱油那样齁咸发苦，自带的清甜味刚好能中和寿司醋的酸感，配三文鱼、北极贝这类刺身也很搭。不过要是平时吃惯了偏淡口的鱼生酱油，可以按1:0.3的比例兑点凉白开或者少量味淋稀释下，鲜爽感会更突出，完全不会抢生鲜本身的鲜甜，比很多专门卖的高价刺身酱油性价比高太多。"},{"question":"1.9L的大瓶生抽倒的时候容易撒漏，有没有什么实用的小技巧可以解决？","answer":"大家收到货之后可以自己单独配个食品级的按压嘴，网上十几块钱的通用款基本都能匹配这个瓶口的尺寸，按一下出量刚好是一小勺，平时凉拌炒菜控量特别方便，完全不会撒的台面上黏糊糊的。要是不想额外买配件，倒的时候把瓶身标签朝上、瓶口朝向外侧倾斜45度，流速会特别稳，不会突然涌出来撒漏，用完立刻把盖子拧紧，也能避免瓶口残留的酱油氧化结黑垢。"},{"question":"这款金标生抽和海天家的味极鲜、特级生抽有什么具体区别？","answer":"金标生抽的氨基酸态氮含量是1.0g/100ml，属于一级酿造酱油，酱香更偏浓郁醇厚，咸度稍微高一点，日常炒菜、佐餐蘸料两用都合适，性价比很高。味极鲜的鲜度更高，氨基酸态氮达到1.2g/100ml，更适合凉拌提鲜，炒菜久煮反而鲜味容易散。而海天特级金标生抽的指标更高，鲜感更柔和，这款普通金标作为日常高频使用的刚需款，用量大也不心疼，适配绝大多数家常场景。"},{"question":"家里有刚满3岁的小孩，能不能用这款生抽给做的辅食调味？","answer":"3岁以上的孩子肾脏代谢能力已经比婴幼儿时期发育完善很多，完全可以少量用这款生抽给辅食提味，它的添加剂很少，没有额外加味精提鲜，比很多儿童酱油的钠含量其实控制得更稳。不过每次添加量不要超过1小勺的1/3，给孩子做蒸蛋、煮面条的时候点一两滴就足够带出鲜香味，不需要额外再加盐，避免摄入过多钠加重孩子代谢负担，1岁以内的辅食就完全不建议添加任何酱油调味了。"}],"user_reviews":[{"nickname":"阿荔","rating":5,"content":"家里常年囤的就是这款金标生抽，1.9L的大瓶算下来比小瓶装划算太多，我家一家三口天天开火炒菜，偶尔拌个凉面、白切鸡蘸料也全用它，酱香特别正，没有那种呛人的工业鲜味儿。上次做凉拌秋葵点了一点，鲜得我家孩子连吃了两大盘，这次趁活动直接囤了两瓶，开盖放冰箱里存着也不怕坏，性价比真的拉满，以后再也不买杂牌酱油了。"},{"nickname":"小宇","rating":2,"content":"这次收到的1.9L装瓶口漏了小半瓶，外包装的纸箱都洇湿了，找客服说要给补两块钱优惠券，我折腾半天擦灶台擦瓶子黏糊糊的太闹心了。而且漏出来的酱油干了之后瓶身外壁结了一层黑垢，我搓了半天都没搓干净，只能把剩的酱油倒去之前用完的旧小瓶子里用，大瓶直接扔了，本来冲着大瓶性价比买的，这次体验真的太差了。"},{"nickname":"阿美","rating":3,"content":"酱油本身味道倒是和之前买的没啥区别，就是1.9L的瓶子实在太重了，我一个小个子女生每次拎起来往小碟子里倒都费劲，好几次差点没拿稳把整瓶摔地上。本来想换500ml的小瓶又觉得不划算，现在只能每次炒菜之前先把酱油倒到小调味瓶里，额外多费一道工序，用着倒是没坏，就是对力气小的人太不友好了，只能说如果是独居的朋友真的别盲目买大瓶装。"}]}}'::jsonb, '4_食品生活/data/p_food_013.json'),
    ('p_food_014', '农夫山泉 东方树叶 无糖茉莉花茶饮料 500ml×15 瓶装茶饮', '农夫山泉', '食品饮料', '茶饮', '食品饮料/茶饮', 75.0, 70.0, 118.0, 400, '4_食品生活/images/p_food_014_live.jpg', '{"product_id":"p_food_014","title":"农夫山泉 东方树叶 无糖茉莉花茶饮料 500ml×15 瓶装茶饮","brand":"农夫山泉","category":"食品饮料","sub_category":"茶饮","base_price":75.0,"image_path":"4_食品生活/images/p_food_014_live.jpg","skus":[{"sku_id":"s_p_food_014_1","properties":{"容量":"500ml","每箱数量":"15瓶","包装":"整箱装"},"price":75.0},{"sku_id":"s_p_food_014_2","properties":{"容量":"500ml","每箱数量":"15瓶","包装":"量贩装"},"price":70.0},{"sku_id":"s_p_food_014_3","properties":{"容量":"500ml","每箱数量":"24瓶","包装":"整箱装"},"price":118.0},{"sku_id":"s_p_food_014_4","properties":{"容量":"500ml","每箱数量":"24瓶","包装":"量贩装"},"price":115.0}],"rag_knowledge":{"marketing_description":"农夫山泉旗下东方树叶无糖茉莉花茶，是真正做到0糖0脂0卡的纯茶饮品，没有添加任何代糖、香精和防腐剂，萃取广西横县当季双瓣茉莉花的鲜爽香气，搭配绿茶茶底的清润回甘，茶味不苦涩、花香不冲鼻，入口是完全自然的茶感。不管是控糖期人群、怕胖的上班族，还是戒了奶茶的学生党、日常不爱喝白水的茶友都很适合。摸鱼工位放一瓶解腻消乏，饭后喝解重油重盐的外卖腻感，健身后喝不会给身体添额外负担，出门郊游塞包里也不占地方。建议开瓶后24小时内喝完，避免风味流失，未开封状态放在阴凉避光处保存就行，别长期放太阳下直晒避免瓶身变形影响口感。","official_faq":[{"question":"这款东方树叶茉莉花茶真的完全没有添加糖和代糖吗？喝起来会不会有甜感？","answer":"这款东方树叶茉莉花茶确实是完全零糖零代糖的配方，配料表只有水、绿茶、茉莉花茶浸提液、维生素C和碳酸氢钠，没有额外添加任何蔗糖、果葡糖浆，也没有阿斯巴甜、赤藓糖醇这类代糖成分。入口能感受到的极淡清甜感完全来自茶类本身浸出的天然茶多糖，不是人工添加的甜味剂，控糖人群、糖尿病人群在遵医嘱的前提下都可以放心饮用，完全不用担心额外的糖分摄入问题。"},{"question":"500ml的规格整箱运输会不会出现漏液、瓶身被挤压变形的情况？","answer":"我们这款整箱装的东方树叶出厂时采用了农夫山泉专属的加厚食品级PET瓶身，外箱是定制的加厚瓦楞纸箱，内部每瓶之间有卡位隔层缓冲，常规快递运输环境下基本不会出现漏液情况。如果您收到货之后发现有瓶身挤压、瓶盖松动漏液的情况，只需要拍摄好面单和破损商品的同框照片，联系客服上传凭证，我们会第一时间根据破损的瓶数给您对应的退款或者补发服务，完全不用您承担运输带来的损耗损失。"},{"question":"这款茉莉花茶可以用来做DIY饮品吗，比如加柠檬、泡水果冻之类的？","answer":"这款无糖茉莉花茶是非常适合做DIY饮品的基底，本身自带的茉莉花香气不会抢其他食材的风味，纯茶底也没有额外甜味干扰你调整口味。平时你可以直接加几片鲜柠檬和冰块，就是秒出杯的茉莉青提冰茶，也可以冻成茶冰块加到气泡水里，甚至用来煮奶茶、泡冷萃水果茶都完全合适。因为它本身没有添加杂七杂八的添加剂，DIY出来的饮品整体口感会比用含糖茶饮做基底清爽很多，热量也能控制得更低，自己在家做饮品既方便又健康。"},{"question":"500ml×15瓶和24瓶的两个规格，保质期分别是多久，囤货的话怎么存放更好？","answer":"两个规格的同批次产品保质期都是12个月，未开封的状态下只要按照要求正确存放就能在保质期内保持稳定的风味。囤货的时候注意不要把箱子放在阳台被太阳直晒，也不要放在靠近灶台的高温区域，过高的温度和紫外线照射会让茶的风味加速氧化变涩，最好是放在家里阴凉避光的储物间，或者冰箱冷藏层存放，冷藏后的口感会更鲜爽，囤货一次买24瓶的量贩装性价比会更高，够喝大半个月不用频繁补货。"},{"question":"这款东方树叶茉莉花茶的茶底会不会有明显的苦涩感，不爱喝浓茶的人能接受吗？","answer":"这款茉莉花茶的萃取工艺是农夫山泉专门调过的，用的是低温慢萃的方式，只萃取出茶里鲜爽的风味物质，没有萃取到茶叶底部的涩味和茶单宁的厚重苦涩感，整体的茶感是偏清润挂的，花香比茶香先冒出来，咽下去之后喉咙里会有淡淡的绿茶回甘，几乎没有普通浓茶的刺激感。平时不爱喝浓茶、甚至平时只喝甜饮料的人第一次喝也不会觉得难接受，很多第一次尝试东方树叶的用户都是从这款茉莉花茶入门的，接受度在整个系列里是最高的。"}],"user_reviews":[{"nickname":"阿泽","rating":4,"content":"整体喝着还是很对我胃口的，无糖的茶感很清爽，平时吃完火锅喝一瓶解腻巨管用，办公室同事都被我安利了，这次囤的整箱价也比楼下超市单买便宜不少。就是快递送过来的时候外箱角被撞凹了两瓶，其中一瓶瓶身有点压变形了，不过倒是没漏液也没影响喝，就是稍微有点小瑕疵，总体来说还是挺满意的，之后应该还会回购。"},{"nickname":"小夏","rating":5,"content":"我是控糖期被闺蜜种草的这款，本来以为无糖茶会很难喝，结果入口完全惊艳到！茉莉花的香味特别正，完全不是那种香精兑出来的廉价香，茶底清润回甘一点都不涩，平时我用它加几颗冻葡萄和冰块，做出来的果饮比奶茶店二十多一杯的还好喝。这次买的15瓶整箱刚好够我喝半个月，价格也很划算，之后要试试东方树叶其他口味！"},{"nickname":"大宇","rating":2,"content":"这次收到的货实在是太离谱了，一共15瓶里有4瓶喝起来明显有股闷出来的旧纸箱味，完全没有平时喝的鲜爽茉莉香，看了下生产日期虽然没过期，但感觉像是之前被放在高温地方闷了很久的货。找客服说只给退这4瓶的钱，我要的是好货啊，剩下的喝着风味也比之前买的淡很多，以后还是去楼下超市挑新鲜日期的买吧，不敢随便囤整箱了。"},{"nickname":"朵朵","rating":5,"content":"作为不爱喝白水星人，东方树叶这款茉莉花茶我已经回购无数次了！配料表干干净净的，没有乱七八糟的添加，我上班一天能喝一两瓶，完全没有负担。之前买的24瓶量贩装平均下来一瓶才四块多，比超市卖五块一瓶便宜多了，家里冰箱常年囤着，夏天冰完之后喝一口，花香混着茶味在嘴里散开，比喝那些甜饮料舒服太多，全家人都爱喝。"}]}}'::jsonb, '4_食品生活/data/p_food_014.json'),
    ('p_food_015', '可口可乐 零度汽水 无糖碳酸饮料 330ml×24 罐装', '可口可乐', '食品饮料', '碳酸饮料', '食品饮料/碳酸饮料', 75.0, 38.0, 79.0, 400, '4_食品生活/images/p_food_015_live.jpg', '{"product_id":"p_food_015","title":"可口可乐 零度汽水 无糖碳酸饮料 330ml×24 罐装","brand":"可口可乐","category":"食品饮料","sub_category":"碳酸饮料","base_price":75.0,"image_path":"4_食品生活/images/p_food_015_live.jpg","skus":[{"sku_id":"s_p_food_015_1","properties":{"容量":"330ml","数量":"24罐","包装":"易拉罐整箱"},"price":75.0},{"sku_id":"s_p_food_015_2","properties":{"容量":"330ml","数量":"12罐","包装":"迷你装"},"price":42.0},{"sku_id":"s_p_food_015_3","properties":{"容量":"330ml","数量":"12罐","包装":"易拉罐整箱"},"price":38.0},{"sku_id":"s_p_food_015_4","properties":{"容量":"330ml","数量":"24罐","包装":"迷你装"},"price":79.0}],"rag_knowledge":{"marketing_description":"这款可口可乐零度汽水是专为怕甜又舍不得经典可乐风味的爱好者打造的无糖碳酸饮料，完全不添加白砂糖，采用阿斯巴甜等合法代糖调出和原味可乐几乎无差的激爽口感，喝下去一口就会冲上来绵密的气泡，带着熟悉的可口可乐标志性香气，完全没有代糖常见的奇怪后味。330ml的罐装大小刚好是一次能喝完的量，不会因为开瓶放久跑气浪费。不管是平时健身控卡的运动党、戒糖的上班族、怕热量超标的学生党都适合喝。追剧看球赛、朋友宅家开黑、吃火锅撸串解腻、上班摸鱼提神的时候掏出来冰一下，爽感直接拉满。提醒大家开罐的时候别对着人对着自己的脸，冰镇别放零度以下太久，不然容易喷罐，碳酸饮料开了尽快喝完别放隔夜就好。现在还能选12罐的迷你装，想先试试水的朋友也完全没负担。","official_faq":[{"question":"这款330ml罐装的零度可乐整箱和普通含糖可口可乐的口感差别大吗？","answer":"我们这款零度汽水完全沿用了可口可乐经典的气泡配比和风味基底，只是用合规代糖替换了白砂糖，刻意调低了代糖的后苦占比，大部分人日常喝的话几乎尝不出和普通含糖款的明显差别，只有对甜味特别敏感的少数用户，可能会在喝完十分钟左右感受到极淡的代糖余味，整体的杀口感、气泡绵密度和标志性的焦糖香都和常规款完全对齐，很适合想控糖又舍不得可乐风味的用户选择。"},{"question":"330ml×24罐的整箱零度可乐收到后如果出现个别罐瘪罐的情况还能正常喝吗？","answer":"只要易拉罐的密封拉环位置没有破损、罐体没有出现肉眼可见的漏液缝隙，哪怕罐身因为运输磕碰出现轻微凹陷，都不会影响内部饮料的卫生和品质，完全可以正常饮用。要是瘪罐已经导致拉环变形、密封层开裂甚至有液体渗出的情况，就千万不要喝了，大家可以直接联系客服上传破损照片，我们会按照破损的数量直接给你做对应金额的退款补偿，不用把整箱退回，处理起来很方便。"},{"question":"这款零度可乐330ml的罐装，放冰箱冻成冰沙会出现涨罐爆开的情况吗？","answer":"因为可乐里含有大量碳酸，水分冻成冰之后体积会比原本的液态扩大近十分之一，要是把未开罐的零度可乐直接放在0度以下的冷冻层放超过4小时，大概率会出现罐体变形，严重的甚至会直接涨裂漏液。想要喝冰沙口感的话，建议大家先把罐身开一个小缝放掉部分气体，再放进零下2度左右的软冷冻层，大概2个小时就能得到半冰沙的状态，既不会爆开，口感也刚好绵密爽口。"},{"question":"330ml×12罐的迷你装零度可乐和24罐整箱的产品品质是完全一样的吗？","answer":"两款只是售卖的包装规格不同，里面的330ml零度可乐是完全同一条生产线生产的，原料配比、气泡压力、保质期标准都完全一致，没有任何品质差异。迷你装更适合租房住空间小、喝可乐频率不高，怕囤24罐放太久临期的用户，整箱装性价比更高，适合家庭日常囤货、办公室采购或者经常和朋友聚会需要大量可乐的用户，大家可以根据自己的实际使用需求选对应的规格就好。"}],"user_reviews":[{"nickname":"阿凯","rating":2,"content":"这次买的整箱24罐零度可乐，到货拆开之后数了下居然有6罐的气泡特别少，开罐的时候几乎没有那种冲上来的气泡声，倒出来半分钟气就全跑光了，喝着像没气的甜水，完全不是平时喝的那种劲爽口感。找客服反馈也半天才回复，说可能是运输的时候高温晃到了不给换，我平时经常买这款，从来没遇到过这种情况，这次的品控确实太让人失望了。"},{"nickname":"小夏","rating":2,"content":"下单的时候特意选了24罐整箱的零度，想着囤着喝更划算，结果送过来的时候外包装被雨淋得全湿了，底部纸箱直接泡烂，最底下那层三罐可乐的罐身全锈了，锈迹都渗到罐口的封边位置了，哪敢直接下嘴啊。找客服沟通了好久只给赔3块钱，说其他罐没坏就没问题，我买整箱不就是图省心吗，这种处理方式实在没法让人满意。"},{"nickname":"阿泽","rating":5,"content":"我戒糖快半年了，嘴馋想喝可乐就一直买这款零度的330ml整箱装，气泡特别足，冰完之后一口下去杀口感巨爽，完全喝不出是无糖的，配我家周末的火锅简直绝了。24罐的价格算下来比超市单买便宜快一半，每次喝完直接把空罐丢回收箱也不占地方，整箱送过来包装特别严实，每罐都完好无损，我已经回购第三次了，以后囤可乐就认准这家店了。"},{"nickname":"朵朵","rating":3,"content":"买的12罐迷你装零度，价格比我预想的稍贵一点，整体喝起来倒是和平时线下买的没什么区别，但是生产日期是半年前的，距离保质期只剩不到三个月，我本来想囤着慢慢喝的，这一下根本喝不完最后肯定要临期浪费。味道倒是没什么问题，要是能给新日期的货就好了，这次体验只能说中规中矩，算不上差但也没有很满意。"},{"nickname":"大张","rating":1,"content":"这次买的24罐整箱零度可乐，打开喝第一罐就觉得味道不对，有股怪怪的塑料味，连续开了三罐都是这个味道，看了下生产日期居然还有一个星期就过期了，商家临期的货居然当正常新品卖。找客服理论直接装死，发了十几条消息半天才回一句说无糖款就是这个味道，我喝了十几年零度可乐什么味我能不知道？真的是太离谱了，以后绝对不会再来这家买东西。"}]}}'::jsonb, '4_食品生活/data/p_food_015.json'),
    ('p_food_016', '蒙牛 特仑苏 纯牛奶 250ml×16 盒装 常温乳制品', '蒙牛', '食品饮料', '牛奶', '食品饮料/牛奶', 85.0, 85.0, 118.0, 400, '4_食品生活/images/p_food_016_live.jpg', '{"product_id":"p_food_016","title":"蒙牛 特仑苏 纯牛奶 250ml×16 盒装 常温乳制品","brand":"蒙牛","category":"食品饮料","sub_category":"牛奶","base_price":85.0,"image_path":"4_食品生活/images/p_food_016_live.jpg","skus":[{"sku_id":"s_p_food_016_1","properties":{"单盒容量":"250ml","整箱数量":"16盒","包装类型":"家庭装"},"price":85.0},{"sku_id":"s_p_food_016_2","properties":{"单盒容量":"250ml","整箱数量":"16盒","包装类型":"礼盒装"},"price":89.0},{"sku_id":"s_p_food_016_3","properties":{"单盒容量":"250ml","整箱数量":"24盒","包装类型":"家庭装"},"price":108.0},{"sku_id":"s_p_food_016_4","properties":{"单盒容量":"250ml","整箱数量":"24盒","包装类型":"礼盒装"},"price":118.0}],"rag_knowledge":{"marketing_description":"这款蒙牛特仑苏纯牛奶可是很多家庭的日常囤货首选，采用专属限定牧场的优质生牛乳奶源，没有额外添加香精、防腐剂，每100ml就含有3.6g优质乳蛋白，奶香醇厚不寡淡，入口顺滑没有奶腥味。不管是正在长身体的中小学生、需要补充营养的上班族，还是日常补钙的中老年群体都很适合。早上赶时间配面包当早餐，下午办公室泡咖啡做拿铁，晚上睡前温一杯助眠，家庭聚会分给客人都很合适。平时建议放在阴凉干燥处避光储存，喝之前要是肠胃怕凉可以连盒放到40度左右的温水里捂3分钟，注意不要高温煮沸破坏营养，开盒后要24小时内喝完哦。现在有16盒家庭装和24盒礼盒装可选，日常自喝选16盒刚好够半个月的量，走亲访友拎24盒的礼盒装也特别体面。","official_faq":[{"question":"这款250ml×16盒的特仑苏家庭装，乳蛋白含量和其他款特仑苏有区别吗？","answer":"完全没有区别哦，这款家庭装的特仑苏纯牛奶和其他规格的特仑苏奶源标准是完全统一的，同样采用专属有机牧场外的限定优质放牧区生牛乳为原料，每100ml都保证含有3.6g原生优质乳蛋白，原生高钙含量也达到120mg/100ml，没有因为是家庭装就降低原料标准。区别仅在于包装规格更适配日常自喝的家庭场景，省去了礼盒装的外层硬礼带设计，性价比更高，喝起来的口感和营养成分和其他款特仑苏纯牛奶完全一致，大家可以放心购买。"},{"question":"这款常温特仑苏纯牛奶的保质期是多久，收到货的时候剩余保质期一般还有多久？","answer":"这款盒装特仑苏纯牛奶的标注保质期是6个月也就是180天，我们仓库出货的时候都会优先挑选最近30天内生产的新鲜批次发出，正常情况下大家收到货之后剩余保质期至少还有120天以上，完全足够普通家庭在临期前喝完。如果是购买24盒的礼盒装用来走亲访友，也完全不用担心送礼的时候临期尴尬，要是收到货发现剩余保质期少于90天，大家可以直接联系客服申请退换货，我们不会让大家临期喝奶，所有批次的生产日期都喷印在盒身的顶部位置，大家拿到手就能清晰看到。"},{"question":"这款特仑苏250ml的小盒包装，可以直接放到微波炉里加热吗？","answer":"不建议大家直接把未拆封的整盒特仑苏放到微波炉里加热哦，一方面纸盒的包装材质有铝箔复合层，直接放进微波炉不仅会产生电火花有起火风险，密封状态下加热还会因为盒内空气膨胀发生胀盒甚至炸裂的情况。想要加热喝的话，要么把纸盒开封把牛奶倒到微波炉适用的陶瓷杯或者玻璃杯里，用中火加热1分钟左右就刚好温乎，要么直接整盒放到40到50度的温水里泡3到5分钟，这样加热不会破坏牛奶里的活性营养物质，口感也能保持原本的醇香，比直接煮沸的风味好很多。"},{"question":"这款16盒家庭装的特仑苏，外包装是整箱原封的吗，会不会运输过程中出现漏盒撒漏的情况？","answer":"咱们这款250ml×16盒的家庭装特仑苏，发快递的时候都是直接发蒙牛原厂未拆封的整箱原包装，原厂纸箱本身就做了加厚的瓦楞抗压设计，内部16盒牛奶也有专属的瓦楞卡槽固定，不会在箱子里来回晃荡。同时我们发货前还会在外层额外再加一层气泡缓冲膜包裹，降低运输过程中的暴力分拣带来的破损概率。哪怕真的收到货有出现个别盒身挤压漏液、胀盒的情况，大家只要第一时间拍照片联系客服，我们可以直接按破损盒数给大家全额退款，不需要退回剩下的商品，处理流程特别省心。"}],"user_reviews":[{"nickname":"阿圆","rating":5,"content":"我家每周都要囤两箱特仑苏，这次买的16盒家庭装太合我心意了，刚好够我和我家上小学的儿子喝半个月。奶香味特别浓，倒出来是那种醇厚的奶白色，儿子之前不爱喝纯牛奶，现在每天早上主动要求喝一盒配面包，测了下配料表只有生牛乳，没有乱七八糟的添加，给孩子喝特别放心。这次收到的批次是半个月前刚生产的，喝着新鲜得很，喝完下次还来回购。"},{"nickname":"阿凯","rating":4,"content":"整体喝起来还是熟悉的特仑苏味道，蛋白含量高喝着确实比普通纯牛奶香，平时早上来不及做饭拿一盒配燕麦，饱腹感挺强的，当早餐挺合适的。就是这次快递送上门的时候外箱角被压扁了两小块，虽然里面的牛奶盒没漏没破，但其中两盒的侧面被压得凹进去一大块，用来送人的话肯定不好看，还好我是自己家喝不影响，建议商家可以在外箱多垫点泡沫。"},{"nickname":"小夏","rating":2,"content":"这次的购物体验真的有点差，收到货的时候没注意，拆箱拿第三盒的时候发现底部的两盒早就漏了，流得箱子里面全是黏糊糊的奶渍，还有点发酸的味道，问了客服之后说可以赔我两盒的钱，但是我一箱放客厅漏了半天都臭了，剩下的奶我总觉得沾到漏出来的奶了，不敢给家里小孩喝，等于半箱都浪费了，处理结果不太让人满意。"},{"nickname":"朵朵","rating":4,"content":"奶的品质是没问题的，我平时喜欢用它泡自制拿铁，打出来的奶沫特别绵密，比用便宜的纯牛奶打出来的效果好太多，做出来的咖啡香得不行。就是这个16盒的家庭装没有提手啊，之前买的老版本还有提手，这次搬上楼的时候抱着特别滑，差点摔在楼梯上，要是能加个简易提手就方便多了，其他方面都挺满意的，味道和营养都在线。"},{"nickname":"老周","rating":4,"content":"家里老人习惯每天晚上睡前温一杯纯牛奶补钙，一直都买的特仑苏，喝着肠胃也不难受，不会像有些便宜牛奶喝了胀气。这次买的16盒装性价比确实比超市要便宜几块钱，算下来单盒比超市便宜五毛左右。唯一不太好的就是收到货看生产日期是两个月前的，剩余保质期只剩四个月了，我家喝得慢估计喝到最后刚好临期，要是能给发更近的新鲜批次就完美了。"},{"nickname":"萌萌","rating":3,"content":"这次买的这批奶口感感觉和之前买的不太一样，喝着稀了一点，没有之前那么浓厚的奶香味，兑了水似的，倒出来颜色都偏浅一点。找了客服问说批次不同奶源有小波动，但是我家一直常年喝特仑苏，喝了快五六年了，这次这个口感确实差得有点明显，勉强能喝但体验没之前好，价格倒是没便宜多少，下次可能要换其他店买试试，看看是不是批次的问题。"}]}}'::jsonb, '4_食品生活/data/p_food_016.json'),
    ('p_food_017', '伊利 安慕希 希腊风味常温酸奶 原味 205g×10 盒装', '伊利', '食品饮料', '酸奶', '食品饮料/酸奶', 68.0, 62.0, 108.0, 400, '4_食品生活/images/p_food_017_live.jpg', '{"product_id":"p_food_017","title":"伊利 安慕希 希腊风味常温酸奶 原味 205g×10 盒装","brand":"伊利","category":"食品饮料","sub_category":"酸奶","base_price":68.0,"image_path":"4_食品生活/images/p_food_017_live.jpg","skus":[{"sku_id":"s_p_food_017_1","properties":{"口味":"原味","整箱规格":"205g×10盒","包装类型":"普通装"},"price":68.0},{"sku_id":"s_p_food_017_2","properties":{"口味":"原味","整箱规格":"205g×10盒","包装类型":"组合装"},"price":62.0},{"sku_id":"s_p_food_017_3","properties":{"口味":"原味","整箱规格":"205g×16盒","包装类型":"普通装"},"price":108.0},{"sku_id":"s_p_food_017_4","properties":{"口味":"原味","整箱规格":"205g×16盒","包装类型":"组合装"},"price":99.0}],"rag_knowledge":{"marketing_description":"伊利安慕希这款原味希腊风味常温酸奶，采用甄选优质生牛乳发酵，蛋白质含量比普通国标酸奶高出35%，口感浓稠丝滑，自带天然发酵的清醇奶香，没有多余的香精甜腻感。不用冷藏就能储存的特性特别省心，不管是早八人赶时间抓一盒配面包当快手早餐，宝妈给娃装去学校当课间加餐，还是居家追剧、办公室摸鱼当解馋小食都超适配，控糖人群、老人小孩都能放心喝。建议开盒就尽快喝完，没开封的话放在阴凉干燥处避光保存就行，要是肠胃怕凉，冬天也可以连盒泡在40度左右的温水里温2分钟再喝，注意不要高温煮沸也不要冷藏后冻成冰，避免破坏里面的活性营养物质哦。现在有10盒普通装和16盒组合装两个规格可选，日常囤货选组合装性价比更高。","official_faq":[{"question":"这款205g×10的原味安慕希常温酸奶，里面有没有添加防腐剂来实现长期常温储存呀？","answer":"这款原味安慕希是没有添加任何防腐剂的哦，我们是采用了行业先进的巴氏杀菌+无菌冷灌装工艺，在全程无菌的封闭环境里完成灌装封盒，把酸奶里的杂菌完全灭活，同时保留住发酵后的原生营养和香浓口感，不用靠防腐剂就能在常温条件下完整保存6个月。大家收到货只要放在阴凉干燥的地方避光存放，没开封的情况下完全不用担心变质问题，开盒之后尽快饮用完就可以啦，完全符合国家食品饮料的安全标准。"},{"question":"我家有刚满3岁的小朋友，能不能直接给他喝这款原味安慕希呀？有没有什么需要注意的？","answer":"3岁以上的宝宝完全可以正常饮用这款原味安慕希哦，它的成分表没有添加多余的人工甜味剂和香精，生牛乳发酵出来的醇厚口感小朋友接受度很高，里面的优质乳蛋白和钙元素还能帮小朋友补充日常成长所需的营养。不过要注意给小朋友喝的时候最好家长帮忙剪开或者教他正确掀开吸管封条，避免被不小心戳到，第一次喝可以先小量尝试观察有没有肠胃不适的情况，也不要刚从温度特别低的室外拿过来就直接给孩子喝，稍微放一会回温更友好。"},{"question":"我看这款有205g×10和205g×16两个规格，这两款的酸奶本身品质、配料是不是有区别呀？","answer":"大家完全不用担心两个规格的酸奶本身有任何品质差异哦，不管是205g×10的原味装还是205g×16的组合装，里面的单盒酸奶都是一模一样的原味配方，生牛乳来源、发酵工艺、营养参数、口感风味完全没有任何差别，只是整箱的装盒数量不同，定价也对应不一样。10盒装适合平时1-2个人短时间内喝、试喝尝鲜的用户选，16盒装适合家里人口多、或者平时经常把酸奶当日常饮品囤货的用户，组合装算下来单盒均价更划算，大家可以根据自己的需求选就行。"},{"question":"这款安慕希原味酸奶可以用来做水果捞、酸奶碗之类的甜品吗？浓稠度够不够呀？","answer":"这款原味安慕希的浓稠度特别适合用来做各种自制甜品哦，我们在发酵的时候特意调整了工艺，让它的质地比普通稀酸奶厚重很多，倒在碗里完全不会轻易往外流，不管是拌切好的草莓、芒果、蓝莓做水果捞，还是加燕麦脆、奇亚籽、坚果碎做酸奶碗，甚至是冻起来做酸奶冰棍、淋在蛋糕上当蘸酱都完全没问题，醇厚的奶香味能把水果的清甜衬得更明显，做出来的口感比用普通稀酸奶好很多，不会出现一拌就稀得像水一样的情况，很多用户买它回去就是专门用来做手工甜品的。"},{"question":"我收到货之后发现整箱里有几盒的外包装盒有点挤压变形了，里面的酸奶会不会变质不能喝了呀？","answer":"如果只是外包装的纸盒被挤压凹进去、没有出现破洞漏液、吸管口封膜开裂的情况，里面的酸奶是完全可以正常饮用的哦，我们的利乐包装盒本身的密封强度很高，轻微挤压只会让外层纸盒变形，完全破坏不了内部的无菌密封层，不会有杂菌进去污染酸奶。要是大家发现挤压之后有漏液、胀盒的情况，就不要喝了，直接联系我们的售后客服上传照片，我们会第一时间给你处理退换，不用担心喝到变质的产品，这种运输途中的轻微挤压属于正常情况，不影响产品品质。"},{"question":"这款安慕希原味酸奶的碳水含量大概是多少，控糖期的人能不能适量喝呀？","answer":"这款原味安慕希每100g的碳水化合物含量是大约11.5g，属于发酵酸奶里的常规合理水平，大部分的碳水来自牛乳本身自带的乳糖和少量添加的白砂糖，升糖速度比喝普通甜饮料要平缓很多。控糖期的人群如果日常控糖要求不是特别严苛，每天喝1盒205g的完全没问题，不会给身体造成太大的代谢负担，喝完之后可以适当减少当天其他精制糖的摄入就好。如果是需要严格控糖的糖尿病人群，建议先咨询自己的主治医生之后再根据身体情况判断能不能饮用更稳妥。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"这次收到货真的太糟心了，整箱10盒里面有3盒吸管的封膜是破的，酸奶漏得箱子里黏糊糊的，找售后还半天不回复。我本来是买来给第二天的团建当伴手礼的，现在根本没法拿出去送人，只能自己扔了大半，花68块钱买一堆漏的，真的太不值了，之前买从来没出过这种问题，这次体验实在太差，以后不敢随便囤了。"},{"nickname":"小桃","rating":3,"content":"这次买的这箱安慕希，保质期剩下不到1个月就到期了，我本来是想囤着慢慢喝的，结果算下来根本喝不完，最后剩了两三盒只能赶紧送人。价格68块钱10盒，也不算特别便宜，发临期品也不提前在详情页标注提醒一下，收到货找客服只说临期也能喝没其他补偿，不是难喝就是囤货计划被打乱了，整体体验算不上好也不算特别糟吧。"},{"nickname":"萌萌","rating":5,"content":"回购N次的老粉了！这个原味安慕希口感真的巨浓稠，每次配我自己烤的吐司当早餐，咬下去满满的奶香，一点都不像有些酸奶稀得跟兑了水一样。这次凑活动囤了两箱16盒的，算下来单盒才6块多，放办公室每天下午摸鱼喝一盒，同事都被我种草跟着一起下单了，家里我家5岁的娃每天放学都要喊着要喝，完全不挑，真的超划算超好喝！"}]}}'::jsonb, '4_食品生活/data/p_food_017.json'),
    ('p_food_018', '李锦记 特级草菇老抽 1.65L 瓶装酱油 家庭厨房调味品', '李锦记', '食品饮料', '调味品', '食品饮料/调味品', 29.0, 9.0, 32.0, 400, '4_食品生活/images/p_food_018_live.jpg', '{"product_id":"p_food_018","title":"李锦记 特级草菇老抽 1.65L 瓶装酱油 家庭厨房调味品","brand":"李锦记","category":"食品饮料","sub_category":"调味品","base_price":29.0,"image_path":"4_食品生活/images/p_food_018_live.jpg","skus":[{"sku_id":"s_p_food_018_1","properties":{"容量":"500ml","包装类型":"玻璃瓶装"},"price":15.0},{"sku_id":"s_p_food_018_2","properties":{"容量":"500ml","包装类型":"塑料瓶装"},"price":9.0},{"sku_id":"s_p_food_018_3","properties":{"容量":"1.65L","包装类型":"玻璃瓶装"},"price":32.0},{"sku_id":"s_p_food_018_4","properties":{"容量":"1.65L","包装类型":"家庭塑料装"},"price":29.0}],"rag_knowledge":{"marketing_description":"李锦记这款特级草菇老抽，核心卖点是添加了自然发酵的草菇浸出液，晒足180天的传统工艺酿造，上色红亮挂壁不发苦，咸香醇厚不带刺鼻酱味。特别适合平时爱做红烧菜、卤味的三口以上大家庭、开小餐馆的个体户，日常做红烧肉、酱牛肉、红烧茄子、卤猪脚都能用，只要几滴就能给食材挂上亮红的酱色，不用额外炒糖色省很多事。成分选用非转基因大豆、小麦粉搭配新鲜草菇提取液，没有添加人工合成的焦糖色。使用建议红烧时出锅前10分钟放就足够，别倒太多避免菜色发黑，开封后一定要放在冰箱冷藏层保存，避免长时间放在灶台边高温环境里导致风味变酸变质。","official_faq":[{"question":"这款特级草菇老抽和普通的酿造老抽上色效果有什么不一样？","answer":"这款特级草菇老抽因为在发酵过程中添加了新鲜草菇的浸出液，经过180天充足晒制发酵，产生的天然棕红色素比普通老抽更透亮，上色是鲜亮的酱红不是死黑感，做出来的红烧肉、卤鸭表皮挂色均匀油亮，不会出现局部发苦发乌的情况，哪怕你新手把控不好用量，也不容易把菜炒得黑乎乎的，完全不用额外费心炒糖色就能做出馆子级的卖相。"},{"question":"1.65L的大瓶装开封之后怎么保存才不容易变质？","answer":"1.65L的大容量包装开封之后，第一时间拧紧瓶盖放到冰箱的冷藏层存放就行，千万不要一直放在灶台边，平时炒菜产生的高温水汽很容易跑进瓶里，没半个月就会让酱油表层生出白花、风味发酸。如果平时用的频次不是特别高，也可以分装一部分到干燥无油的小挤瓶里，剩下的大瓶密封好放回冰箱，既方便日常取用也不会反复让大瓶接触外界空气，能完整保留醇厚的草菇酱香。"},{"question":"这款草菇老抽可以用来做凉拌菜直接生食吗？","answer":"不建议直接拿这款草菇老抽做凉拌菜哦，它的定位是专门的烹饪上色老抽，盐分浓度比生抽高很多，鲜度也不是专门为生食调配的，直接倒在凉拌菜里会特别咸，还会把整盘菜染得黑乎乎影响卖相。它最适合的是高温焖煮的红烧、卤制、酱焖类菜式，经过几分钟的高温烹饪之后，草菇的鲜香味会完全释放出来，上色效果也能完全发挥出来，要是做凉拌菜更推荐选李锦记的特级生抽系列更合适。"},{"question":"同系列的500ml玻璃装和1.65L家庭装的成分、风味是一样的吗？","answer":"两款的核心原料、发酵工艺、成品风味完全是统一标准的，都是用同样批次的非转基因大豆、小麦粉搭配草菇浸出液经过180天发酵制成，唯一的区别就是包装容量不同。1.65L的大容量装更适合平时做饭频次高、家里人口多，或者开家常菜小馆、卤味店的用户，算下来单毫升价格更划算，500ml玻璃装更适合租房独居、平时做饭少的年轻人，短时间内能用完不会浪费，大家可以根据自己的使用量选就行。"},{"question":"用这款草菇老抽卤出来的卤汁能不能反复卤煮食材，会不会越卤越咸？","answer":"完全可以用来调配老卤，因为它的酱香沉厚不寡淡，反复卤煮之后草菇的鲜香味会完全浸到卤汁里，卤出来的食材风味比普通老抽调的卤汁香很多。但要注意每次卤煮新食材的时候，要根据添加的食材重量和补加的清水量，少量分次补加老抽，别一次性倒太多，每次卤完之后还要把卤汁煮开过滤掉杂质，放凉之后密封放到冰箱冷冻层储存，就能长时间保留老卤的醇厚风味，不会出现越卤越咸、颜色发黑的问题。"}],"user_reviews":[{"nickname":"阿明","rating":1,"content":"这次收到的1.65L装瓶盖处居然有漏液，瓶身外面黏糊糊的全是酱油，擦了半天都还留着酱味，而且打开闻味道感觉和之前超市买的不一样，酱香味很淡倒有股奇怪的焦苦味，炒出来的红烧肉颜色发乌，吃着也发苦，根本不是之前用的那种红亮的效果，找客服反馈也没人及时回复，花29块买的这瓶根本没法正常用，太闹心了。"},{"nickname":"小夏","rating":4,"content":"整体用下来味道还可以，做红烧肉上色确实挺亮的，草菇的鲜香味也能尝出来，就是这个1.65L的塑料瓶盖子设计得太费劲了，女生手小拧开特别费力，每次倒的时候都控制不好量，一倒就容易倒多，好几次菜都快咸了才反应过来。要是能改成带按压嘴或者尖嘴挤口的设计就方便很多了，性价比倒是还行，就是使用细节上差点意思。"},{"nickname":"张姐","rating":5,"content":"我家厨房常年囤这款草菇老抽，这次看到1.65L装做活动直接囤了两瓶，真的太好用了！上周做了一大锅卤牛肉，就放了几勺这个老抽，卤出来的牛肉红亮油润，切开来纹理里都浸着酱色，连我家不爱吃卤味的小孙子都啃了两大块，味道是纯纯的酱香加淡淡的草菇鲜，完全没有那种劣质老抽的焦苦味，这么大一瓶我们家五六口人用俩月都没问题，太省心了。"},{"nickname":"阿凯","rating":4,"content":"开外卖店选的这款老抽，之前试了好几个牌子，上色效果确实比大部分平价款好，炒出来的红烧茄子、卤肉饭卖相都很好，客人也没说过味道奇怪。唯一的问题就是大瓶寄过来的时候没有泡沫缓冲，瓶身有个小凹陷，好在没漏液不影响使用，希望下次发货的时候能多加点保护缓冲的东西，不然万一漏了整瓶都浪费了，整体来说还是会回购的。"},{"nickname":"阿雯","rating":4,"content":"之前一直买500ml玻璃瓶装的，这次换了1.65L的大桶家庭装，算下来单价确实划算很多，做红烧排骨什么的上色均匀不发黑，味道也和之前小瓶的一模一样。就是大瓶太重了，每次从柜子里拿出来倒油都得两只手抱着，我个子矮举着倒油好几次差点撒出来，要是品牌能出个配套的分装小壶就好了，使用感能提升不少。"}]}}'::jsonb, '4_食品生活/data/p_food_018.json'),
    ('p_food_019', '百草味 每日坚果A款 750g/30袋 混合坚果零食礼盒', '百草味', '食品饮料', '坚果/零食', '食品饮料/坚果/零食', 118.0, 111.0, 157.0, 400, '4_食品生活/images/p_food_019_live.jpg', '{"product_id":"p_food_019","title":"百草味 每日坚果A款 750g/30袋 混合坚果零食礼盒","brand":"百草味","category":"食品饮料","sub_category":"坚果/零食","base_price":118.0,"image_path":"4_食品生活/images/p_food_019_live.jpg","skus":[{"sku_id":"s_p_food_019_1","properties":{"规格":"25g×30袋","版本":"经典混合坚果"},"price":118.0},{"sku_id":"s_p_food_019_2","properties":{"规格":"25g×30袋","版本":"家庭分享装"},"price":111.0},{"sku_id":"s_p_food_019_3","properties":{"规格":"25g×40袋","版本":"经典混合坚果"},"price":157.0},{"sku_id":"s_p_food_019_4","properties":{"规格":"25g×40袋","版本":"家庭分享装"},"price":148.0}],"rag_knowledge":{"marketing_description":"百草味这款每日坚果A款是专门搭配好的黄金配比混合坚果礼盒，单包25g刚好是成人每日摄入坚果的推荐量，里面包含巴旦木仁、夏威夷果仁、榛子仁、核桃仁这4种纯坚果，再搭配蔓越莓干、蓝莓干2种果干，没有多余的调味添加，坚果都是低温慢烘锁鲜，不会有油耗味。不管是通勤路上揣两袋当摸鱼小零食，给家里老人小孩当日常营养补给，还是办公室同事分着吃、周末带出门当露营小食都特别合适。目前有两个规格可选，30袋经典款刚好够吃整一个月，40袋家庭分享装更适合多口之家囤货。要注意开封后尽量当天吃完，没吃完的记得密封放阴凉干燥处，有坚果过敏情况的朋友千万别食用哦。","official_faq":[{"question":"百草味每日坚果A款里面具体都有哪些配料，有没有额外加盐加糖？","answer":"这款A款的配料是4种坚果加2种果干，分别是巴旦木仁、夏威夷果仁、榛子仁、核桃仁，搭配蔓越莓干和蓝莓干，全程没有额外添加食盐、白砂糖、香精或者防腐剂，坚果只用低温轻烘的工艺处理，最大程度保留本身的原香和营养，果干也只保留了水果本身的清甜，不会太甜腻，不管是控糖人群还是小朋友都可以放心吃，不用担心额外的调味负担。"},{"question":"25g×30袋的经典款和25g×40袋的家庭分享装，除了袋数之外还有其他区别吗？","answer":"这两个SKU除了总净含量和售价不同之外，配料、每袋的分量、礼盒的包装设计都是完全一致的，都是A款的经典配方，每袋固定25g的配比，30袋款总重750g售价118元，刚好满足单人连续吃30天的需求，很多上班族会选这个规格自己日常吃；40袋的家庭分享装总重1000g售价148元，性价比更高，适合一家三口或者朋友合租一起囤着分着吃，平均下来单袋价格更划算，两种都是新鲜日期生产的。"},{"question":"这款每日坚果的保存条件是什么，整盒未拆的情况下保质期有多久？","answer":"这款每日坚果未开封的情况下，放在阴凉干燥、避免阳光直射的地方常温保存就可以，不需要放冰箱冷藏，冰箱里的水汽反而容易让坚果受潮变软，整盒未拆封的保质期是180天，每一小袋都是独立充氮包装，能最大程度隔绝氧气和水汽，哪怕放在办公室抽屉里放半个月也不会变味受潮，要是已经拆开单袋的话，建议2小时内吃完，放久了坚果的脆度会下降，还容易沾染空气中的潮气变哈。"},{"question":"家里有3岁的小朋友能不能吃这款每日坚果A款？有没有容易卡噎的问题？","answer":"3岁以上已经有自主咀嚼能力的小朋友可以吃，这款里面的坚果都提前做了小颗切割处理，不会有整颗大果仁的情况，不容易卡喉咙，不过给小朋友吃的时候还是建议家长在旁边看护，让孩子慢慢嚼，不要边跑边吃。如果是3岁以下还没完全长好磨牙的小朋友，建议把果仁碾碎混到酸奶或者粥里再给孩子吃，既方便吞咽，也能补充坚果里的不饱和脂肪酸，给小朋友当日常加餐特别合适。"},{"question":"这款每日坚果A款的礼盒包装能不能直接用来送礼，要不要额外再装礼品袋？","answer":"这款本身就是专门做的礼盒款，外包装是百草味定制的烫金浮雕礼盒，颜值很高，正面印着清晰的每日坚果专属标识，侧面还有营养成分表和配料说明，整盒拎着大小刚好，不管是过节走亲戚给长辈送，还是给同事当福利送、给坐月子的朋友当伴手礼都完全拿得出手，不需要额外再买礼品袋，礼盒本身自带可提的拎手，拎着出门特别方便，很多客户买回去直接当员工端午中秋的福利，反馈都很好。"}],"user_reviews":[{"nickname":"小桃","rating":3,"content":"这次收到的货感觉品控有点不稳定，拆到第7袋的时候里面居然有一颗巴旦木仁是已经发苦的，明显是放久了的油耗味，跟客服反馈之后倒是很快给赔了那几袋的钱。但整盒30袋里有3袋的蔓越莓干粘成了一大块，撕开包装袋倒出来的时候果干都粘在袋底抠都抠不下来，以前买的老款都没遇到过这种情况，希望品牌之后能品控再抓严点，不然花一百多买总踩坑太闹心了。"},{"nickname":"阿泽","rating":5,"content":"回购第三箱了！这次直接买的40袋家庭装，放在玄关的收纳盒里，每天出门抓一袋塞包里刚好。每一袋的配比都很匀，坚果都脆生生的完全没有哈味，果干也不会太甜，我家上小学的儿子每天放学都主动要吃一袋，说比学校门口的薯片好吃多了。之前买过别的牌子的每日坚果，好多里面混好多占重量的花生，百草味这款A款完全没凑数的配料，吃着特别放心，活动价入的比超市划算太多。"},{"nickname":"阿晚","rating":3,"content":"买之前没注意看是A款，收到拆了两袋才发现，这款里面完全没有腰果，我之前一直吃的混合款是有腰果的，吃着特别不习惯。而且榛子仁的比例有点少，每袋翻半天只能找到一两颗，大部分都是巴旦木，果干的分量倒是给的挺多，我本身不太爱吃果干，等于每袋有小一半都是我不吃的东西，算下来性价比就很低了。客服说不能拆封退换，只能自己留着慢慢吃，以后买肯定得先看好配方。"},{"nickname":"大刘","rating":2,"content":"这次生产日期比我去年买的旧货早了快3个月，算下来到手离保质期只剩不到两个半月，我买的是30袋的款，本来想慢慢吃一个月，结果拆到后面几袋的时候，明显感觉坚果已经有点发潮变软，完全没有刚收到的时候脆了。找客服反应，人家说临期不在赔付范围内，明明我下单的时候商品页没标是临近保质期的批次，花100多买到这种快要过期的存货，体验真的特别差，以后再也不随便囤大盒的了。"}]}}'::jsonb, '4_食品生活/data/p_food_019.json'),
    ('p_food_020', '日清 合味道 海鲜风味 杯装方便面 79g×12 杯整箱', '日清', '食品饮料', '方便食品', '食品饮料/方便食品', 69.0, 69.0, 72.0, 200, '4_食品生活/images/p_food_020_live.jpg', '{"product_id":"p_food_020","title":"日清 合味道 海鲜风味 杯装方便面 79g×12 杯整箱","brand":"日清","category":"食品饮料","sub_category":"方便食品","base_price":69.0,"image_path":"4_食品生活/images/p_food_020_live.jpg","skus":[{"sku_id":"s_p_food_020_1","properties":{"容量":"79g/杯","数量":"12杯整箱","口味":"海鲜风味"},"price":69.0},{"sku_id":"s_p_food_020_2","properties":{"容量":"79g/杯","数量":"12杯整箱","口味":"混合口味装"},"price":72.0}],"rag_knowledge":{"marketing_description":"日清合味道海鲜风味整箱12杯装，是无数学生党、加班族私藏的速食刚需！每杯精准79g分量刚好管饱，不用自己拆调料包，粉包料包都预封在杯里，浇上沸水等3分钟就能吃。汤底是经典的海鱼熬制鲜味儿，混着细碎的模拟蟹柳、小虾和葱花，面条是日清特有的非油炸韧性麦芯面，久泡也不发坨。特别适合深夜赶方案的打工人、宿舍断电没法开火的学生，还有周末宅家不想点外卖的懒人当垫肚餐。建议泡的时候水位刚好到杯身标线，别加太多水冲淡鲜味，注意开封后如果发现杯盖鼓胀、面饼发霉千万别吃，整箱囤放要放在阴凉干燥处避开阳光直晒，放两三个月都不会坏。","official_faq":[{"question":"这款79g的海鲜风味合味道整箱里，每杯的配料包是单独分装的吗？","answer":"这款海鲜风味合味道没有单独分装的调料包哦，所有的海鲜风味粉料、脱水蔬菜、模拟蟹柳碎、小虾粒还有一点棕榈油，全部都提前封在面饼的空隙位置，不用你动手撕任何包装袋。你只需要撕开杯盖到预留的缺口位置，直接加入刚烧开的沸水，盖回杯盖等待3分钟就可以直接食用，完全不会出现撕调料包撒的满手都是的情况，赶时间的时候泡吃特别省心。"},{"question":"海鲜风味款和同链接的混合口味装，具体的配料区别在哪里？","answer":"咱们这款79g×12杯的海鲜风味整箱，12杯全都是统一的海鲜风味，汤底用的是鲣鱼、海藻提鲜的海鲜基底，配料里固定有脱水小虾、模拟蟹肉棒碎、少量葱花和胡萝卜丁。而72元的混合口味装是随机搭配海鲜、牛肉、猪骨、咖喱4种热门口味各3杯，每杯的配料都对应各自的风味，比如牛肉款会加牛肉粒、猪骨款会加浓白骨汤粉，大家可以根据自己是想固定吃爱喝的海鲜味，还是想尝不同口味来选。"},{"question":"这款海鲜风味合味道的面饼是不是油炸的，吃起来会不会特别油？","answer":"这款海鲜风味合味道用的是日清独创的低温热风干燥工艺制作的面饼，不属于传统高温油炸面饼，脂肪含量比普通油炸杯面低30%左右。你泡开之后几乎不会看到表层飘着厚厚的油花，汤底的鲜味儿大部分来自海鲜提取物，吃起来是清鲜不腻的口感，哪怕夏天没胃口吃重口的泡面，泡这杯也不会觉得闷得慌，连汤喝完也不会觉得嘴里发腻发苦。"},{"question":"整箱12杯的海鲜风味合味道，保质期有多久，囤货的话怎么存放比较好？","answer":"这款合味道整箱未开封的状态下，保质期是6个月，咱们仓库发的货都是最近1个月内生产的新鲜批次，到手之后算下来能放小半年不用急着吃完。存放的时候别放在阳台能晒到太阳的地方，也别放在厨房灶台边靠近高温的位置，找家里阴凉干燥的柜子角落平放就行，不要往上面压特别重的东西避免把面饼压碎，只要杯身密封没破损，过了保质期之前吃都完全没问题。"},{"question":"能不能用微波炉加热这款合味道的杯面，会不会有安全问题？","answer":"咱们这款合味道的杯身材质是食品级的聚苯乙烯，本身是适配沸水冲泡设计的，不建议大家直接把整杯放进微波炉加热，要是想吃更烫更浓郁的口感，可以先把面饼和配料倒在自己家里可微波的陶瓷或者玻璃碗里，加沸水之后放微波炉转1分钟就行。直接放原杯进微波炉的话，高温容易让杯身变形，还可能析出对身体不好的物质，大家千万别图省事直接整杯加热哦。"},{"question":"这款海鲜风味的整箱装，适合给小朋友当加餐吃吗，钠含量会不会太高？","answer":"这款海鲜风味合味道每杯的钠含量大概是1300mg，属于常规速食的钠含量水平，不建议3岁以下的小朋友直接整杯连汤吃完。如果要给家里的大朋友或者学龄小朋友当临时加餐，可以泡的时候比杯身标注的水位线多倒小半杯开水，稀释掉一部分汤底的咸味，也可以自己加一点新鲜的青菜、打散的鸡蛋碎进去煮两分钟，既能降低整体的钠占比，营养也会更丰富，偶尔当应急加餐吃完全没问题。"}],"user_reviews":[{"nickname":"阿泽","rating":3,"content":"这次收到的整箱12杯，有三四杯的面饼都碎成渣了，拿出来的时候碎渣从杯缝里往外掉，泡完根本找不到完整的面条，吃起来都是碎糊糊的。问了客服说是运输途中快递暴力摔的，虽说不是产品本身的问题，但囤整箱本来就是想方便拿完整的杯面吃，碎成这样体验真的很差，也没给啥像样的补偿，以后不敢随便囤整箱了，还是每次买几杯算了。"},{"nickname":"小棠","rating":4,"content":"整体味道还是我从小吃到大的海鲜味儿，鲜得很，三分钟泡开就能吃特别方便，本来想直接给好评的，但这次收到的货离保质期只剩不到2个月了，买整箱12杯本来是想囤着慢慢吃，结果算下来差不多两天就得吃一杯，我平时也不是顿顿吃泡面，最后两三杯估计得赶着临期才能吃完。要是发货能给发至少剩4个月以上保质期的批次就完美了，这点确实有点小遗憾。"},{"nickname":"阿凯","rating":2,"content":"这次买的海鲜风味不知道是不是批次不对，吃起来海鲜味特别淡，汤喝着跟加了半杯没味道的白开水似的，里面的小虾粒数来数去不到5个，连平时标志性的蟹柳碎都几乎找不到。之前在超市单买的同款明明鲜味儿特别浓，汤都能喝完，这次整箱12杯全都是这个味儿，花六十多买的感觉特别不值，以后再也不在网上囤整箱的了。"},{"nickname":"阿米","rating":3,"content":"我是冲着合味道不用撕调料包的特点买的，结果这次有两杯的密封膜没封严，拆开杯盖之后发现粉料都潮了结块了，面饼摸起来也软软的，根本不敢吃。找客服只给退了那两杯的钱，剩下的十杯倒是没问题，但整箱囤货碰到两杯坏的，本来想留着应急的，平白少了两个库存，体验真的不太好，感觉品控还是没之前严了。"},{"nickname":"小俞","rating":5,"content":"真的是我常年囤货的刚需速食！每次加班到九点多回到出租屋，懒得点外卖就泡一杯，刚好79g的量吃着饱又不会撑得难受，不用撕一堆调料包太爽了，浇上开水刷两分钟短视频就能吃，海鲜汤底鲜得刚刚好，连汤我每次都喝大半杯。这次整箱买算下来单杯比超市便宜快两块钱，日期也特别新鲜，放我办公桌底下囤着，再也不用加班的时候跑下楼买泡面了，太省心了。"}]}}'::jsonb, '4_食品生活/data/p_food_020.json'),
    ('p_food_021', '康师傅 红烧牛肉面 方便面袋装 114g×5 袋 五连包整袋', '康师傅', '食品饮料', '方便食品', '食品饮料/方便食品', 18.9, 18.9, 68.0, 300, '4_食品生活/images/p_food_021_live.jpg', '{"product_id":"p_food_021","title":"康师傅 红烧牛肉面 方便面袋装 114g×5 袋 五连包整袋","brand":"康师傅","category":"食品饮料","sub_category":"方便食品","base_price":18.9,"image_path":"4_食品生活/images/p_food_021_live.jpg","skus":[{"sku_id":"s_p_food_021_1","properties":{"口味":"红烧牛肉面","规格":"114g×5袋","包装":"五连包"},"price":18.9},{"sku_id":"s_p_food_021_2","properties":{"口味":"红烧牛肉面","规格":"114g×10袋","包装":"家庭装"},"price":35.0},{"sku_id":"s_p_food_021_3","properties":{"口味":"红烧牛肉面","规格":"114g×20袋","包装":"整箱装"},"price":68.0}],"rag_knowledge":{"marketing_description":"从小到大吃的经典康师傅红烧牛肉面来啦！每袋足足114g，面饼搭配秘制红烧牛肉酱包，还有脱水蔬菜粒和浓缩骨汤粉，煮出来汤汁浓得挂面，咸香带点微甜的老味道完全没改版。不管是熬夜追剧的学生党、加班到深夜的打工人，还是周末不想开火的独居青年都合适。赶时间的时候开水泡3分钟就能吃，有空的话加个煎蛋烫把青菜，直接升级成馆子级别的美味。现在有五连包、10袋家庭装还有20袋整箱装可以选，囤一次能吃大半个月。要注意的是里面的酱包油脂含量不低，肠胃弱的朋友别放全，开封之后要尽快吃完，别放潮了影响口感哦。","official_faq":[{"question":"这款114g的康师傅红烧牛肉面，每袋的配料具体都包含什么？","answer":"每袋114g的配置是90g左右的油炸小麦粉面饼，搭配3个独立料包：首先是经典红烧牛肉风味酱包，用慢熬牛板筋油搭配酱油、冰糖熬出标志性的红亮汤汁基底，然后是菜粉混合包，包含脱水牛肉粒、胡萝卜丁、青葱段和汤粉调味包，最后还有一小包芝麻香油提香，没有多余的香精味，都是大家熟悉的老味道，泡开之后每一口面都能挂上浓郁的汤汁。"},{"question":"三个不同规格的康师傅红烧牛肉面，分别适合什么场景选购？","answer":"咱们的三款规格适配不同需求：114g×5袋的五连包适合第一次回购想尝鲜，或者平时只是偶尔当宵夜加餐的单身用户，半个月内就能吃完不会放潮；114g×10袋的家庭装适合两口小家庭，平时不想开火当简餐，两周左右吃完也新鲜；114g×20袋的整箱装适合合租室友凑单、住校学生囤货，或者经常需要加班备餐的用户，算下来单袋成本更低，囤一次能吃一整个多月很划算。"},{"question":"这款袋装红烧牛肉面除了直接泡，还有什么好吃的进阶吃法推荐？","answer":"除了常规开水泡3分钟的吃法，还推荐两个超简单的进阶做法：第一种是煮面，水开之后放面煮2分钟捞出来，过一遍凉水面会更筋道，重新烧小半锅水把料包放进去煮成汤，撒上点葱花加个煎蛋，比泡出来香一倍；第二种是炒面，面煮到8分熟捞出来过凉水沥干，倒一点点油把面和酱包翻匀，加点火腿肠丝和青菜叶，干香入味当正餐吃完全没问题，比外卖健康又省事。"}],"user_reviews":[{"nickname":"阿明","rating":1,"content":"这次收到的五连包太离谱了，拆开第一袋面饼就有明显的油哈味，明显是放久了氧化了。我之前一直买这个款从来没遇到过，以为是个例，连拆了两袋味道都不对，料包的酱还漏了小半袋在包装里黏糊糊的。找客服说只能退单包的钱，我买的整包都不敢吃，最后折腾半天才退全款，体验真的太差了，以后不敢随便囤货了。"},{"nickname":"小桃","rating":1,"content":"收到货数了一下，10袋家庭装居然少了一袋，找客服核对了快递称重说没问题，让我自己拆所有包装翻，翻了半天连个影子都没找到。而且有两袋的面饼边缘都碎成渣了，泡出来根本没有完整的面条，大半都是碎面渣子，吃起来口感散得不行。之前线下超市买的从来没碎这么严重，这包装就套了个薄塑料袋，运输过程全给晃碎了，太不值了。"},{"nickname":"阿凯","rating":2,"content":"整体味道其实还是小时候的味道，就是觉得现在的分量有点虚，标注的114g，面饼捏起来感觉比以前薄了不少，我一个男生泡两袋才刚吃饱，一袋吃完半小时就饿了。酱包的味道也比以前淡了点，泡出来的汤没有以前那么浓，得自己额外加点盐才有味。价格倒是比超市便宜点，但是算下来要吃两袋才能饱，其实反而更贵了，有点不太划算。"},{"nickname":"月月","rating":5,"content":"我真的是康师傅红烧牛肉面的死忠粉，囤了整箱放在出租屋里，加班到十点多回来泡上一袋，加个我提前腌好的溏心蛋，汤浓面香，一口下去整个人都暖过来了。这次的整箱装价格比楼下便利店单买便宜快一半，每袋都完好没碎，酱包也没漏，生产日期都是半个月内的新货，吃起来就是熟悉的老味道，一点都没变味，以后就固定在这家囤货了。"},{"nickname":"阿泽","rating":2,"content":"本来是冲着经典味道买的，结果收到货发现其中三袋的料包居然少了菜包，只有粉包和酱包，泡出来的面光有咸味一点牛肉粒和青菜碎都没有，吃起来寡淡得很，完全不是平时的味道。找客服只给补了三块钱差价，也没补发缺失的料包，剩下的几袋我每次拆开都要先检查料包齐不齐，太麻烦了，下次不会再来买了。"}]}}'::jsonb, '4_食品生活/data/p_food_021.json'),
    ('p_food_022', '三顿半 冷萃超即溶 黑咖啡 6颗装 冷泡即溶精品速溶咖啡', '三顿半', '食品饮料', '咖啡', '食品饮料/咖啡', 58.0, 58.0, 108.0, 200, '4_食品生活/images/p_food_022_live.jpg', '{"product_id":"p_food_022","title":"三顿半 冷萃超即溶 黑咖啡 6颗装 冷泡即溶精品速溶咖啡","brand":"三顿半","category":"食品饮料","sub_category":"咖啡","base_price":58.0,"image_path":"4_食品生活/images/p_food_022_live.jpg","skus":[{"sku_id":"s_p_food_022_1","properties":{"数量":"6颗装","口味":"冷萃黑咖"},"price":58.0},{"sku_id":"s_p_food_022_2","properties":{"数量":"12颗装","口味":"冷萃黑咖"},"price":108.0}],"rag_knowledge":{"marketing_description":"三顿半这款冷萃超即溶黑咖啡，专门用冷萃工艺萃取精品阿拉比卡咖啡豆，全程低温锁香，没有普通速溶的焦苦感，入口是清润的坚果淡香，几乎没有酸涩味。6颗便携小杯装完全无添加糖、无植脂末，纯黑咖啡配方，控糖健身党、日常靠咖啡续命的打工人、喜欢户外出行的咖啡爱好者都适配。办公室赶方案丢进矿泉水瓶摇3秒就能泡好，居家配冰块就是门店级冰冷萃，周末露营塞包里完全不占地方。建议用200-300ml常温水/冰水冲调，热泡也不发酸，开封后尽快饮用，储存在阴凉干燥处避免阳光直晒，开罐后注意密封防潮。现在还有6颗尝鲜装和12颗囤货装可选，性价比超高。","official_faq":[{"question":"这款冷萃超即溶黑咖啡和三顿半其他款的即溶黑咖啡风味上有什么区别？","answer":"这款冷萃款是专门模拟12小时低温冷萃的萃取工艺，从咖啡豆研磨开始全程控温，只提取豆子里甜度高、苦味柔和的风味物质，完全避开高温萃取容易带出的焦苦、涩感，入口会更顺滑清润，带淡淡的坚果、焦糖甜感，完全没有普通热萃速溶的尖锐酸感，哪怕直接用冰水冲也能快速溶解出匀润的口感，不用等待焖泡，和门店现做冷萃的风味还原度能达到90%以上。"},{"question":"这款6颗装的冷萃黑咖可以用热牛奶直接冲调吗？会不会结块？","answer":"完全可以用热牛奶冲调，这款超即溶的冻干粉做了超微粉碎处理，表面是多孔的速溶结构，哪怕是60-70度的热牛奶倒进去，不用搅拌3秒就能完全溶解，不会出现结块沉底的情况，冲出来就是丝滑的冷萃风味拿铁，比普通热萃咖啡冲出来的拿铁少了酸感，奶香味和咖啡的坚果香融合得更协调，怕喝黑咖的苦的朋友，完全可以直接搭配常温奶、热燕麦奶做奶咖，风味表现都很出彩。"},{"question":"这款冷萃黑咖的咖啡因含量大概是多少？睡前3小时喝会不会影响睡眠？","answer":"每一颗这款冷萃黑咖啡的净含量是2g，对应咖啡因含量大概在120-150mg左右，差不多等于一杯中杯美式的咖啡因浓度，正常对咖啡因耐受的用户，睡前3小时喝基本不会有失眠的问题，但如果是平时很少碰咖啡、咖啡因特别敏感的人群，还是建议尽量在下午3点前饮用，避免因个人体质差异出现入睡困难的情况，也可以尝试半颗冲泡，降低咖啡因摄入浓度的同时也能喝到冷萃风味。"},{"question":"不同规格的6颗装和12颗装冷萃黑咖，咖啡豆原料是不是一样的？","answer":"两款不同规格的冷萃黑咖用的是完全一模一样的原料和生产工艺，都是选用同一批次的精品级阿拉比卡豆，经过同一条低温冷萃冻干生产线加工，风味、咖啡因含量、溶解速度完全没有区别，定价不同只是因为规格的批量优惠，6颗装定价58元是适合第一次尝试的用户尝鲜，避免买多了不合口味浪费，12颗装定价108元相当于单颗成本降到9元，适合日常高频喝的老用户囤货，性价比会更高。"}],"user_reviews":[{"nickname":"阿泽","rating":2,"content":"这次收到的6颗装里有两颗罐身居然漏了点咖啡粉，倒出来的时候发现里面的粉好像有点受潮结块，冲的时候溶解速度比之前买的慢好多，摇了半天才化开，口感喝着也有点发苦，没有之前那种淡淡的坚果香。58块钱6颗价格不算便宜，还遇到品控问题挺失望的，找客服说给我退两颗的钱，整体体验不太好，本来是冲着老牌子买的，这次有点踩雷。"},{"nickname":"小柚","rating":5,"content":"真的太爱这款冷萃即溶咖啡了！我平时上班揣两颗在通勤包里，到公司拧开矿泉水瓶丢进去摇两下就能喝，完全不用等，入口完全没有普通速溶的焦酸味，清润的带点焦糖甜，我这种喝不了苦咖啡的人直接冲冰水都能接受，最近健身期无糖无添加太合适了，连喝了一周掉秤都挺顺畅，这次喝完准备直接入12颗装囤货，比天天点外卖咖啡划算太多。"},{"nickname":"阿凯","rating":3,"content":"之前看朋友推荐买的6颗装尝鲜，整体风味确实还行，冷泡挺方便的，就是58块钱6颗算下来快10块钱一颗了，性价比实在有点低。我平时每天都要喝两杯咖啡，算下来一个月要花大几百在这上面，喝着和我之前买的几十块钱一大罐的冷萃速溶差别没有想象中大，尝个鲜可以，让我长期买确实有点负担不起，偶尔出差带两颗应急还行，日常喝还是选更便宜的款算了。"}]}}'::jsonb, '4_食品生活/data/p_food_022.json'),
    ('p_food_023', '雀巢 金牌 冻干速溶咖啡 100g 瓶装 黑咖啡', '雀巢', '食品饮料', '咖啡', '食品饮料/咖啡', 42.0, 36.0, 78.0, 400, '4_食品生活/images/p_food_023_live.jpg', '{"product_id":"p_food_023","title":"雀巢 金牌 冻干速溶咖啡 100g 瓶装 黑咖啡","brand":"雀巢","category":"食品饮料","sub_category":"咖啡","base_price":42.0,"image_path":"4_食品生活/images/p_food_023_live.jpg","skus":[{"sku_id":"s_p_food_023_1","properties":{"容量":"100g","包装":"玻璃瓶装"},"price":42.0},{"sku_id":"s_p_food_023_2","properties":{"容量":"200g","包装":"经济装"},"price":72.0},{"sku_id":"s_p_food_023_3","properties":{"容量":"100g","包装":"经济装"},"price":36.0},{"sku_id":"s_p_food_023_4","properties":{"容量":"200g","包装":"玻璃瓶装"},"price":78.0}],"rag_knowledge":{"marketing_description":"这款雀巢金牌冻干速溶黑咖啡，用的是先进的低温冻干锁香技术，把阿拉比卡咖啡豆的焦香和坚果香气完整留住，完全不像普通速溶的酸涩感。配料表只有纯咖啡粉，没有额外添加糖和植脂末，喝着完全无负担。不管是早八人赶通勤冲一杯消水肿，下午办公室摸鱼醒神，还是健身前喝一杯提升燃脂效率都超合适。100g玻璃瓶装的密封性特别好，每次喝舀1-2勺用85℃左右的温水冲开就行，怕苦的加冰加燕麦奶都很搭。注意开封后要放在阴凉干燥处密封保存，别让水汽跑进去结块，按每天喝1杯算100g装大概能喝1个多月，想更划算直接入200g经济装更省心。","official_faq":[{"question":"这款雀巢金牌冻干黑咖啡和普通款的雀巢速溶黑咖啡口感差别大吗？","answer":"差别还是很明显的，普通款大多采用高温喷雾干燥工艺，香气流失多，入口容易带点焦苦的涩感，这款金牌用的是低温冻干技术，在零下40℃左右的环境里把萃取的咖啡液直接冻成固态再升华除水，完整保留了阿拉比卡咖啡豆的原生花果香和坚果尾韵，冲开之后香气特别浓郁，入口顺滑不喇喉咙，几乎没有杂味，哪怕是直接兑冷水也能快速溶解，不会出现结块挂杯的情况。"},{"question":"100g的玻璃瓶装和200g的经济装除了容量之外，咖啡本身品质有区别吗？","answer":"两款的咖啡粉原料、制作工艺完全是一模一样的，都是同一条生产线产出的纯阿拉比卡冻干咖啡粉，没有任何品质差异，区别只在于包装规格：100g是带螺旋盖的透明玻璃瓶，放在办公室桌面随拿随用特别方便，喝完的空瓶子还能用来装小零食或者收纳别针回形针这类小物件；200g是密封铝箔袋经济装，性价比更高，适合日常咖啡消耗量比较大、已经有合适密封容器的老用户囤货，平均每克的单价比瓶装要便宜近3成。"},{"question":"这款黑咖啡每天最多喝多少杯比较合适，会不会有心悸的情况？","answer":"这款每2g咖啡粉的咖啡因含量大概在60-70mg左右，符合正常速溶黑咖啡的标准含量，健康成年人每天摄入不超过400mg咖啡因都是安全的，换算下来就是一天喝5-6杯也没问题。但要是平时很少喝咖啡、对咖啡因比较敏感的人，建议第一天先冲半杯试试水，不要空腹一次性喝太浓的，不然确实可能出现心跳发慌、手抖的情况，也不建议晚上睡前3小时内喝，避免影响睡眠质量。"},{"question":"开封之后的咖啡粉如果不小心受潮结块了，还能继续喝吗？","answer":"如果只是刚受潮、咖啡粉结成轻轻一捏就碎的松散小块，没有出现发霉、变味、长白毛的情况，把它放在干燥通风的地方晾几小时，之后尽快喝完是完全没问题的。但要是结块已经硬到捏不动，甚至打开罐子能闻到霉味、酸味，就说明咖啡粉已经被微生物污染变质了，千万别舍不得扔，喝了容易闹肚子。平时开封之后每次用完一定要把瓶盖拧紧，别用沾了水的勺子挖粉，就能很大程度避免受潮结块。"},{"question":"这款冻干黑咖啡可以用来做冷萃或者气泡美式这类花式饮品吗？","answer":"完全可以，它的溶解度特别优秀，不管是冷水、气泡水还是冰牛奶都能快速化开，不会有沉底的粉渣。做冷萃的话，取2勺咖啡粉倒进装满冷水的瓶子里，放冰箱冷藏4小时就能得到不输门店的冷萃咖啡，省了冷萃壶的麻烦；做气泡美式就更简单了，先在杯子里倒半杯气泡水加冰块，再把咖啡粉撒进去搅两下，气泡会带着咖啡的香气直往鼻尖钻，比用普通速溶冲出来的风味层次丰富太多，还能自己DIY加柠檬片、桂花糖浆调出专属口味。"}],"user_reviews":[{"nickname":"阿远","rating":2,"content":"这次收到的瓶装咖啡粉总感觉品质不对，倒出来的粉不是平时那种蓬松的冻干颗粒，好多碎末，冲的时候挂杯特别严重，杯底留了一圈化不开的渣，喝起来的焦苦味特别重，完全没有之前买的那种坚果香，喝了半杯胃里就反酸了，找客服问也只说批次不同正常，明明之前喝了大半年都没遇过这种情况，这次体验真的挺失望的。"},{"nickname":"小柚","rating":5,"content":"这罐我已经回购第三瓶了，早八赶课来不及去楼下咖啡店，挖一勺用温水冲开30秒就能搞定，香气直接飘满整个宿舍，完全没有普通速溶的酸涩味，我习惯早上喝完再去跑半小时步，消水肿效果超明显，一上午脸都不肿，透明玻璃瓶颜值还很高，放书桌上当摆件都好看，喝完我还留着装自己摘的干花，性价比真的甩同价位其他黑咖啡好几条街。"},{"nickname":"阿凯","rating":5,"content":"作为每天至少两杯咖啡的程序员，我囤了两大罐这个咖啡，下午写代码犯困的时候冲一杯，比喝甜滋滋的奶茶健康多了，没有额外加糖，兑点冰燕麦奶就是外面卖的拿铁，算下来一杯成本才一块多，冻干颗粒遇水直接就化，从来没出现过结块的情况，喝了大半年也没觉得腻，最近直接囤了200g的经济装，够我喝两个多月，太适合我们这种咖啡刚需党了。"}]}}'::jsonb, '4_食品生活/data/p_food_023.json'),
    ('p_food_024', '元气森林 白葡萄味 苏打气泡水 480ml×12 0糖0脂0卡', '元气森林', '食品饮料', '碳酸饮料', '食品饮料/碳酸饮料', 52.0, 48.0, 100.0, 400, '4_食品生活/images/p_food_024_live.jpg', '{"product_id":"p_food_024","title":"元气森林 白葡萄味 苏打气泡水 480ml×12 0糖0脂0卡","brand":"元气森林","category":"食品饮料","sub_category":"碳酸饮料","base_price":52.0,"image_path":"4_食品生活/images/p_food_024_live.jpg","skus":[{"sku_id":"s_p_food_024_1","properties":{"口味":"白葡萄味","容量":"480ml","数量":"12瓶","包装":"整箱装"},"price":52.0},{"sku_id":"s_p_food_024_2","properties":{"口味":"白葡萄味","容量":"480ml","数量":"12瓶","包装":"量贩装"},"price":48.0},{"sku_id":"s_p_food_024_3","properties":{"口味":"白葡萄味","容量":"480ml","数量":"24瓶","包装":"整箱装"},"price":100.0},{"sku_id":"s_p_food_024_4","properties":{"口味":"白葡萄味","容量":"480ml","数量":"24瓶","包装":"量贩装"},"price":96.0}],"rag_knowledge":{"marketing_description":"夏天怕喝甜饮料长胖的朋友看过来！这款元气森林白葡萄味苏打气泡水，核心就是0糖0脂0卡的清爽配方，用赤藓糖醇替代普通蔗糖，入口是沁爽的白葡萄鲜果香气，没有人工甜味剂的齁感，细密的气泡在舌尖炸开的感觉特别解腻。不管是上班族下午摸鱼解乏、健身后补水、家庭聚餐解辣解腻，还是朋友露营聚会分享都超合适，整箱囤性价比更高。建议冷藏后口感更佳，开封后尽量2小时内喝完避免气泡散掉，注意未成年小朋友不建议大量饮用碳酸类饮品，肠胃敏感人群也不要空腹猛喝哦。","official_faq":[{"question":"这款白葡萄味气泡水喝起来会不会有明显的代糖怪味？","answer":"完全不会有常规代糖的发苦后味，我们选用的是纯度99.5%以上的赤藓糖醇，搭配模拟真实白葡萄果香的食用香精，调整了7次风味配比才最终定版，入口是鲜摘晴王葡萄的清甜感，气泡刚入口时的刺激感还能冲淡代糖的残留感，大部分喝过的用户反馈几乎和吃新鲜冰镇葡萄的味道接近，完全不会出现喝完嘴里发涩发苦的情况，就算平时不爱喝代糖饮品的人也能轻松接受。"},{"question":"整箱装的480ml*12瓶和量贩装24瓶分别适合什么场景囤货？","answer":"12瓶的常规整箱装总容量是5.76L，刚好适合独居或者2人小家庭囤一周左右的饮用量，放在办公室工位边和同事分也刚好不会剩太多，保质期内完全能喝完不会浪费。24瓶的量贩装总容量接近12L，适合三人以上的家庭、经常组织朋友野餐露营的用户，或者开小型便利店、工作室需要给员工准备日常饮品的采购，算下来单瓶价格只要4块钱，比单独单瓶买便宜近1块，长期喝的话性价比高很多，囤一次能喝半个月左右。"},{"question":"这款白葡萄味气泡水里的气泡能维持多久，开封后容易跑气吗？","answer":"我们在灌装的时候是采用的高压等压灌装工艺，每瓶的含气量稳定在3.5倍左右，未开封放在阴凉避光处存放的话，就算距离生产还有3个月，打开之后的气泡还是很足的。正常开封后拧紧瓶盖放在冰箱冷藏，24小时内喝气泡感还能保留80%左右，如果敞开放在常温下，大概2个小时气泡就会基本散尽变成没有气泡的甜水，所以建议大家开瓶之后尽快喝完，没喝完一定要把瓶盖拧紧再冷藏存放。"},{"question":"减脂期喝这款气泡水真的完全不会产生热量影响减重吗？","answer":"这款气泡水的营养成分表明确标注每100ml能量为0千焦，碳水化合物含量也几乎可以忽略，用的赤藓糖醇是人体不会参与代谢的甜味物质，喝进去之后只会通过尿液直接排出体外，完全不会转化成热量或者堆积成脂肪，就算你一天喝3瓶480ml的总量，摄入的总热量也不到2大卡，完全可以忽略不计，减脂期嘴馋想喝带味道的气泡饮料完全可以放心喝，不会拖慢减重进度。"},{"question":"这款白葡萄味气泡水整箱发货的时候会有破损漏液的情况吗？破损了怎么处理？","answer":"我们的整箱包装用的是加厚五层瓦楞纸箱，每瓶之间还有对应的卡槽隔开，运输过程中还会在外层缠绕缓冲气泡膜，正常快递暴力运输情况下的破损率不到0.1%，几乎很少出现漏液情况。如果大家收到货之后发现有瓶子裂了、漏液的问题，只需要在签收之后24小时内联系客服，上传破损的照片和视频凭证，我们会直接按照破损的瓶数给你退款，不用把破损的商品寄回来，处理流程非常简单不用大家多费心。"},{"question":"这款白葡萄味气泡水有没有添加防腐剂，保质期是多久？","answer":"这款白葡萄味苏打气泡水完全没有添加任何山梨酸钾、苯甲酸钠类的防腐剂，靠着密封高压灌装和本身的酸性环境实现长期保质，常温未开封放在阴凉避光、温度不超过30度的环境下，保质期是12个月，完全可以放心囤货。如果存放的时候长期放在太阳底下暴晒，瓶身的温度超过50度，不仅会让气泡快速散失，还可能影响果香的风味，所以大家存放的时候避开阳台、灶台这类高温向阳的位置就好。"}],"user_reviews":[{"nickname":"阿凯","rating":1,"content":"这次收到的整箱12瓶大半都气跑光了，打开第一瓶的时候完全没有气泡的感觉，就像带点甜味的白葡萄糖水，喝起来寡淡得要死，问了客服说可能是运输过程中被暴晒过，退了我几瓶的钱但剩下的半箱根本没法喝，之前买过好多次这次体验真的太差了，花52块钱买一箱没气的甜水，以后再也不从这家囤货了，太闹心。"},{"nickname":"小桃","rating":5,"content":"我真的是元气森林白葡萄味的死忠粉！这次囤了24瓶的量贩装平均下来单瓶才4块钱，放在冰箱里冰上半小时拿出来，喝一口满满的葡萄清香，气泡绵密又够劲，吃火锅撸串的时候配它解辣又解腻，0糖0脂喝多了也不怕胖，之前每次吃晚饭喝可乐都要担心热量超标，现在换成这个一天喝两瓶都毫无负担，太对我胃口了。"},{"nickname":"阿泽","rating":5,"content":"办公室几个同事凑单买了两箱白葡萄味的，放冰箱里大家下午摸鱼的时候拿一瓶，比喝奶茶健康多了，白葡萄的味道特别清爽，没有那些花里胡哨的杂味，气泡在嘴里炸开的感觉瞬间就能把下午的困意冲没，我们算过量贩装的价格比楼下超市便宜快一半，之后准备每个月都拼一单，太适合我们这种怕胖又爱喝带气饮料的打工人了。"},{"nickname":"朵朵","rating":2,"content":"这次收到的货日期有点不太好，距离保质期只剩不到2个月了，12瓶我本来打算慢慢喝，现在得赶在过期之前硬喝完，而且有两三瓶的味道尝起来有一点点发闷，没有之前喝的新鲜日期的葡萄味那么清新，气泡也比之前买的弱不少，找客服反馈只给补了5块钱优惠券，感觉不太值这个价格，之后还是买临期更近的新货比较好。"}]}}'::jsonb, '4_食品生活/data/p_food_024.json'),
    ('p_food_025', '农夫山泉 水溶C100 柠檬味饮料 445ml×15 瓶装 维生素C饮品', '农夫山泉', '食品饮料', '功能饮料', '食品饮料/功能饮料', 89.0, 84.9, 139.0, 400, '4_食品生活/images/p_food_025_live.jpg', '{"product_id":"p_food_025","title":"农夫山泉 水溶C100 柠檬味饮料 445ml×15 瓶装 维生素C饮品","brand":"农夫山泉","category":"食品饮料","sub_category":"功能饮料","base_price":89.0,"image_path":"4_食品生活/images/p_food_025_live.jpg","skus":[{"sku_id":"s_p_food_025_1","properties":{"口味":"柠檬味","容量":"445ml","箱规":"15瓶","包装":"整箱装"},"price":89.0},{"sku_id":"s_p_food_025_2","properties":{"口味":"柠檬味","容量":"445ml","箱规":"15瓶","包装":"量贩装"},"price":84.9},{"sku_id":"s_p_food_025_3","properties":{"口味":"柠檬味","容量":"445ml","箱规":"24瓶","包装":"整箱装"},"price":139.0},{"sku_id":"s_p_food_025_4","properties":{"口味":"柠檬味","容量":"445ml","箱规":"24瓶","包装":"量贩装"},"price":135.0}],"rag_knowledge":{"marketing_description":"农夫山泉水溶C100柠檬味饮料，每瓶足足添加相当于3个新鲜柠檬的维C含量，酸甜度刚好卡在黄金比例，不会像纯柠檬汁那样涩口酸牙，也没有普通甜饮料的齁腻感，入口是清爽的鲜柠檬香气，余味还带着淡淡的柑橘清苦感。特别适合日常通勤族、学生党、运动爱好者饮用，摸鱼时配外卖、健身后补充电解质、野餐聚会分着喝都超合适，没有添加人工合成维C成分，天然萃取的维生素C好吸收，平时上班赶时间来不及吃水果，揣一瓶就能补够每日所需的部分维C。建议冰镇后口感更佳，开封后尽量24小时内喝完，避免阳光直晒存放，糖分控制得很友好，怕胖的朋友日常当调味水喝也无负担。","official_faq":[{"question":"这款水溶C100柠檬味饮料，每瓶实际添加的维生素C含量具体是多少？","answer":"这款445ml装的柠檬味水溶C100，每瓶的维生素C添加量约为100mg，刚好满足中国营养学会推荐的成年人每日维C基础需求量，相当于3个新鲜黄柠檬的平均维C含量，我们采用的是从新鲜柑橘类水果中萃取的天然维C成分，不是人工合成的VC添加剂，性质更温和，人体吸收效率也更高，日常来不及吃新鲜水果的时候喝一瓶，就能快速补充当日所需的部分维C，不会给身体造成额外代谢负担。"},{"question":"整箱装的水溶C100发货时会有破损漏液的情况吗，售后怎么处理？","answer":"我们的整箱产品发货前都会做二次加固处理，外层加定制的加厚气泡缓冲层，再套上硬快递纸箱，内部每瓶之间都有分隔卡固定，正常运输情况下几乎不会出现漏液破损问题。如果您收货时发现有瓶身开裂、漏液、瓶盖翘起导致饮料变质的情况，只需要在签收后24小时内拍好问题照片联系客服，我们会按照破损的瓶数给您等额退款或者补发对应数量的新品，不需要您把破损的商品寄回，省掉来回折腾的麻烦，尽可能保障您的购物体验。"},{"question":"这款柠檬味水溶C100的含糖量高不高，控糖人群可以喝吗？","answer":"这款水溶C100的每100ml含糖量约为4.5g，整瓶445ml的总糖量在20g左右，比普通碳酸饮料的含糖量低近一半，酸甜的口感大多来自新鲜柠檬本身的清鲜风味，额外添加的精制糖占比很低。如果是严格控糖的人群，每天喝半瓶以内基本不会造成糖分摄入超标，不建议直接替代白水大量饮用，血糖不稳定的人群也建议咨询医生后按需选择，相比市面上其他同价位的果味饮料，它的糖分控制已经做得相当友好了。"}],"user_reviews":[{"nickname":"阿凯","rating":2,"content":"这次收到的整箱货，好多瓶的瓶身都被挤得凹进去一大块，虽然没漏液但拿在手里怪怪的，喝起来味道倒是没什么问题，可瓶身凹进去之后放包里很容易漏空气进去，没开封的也感觉密封性受了影响。本来是冲着整箱囤能放久一点，这下凹瓶的那几瓶总担心会提前变味，联系客服只给退了5块钱的优惠券，感觉处理得不是很让人满意，下次还是买便利店单瓶的算了。"},{"nickname":"小夏","rating":3,"content":"等了三天才送到，打开箱子就闻到一股怪味，有两瓶的瓶盖没拧紧撒出来半瓶，流的箱子里黏糊糊的，剩下的13瓶虽然没漏，但瓶身外面全沾了黏糊糊的饮料，我一瓶一瓶冲了半天才擦干净。味道倒是我常喝的那个熟悉的柠檬味，不然直接就退了，就是这次的快递包装太不走心了，里面连个缓冲的东西都没有，饮料在箱子里晃来晃去的，洒的到处都是，体验真的挺一般的。"},{"nickname":"大张","rating":1,"content":"收到货喝第一口直接懵了，味道完全不对，酸甜味特别奇怪，喝着有种发馊的怪味，看了下瓶身的生产日期，居然还有半个月就到期了，整整15瓶临期货，页面上根本没标注是临期商品。我找客服理论，对方说临期不属于质量问题不给退，喝了一口闹了两天肚子，剩下的整箱直接扔了，花快九十块买一堆临期变质边缘的饮料，太坑人了，以后绝对不会再来这家店买。"},{"nickname":"月月","rating":1,"content":"标注的是445ml×15瓶整箱，我数了好几遍只有13瓶，少了整整两瓶，找客服说调监控核实，调了三天最后只赔了两瓶的差价，一点道歉的意思都没有。而且饮料喝着感觉比之前在超市买的甜很多，维C的那种清爽感几乎没了，不知道是不是储存不当影响了风味，九十块钱买13瓶味道不对的饮料，算下来比超市单瓶买还贵，真的太闹心了，以后再也不在网上囤这款饮料了。"},{"nickname":"阿柚","rating":5,"content":"我真的是水溶C的忠实老粉，喝了快十年了，这次囤整箱比超市单买划算好多！快递送来箱子严严实实的，每瓶都完好无损，冰了之后喝一口，那个清爽的柠檬酸甜味直接炸开，一点都不齁，酸得很正，刚好解夏天吃火锅、小龙虾的腻。平时上班下午困了来一瓶，补维C还能提神，比喝咖啡健康多了，15瓶刚好够我和室友喝一周多，已经加购物车准备下次回购24瓶的量贩装了，太对我胃口了。"},{"nickname":"小橙","rating":5,"content":"对比了好几家店终于选对了，收到的所有饮料生产日期都是最近一个月的，特别新鲜！柠檬味特别正，不是那种香精勾兑的廉价果味，喝完嘴里不会留奇怪的甜腻感，运动完喝一瓶，补充维C还能润润嗓子，比喝白水有滋味多了。整箱的价格算下来单瓶比便利店便宜两块多，放在办公室跟同事分着喝，大家都问我要链接，囤一次够喝大半个月，农夫山泉的品质真的稳，完全没踩雷。"}]}}'::jsonb, '4_食品生活/data/p_food_025.json')
ON CONFLICT (product_id) DO UPDATE
   SET title = EXCLUDED.title,
       brand = EXCLUDED.brand,
       category = EXCLUDED.category,
       sub_category = EXCLUDED.sub_category,
       category_path = EXCLUDED.category_path,
       base_price = EXCLUDED.base_price,
       price_min = EXCLUDED.price_min,
       price_max = EXCLUDED.price_max,
       stock_total = EXCLUDED.stock_total,
       image_path = EXCLUDED.image_path,
       raw_json = EXCLUDED.raw_json,
       source_file = EXCLUDED.source_file,
       status = 'ACTIVE',
       updated_at = now()
;

INSERT INTO ecommerce_offline.ecom_product_knowledge (product_id, marketing_description)
VALUES
    ('p_beauty_001', '雅诗兰黛特润修护肌活精华露（小棕瓶）是品牌经典抗初老单品，主打夜间肌底修护。核心成分含高浓度二裂酵母发酵产物溶胞物，能深入修护日间紫外线、污染造成的损伤，促进肌肤代谢；搭配透明质酸锁水保湿，猴面包树籽提取物淡纹紧致。适合25+有干纹细纹、熬夜后暗沉的抗初老人群，夜间护肤时使用效果更佳。建议每晚洁面爽肤后，取3-4滴掌心温热，轻按面部至吸收，后续搭配面霜锁养。注意开封后6个月内用完，敏感肌先做耳后测试，避免不适。'),
    ('p_beauty_002', '兰蔻小黑瓶精华肌底液是品牌经典明星产品，核心成分含98%高纯度二裂酵母发酵产物溶胞物，搭配益生元复合物，能深入肌底修护受损屏障，强韧肌肤抵御力。适合25+初抗老、皮肤不稳定（换季敏感/熬夜暗沉）、毛孔粗大的人群。日常护肤可作为第一步使用，早晚洁面后取3-4滴，轻轻按摩至吸收，后续叠加其他精华或面霜效果更佳。熬夜后用它急救，能快速缓解肌肤疲劳感；换季时用可稳定肌肤状态。注意事项：开封后建议6个月内用完，敏感肌使用前先在耳后做局部测试，避免不适。不同规格中，50ml和75ml性价比更高，适合长期使用的用户。'),
    ('p_beauty_003', 'SK-II神仙水（护肤精华露）核心成分是90%以上的PITERA™酵母发酵滤液，这是SK-II独家灵魂成分，含氨基酸、矿物质、有机酸等多种活性物质。适合25+有初老迹象、毛孔粗大、角质粗糙或肤色暗沉的人群。日常护肤可作为洁面后第一步，用化妆棉擦拭全脸，或熬夜、约会前湿敷5-10分钟急救。它能温和调理角质，促进肌肤代谢，收缩毛孔，让皮肤水晶透亮、保湿不油腻。使用建议：洁面后取适量倒在化妆棉上轻擦或轻拍吸收；敏感肌首次需耳后测试建立耐受；开封后6个月内用完，避光保存。'),
    ('p_beauty_004', '资生堂新红妍肌活精华露（红腰子）是品牌明星修护精华，核心含ULTIMUNE肌活复合物，能激活肌肤自身防御机制，强韧肌底。添加保加利亚玫瑰水与透明质酸，兼顾舒缓与保湿。适合换季敏感、熬夜后肌肤暗沉不稳定、或长期受外界刺激的人群。日常护肤时，洁面爽肤后取2-3泵，轻柔按摩全脸至吸收，早晚均可使用。换季或肌肤状态差时可增加用量。注意：敏感肌首次使用建议先在耳后做局部测试，开封后6个月内用完，避免成分失效影响效果。'),
    ('p_beauty_005', '科颜氏新集焕白均衡亮肤淡斑精华液，核心卖点在于温和淡斑与均匀提亮肤色，专为有日晒斑、熬夜暗沉、痘印色素沉淀问题的人群设计。其含有的维生素C衍生物（乙基维生素C）能有效抑制黑色素生成，玻色因成分则帮助修护肌肤屏障，同时添加透明质酸保湿因子，让精华在淡斑的同时保持肌肤水润。质地清爽不黏腻，适合早晚护肤使用，尤其适合长期面对电脑、日晒较多或作息不规律的人群。使用建议：取3-4滴于掌心，轻轻拍打至全脸吸收，后续搭配乳液或面霜锁住养分；白天使用时务必配合足量防晒，避免紫外线加重色素沉淀。注意事项：敏感肌首次使用前需在耳后做皮肤测试，若出现红肿刺痛请立即停用。'),
    ('p_beauty_006', '巴黎欧莱雅新多重防护隔离露，主打水感轻薄质地，上脸瞬间推开成膜，无厚重黏腻感。采用欧莱雅专利麦色滤科技，实现SPF50+ PA++++高倍广谱防晒，有效阻隔UVA/UVB，添加玻尿酸与维生素E，防晒同时修护肌肤屏障，自然提亮肤色，让后续妆容更服帖。适合油皮、混油皮及追求清爽肤感人群，日常通勤、上学、逛街或短途户外游玩适用。使用建议：出门前15分钟取一枚硬币大小，面部颈部均匀拍打吸收，后续可叠加粉底或散粉。注意事项：敏感肌先做耳后测试，长时间户外每2-3小时补涂，避免接触眼睛破损肌肤。'),
    ('p_beauty_007', '薇诺娜舒敏保湿特护霜专为敏感肌打造，核心成分含马齿苋提取物（快速舒缓泛红干痒）、青刺果油（补充皮肤脂质修护屏障）及透明质酸（深层锁水保湿）。适合屏障受损、换季泛红、干痒脱皮的敏感肌人群，日常可作基础保湿面霜，换季或医美后可厚敷急救。使用时取黄豆大小均匀涂抹面部，轻按至吸收；急救时厚敷15-20分钟后擦去剩余。注意：开封后6个月内用完，敏感肌首次用前需耳后测试，避免与刺激性产品叠加。'),
    ('p_beauty_008', '玉兰油新生塑颜金纯面霜（大红瓶）是针对25+初老肌肤设计的抗衰利器，核心成分含高浓度烟酰胺与五胜肽（Pal-KTTKS），烟酰胺助力提亮肤色、促进胶原蛋白生成，五胜肽精准淡退动态纹与静态纹，搭配透明质酸深层锁水，实现紧致提拉、淡纹保湿三重功效。SKU分三种：50g日霜质地轻盈，适合日常通勤或春夏使用；50g滋润型添加额外保湿因子，适合秋冬或干皮；14g随身装方便出差旅行补涂。使用时取黄豆大小均匀涂于面部颈部，配合向上提拉按摩更易吸收。敏感肌建议先做耳后测试，开封后6个月内用完，避免阳光直射。'),
    ('p_beauty_009', '珀莱雅双抗精华2.0（50ml）主打抗氧抗糖双效修护，核心成分含高浓度麦角硫因+虾青素，协同清除自由基、抑制糖化反应，改善暗沉蜡黄与初老细纹。适合25+有初老迹象、熬夜后肤色暗沉或长期面对电子屏的人群。日常护肤可早晚使用，熬夜后可厚涂急救。使用时取3-4滴于掌心，轻揉乳化后按压上脸，搭配珀莱雅红宝石精华可强化抗老效果。注意事项：敏感肌需先在耳后做皮肤测试，开封后建议6个月内用完，避免阳光直射存放。'),
    ('p_beauty_010', '安热沙金灿倍护防晒乳（经典金瓶）是户外防晒的明星产品，核心采用品牌特有的Aqua Booster EX遇水增强技术，遇汗遇水后防晒膜更紧密，SPF50+ PA++++的高倍防护能有效阻隔UVA/UVB，避免晒伤晒黑。适合户外爱好者、通勤族及易出汗人群，无论是爬山、海滩度假还是日常上班都适用。质地清爽不油腻，涂抹后快速成膜，无明显泛白感。成分中添加保湿因子，兼顾防晒与肌肤保湿。使用建议：出门前15-20分钟均匀涂抹于面部及身体暴露部位，面部用量约一元硬币大小；防水配方需用卸妆产品清洁，敏感肌建议先在耳后做皮肤测试，避免入眼，存放于阴凉干燥处。'),
    ('p_beauty_011', '珊珂洗颜专科绵润泡沫洁面乳主打绵密细腻的泡沫清洁体验，核心添加蚕丝蛋白精华与双重透明质酸，既能深入毛孔带走油脂污垢，又能在清洁后留下水润保护膜。适合中性、混合性皮肤日常使用，无论是晨间唤醒肌肤还是晚间卸除淡妆后的二次清洁都很合适。标准装需搭配起泡网搓出丰富泡沫，泵装则直接按压即可获得绵密泡泡，使用更便捷。注意事项：敏感肌首次使用建议先在耳后做皮肤测试，避免入眼，若不慎入眼请立即用清水冲洗；干性皮肤使用后建议及时涂抹保湿产品。'),
    ('p_beauty_012', '理肤泉特安舒缓修复霜滋润型是专为干性敏感肌打造的屏障修复神器，核心卖点在于温和修复受损屏障、长效保湿舒缓泛红。含高浓度理肤泉温泉水，富含硒、锌等矿物质，能快速舒缓肌肤刺激与泛红；添加神经酰胺3和4，精准补充皮肤屏障缺失的脂质，增强锁水能力；乳木果油与甘油协同作用，深层滋润干燥肌肤，缓解脱皮紧绷。适用人群为干性敏感肌、屏障受损肌肤，尤其适合换季泛红、空调房干燥、医美术后修复场景。使用建议：早晚洁面后取黄豆大小，轻柔按摩至吸收，避免拉扯；泛红严重时可厚敷10分钟作急救。注意事项：开封后6个月内用完，若出现刺痛红肿立即停用，存放于阴凉干燥处，避免阳光直射。'),
    ('p_beauty_013', '方里这款柔焦蜜粉饼简直是油皮混油皮的福音！7g的小巧体积揣在包里便携性拉满，细腻如烟的粉质上脸瞬间柔焦，毛孔被隐形得干干净净，还能自然提亮肤色，拒绝假白感。核心卖点是控油定妆+隐匿毛孔+提亮，适合油皮、混油皮日常通勤、夏季长时间带妆或容易出油的场景。使用时建议取粉后先在盖子上蹭掉余粉，轻拍上脸（T区重点按压）；干皮姐妹需做好保湿打底避免卡粉。补充装12g不含外壳，性价比更高，适合回购用户替换，环保又省钱。'),
    ('p_beauty_014', '花西子空气蜜粉（8.5g）以“空气感定妆”为核心，打造清透持久的妆效。经典款与控油款双选择，满足不同肤质需求。核心卖点在于超细蚕丝粉体，上脸零厚重感，同时添加珍珠粉提亮肤色，自然不假白。适用人群包括混油、油皮日常通勤，干皮夏季或T区局部使用；使用场景覆盖上班、约会、旅行等长时间带妆场合。成分上，天然温和配方，无酒精无刺激，敏感肌可先做耳后测试。使用建议：粉扑轻蘸后抖去余粉，按压式上妆，T区重点加强；注意事项：存放干燥处，开封后12个月内用完，避免粉末入眼。'),
    ('p_beauty_015', '完美日记这款仿生膜精华唇釉，3g小巧便携，核心采用仿生膜技术，能模拟唇部天然脂质结构形成透气保护膜，锁住水分同时呈现高级丝绒哑光质感。不同于普通哑光唇釉的拔干问题，它添加透明质酸与植物精华，上唇滋润不紧绷，显色饱满均匀，持妆长达6小时不易掉色沾杯。适合日常通勤的上班族、爱美的学生党，或是需要持久妆容的约会、聚会场景。使用建议：清洁唇部后，干燥季节可薄涂润唇膏打底再涂抹；注意开封后6个月内用完，避免阳光直射，若出现过敏请立即停用。'),
    ('p_beauty_016', 'AHC塑颜修护全脸眼霜是一款针对眼周及全脸初老问题的多效护理产品，30ml大容量满足日常需求。核心卖点在于全脸可用，不仅能改善眼周干燥、细纹、暗沉，还可用于法令纹、抬头纹等部位，实现一站式修护。成分上添加高浓度玻尿酸深层锁水，视黄醇衍生物温和淡纹，烟酰胺提亮肤色，质地轻盈易吸收。适用人群为25+有初老迹象、眼周干燥或有细纹暗沉的人群。使用场景：早晚洁面后，取黄豆大小点涂眼周及需要护理区域，轻轻打圈按摩至吸收。注意事项：敏感肌建议先耳后测试，避免入眼，开封后6个月内用完，存放于阴凉干燥处。'),
    ('p_beauty_017', '芳珂纳米温和净化卸妆油是敏感肌友好型卸妆产品，核心卖点在于纳米级卸妆分子与无添加配方——纳米分子能深入毛孔包裹彩妆及污垢，无香料、酒精、防腐剂等刺激成分，通过敏感肌测试。适用人群涵盖敏感肌、混合肌及追求温和清洁的人群，日常淡妆、浓妆（含防水彩妆）均适用。使用场景包括每日晚间卸妆、出差便携（120ml容量适中）。使用建议：干手干脸取2-3泵，按摩1-2分钟（眼唇重点按摩），加少量水乳化至白色乳液状，温水冲洗；注意事项：开封后60天内用完（无防腐剂易变质），皮肤有伤口或过敏期暂停使用，存放于阴凉干燥处。'),
    ('p_beauty_018', 'The Ordinary这款烟酰胺10%锌1%精华液是油痘肌和暗沉肌的高性价比选择。核心成分10%烟酰胺能调节皮脂分泌、淡化毛孔并提亮肤色，1%锌则辅助控油舒缓。适合油性/混合性皮肤、有毛孔粗大或肤色不均问题的人群。日常护肤时，洁面爽肤后取2-3滴涂抹全脸（避开眼周），初期建议隔天使用建立耐受，后续可增至每日。注意：敏感肌需先耳后测试，避免与高浓度酸类（如水杨酸）同时使用，使用期间做好防晒。'),
    ('p_beauty_019', '兰蔻清滢柔肤水（大粉水）是干性肌肤的秋冬保湿救星！核心卖点在于它浓稠如精华液的质地，却能快速渗透不粘腻，蕴含玫瑰精华与玻尿酸成分，深层舒缓干燥肌肤，补充流失水分。适用人群精准锁定干性、偏干及换季敏感干皮，日常护肤第一步用它，早晚轻拍或用化妆棉擦拭都可，妆前打底还能让底妆更服帖。400ml大容量适合居家长期使用，200ml旅行装则方便出差携带。注意事项：敏感肌首次使用建议先在耳后做局部测试，避免直接接触眼周，开封后6个月内用完效果最佳。'),
    ('p_beauty_020', '油皮姐妹看过来！雅诗兰黛持妆粉底液SPF10PA是夏日底妆的不二之选！核心卖点在于持久遮瑕、控油抗汗，30ml装便携又耐用。适用人群主要是油皮、混油皮，尤其适合需要长时间持妆的上班族、学生党或户外活动爱好者。使用场景覆盖通勤8小时不脱妆、约会防蹭、夏日出游抗汗。配方含控油科技，能吸附多余油脂，SPF10PA提供日常基础防晒，质地清透不厚重。使用建议：妆前用清爽保湿乳打底，用打湿的美妆蛋轻拍上妆避免搓泥；注意事项：敏感肌先耳后测试，色号选择参考试色或客服，油皮友好款更适合大油皮，经典款适合混油皮。'),
    ('p_beauty_021', '科颜氏这款牛油果眼霜是万千干纹眼周星人的老熟人啦，核心采用冷压萃取的智利天然牛油果油，搭配维生素E与神经酰胺复合物，质地是那种刚挖出来像柔滑牛油果泥、触肤就会慢慢化水的特殊配方，完全不会糊眼闷脂肪粒。特别适合20岁+初抗老、眼周容易卡干纹、换季洗完脸眼尾立刻紧绷的人群，不管是熬夜追完剧急救涂一层、上妆前厚敷5分钟给眼周打个底，还是日常早晚护肤最后一步用都适配。使用时记得取绿豆大小，用指腹轻轻点按在眼周从内到外揉开到吸收就行，要注意刚挖出来别直接厚涂猛搓，还有避开眼内黏膜区域哦，14g便携装揣包里出差旅行超方便，28g标准装天天用也能用小半年，性价比很高。'),
    ('p_beauty_022', '薇诺娜极润保湿面膜专为干敏肌设计，核心成分含云南高原青刺果油与马齿苋提取物，能密集补水同时舒缓泛红。75g涂抹式包装适合夜间厚敷，25g*5片装便携适合出差。使用时取适量均匀涂于面部，避开眼唇，15-20分钟后洗净。注意开封后6个月内用完，敏感肌首次使用建议先做耳后测试。'),
    ('p_beauty_023', '理肤泉这款特护清盈防晒乳，专为易敏肌设计，50ml的容量刚好满足日常通勤或短途旅行需求。它采用高倍防晒配方，SPF50+ PA++++，能有效抵御UVA/UVB伤害，同时添加了理肤泉温泉水成分，舒缓肌肤不适。清盈型质地轻薄不油腻，上脸后快速成膜，不会闷痘，适合油皮或混合皮在夏季使用；轻薄无润色款则更适合追求自然妆感的人群，后续上妆也不会搓泥。建议在洁面爽肤后，取适量均匀涂抹于面部，避开眼周，户外活动时每2小时补涂一次。注意：若肌肤出现红肿、瘙痒等不适，应立即停用并咨询医生。'),
    ('p_beauty_024', '珀莱雅这瓶赋能鲜颜淡纹紧致精华，主打的就是针对初老、熟龄肌的纹路改善！核心添加了高浓度六胜肽-1和双重胶原肽组合，搭配肌肽抗糖buff，能精准淡化抬头纹、法令纹、眼周干纹这些显老纹路，同时把松垮的脸撑得弹润紧致。特别适合25+开始冒小干纹、经常熬夜脸垮、化妆卡纹的姐妹。早晚洁面爽肤之后取2-3滴揉开上脸，顺着从下颌线往太阳穴的方向轻拉按摩到吸收，后续叠加乳液面霜完全不搓泥。敏感肌第一次用先在耳后试敏，避开眼周直接涂抹，孕期建议先咨询医生再用哦，日常通勤、熬夜救急、抗老维稳用它都超合适，现在还有30ml常规装和45ml大容量装可选，性价比拉满。'),
    ('p_beauty_025', '花西子这款螺黛生花双头眉笔专门针对东方人眉形设计，0.08g的极细笔芯能精准点描每根毛流，就像用毛笔勾线一样丝滑不卡壳，显色度刚好不会重手变蜡笔小新，添加的持色覆膜成分日常通勤出汗、喝冰饮沾到水汽都不容易晕成大黑块。特别适合手残新手、追求野生眉妆感的女生，不管是日常上班快速描眉，还是约会拍特写妆造都能用。一头是细笔芯一头是螺旋眉刷，画之前先梳顺眉毛再填补空缺，画完扫掉浮色就很自然，注意用的时候手别太用力压笔芯，不然容易断，存放在阴凉干燥的地方别晒到太阳就能用很久。'),
    ('p_digital_001', 'Apple iPhone 17 Pro搭载全新A19 Pro芯片，带来颠覆性性能提升，无论是大型3A游戏还是专业视频剪辑都能流畅运行。6.3英寸超视网膜XDR显示屏，支持ProMotion自适应刷新率，户外强光下依然清晰。256GB起步的存储容量，满足摄影爱好者和商务人士的存储需求。宇宙橙、远峰蓝、深空黑三色可选，其中宇宙橙采用独特的哑光玻璃工艺，握感舒适且不易留指纹。适合追求极致体验的科技爱好者、内容创作者以及需要高效办公的商务人群。日常使用建议开启低电量模式延长续航，拍摄专业视频时可搭配MagSafe配件提升稳定性。注意：不同存储版本价格差异较大，选购时需根据自身需求选择。'),
    ('p_digital_002', '华为Pura 90 Pro是主打超感光影像的曲面屏轻薄旗舰，整机仅重193g搭配8.2mm超薄中框，持握久了也不会累手。核心的超感光主摄搭载专属徕卡调校RYYB传感器，暗光环境下拍夜景人像不用开补光灯也能保留细腻肤感，配合大曲率的1.5K臻彩曲面屏，刷剧修图色彩准到和专业显示器差不离。适合摄影爱好者、重度手机办公族、日常爱拍娃拍风景的普通用户，出门逛夜市、爬山拍日出、通勤移动办公都够用。建议平时贴配套的全胶曲面钢化膜避免刮花屏幕，注意不要把手机和尖锐金属钥匙同放口袋，长期不用的时候别把电量耗到低于20%再充电，能更好保护电池健康度。'),
    ('p_digital_003', 'iPhone 17 Pro Max这次直接把大屏体验拉到新高度，6.9英寸超视网膜XDR显示屏不管是刷4K纪录片还是连剪几小时vlog都够爽，A19 Pro仿生芯片的算力直接把移动端3A游戏和专业修图的速度拉满，连导出4K 60帧视频都几乎秒完成。机身用的是全新航空级钛合金边框，这次新增的宇宙橙、冰川蓝配色质感特别绝，256GB起步的存储完全能装下上万张Raw格式照片和几十部高清剧。特别适合内容创作者、重度手游玩家和平时爱用手机替代随身电脑的商务人群，不管是通勤刷剧、外出跑活动剪素材还是周末户外拍星轨都能hold住。提醒大家到手别直接撕掉边框的防护膜，第一次充电用原装27W头激活电池效率，贴钢化膜要避开屏下 Face ID 区域避免影响解锁速度。'),
    ('p_digital_004', '这款华为MateBook 14鸿蒙版是专为高效生产力打造的14英寸轻薄本，搭载鸿蒙分布式能力，能和华为手机、平板、智慧屏无缝跨端协同，碰一下就能直接互传大文件、接力编辑未完成的文档，还支持多屏同开拖拽素材。整机重量仅1.49kg，三面窄边的2K触控屏占比高达90%，锐龙处理器性能够撑住连续跑8小时PS修图、多文档开十几个网页的办公需求，65W便携快充出门充15分钟就能用3小时。特别适合经常跑外勤的职场人、需要赶课程作业的大学生，日常通勤塞包里完全不压肩。使用时注意别用尖锐硬物刮碰触控屏，跨端协同需要设备登录同一个华为账号才能触发全功能，长期高负载使用建议垫高底部保证散热。基础款16GB+512GB日常用足够，经常存大量工程文件的用户直接选1TB高配版更省心。'),
    ('p_digital_005', '华为MatePad Pro Max 12.6英寸平板，核心卖点是适配办公需求的高刷大屏与多任务并行能力，12.6英寸高色域高刷屏拖滑无拖影，分屏最多同时开3个独立应用，侧边还能悬浮小窗回消息，彻底摆脱小屏平板办公的局促感。不管是经常要带设备开线上会的职场打工人，还是需要分屏查资料写文档的内容创作者，或是用来上网课做笔记的高校学生都适配。日常带出门赶方案、居家同时挂会议记笔记剪短视频都顺手，全金属机身握感扎实抗造，搭配M-Pencil使用延迟极低。使用建议平时开智能刷新率模式更省电，注意别让尖锐硬物直接刮到屏幕表面，Wi-Fi版不支持插SIM卡，出门在外需要提前备好手机热点哦。'),
    ('p_digital_006', '这款14英寸Apple MacBook Pro搭载全新M5系列芯片，是面向专业创作者、程序开发者、高端商务人士的高性能生产力工具。核心配置覆盖16GB-32GB统一内存、512GB-1TB高速SSD，搭配Liquid Retina XDR显示屏，峰值亮度可达1600尼特，户外强光下剪辑HDR素材也能看清细节。机身采用全铝一体成型工艺，深空黑版本加入特殊纳米涂层抗指纹，连续视频剪辑续航最长可达18小时，外出跑项目一整天不用带充电器。适合4K视频调色、3D建模渲染、大型工程代码编译等重度工作场景，日常用来修图、做方案、线上会议也丝滑流畅。使用时建议尽量在官方适配的65W以上PD充电器下充电，不要用第三方廉价快充头，长时间高负载运行时别把机身放在被褥等软质不透气表面上，避免堵塞底部散热格栅影响性能释放。'),
    ('p_digital_007', '华为FreeBuds Pro 5是专为追求高音质和强降噪体验的数码爱好者、通勤族、办公党打造的旗舰级真无线耳机。搭载华为自研的超感知主动降噪系统，最高降噪深度可达55dB，搭配全新升级的高解析音频解码，能完整还原Hi-Res Audio标准的细节音效，哪怕是古典乐里的弦乐泛音、演唱会现场的现场感都能精准捕捉。单耳满电可支持6小时降噪模式播放，搭配充电盒总续航能到30小时，支持快充15分钟听歌4小时。机身采用贴合耳廓的人体工学半开放倾耳设计，典雅黑哑光不容易沾指纹，冰霜银磨砂质感高级。日常通勤挤地铁、办公室赶方案、居家沉浸式听歌都能用，使用时建议首次佩戴先在华为智慧生活APP里做贴合度检测，选择适配的耳塞套，不要在雷雨天气或者高水压的水下环境佩戴，避免元器件受潮损坏。'),
    ('p_digital_008', '这台小米17 Ultra是专为影像发烧友、手游重度玩家和职场精英打造的年度旗舰，搭载小米自研澎湃影像芯片+潜望长焦模组，配合2K超高刷新率的定制AMOLED屏，全链路5G网络适配各类高速场景。日常出门扫街拍远景不用带沉重的单反，随手就能拍出细节拉满的长焦成片；刷高帧影视、玩3A手游的时候画面丝滑不拖影。全系列LPDDR5X内存搭配UFS4.0闪存，多开办公软件也不会卡顿。使用建议是首次开机可在影像设置里开启澎湃芯片专属的夜景增强模式，长时间户外拍摄建议搭配官方散热背夹，注意不要用非原装快充头长时间充电，避免损伤内置电池寿命。'),
    ('p_digital_009', '小米17 Max是专为影音游戏爱好者打造的大屏5G性能旗舰，搭配超窄边7英寸2K超清大屏，支持120Hz自适应高刷，峰值亮度达1800nit，户外强光下看剧刷攻略也清晰透亮。内置6800mAh超大容量长续航电池，搭配120W有线快充+50W无线快充，连续满帧玩3小时《原神》还剩62%电量，追完一整季24集连续剧都不用中途插电。搭载旗舰级骁龙8 Gen4处理器，配合满血版LPDDR5X运存，后台同时挂10个APP切换也不会杀后台。特别适合经常出差的通勤党、常驻宿舍的手游玩家、日常爱刷剧剪vlog的内容创作者使用。建议日常搭配官方附赠的全包边软壳使用，注意避免从1.5米以上高度直接掉落，虽然屏幕用了康宁大猩猩最新防刮玻璃，还是尽量不要和钥匙、硬币等硬物同放在裤袋边角摩擦哦。'),
    ('p_digital_010', '小米MIX Fold 5作为小米旗下最新的内折大屏旗舰折叠屏，专为高效办公和沉浸式影音体验打造。展开后超大的内屏支持最多4个应用同屏分栏显示，处理报表的同时还能开线上会议、查参考资料、回客户消息，职场移动办公效率直接拉满；日常刷4K高清剧集、玩大屏开放世界手游时，视野比普通直屏手机多出近60%。整机采用轻量化钛合金铰链，反复折叠数十万次也不容易出现折痕凸起，配装旗舰级骁龙最新移动平台，多任务后台同时运行也几乎不会卡顿。适合经常外勤的商务人士、影音发烧友、创意内容创作者入手，平时注意别用尖锐硬物直接划蹭内屏，合盖时避免夹到钥匙等硬物，能大幅延长屏幕使用寿命。标准版12GB+512GB足够日常使用，重度存资料拍素材的用户更推荐选16GB+1TB高配版。'),
    ('p_digital_011', '小米平板8 Pro搭载12.1英寸高刷大屏，2.8K超清分辨率配合144Hz自适应刷新率，刷剧玩游戏丝滑不拖影，双超大存储版本可选，8+256G刚好装下几十部高清剧和全套学习课件，12+512G适合存大量设计素材和办公文档。适配小米生态跨屏互联，手机碰一下就能秒传文件，多窗口分屏最多同时开4个应用，上网课的同时能记笔记查资料。不管是学生党上网课刷题库、上班族移动轻办公改报表，还是宅家追剧打休闲游戏都很适配。建议搭配原装磁吸触控笔和键盘套使用体验更好，注意它仅支持Wi-Fi联网，外出没有热点的话得连手机热点，长时间高负载使用时建议摘掉厚重的保护壳辅助散热哦。'),
    ('p_digital_012', '这台搭载M5 Pro/Max芯片的16英寸MacBook Pro，是为创意从业者量身打造的生产力猛兽。核心卖点直接拉满：最高可选64GB统一内存与2TB高速SSD，应对8K视频剪辑、3A级3D建模渲染、上百图层的PS/AI大型设计文件丝毫不卡，16英寸Liquid Retina XDR显示屏支持P3广色域与1600尼特峰值亮度，做调色修图完全不用外接校色屏。机身采用全金属一体成型工艺，连续续航最长可达22小时，赶方案跑外地不用随身带充电器。适配人群覆盖影视后期设计师、3D建模师、资深游戏开发者、专业编曲制作人，不管是居家工作室干活、线下采风剪素材、跨城出差赶提案都能用。建议日常使用搭配官方氮化镓充电器更轻便，注意不要和尖锐硬物放在一起避免机身掉漆，长时间高负载运行时别放在毛绒床面这类不透气的表面上影响散热。'),
    ('p_digital_013', '这款搭载M5芯片的13英寸iPad Pro，配备Liquid视网膜XDR显示屏，峰值亮度最高可达1600尼特，阳光下看设计稿、剪4K影片都能看清暗部细节。256GB起步的存储容量，存满上百个专业绘图工程、几十部4K剪辑素材都毫无压力，Wi-Fi版完全能覆盖居家办公、画室创作、大学生做课设的日常需求，深空黑和银色两个配色适配不同使用场景。特别适合平面设计师、短视频创作者、高校美术生这类专业用户，日常用Apple Pencil写画延迟几乎感知不到。使用时建议搭配官方类纸膜减少屏幕反光，平时别把它长时间放在阳光直射的汽车中控台，避免XDR屏长时间处于极端高温下影响色彩校准精度。'),
    ('p_digital_014', 'OPPO Find N6是主打内折柔性大屏体验的旗舰折叠屏，搭载经过多次迭代的精工铰链，折痕几乎隐于7.82英寸的内折大屏之下，展开后屏幕比例接近黄金比例，不管是同时打开微信、文档和会议界面的多任务办公，还是拉满画幅看杜比视界大片，沉浸感拉满。它分12GB+512GB标准版和16GB+1TB高配版两个规格，适配经常外勤的职场办公族、资深影音爱好者、需要兼顾工作娱乐的数码发烧友。平时用尽量避免尖锐物品直接刮擦内屏，折叠时不要夹到细碎的小物件，长期重度多任务运行时可以适当开启系统自带的内存清理后台，能大幅延长手机的使用生命周期。'),
    ('p_digital_015', '这台OPPO Find X9 Ultra是实打实的年度影像旗舰，搭载超大底主摄传感器，搭配自研影像NPU，暗光夜拍、远景抓拍都能出纯净通透的大片，没有普通手机常有的噪点糊片问题。2K分辨率的高刷屏支持自适应刷新率，刷短视频、玩高帧手游时画面丝滑跟手，长时间看剧也不容易眼累。内置大容量电池搭配100W快充，出门跑一天通勤、拍素材也不用到处找充电宝，5G全频段覆盖信号稳得很。特别适合摄影爱好者、重度手游玩家和经常出差的商务人士，日常扫街探店拍美食、周末户外拍风光、通勤刷剧办公都能hold住。建议日常搭配原厂带的素皮壳使用，避免后摄模组刮花，前3次充满后再多充10分钟激活电池活性，注意别边充边玩高负载游戏避免机身过热。'),
    ('p_digital_016', 'OPPO Reno 16 Pro是专门为爱拍人像的年轻用户打造的轻薄5G旗舰机，整机拿在手里几乎没有坠手感，长时间刷剧出门扫街揣口袋都毫无负担。核心的人像摄影系统搭配原生柔光环，暗光下拍夜市合照、咖啡馆氛围感照片都不用额外补光，肤感磨皮自然不假白。搭载的高刷屏刷短视频、玩轻度手游时跟手度拉满，搭配大毫安时电池和满血快充，出门忘充电午休充10分钟就能刷一下午社交软件。特别适合喜欢记录日常通勤、和闺蜜出游、下班探店瞬间的学生党、职场新人，平时用机尽量别用非官方的快充头，避免损伤电池健康，裸机使用建议单独贴高清钢化膜防刮花。'),
    ('p_digital_017', 'vivo X300 Ultra是专门为影像发烧友、高清内容创作者打造的旗舰级5G手机，标配2K级10亿色护眼直屏，支持1920Hz高频PWM调光，长时间剪vlog、刷4K内容眼睛也不容易酸。搭载旗舰级影像模组，大底主摄搭配潜望式长焦，不管是凌晨拍星空特写还是出门扫街抓路人动态都能出大片。满电状态下连续重度使用能撑一整天，搭在的旗舰处理器玩满帧大型手游也不卡顿，特别适合经常外出拍素材的博主、追求顶级使用体验的数码爱好者。日常使用建议贴官方配套的钢化膜，避免刮花高清屏幕，注意不要在超过45度的高温环境下长时间录像，防止机身触发温控保护。'),
    ('p_digital_018', '这款Apple AirPods Pro 3心率监测版，核心新增了耳腔式精准心率传感模块，搭配升级的自适应主动降噪功能，最高可抵消48dB环境噪音，支持空间音频头部动态追踪，单次续航可达6小时，搭配MagSafe充电盒总续航最长30小时。特别适合日常通勤的上班族、跑步健身的运动爱好者、长时间戴耳机听网课的学生党使用，早高峰挤地铁、夜跑夜骑、办公室隔绝同事闲聊等场景都能适配。硅胶耳帽有三档尺寸可替换，入耳贴耳不胀耳，运动出汗时心率数据会自动同步到苹果健康APP生成运动报告。使用时建议每两周用干软布擦拭耳机传感区保持清洁，洗澡游泳时务必取下，避免水渍损坏心率监测模组，选马年特别款还能免费定制专属镌刻文字，刻上专属小标记超有纪念意义。'),
    ('p_digital_019', 'vivo Pad 6 Pro搭配12.1英寸高刷全面屏，是专门为学生党、轻办公上班族、影音娱乐爱好者打造的多用途平板。核心卖点是大内存组合搭配高刷新率显示，学习时可以一边开上网课窗口、一边记电子笔记、侧边挂查资料小窗，多任务切换丝滑不卡顿；通勤居家刷剧、玩轻度手游时，屏幕色彩通透流畅度拉满。全金属机身质感扎实，Wi-Fi版无流量卡顿困扰，8+256G版本日常存储课件、存剧完全够用，12+512G版本更适合需要装大量专业绘图、办公软件的用户。使用建议平时搭配原装触控笔记笔记更顺手，注意不要把平板和尖锐硬物放在同一个包里避免刮花屏幕，长期高负载使用时建议摘掉保护壳散热。'),
    ('p_digital_020', '这款搭载M5芯片的13英寸MacBook Air，整机轻至1.24kg薄至1.13cm，全铝Unibody一体成型机身摸起来细腻顺滑，放在通勤包几乎没存在感。16GB统一内存后台同时开十几个网页、修图软件和文档都不卡，512GB起步的SSD传大文件速度拉满，续航满电能撑18小时，出差跑全天会议都不用带充电器。特别适合新媒体从业者日常剪短视频、大学生跑代码写论文、商务人士频繁外勤见客户用，全尺寸蝶式升级剪刀脚键盘敲久了不累，3.5mm耳机孔还保留着。提醒大家不要自行拆机扩容，首次激活建议在苹果官网核验序列号，长期不用保持每月充一次电避免电池亏电。'),
    ('p_digital_021', '华为 MatePad Pro 13.2 英寸定位高端轻办公与创作旗舰平板，主打大尺寸柔性 OLED 屏、轻薄机身和跨设备协同体验。13.2 英寸屏幕在分屏看文档、批注 PDF、追剧和轻度修图时都比常见 11 英寸平板更从容，配合高刷显示，手写和滑动操作会更跟手。机身重量控制在大屏平板里相对轻巧的范围，放进通勤包里不会像笔记本那样占空间，适合经常在会议室、咖啡店、教室和高铁上移动使用。它更适合拿来做会议记录、阅读资料、轻量表格处理、手写批注和影音娱乐，如果你本身就在用华为手机或耳机，多设备流转会更顺。需要注意的是，这类大屏平板并不等同于完整笔记本，不建议把它当作重度视频渲染、长时间大型代码编译或专业三维建模的唯一主力设备；若经常外出手写或办公，建议一步到位选择 512GB 以上版本，并搭配原厂键盘或手写笔使用，避免后期配件成本过高影响体验。'),
    ('p_digital_022', '这台联想ThinkPad X1 Carbon Aura AI元启版2026是专为高端商务人士打造的14英寸轻薄本，整机采用航空级碳纤维材质打造，裸机重量仅1.1kg，薄至14.9mm，揣进通勤公文包完全没负担。搭载的专属Aura AI引擎能自动帮你整理会议纪要、生成商务汇报初稿、智能调优办公场景的功耗，续航最长可达18小时，全天出差不用带充电器。不管是经常跑客户的销售、高频开线上会议的管理层，还是需要随时处理项目的咨询顾问都非常合适。使用建议平时定期通过自带的AI管家更新功能补丁，注意不要在超过35℃的高温环境下长时间高负载运行，避免影响AI功能的运行流畅度。'),
    ('p_digital_023', '联想ThinkBook 14+ 2026是专为职场商务人和在校学生打造的高性能轻薄本，整机薄至15.9mm仅重1.4kg，搭载全新一代标压处理器搭配2.8K 120Hz全尺寸高清全面屏，100%sRGB高色域覆盖让修图、剪视频色彩零偏差。全金属机身耐磨抗造，接口全到不用带拓展坞，原生支持PD快充，满电日常办公能撑7小时以上。日常用来跑多开办公软件、上网课做毕业设计、轻度剪4K素材都完全不卡，出差塞通勤包也毫无负担。使用建议新到手先更新官方驱动优化性能，注意不要边充边高负载运行太久，避免机身局部积热影响续航寿命。'),
    ('p_digital_024', '这款搭载M4芯片的13英寸iPad Pro，拥有堪比桌面级的运算性能，256GB起步的存储空间刚好能装下海量4K剪辑工程、专业绘图素材和离线高清片源。适配第二代Apple Pencil的悬停预览功能，搭配超大屏幕，插画师、视频博主、移动办公族用着都特别顺手。不管是在咖啡馆剪完一支vlog，还是在会议室直接批注数百页方案，又或者躺床上追全景声大片都很丝滑。全机采用航空级铝金属机身，还支持6K视频外接输出，建议平时搭配类纸膜和妙控键盘使用，使用时尽量避开尖锐硬物刮划机身屏幕，长时间高负载运行可以适当取下保护壳辅助散热，避免机身积热。'),
    ('p_digital_025', '2026款11英寸iPad Air搭载全新M4芯片，机身薄至5.9mm，重量仅455g，单手握持逛两小时漫展都不酸。Liquid视网膜屏支持P3广色域，上网课记笔记时公式色彩分明，刷4K剧暗部细节也不拉胯。核心卖点是满血M4带来的AI运算能力，跑专业绘图APP画十几层插画都不卡，连续办公续航能撑10小时，图书馆待一整天不用找插座。适配Apple Pencil二代和妙控键盘，学生党赶作业、上班族轻办公、宅家党剪短视频都能用。使用建议贴类纸膜搭配手写笔记笔记更顺手，注意事项是蜂窝版不支持国内通话功能，仅支持数据流量上网，避免误购。'),
    ('p_clothes_001', '优衣库这款AIRism联名系列的男装宽松圆领T恤，把亲肤棉感和黑科技凉感做了完美融合，不是普通的薄款白T！面料用的是AIRism专属混纺棉，摸上去是软乎乎的棉质质感，贴身穿完全不扎，自带的吸湿速干属性夏天出了汗也不会黏在背上，宽松H版型刚好遮住腰腹的小赘肉，不紧绷也不会垮得像偷穿大人衣服。不管是学生党上课通勤、上班族下班逛夜市、周末约球做轻运动当内搭都合适，单穿配工装裤、牛仔短裤都很出片。建议洗的时候翻面用冷水轻柔模式，别用热水长时间泡，避免破坏面料里的凉感涂层，不要长时间暴晒在正午阳光下，挂在通风阴干能保持版型穿一整个夏天都不变形。'),
    ('p_clothes_002', '优衣库这款男装DRY-EX超快干圆领短袖T恤，专门针对爱运动的男生打造，面料加入了高比例吸湿速干纤维织法，出汗后不会闷在身上黏糊糊贴皮肤，风一吹十来分钟就能基本干透。平时夜跑、健身房撸铁、打球穿完全合适，日常通勤上班、下楼取快递、周末逛公园当内搭外穿也舒服不违和。尺码覆盖M到XL，有灰、黑、蓝三个低饱和百搭色，129的定价日常穿造也不心疼。洗的时候别用热水长时间浸泡，也别和掉色的深色牛仔混洗，平铺阴干就行，不用特意拧干，不容易起皱第二天直接拿出来穿都平整。'),
    ('p_clothes_003', '这款耐克Dri-FIT男子训练短袖T恤是专为运动爱好者打造的高性价比日常训练上衣，核心卖点就是搭载了耐克专属的Dri-FIT速干科技面料，面料采用高密聚酯纤维混纺纤维织就，能快速把运动时渗出的汗液从皮肤表面导出到面料外层，十几分钟就能自然风干不黏身。不管你是健身房撸铁、户外夜跑、日常打球，还是通勤通勤通勤路上随便穿都合适，适配从学生党到职场运动人的各类需求。穿的时候建议不要用热水长时间浸泡，也不要和深色容易掉色的衣物混洗，版型是常规修身款，做大幅度引体向上、波比跳动作都不会卡胳膊露腰，一百多的价格能直接承包你大半年的运动穿搭。'),
    ('p_clothes_004', '这条阿迪达斯Essentials经典三条纹男子针织运动长裤，采用亲肤透气的纯棉混纺针织面料，摸起来软而不塌不容易起球，侧边标志性白三条纹辨识度拉满，收口裤脚能牢牢贴合脚踝不容易往上滑。不管是日常出门取快递、约朋友逛gai，还是夜跑、去健身房练完换休息裤穿都合适，适配学生党、通勤打工人、日常爱运动的所有男生。洗的时候记得反面翻过来冷水手洗/轻柔机洗，别和深色掉色衣物混泡，不要长时间暴晒不然白条纹容易发黄，选码的时候注意如果喜欢宽松效果可以往大拍一码，久穿也不容易变形走样，百元出头的经典款穿两三年都不过时。'),
    ('p_clothes_005', '这款李宁运动生活系列男款连帽套头卫衣，核心卖点就是经典不挑人的基础大Logo印花+舒适耐穿的亲肤面料，日常出街、轻运动穿都完全不违和。面料是320g重磅精梳棉混纺定制款，摸起来软乎乎的但不容易起球，连帽做了加固走线，洗多少次帽型都不容易塌。适用人群覆盖18-40岁的男性，不管是学生党上课、上班族通勤顺路跑两公里，还是周末和朋友约球后散步穿都合适。使用建议：刚拿到手先反过来冷水轻柔洗，不要和深色掉色衣物混泡，印花部分不要直接大力搓洗就能穿很久。注意XL码的深蓝色款定价是269元，选码的时候可以对照详情页的肩围表，喜欢宽松感的朋友可以选比日常穿的大半码哦。'),
    ('p_clothes_006', '这款Nike Sportswear Club男子针织束脚长裤，专为追求舒适与日常质感的男性打造，采用细腻重磅针织毛圈面料，软而不塌上身不易起皱，侧边小绣标低调不浮夸，松紧腰头搭配内置抽绳可自由调节松紧，束脚口剪裁刚好收拢裤腿不堆在脚踝，既能遮住小腿多余线条又不会显得臃肿。日常通勤、楼下取外卖、周末约球热身、休闲探店穿都合适，搭配同品牌卫衣或基础白T都很出片。洗涤建议反面冷水轻柔机洗，不要长时间浸泡、不要用漂白剂，晾晒时拉直裤脚能最大程度保持版型，避免暴晒导致面料发硬变色。'),
    ('p_clothes_007', '这双Nike Air Zoom Pegasus 41男子跑步鞋是耐克飞马系列迭代到第41代的训练款，搭载前后掌分离式Zoom Air气垫，搭配全掌ReactX泡棉中底，缓震反馈比前代更韧不塌。工程网布鞋面做了加密透气孔设计，长时间跑脚不闷汗，标准楦型适配多数亚洲男性脚型。核心卖点是兼顾长距离公路跑的支撑性和日常压街的百搭感，适用人群覆盖每周跑量10-50公里的入门跑者、日常进行3-10公里路跑的健身爱好者，以及需要一双舒适通勤鞋的上班族。日常场景下不管是城市柏油马路训练、小区夜跑还是上班通勤穿都合适。使用建议选大半码更适配厚运动袜，注意不要穿着它去越野跑或进行剧烈对抗球类运动，避免鞋底纹路过度磨损和气垫被尖锐物扎破，雨天穿完及时擦干鞋面缝隙的积水能延长鞋的使用寿命。'),
    ('p_clothes_008', '这双adidas Ultraboost 5男子跑鞋是阿迪达斯专为慢跑爱好者打造的年度升级款，全新升级的Boost中底调校后回弹反馈比上代提升12%，轻量针织鞋面完全贴合脚面，久跑也不闷脚压脚。核心卖点就是软而不塌的缓震脚感，搭配稳定支撑鞋笼设计，既适配3-10公里日常慢跑、间歇训练，平时通勤逛街穿也完全不硌脚。适用人群覆盖入门跑者、日常有运动习惯的上班族，想要一双兼顾运动和出街的百搭鞋款的男生都合适。注意穿着时尽量避开尖锐硬物刮蹭针织面，清洁用软毛刷蘸温和洗涤剂轻刷即可，不要长时间泡水暴晒避免中底缓震性能提前衰减。'),
    ('p_clothes_009', 'HOKA Clifton 9男款跑鞋专为长距离跑者和日常爱逛人群打造，全掌加厚的全新EVA中底重量比前代轻了足足15%，踩着软但完全不塌，落地时的缓震感能把公路的硬震动直接卸掉大半，脚感像踩在软弹的云朵垫上。鞋面是 engineered 工程网布，孔眼排布疏密刚好，夏天跑10公里脚也不闷汗，侧边的支撑块还能稳住足弓不晃。不管你是每周要跑5次10公里的训练党，还是每天要走一万步通勤逛展的朋友都能穿，日常搭配运动装出街也超好看。建议初次上脚先穿普通棉袜走3天日常路再上长距离跑，刚穿不要直接跑半马挑战极限，注意不要踩尖锐碎石避免划破外底耐磨橡胶层。'),
    ('p_clothes_010', '特步160X 6.0 PRO碳板竞速跑鞋，专为进阶跑者打造的马拉松级战靴，全掌搭载全新升级的动态弧面碳板，推进力比上一代提升12%，中底采用超临界发泡泡棉材料，单只42码重量仅185g，上脚几乎无坠脚感。鞋身是mono纱半透网面，兼顾强包裹性和跑程中的透气排汗需求，大底采用CPU耐磨止滑橡胶，干湿地抓地力都拉满。适合全马目标破3、半马进130的进阶跑者，日常10-20公里节奏跑、间歇训练，还有正式马拉松赛事冲成绩都能穿。建议跑前先进行3-5次短距离慢跑磨合开中底，不要穿它日常通勤走长路，避免碳板和中底过早损耗，雨天跑完及时把鞋身缝隙的积水擦干存放。'),
    ('p_clothes_011', '这双Nike LeBron XXI EP男子中帮实战篮球鞋专为球场表现党打造，搭载全掌Zoom Air缓震单元，起跳落地时能快速卸掉冲击力，变相突破时也能保持鞋底贴地感，完全不会出现卸力晃脚的情况。鞋身用的是工程网面搭配热压加固条，轻量还能牢牢兜住脚面，中帮高度刚好卡在脚踝下方，兼顾支撑性还不卡脚腕。EP宽楦调校专门适配亚洲男性偏宽的脚型，42、43码的版本对宽脚球友特别友好，不管是室内塑胶木地板，还是室外水泥地半场训练打局都能hold住。适合詹姆斯球迷、常打全场的锋线球员，以及日常想穿缓震好的鞋走路通勤的运动爱好者。注意别拿去泡水里刷，脏了用软毛刷沾清洁剂擦就好，刚上脚可以穿2-3次压马路踩开缓震再上实战强度。'),
    ('p_clothes_012', '这双安踏KT9是专为篮球运动爱好者打造的旗舰级实战战靴，搭载安踏自研的氮科技中底，回弹效率拉满还能长效缓震，跳投落地时膝盖几乎感受不到硬震。中帮的袜套式鞋领口刚好卡在脚踝下方，不卡跟腱还能给到足侧稳定支撑，变相突破的时候完全不用担心侧翻崴脚。不管是室内木地板的正式比赛、塑胶外场的日常野球局，还是球馆的日常力量训练都能hold住。鞋面用的是高强度工程网布，透气不闷脚还能贴合脚面做锁定，建议选正常偏大半码的脚感更舒服，打完球及时把鞋内汗渍通风晾干，不要直接用水猛冲中底，能延长鞋子的实战寿命，特别适合投手型打法和经常打全场的球友入手。'),
    ('p_clothes_013', '这双李宁韦德之道全城12是专门为篮球爱好者打造的专业级实战鞋，中底搭载了李宁最新调教的䨻科技缓震模块，落地时的反馈软弹不卸力，鞋面用的是高强度工程编织材质，侧边加了专项的侧墙支撑TPU，急停变向的时候脚完全不会晃，不管是爱做大幅度变向的后卫，还是需要频繁卡位起跳的锋线都能适配。平时打室内塑胶场、木质地板场完全够用，偶尔压街出门也完全不闷脚。建议大家选码的时候按照日常穿的篮球鞋正码选，上脚穿篮球袜的贴合度刚好，注意不要穿它长期走粗糙的水泥硬地，会加速鞋底的耐磨层损耗，能大大延长鞋子的实战寿命。'),
    ('p_clothes_014', '萨洛蒙这款X ULTRA 4男子徒步鞋专门针对户外爱好者打造，核心搭载GORE-TEX防水科技膜，搭配轻量密网鞋面，既能完全阻隔突降的山雨、溪流溅水渗入，又能快速排出脚汗避免闷脚。中底采用改进型的ADV-CUSHION缓震材料，整鞋自重比上一代X ULTRA 3轻了近80g，长时间爬台阶走碎石路也不会累脚。外底是专属的大耳齿抓地花纹，搭配Contagrip防滑配方，湿滑青苔石阶、松软泥地陡坡都能稳稳吃住地面。特别适合每周进山徒步的进阶玩家、日常走郊野绿道的运动爱好者，近郊单日10-20公里徒步、低海拔登山、轻度越野跑都能适配。建议大家穿厚款户外徒步袜选购，尽量留半指的富余鞋长，新鞋前3次走短距离磨合，别直接挑战高难度长线。注意日常不要用硬毛刷猛刷防水膜表层，避免破坏防泼水面料涂层影响防水效果。'),
    ('p_clothes_015', '迈乐这款MOAB 3 GTX男款徒步鞋，专为硬核户外爱好者打造，搭载正版GORE-TEX防水薄膜，连暴雨天走山间溪路都能保持鞋内干爽，中底用了升级的EVA记忆缓震材质，足弓处做了专属硬质支撑片，踩碎石陡坡也不会崴脚。适用经常走长线徒步、周末近郊越野、日常逛郊野公园的男士，不管是泥地、碎石路还是浅滩都能hold住。提醒大家选码前可以先测下净脚长，穿厚户外袜的话建议选大半码，日常不要穿着它长时间跑柏油马路，很容易加快鞋底纹路磨损，养护的时候也别直接暴晒，阴干就好，能穿更久。'),
    ('p_clothes_016', '这条Lululemon Align 25英寸高腰紧身裤，是专为喜爱轻运动和日常舒适感的女生打造的裸感神裤。采用品牌专属的Nulu裸感面料，摸上去像第二层皮肤一样软滑完全不磨肤，高腰宽腰头刚好卡在腰最细的位置，完全不卷边还能悄悄收住小肚腩，25英寸的裤长刚好落在脚踝上方两厘米处，对小个子也特别友好不堆裤脚。不管是做流瑜伽、普拉提这类需要大幅度拉伸的运动，还是配卫衣、长外套直接出门逛街、取快递、接娃都完全不尴尬，外穿也不显内裤边。建议洗的时候翻过来用冷水手洗或套洗衣袋轻柔机洗，别用柔顺剂，避免挂勾到尖锐物品勾丝，正常穿保养得当能保持大半年的裸感软弹状态。'),
    ('p_clothes_017', '这款始祖鸟Gamma男款软壳长裤，采用自家专属Fortius 2.0弹力磨毛面料，兼顾强耐磨性与四面弹力，裤身做了DWR防泼水处理，细碎小雨、登山溅起的泥点都不容易沾身。臀部和大腿侧做了双层加固剪裁，攀爬、深蹲大动作完全不卡裆掉裆，内置的腰带卡扣不用额外配腰带，侧袋带拉链防止徒步时东西滑出。特别适合热爱周末单日徒步、岩壁攀援、日常近郊轻户外的男性玩家，平时通勤搭配速干衣也毫无违和感。使用建议选对腰围尺码，攀爬时不要刻意蹭尖锐岩壁锐角，日常清洁用中性洗衣液冷水机洗，别用柔顺剂，避免破坏面料的防泼水处理层。'),
    ('p_clothes_018', '北面这台28L Borealis双肩包绝对是通勤党和轻户外爱好者的刚需宝藏！采用品牌专属的防泼水面料，溅到雨天积水、咖啡洒到表面擦一下就干净，主舱隔层专门适配16寸笔记本，侧边弹力兜能塞下500ml保温杯+折叠晴雨伞，背板的穿孔发泡棉自带透气缓冲，背三小时挤地铁都不会闷汗压肩。日常适合朝九晚五通勤族、高校走读生，周末近郊徒步、探店短途出行也完全够用。使用建议是装超过10斤重物时记得调整胸带分散压力，注意不要长时间把包泡在水里，尖锐刀锋类物品装进去最好套个小布袋避免刮蹭内层面料。三个配色不管是搭休闲装还是工装风都毫无违和感，颜值实用性双在线。'),
    ('p_clothes_019', '这款Nike Heritage86 Futura刺绣棒球帽是日常出街的百搭刚需款，帽身用的是重磅水洗棉面料，软而不塌不会随便变形，正面经典Futura勾子是高密度立体刺绣，摸上去有明显凹凸感不是廉价热印。后面配的尼龙魔术贴调节扣，头围54到60厘米都能贴合适，不用怕卡头或者掉帽檐。学生党早八赶课遮乱发、健身跑街挡小太阳、出游搭运动服卫衣都适配，不用特意搭配就能出片。平时洗的时候建议手洗反过来搓刺绣部分，别长时间泡热水，挂在通风处阴干就好，别用洗衣机搅不然容易把帽檐衬布搅歪，戴个两三年质感都不会垮。'),
    ('p_clothes_020', '这是迪卡侬KALENJI系列专为男性跑者打造的基础训练速干T恤，整衣采用高密聚酯纤维蜂窝网眼面料，重量仅120g左右，上身几乎零负担。面料自带的导水沟槽结构能快速把运动产生的汗液从皮肤表面导出扩散，30℃以上天跑5公里也不会贴身黏糊，跑后半小时自然晾干完全不留汗味。专门适配夜跑的反光条嵌在衣摆侧边，傍晚沿江跑也能让来往车辆清晰注意到你。版型做了微宽松剪裁，不会紧勒胸口抬臂跑完全不卡肩。适合日常路跑、健身房力量训练、周末郊野徒步、日常通勤遛弯等多种场景，不管是刚入门的跑步新手还是日常保持训练的运动爱好者都能穿。洗涤建议用常温水手洗或轻柔机洗，不要用柔顺剂浸泡，会破坏面料的导汗结构，长时间暴晒也容易让速干层老化变硬。'),
    ('p_clothes_021', '这款Nike Dri-FIT Miler男子速干短袖T恤，专为公路跑、日常路跑训练打造，采用耐克专属Dri-FIT速干科技面料，能快速把运动时体表的汗液导流到面料外层挥发，跑完全程后背也不容易闷出黏腻感。整体面料做了轻量化处理，比普通棉T恤轻将近一半，上身几乎零负担，肩部和侧缝的剪裁做了优化，大幅度摆臂时完全不会卡胳肢窝。特别适合日常有3-10公里公路跑训练需求的跑者，也能用来做健身房有氧、夜骑、日常通勤穿搭。建议手洗或轻柔机洗，不要用漂白剂浸泡，晾晒时避免长时间暴晒，能更好保留面料的速干性能，不要穿着它长时间泡在水里，避免影响使用寿命。'),
    ('p_clothes_022', '这款adidas Originals三叶草男款连帽套头卫衣，是街头潮流爱好者的刚需款，核心卖点就是胸口的经典三叶草白底刺绣logo，复古辨识度拉满不撞款。面料用的是320g重磅亲肤毛圈棉，不薄不透、贴身穿软乎乎的还不容易起球，连帽处的抽绳做了同色系加固设计，洗多少次都不会变形。不管是日常上课、通勤遛弯，还是约兄弟去球馆热身、周末逛潮展穿都适配。版型是偏宽松的落肩剪裁，微胖男生穿也能藏住小肚腩不显臃肿。选码建议日常穿常规码数选对应码数就行，喜欢oversize风可以拍大一码，注意不要用热水长时间浸泡，反面翻过来洗能最大程度保护logo不会脱落。'),
    ('p_clothes_023', '优衣库这款男士DRY速干运动短裤，采用品牌专属的高密透气速干面料，摸上去是薄而有韧劲的肌理感，完全不闷汗不贴腿，走步带风的轻薄感夏天穿特别舒服。核心卖点是运动后10分钟左右就能把表层汗气全散掉，不会像普通棉短裤那样湿乎乎贴在腰胯上难受。特别适合日常晨跑、健身房力量训练、室内篮球半场局穿，日常下楼取快递、遛弯买菜、居家当睡裤也完全合适。面料是经过抗起球预处理的，机洗不容易起毛边，洗完挂晾半小时差不多就能干透。使用建议选比平时穿的休闲裤大半个码更宽松，运动做大幅度踢腿动作也不会卡裆，注意不要和带尖锐装饰的牛仔裤同洗，避免勾丝，浅色款久穿轻微泛黄可以用中性洗衣液轻轻搓揉就能恢复，不用大力拧扯面料。'),
    ('p_clothes_024', '这款北面Horizon系列轻量速干运动鸭舌帽，专门为户外出行和日常运动打造，帽身采用北面专属的速干针织面料，整体重量不到80g，上头顶着几乎没负担。面料自带细密透气网眼结构，长时间佩戴也不会闷出满头汗，还自带UPF50+的防晒力，能挡住大部分正午直射的紫外线，避免脸侧和后颈被晒红。后脑勺是可调节的魔术贴设计，不管头围54cm到61cm的男女都能调到最贴合的松紧度，不会跑跳两下就掉。不管是周末徒步登山、日常夜跑晨练、通勤骑车买咖啡，还是去海边露营逛景点都能用。平时戴完随手塞包里也不占地方，脏了直接冷水手洗阴干就行，别用热水泡也别扔烘干机烘，不然会破坏速干面料的防晒涂层。'),
    ('p_clothes_025', '这款Osprey日光+20L双肩包绝对是轻量出行的刚需款，主身用的是高密度防泼水面料，整包自重才不到0.7kg，背久了也不会压肩。核心卖点就是兼顾户外徒步和日常通勤双场景适配，正面带快取仓可以直接塞公交卡和口罩，侧面弹力网兜能插下500ml水杯和折叠遮阳伞，主仓内层有专门的15.6寸电脑隔层，分区特别清晰。不管是周末单日近郊徒步的驴友，还是每天挤地铁的通勤族、出门逛展的学生党都能用。平时背的时候尽量别装超过10kg的重物，不要长时间泡在水里，虽然防泼溅但大雨里还是建议套个防雨罩，能用好多年都不变形。'),
    ('p_food_001', '三顿半数字星球系列的超即溶咖啡，把6种不同烘焙度的精品咖啡装进迷你小杯，从浅烘带柑橘花香的1号，到深烘有可可焦香的6号，不用专业器具也能一秒冲出门店级口感。选用100%阿拉比卡精品豆，通过低温冻干锁留住豆子原有的风味，没有额外添加糖和植脂末。不管是早八赶时间的上班族、需要提神的学生党，还是爱尝不同风味的咖啡爱好者都适配：早上配冰牛奶做拿铁，下午兑气泡水做特调，出门塞两小杯在包里完全不占地方。建议开封后3天内喝完风味最佳，平时放在阴凉干燥处避光保存，别放在冰箱容易受潮影响溶解速度。'),
    ('p_food_002', '这款雀巢1+2原味三合一速溶咖啡，是很多老粉喝了十几年的经典款！每一条精准配比了阿拉比卡咖啡粉、进口奶源和白砂糖，冲开就是入口丝滑的奶香咖啡味，完全没有焦苦感，不用额外加奶加糖超省心。不管是朝九晚五的打工人早八醒神、学生党熬夜赶作业，还是朋友小聚想快速调出一杯暖饮，撕开包装用150ml左右的85℃热水冲开搅两下就搞定，3秒就能出杯。咱们有两个规格可选：50条小包装适合独居上班族尝鲜，100条家庭装性价比更高，放办公室茶水间、家里储物柜都合适。注意开袋后要马上冲饮，没喝完的整条要放在阴凉干燥处避光保存，别放冰箱容易受潮结块哦。'),
    ('p_food_003', '喜欢纯茶味又怕甜腻的朋友看过来！东方树叶无糖乌龙茶是农夫山泉旗下火了十多年的经典款，整瓶完全不含额外添加糖，热量几乎为0，用的是真乌龙茶萃取液，没有多余香精勾兑，入口是炭火焙香的醇厚茶味，回甘清润不会发涩发苦。特别适合控糖人群、健身党、上班摸鱼想解腻的打工人，还有爱喝奶茶又怕长胖的姐妹当低糖替代。上班放工位摸鱼喝，吃重油重盐的外卖配它解腻解辣，出门健身塞包里随时补水解渴都合适。建议阴凉处存放，开封后尽量24小时内喝完，冰镇之后茶香味会更突出，注意未开封的状态下别放在阳光直晒的地方久放，避免风味流失哦。'),
    ('p_food_004', '元气森林白桃味气泡水是专为怕甜怕腻又爱爽感的人量身打造的快乐水，核心就是实打实的0糖0脂0卡，用赤藓糖醇代替白砂糖，喝起来完全没有普通碳酸饮料喝完齁嗓子反酸的问题，入口是刚咬开脆甜水蜜桃的鲜爽香气，细密的气泡在舌尖炸开，凉丝丝的特别解腻。不管是健身控卡期的运动党、正在控糖的减脂人群、怕胖的学生上班族，还是戒糖又嘴馋的奶茶爱好者都能放心喝。平时吃火锅撸串配它解辣解腻，上班困了冰一瓶提神醒脑，逛超市随手拿一瓶边走边喝也很方便。收到货如果没开封最好放阴凉避光处，别暴晒，冰1-2小时口感最好，开瓶之后尽快喝完避免气泡散掉哦。'),
    ('p_food_005', '这款东鹏特饮500ml经典瓶装功能饮料，是不少熬夜党、运动族的随身能量补给首选。核心添加了牛磺酸、适量咖啡因与多种B族维生素，大瓶500ml的容量比常规小瓶多了近一半，一口下去是熟悉的清甜焦香口感，快速帮你驱散困意、补充消耗的体能。特别适合开长途的货车司机、连续加班的上班族、课后还要训练的体育生，或是约着组队打一下午球的球友。建议犯困、体能告急时小口慢饮，不要短时间猛灌，孕妇、未成年人和对咖啡因敏感的朋友就不要饮用啦，常温避光存放就能保留新鲜风味。'),
    ('p_food_006', '这款国产红牛维生素功能饮料，每罐250ml科学配比牛磺酸、赖氨酸，搭配适量咖啡因与多种B族维生素，精准补充身体消耗的能量，不是甜腻的汽水感，入口是大家熟悉的清爽酸甜味。特别适合跑长途的货车司机、经常熬夜赶方案的上班族、周末约着打球撸铁的运动党，还有踏青出游、加班备考、长时间开黑这些容易犯困没精神的场景，拿出来喝一罐十几分钟就能感觉到状态回来。现在有整箱24罐和半箱12罐两个规格可选，整箱装囤在家放办公室都很划算，开罐即饮特别方便。要注意的是，这款饮料不建议睡前喝，孕妇、未成年人和对咖啡因敏感的朋友也不建议饮用，运动后别直接猛灌，稍缓两分钟再喝更舒服哦。'),
    ('p_food_007', '伊利金典有机纯牛奶选用专属有机牧场的甄选奶源，全程遵循有机标准管控，不额外添加人工成分，每盒250ml都带着自然的浓郁乳香，乳蛋白含量高于普通纯牛奶，口感顺滑不腥腻。这款常温盒装牛奶分12盒、24盒两种规格可选，72元12盒、135元24盒的定价也很划算，不管是家里有学龄孩子当早餐配面包、上班族办公室下午饿了当加餐，还是长辈日常补充营养都特别合适。平时囤货放在阴凉干燥处避光保存就行，开盒即饮特别方便，要是肠胃怕凉也可以隔着温水温个2分钟再喝，注意没喝完的牛奶要密封放冷藏，24小时内喝完避免变质哦。'),
    ('p_food_008', '蒙牛纯甄这款经典原味常温酸牛奶，没有额外添加香精、防腐剂，生牛乳发酵出的口感绵密丝滑，酸香里裹着淡淡的自然乳甜，完全没有齁人的工业甜味。200g的小盒身材刚好，揣在通勤包、学生书包里都不占地方，不管是赶早八路上配面包当快手早餐，下午办公室摸鱼解腻，还是家里小孩放学当加餐都合适。全年龄段都能喝，家里老人怕凉也不用热得麻烦，常温放着就能随时掏出来喝。建议开盒就一次性喝完，别放太久影响风味，没开封的话避光阴凉处存就行，别搁太阳直晒的地方。'),
    ('p_food_009', '三只松鼠这款每日坚果专门为懒得搭配坚果、追求每日精准营养的朋友量身打造，整整30袋总重750g，每袋都是25g的独立密封小包装，不用怕开袋后受潮变质。搭配都是科学配比的6种果仁果干，没有额外添加白砂糖调味，保留坚果原生香，不会齁甜发腻。不管是职场人通勤揣一袋当下午茶垫肚子，学生党课间补充能量，还是宝妈给家里小朋友当健康加餐、全家周末出游揣几袋解闷都合适。建议每天拆开1袋直接吃，也可以倒在酸奶、燕麦碗里拌着吃，口感层次更丰富。要注意坚果开封后尽量当天吃完，里面的果仁含少量油脂，放在阴凉干燥处存放，别暴晒也别放冰箱冷藏容易返潮。礼盒装还能直接当伴手礼送亲戚朋友，体面又实用。'),
    ('p_food_010', '良品铺子这款肉松饼可是实打实的国民解馋小点心，足足1000g整箱装差不多有40枚，皮薄得能透出内里满满的肉松，咬一口外层酥软掉渣，内馅咸香不腻，肉香直钻鼻腔，完全不是那种淀粉感很重的廉价货。配料里用的是精选猪腿肉松，搭配小麦粉和鲜鸡蛋调的外皮，不加多余的人工香精，老人小孩吃着也放心。平时赶早八来不及买早饭，揣两个在包里配杯热牛奶就能顶一上午；办公室摸鱼饿了拿一个垫肚子，出门郊游分给同行的朋友也够吃。家里囤货选1kg装更划算，要是想先试味选500g约20枚的规格也合适，注意开封后尽量3天内吃完，放在阴凉干燥处别晒，受潮了外皮会软掉影响口感哦。不管是学生党、上班族还是平时爱囤点心的长辈，都能吃得满意。'),
    ('p_food_011', '作为国民级泡面标杆，这箱康师傅经典红烧牛肉面绝对是你手边的稳妥速食选择！每桶足足110g面饼，搭配专属熬制的红烧牛肉酱包、金黄脱水蔬菜包和鲜香风味粉包，泡开后牛肉香直钻鼻子，面条筋道不发软。不管是熬夜赶项目的上班族、宿舍赶作业的学生党，还是长途自驾游想快速垫肚子的出行族都超适配，加班晚归不想开火、临时加餐、懒癌犯了不想做饭的时候，倒满开水焖3分钟就能吃上热乎的。建议泡的时候加根火腿肠或者卧个鸡蛋，口感直接升级。注意哦，未开封要放在阴凉干燥处避光存放，拆封后要及时食用，里面的脱水料包千万别直接倒干吃，避免齁咸。'),
    ('p_food_012', '咱这款统一老坛酸菜牛肉面可是出了名的国民经典款，每桶足足121g，酸脆发酵的老坛酸菜是核心灵魂，搭配劲道非油炸感的面饼、浓郁牛肉汤底包，酸辣平衡得刚好够味。特别适合租房打工人、熬夜备考学生党、长途出行的旅客囤货，不管是加班到深夜懒得开火，周末宅家追剧不想点外卖，还是临时应急垫肚子都超合适。建议大家泡的时候先把酸菜包全部倒进去，用刚烧开的沸水没过面饼，盖盖焖5分钟再拌开，酸香味直接飘满整个屋子。注意整箱存放要放在阴凉干燥不晒太阳的地方，拆封后尽快食用，对酸菜类食材过敏的朋友要谨慎下单哦，6桶小规格适合尝鲜，12桶整箱装性价比拉满够吃大半个月。'),
    ('p_food_013', '这款海天金标生抽1.9L大瓶装，是无数家庭厨房的常驻调味王牌，核心卖点就是采用非转基因黄豆经传统高盐稀态工艺足期酿造，酱香味醇厚自然，鲜度不齁不冲，完全没有工业调味的突兀感。特别适合日常开火频率高的三口之家、租房党整屋拼饭的年轻人，还有常给孩子做辅食餐的宝妈。平时不管是白切鸡蘸料、凉拌黄瓜提鲜，还是家常小炒、焖炖上色都能用，主要成分只有水、非转基因大豆、小麦粉、食用盐，没有多余的杂七杂八添加剂，吃着放心。建议开盖后放冰箱冷藏，要是平时用得少也可以选500ml小瓶装避免放久风味散掉，注意别放在灶台边长期被高温烘烤，容易提前变质变味。'),
    ('p_food_014', '农夫山泉旗下东方树叶无糖茉莉花茶，是真正做到0糖0脂0卡的纯茶饮品，没有添加任何代糖、香精和防腐剂，萃取广西横县当季双瓣茉莉花的鲜爽香气，搭配绿茶茶底的清润回甘，茶味不苦涩、花香不冲鼻，入口是完全自然的茶感。不管是控糖期人群、怕胖的上班族，还是戒了奶茶的学生党、日常不爱喝白水的茶友都很适合。摸鱼工位放一瓶解腻消乏，饭后喝解重油重盐的外卖腻感，健身后喝不会给身体添额外负担，出门郊游塞包里也不占地方。建议开瓶后24小时内喝完，避免风味流失，未开封状态放在阴凉避光处保存就行，别长期放太阳下直晒避免瓶身变形影响口感。'),
    ('p_food_015', '这款可口可乐零度汽水是专为怕甜又舍不得经典可乐风味的爱好者打造的无糖碳酸饮料，完全不添加白砂糖，采用阿斯巴甜等合法代糖调出和原味可乐几乎无差的激爽口感，喝下去一口就会冲上来绵密的气泡，带着熟悉的可口可乐标志性香气，完全没有代糖常见的奇怪后味。330ml的罐装大小刚好是一次能喝完的量，不会因为开瓶放久跑气浪费。不管是平时健身控卡的运动党、戒糖的上班族、怕热量超标的学生党都适合喝。追剧看球赛、朋友宅家开黑、吃火锅撸串解腻、上班摸鱼提神的时候掏出来冰一下，爽感直接拉满。提醒大家开罐的时候别对着人对着自己的脸，冰镇别放零度以下太久，不然容易喷罐，碳酸饮料开了尽快喝完别放隔夜就好。现在还能选12罐的迷你装，想先试试水的朋友也完全没负担。'),
    ('p_food_016', '这款蒙牛特仑苏纯牛奶可是很多家庭的日常囤货首选，采用专属限定牧场的优质生牛乳奶源，没有额外添加香精、防腐剂，每100ml就含有3.6g优质乳蛋白，奶香醇厚不寡淡，入口顺滑没有奶腥味。不管是正在长身体的中小学生、需要补充营养的上班族，还是日常补钙的中老年群体都很适合。早上赶时间配面包当早餐，下午办公室泡咖啡做拿铁，晚上睡前温一杯助眠，家庭聚会分给客人都很合适。平时建议放在阴凉干燥处避光储存，喝之前要是肠胃怕凉可以连盒放到40度左右的温水里捂3分钟，注意不要高温煮沸破坏营养，开盒后要24小时内喝完哦。现在有16盒家庭装和24盒礼盒装可选，日常自喝选16盒刚好够半个月的量，走亲访友拎24盒的礼盒装也特别体面。'),
    ('p_food_017', '伊利安慕希这款原味希腊风味常温酸奶，采用甄选优质生牛乳发酵，蛋白质含量比普通国标酸奶高出35%，口感浓稠丝滑，自带天然发酵的清醇奶香，没有多余的香精甜腻感。不用冷藏就能储存的特性特别省心，不管是早八人赶时间抓一盒配面包当快手早餐，宝妈给娃装去学校当课间加餐，还是居家追剧、办公室摸鱼当解馋小食都超适配，控糖人群、老人小孩都能放心喝。建议开盒就尽快喝完，没开封的话放在阴凉干燥处避光保存就行，要是肠胃怕凉，冬天也可以连盒泡在40度左右的温水里温2分钟再喝，注意不要高温煮沸也不要冷藏后冻成冰，避免破坏里面的活性营养物质哦。现在有10盒普通装和16盒组合装两个规格可选，日常囤货选组合装性价比更高。'),
    ('p_food_018', '李锦记这款特级草菇老抽，核心卖点是添加了自然发酵的草菇浸出液，晒足180天的传统工艺酿造，上色红亮挂壁不发苦，咸香醇厚不带刺鼻酱味。特别适合平时爱做红烧菜、卤味的三口以上大家庭、开小餐馆的个体户，日常做红烧肉、酱牛肉、红烧茄子、卤猪脚都能用，只要几滴就能给食材挂上亮红的酱色，不用额外炒糖色省很多事。成分选用非转基因大豆、小麦粉搭配新鲜草菇提取液，没有添加人工合成的焦糖色。使用建议红烧时出锅前10分钟放就足够，别倒太多避免菜色发黑，开封后一定要放在冰箱冷藏层保存，避免长时间放在灶台边高温环境里导致风味变酸变质。'),
    ('p_food_019', '百草味这款每日坚果A款是专门搭配好的黄金配比混合坚果礼盒，单包25g刚好是成人每日摄入坚果的推荐量，里面包含巴旦木仁、夏威夷果仁、榛子仁、核桃仁这4种纯坚果，再搭配蔓越莓干、蓝莓干2种果干，没有多余的调味添加，坚果都是低温慢烘锁鲜，不会有油耗味。不管是通勤路上揣两袋当摸鱼小零食，给家里老人小孩当日常营养补给，还是办公室同事分着吃、周末带出门当露营小食都特别合适。目前有两个规格可选，30袋经典款刚好够吃整一个月，40袋家庭分享装更适合多口之家囤货。要注意开封后尽量当天吃完，没吃完的记得密封放阴凉干燥处，有坚果过敏情况的朋友千万别食用哦。'),
    ('p_food_020', '日清合味道海鲜风味整箱12杯装，是无数学生党、加班族私藏的速食刚需！每杯精准79g分量刚好管饱，不用自己拆调料包，粉包料包都预封在杯里，浇上沸水等3分钟就能吃。汤底是经典的海鱼熬制鲜味儿，混着细碎的模拟蟹柳、小虾和葱花，面条是日清特有的非油炸韧性麦芯面，久泡也不发坨。特别适合深夜赶方案的打工人、宿舍断电没法开火的学生，还有周末宅家不想点外卖的懒人当垫肚餐。建议泡的时候水位刚好到杯身标线，别加太多水冲淡鲜味，注意开封后如果发现杯盖鼓胀、面饼发霉千万别吃，整箱囤放要放在阴凉干燥处避开阳光直晒，放两三个月都不会坏。'),
    ('p_food_021', '从小到大吃的经典康师傅红烧牛肉面来啦！每袋足足114g，面饼搭配秘制红烧牛肉酱包，还有脱水蔬菜粒和浓缩骨汤粉，煮出来汤汁浓得挂面，咸香带点微甜的老味道完全没改版。不管是熬夜追剧的学生党、加班到深夜的打工人，还是周末不想开火的独居青年都合适。赶时间的时候开水泡3分钟就能吃，有空的话加个煎蛋烫把青菜，直接升级成馆子级别的美味。现在有五连包、10袋家庭装还有20袋整箱装可以选，囤一次能吃大半个月。要注意的是里面的酱包油脂含量不低，肠胃弱的朋友别放全，开封之后要尽快吃完，别放潮了影响口感哦。'),
    ('p_food_022', '三顿半这款冷萃超即溶黑咖啡，专门用冷萃工艺萃取精品阿拉比卡咖啡豆，全程低温锁香，没有普通速溶的焦苦感，入口是清润的坚果淡香，几乎没有酸涩味。6颗便携小杯装完全无添加糖、无植脂末，纯黑咖啡配方，控糖健身党、日常靠咖啡续命的打工人、喜欢户外出行的咖啡爱好者都适配。办公室赶方案丢进矿泉水瓶摇3秒就能泡好，居家配冰块就是门店级冰冷萃，周末露营塞包里完全不占地方。建议用200-300ml常温水/冰水冲调，热泡也不发酸，开封后尽快饮用，储存在阴凉干燥处避免阳光直晒，开罐后注意密封防潮。现在还有6颗尝鲜装和12颗囤货装可选，性价比超高。'),
    ('p_food_023', '这款雀巢金牌冻干速溶黑咖啡，用的是先进的低温冻干锁香技术，把阿拉比卡咖啡豆的焦香和坚果香气完整留住，完全不像普通速溶的酸涩感。配料表只有纯咖啡粉，没有额外添加糖和植脂末，喝着完全无负担。不管是早八人赶通勤冲一杯消水肿，下午办公室摸鱼醒神，还是健身前喝一杯提升燃脂效率都超合适。100g玻璃瓶装的密封性特别好，每次喝舀1-2勺用85℃左右的温水冲开就行，怕苦的加冰加燕麦奶都很搭。注意开封后要放在阴凉干燥处密封保存，别让水汽跑进去结块，按每天喝1杯算100g装大概能喝1个多月，想更划算直接入200g经济装更省心。'),
    ('p_food_024', '夏天怕喝甜饮料长胖的朋友看过来！这款元气森林白葡萄味苏打气泡水，核心就是0糖0脂0卡的清爽配方，用赤藓糖醇替代普通蔗糖，入口是沁爽的白葡萄鲜果香气，没有人工甜味剂的齁感，细密的气泡在舌尖炸开的感觉特别解腻。不管是上班族下午摸鱼解乏、健身后补水、家庭聚餐解辣解腻，还是朋友露营聚会分享都超合适，整箱囤性价比更高。建议冷藏后口感更佳，开封后尽量2小时内喝完避免气泡散掉，注意未成年小朋友不建议大量饮用碳酸类饮品，肠胃敏感人群也不要空腹猛喝哦。'),
    ('p_food_025', '农夫山泉水溶C100柠檬味饮料，每瓶足足添加相当于3个新鲜柠檬的维C含量，酸甜度刚好卡在黄金比例，不会像纯柠檬汁那样涩口酸牙，也没有普通甜饮料的齁腻感，入口是清爽的鲜柠檬香气，余味还带着淡淡的柑橘清苦感。特别适合日常通勤族、学生党、运动爱好者饮用，摸鱼时配外卖、健身后补充电解质、野餐聚会分着喝都超合适，没有添加人工合成维C成分，天然萃取的维生素C好吸收，平时上班赶时间来不及吃水果，揣一瓶就能补够每日所需的部分维C。建议冰镇后口感更佳，开封后尽量24小时内喝完，避免阳光直晒存放，糖分控制得很友好，怕胖的朋友日常当调味水喝也无负担。')
ON CONFLICT (product_id) DO UPDATE
   SET marketing_description = EXCLUDED.marketing_description,
       updated_at = now()
;

