    ('p_beauty_002:product_profile:0', 'p_beauty_002', 'p_beauty_002:product_parent:0', 'child', 'product_profile', 0, '# 兰蔻小黑瓶全新精华肌底液修护维稳细腻毛孔提亮肤色30ml
