    ('p_beauty_020:product_profile:0', 'p_beauty_020', 'p_beauty_020:product_parent:0', 'child', 'product_profile', 0, '# 雅诗兰黛持妆粉底液SPF10PA持久遮瑕控油抗汗清透底妆30ml
