    ('p_food_001:product_parent:0', 'p_food_001', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_001","externalRef":"p_food_001","title":"三顿半 数字星球系列 超即溶精品咖啡1-6号 18颗装精品速溶咖啡","brand":"三顿半","category":"食品饮料","subCategory":"咖啡","categoryPath":"食品饮料/咖啡","priceMin":128.0,"priceMax":258.0,"stock":1400,"imagePath":"4_食品生活/images/p_food_001_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_001:product_profile:0', 'p_food_001', 'p_food_001:product_parent:0', 'child', 'product_profile', 0, '# 三顿半 数字星球系列 超即溶精品咖啡1-6号 18颗装精品速溶咖啡
品牌：三顿半
