    ('p_food_009:product_parent:0', 'p_food_009', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_009","externalRef":"p_food_009","title":"三只松鼠 每日坚果750g/30袋 混合坚果仁干果礼盒独立小包装","brand":"三只松鼠","category":"食品饮料","subCategory":"坚果/零食","categoryPath":"食品饮料/坚果/零食","priceMin":59.0,"priceMax":99.0,"stock":400,"imagePath":"4_食品生活/images/p_food_009_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_009:product_profile:0', 'p_food_009', 'p_food_009:product_parent:0', 'child', 'product_profile', 0, '# 三只松鼠 每日坚果750g/30袋 混合坚果仁干果礼盒独立小包装
