    ('p_food_010:product_parent:0', 'p_food_010', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_010","externalRef":"p_food_010","title":"良品铺子 肉松饼1000g/箱 松软糕点休闲零食早餐代餐点心","brand":"良品铺子","category":"食品饮料","subCategory":"坚果/零食","categoryPath":"食品饮料/坚果/零食","priceMin":32.0,"priceMax":62.0,"stock":400,"imagePath":"4_食品生活/images/p_food_010_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_010:product_profile:0', 'p_food_010', 'p_food_010:product_parent:0', 'child', 'product_profile', 0, '# 良品铺子 肉松饼1000g/箱 松软糕点休闲零食早餐代餐点心
品牌：良品铺子
类目：食品饮料/坚果/零食
价格区间：32.0 ~ 62.0
