    ('p_food_013:product_parent:0', 'p_food_013', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_013","externalRef":"p_food_013","title":"海天 金标生抽1.9L 瓶装酱油 家用厨房调味料酱香鲜味佐餐蘸料","brand":"海天","category":"食品饮料","subCategory":"调味品","categoryPath":"食品饮料/调味品","priceMin":9.0,"priceMax":22.0,"stock":400,"imagePath":"4_食品生活/images/p_food_013_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_013:product_profile:0', 'p_food_013', 'p_food_013:product_parent:0', 'child', 'product_profile', 0, '# 海天 金标生抽1.9L 瓶装酱油 家用厨房调味料酱香鲜味佐餐蘸料
品牌：海天
