    ('p_food_014:product_parent:0', 'p_food_014', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_014","externalRef":"p_food_014","title":"农夫山泉 东方树叶 无糖茉莉花茶饮料 500ml×15 瓶装茶饮","brand":"农夫山泉","category":"食品饮料","subCategory":"茶饮","categoryPath":"食品饮料/茶饮","priceMin":70.0,"priceMax":118.0,"stock":400,"imagePath":"4_食品生活/images/p_food_014_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_014:product_profile:0', 'p_food_014', 'p_food_014:product_parent:0', 'child', 'product_profile', 0, '# 农夫山泉 东方树叶 无糖茉莉花茶饮料 500ml×15 瓶装茶饮
