    ('p_food_017:product_parent:0', 'p_food_017', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_017","externalRef":"p_food_017","title":"伊利 安慕希 希腊风味常温酸奶 原味 205g×10 盒装","brand":"伊利","category":"食品饮料","subCategory":"酸奶","categoryPath":"食品饮料/酸奶","priceMin":62.0,"priceMax":108.0,"stock":400,"imagePath":"4_食品生活/images/p_food_017_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_017:product_profile:0', 'p_food_017', 'p_food_017:product_parent:0', 'child', 'product_profile', 0, '# 伊利 安慕希 希腊风味常温酸奶 原味 205g×10 盒装
品牌：伊利
