    ('p_food_018:product_parent:0', 'p_food_018', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_018","externalRef":"p_food_018","title":"李锦记 特级草菇老抽 1.65L 瓶装酱油 家庭厨房调味品","brand":"李锦记","category":"食品饮料","subCategory":"调味品","categoryPath":"食品饮料/调味品","priceMin":9.0,"priceMax":32.0,"stock":400,"imagePath":"4_食品生活/images/p_food_018_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_018:product_profile:0', 'p_food_018', 'p_food_018:product_parent:0', 'child', 'product_profile', 0, '# 李锦记 特级草菇老抽 1.65L 瓶装酱油 家庭厨房调味品
品牌：李锦记
