    ('p_food_023:product_parent:0', 'p_food_023', NULL, 'parent', 'product_parent', 0, NULL, NULL, false, 'none', '{"field":"product"}'::jsonb, '{"productId":"p_food_023","externalRef":"p_food_023","title":"雀巢 金牌 冻干速溶咖啡 100g 瓶装 黑咖啡","brand":"雀巢","category":"食品饮料","subCategory":"咖啡","categoryPath":"食品饮料/咖啡","priceMin":36.0,"priceMax":78.0,"stock":400,"imagePath":"4_食品生活/images/p_food_023_live.jpg","chunkLevel":"parent","chunkType":"product_parent"}'::jsonb),
    ('p_food_023:product_profile:0', 'p_food_023', 'p_food_023:product_parent:0', 'child', 'product_profile', 0, '# 雀巢 金牌 冻干速溶咖啡 100g 瓶装 黑咖啡
品牌：雀巢
